INSERT INTO `faq` (`id`, `parent_id`, `key_name`, `question_text`, `answer_text`) VALUES
(1, NULL, 'P1', 'ASI Eksklusif', NULL),
(2, 1, 'P1.1', 'Apa peran BKKBN dalam mendukung pemberian ASI eksklusif di masyarakat?', 'Memberikan edukasi tentang pentingnya ASI eksklusif dan mendukung layanan konseling menyusui.'),
(3, NULL, 'P2', 'Anemia', NULL),
(4, 3, 'P2.1', 'Bagaimana upaya BKKBN dalam mencegah anemia pada remaja dan ibu hamil?', 'Melakukan edukasi, pemeriksaan kesehatan, dan distribusi tablet tambah darah untuk remaja dan ibu hamil.'),
(5, 3, 'P2.2', 'Apa itu Anemia?', 'Anemia adalah kondisi ketika jumlah sel darah merah dalam tubuh rendah dan tidak berfungsi dengan baik. Kondisi ini membuat tubuh tidak mendapat cukup oksigen sehingga kulit akan terlihat lebih pucat dan tubuh terasa mudah lelah'),
(6, 3, 'P2.3', 'Apa penyebab anemia?', 'Anemia terjadi ketika tubuh kekurangan sel darah merah sehat atau hemoglobin. Akibatnya, kadar oksigen di dalam darah berkurang (hipoksemia) dan sel-sel dalam tubuh juga tidak mendapat cukup oksigen. Hal ini dapat mengganggu fungsi organ secara menyeluruh.\n \n Secara garis besar, anemia terjadi akibat tiga kondisi berikut ini:\n \n - Produksi sel darah merah yang kurang\n - Kehilangan darah secara berlebihan\n - Hancurnya sel darah merah yang terlalu cepat'),
(7, 3, 'P2.4', 'Anemia lebih sering terjadi kepada siapa?', 'Di Indonesia, anemia rentan terjadi pada kelompok remaja. Tidak hanya remaja perempuan, tetapi remaja laki-laki juga berisiko mengalami anemia. Hanya saja, prevalensi anemia pada perempuan 6% lebih tinggi daripada laki-laki.'),
(8, 3, 'P2.5', 'Apa penyebab anemia pada remaja?', 'Anemia pada remaja umumnya disebabkan oleh:\n \n - Kurangnya pengetahuan dan kepedulian kelompok remaja dan orang disekitarnya akan anemia.\n - Kurangnya asupan zat besi, vitamin B9, vitamin B12, vitamin C, seng, dan protein.\n - Tingginya asupan makanan atau minuman yang menghambat penyerapan zat besi, seperti kopi dan teh yang mengandung fitat dan tanin.\n - Mengidap penyakit, seperti gangguan pencernaan, infeksi, dan berbagai penyakit kronis.\n \n Namun, remaja perempuan memiliki penyebab anemia yang lain, yaitu Menstruasi. Remaja perempuan akan kehilangan zat besi sebanyak 5–10% seiring dengan berlangsungnya menstruasi. Defisiensi zat besi ini akan menyebabkan siklus menstruasi menjadi tidak normal sehingga mereka rentan terkena anemia.'),
(9, 3, 'P2.6', 'Apa akibat dari anemia?', 'Secara umum, anemia menyebabkan gangguan pertumbuhan, gangguan fungsi kognitif dan psikomotorik, penurunan imunitas, serta penurunan produktivitas. Namun, pada remaja perempuan, anemia memiliki dampak jangka panjang yang lain, seperti persalinan prematur, peningkatan risiko kematian saat melahirkan, serta berat bayi lahir rendah (BBLR) dan stunting.'),
(10, 3, 'P2.7', 'Apa gejala anemia?', 'Berikut adalah gejala anemia yang harus diwaspadai.\n \n - 5L (lemah, letih, lesu, lelah, dan lalai)\n - Pandangan berkunang-kunang dan pusing\n - Pucat pada kulit, kelopak mata, bibir, lidah, telapak tangan, dan kuku.\n - Lebih emosional'),
(11, 3, 'P2.8', 'Bagaimana cara mencegah anemia?', 'Untuk mencegah anemia, lakukanlah langkah-langkah sebagai berikut!\n \n - Meningkatkan pengetahuan dan kepedulian akan anemia.\n - Mengonsumsi sumber protein hewani, seperti ayam, telur, ikan, dan daging untuk meningkatkan pembentukan Hb.\n - Mengonsumsi makanan atau minuman yang dapat meningkatkan penyerapan zat besi, seperti sayur dan buah yang mengandung vitamin C dan seng.\n - Menghindari konsumsi makanan atau minuman yang dapat menghambat penyerapan zat besi setelah makan, seperti teh dan kopi.\n - Menghindari konsumsi tablet tambah darah (TTD) bersamaan dengan obat asam lambung, susu, teh, maupun kopi.'),
(12, 3, 'P2.9', 'Mengapa anemia lebih sering dialami remaja putri?', '> Remaja putri sedang tumbuh “cepat” dan aktifitasnya meningkat, sehingga kebutuhan zat gizi, termasuk zat gizi Besi dan zat gizi lainnya juga meningkat.\n > Remaja putri yang sudah mengalami haid akan kehilangan darah setiap bulan sehingga membutuhkan zat besi lebih banyak dibanding remaja putra.\n > Banyak remaja putri melakukan diet yang keliru untuk menurunkan berat badan dengan mengurangi asupan protein hewani, padahal protein hewani dibutuhkan untuk pembentukan hemoglobin darah.\n > Selain itu sebagian remaja putri terkadang mengalami gangguan haid yang lebih lama atau lebih banyak dari biasanya.\n \n Semua hal yang disebutkan di atas merupakan beberapa faktor risiko terjadinya a nemia pada remaja putri, itulah sebabnya mengapa remaja putri merupakan sasaran utama ( hulu) dalam memutus mata rantai terjadinya anemia pada masa remaja dewasa dan menuju masa kehamilan.'),
(13, 3, 'P2.10', 'Apakah Tablet Tambah Darah itu ?', 'Tablet Tambah darah (TTD) adalah suplemen yang berisi zat besi dan asam folat yang berfungsi untuk membantu membentuk hemoglobin darah.'),
(14, 3, 'P2.11', 'Siapa yang harus minum Tablet Tambah Darah (TTD)?', 'Remaja, calon pengantin, ibu hamil dan nifas erta Wanita usia subur lainnya (Usia ≥ 19 tahun tidak hamil) karena masih haid.'),
(15, 3, 'P2.12', 'Berapa dosis Tablet Tambah Darah yang diperlukan?', 'Untuk remaja putri yang tidak anemia (dosis pencegahan):\n Minum 1 tablet tambah darah setiap minggu, selama 1 (satu) tahun dengan total 52 tablet\n \n Untuk pengobatan bagi remaja putra dan putri yang anemia, dianjurkan untuk konsultasi ke dokter\n \n Cara mendapatkan tablet tambah darah, bisa ke puskesmas/dokter atau beli di apotek (dalam bentuk tablet tambah darah atau multi vitamin yang kandungan besi elementalnya minimal 30 mg).'),
(16, 3, 'P2.13', 'Apakah Tablet Tambah Darah berbahaya?', 'Tidak, bila diminum sesuai anjuran tetapi bagi mereka yang menderita penyakit darah tertentu seperti Thalassemia dan Hyperchromatosis. Tetapi untuk penderita Malaria, konsumsi Tablet Tambah Darah dihentikan dan dapat diberikan Kembali bila sudah sembuh.'),
(17, 3, 'P2.14', 'Mengapa minum Tablet Tambah Darah tidak berbahaya ?', 'Tubuh mempunyai kemampuan/mekanisme pengaturan penyerapan besi ke dalam tubuh (sifat otoregulasi). Bila dalam tubuh kita mempunyai cadangan zat besi yang cukup, maka zat besi yang dari makanan atau TTD yang kita minum hanya sedikit yang diserap, dan sisanya dibuang melalui faeces.'),
(18, 3, 'P2.15', 'Apa efek samping dari Tablet Tambah Darah?', 'Gejala yang mungkin timbul saat mengkonsumsi TTD, antara lain: perut perih, mual, sembelit dan kotoran berwarna hitam.\n \n Gejala ini pada umumnya tidak berbahaya, dan biasanya setelah beberapa waktu gejala ini berkurang.\n \n Untuk mengurangi gejala ini, sebaiknya TTD diminum kira-kira 1 jam setelah makan malam sebelum tidur agar zat besi bekerja saat kita tidur sehingga efek samping tidak terasa.'),
(19, 3, 'P2.16', 'Bagaimana Peran Tenaga Kesehatan, Remaja, Guru, Orang tua dan Masyarakat Bersama Program Kesehatan dan Pemda dalam Pencegahan/Penanganan Anemia?', 'Tenaga Kesehatan : memberikan edukasi kepada guru dan kader agar mempunyai pemahaman yang cukup dan benar tentang anemia, bahayanya dan cara pencegahannya.\n \n Remaja: dengan mempraktikkan pola makan bergizi seimbang dengan 4 pilarnya dan saling menularkan kepada temannya serta mengkonsumsi TTD sesuai anjuran\n \n Guru :\n - Memberikan motivasi kepada siswa tentang konsumsi TTD dan Kesehatan remaja\n - Memperkuat fungsi UKS dan partisipasi siswa\n - Memberikaan pemahaman dan motivasi kepada orang tua tentang bahaya anemia dan manfaat pola makan bergizi seimbang, dan manfaat konsumsi TTD agar dapat memotivasi anaknya.\n \n Orang Tua :\n Dengan memotivasi/mengingatkan anaknya tentang pola makan dan konsumsi TTD\n Masyarakat antara lain kader, PKK dan kelompok masyarakat saling mendukung dalam upaya menurunkan anemia pada remaja dan kelompok lainnya melalui posyandu, karang taruna, dan lain-lain.\n \n Mengingat masih tingginya prevalensi anemia pada remaja di Indonesia dan menunjukkan adanya kenaikan pada periode 5 (lima) tahun terakhir yang meningkatkan risiko masalah anemia pada remaja yang dapat mengakibatkan risiko kurang sehat, rendahnya prestasi di sekolah dan juga produktifitas kerja maka sangat diperlukan dukungan semua pihak antara lain remaja , lingkungan di rumah, kelompok sebaya, sekolah dan masyarakat untuk bekerja bersama sektor Kesehatan dan pemerintah daerah untuk mensukseskan aksi bergizi pencegahan masalah anemi pada remaja putri dengan konsumsi Tablet Tambah Darah setiap minggu'),
(20, 3, 'P2.17', 'Makanan apa yang mencegah anemia?', 'Daging merah, hati ayam, bayam, kacang-kacangan.'),
(21, 3, 'P2.18', 'Apa yang dimaksud anemia pada ibu hamil?', 'Anemia adalah kondisi terjadinya kekurangan  jumlah sel darah \nmerah yang berperan untuk mengangkut oksigen sehingga tidak mencukupi kebutuhan oksigen secara fisiologis bagi tubuh orang. Anemia pada wanita hamil terjadi apabila kadar hemoglobin darah kurang dari 11g/dl. Pada wanita yang sehat dengan  kecukupan zat besi, konsentrasi hemoglobin berubah drastis selama hamil untuk mencukupi peningkatan volume darah ibu \ndan kebutuhan zat besi bagi janin. Konsentrasi akan menurun selama trimester pertama dan mencapai titik terendah pada \ntrimester kedua. Kadar hemoglobin akan meningkat kembali pada trimester ketiga.'),
(22, 3, 'P2.19', 'Bagaimana anemia pada ibu hamil dapat mempengaruhi kehamilan dan persalinan?', 'Anemia yang terjadi pada kehamilan meningkatkan risiko kematian ibu dan bayinya. Selain itu, anemia tersebut meningkatkan risiko \nterjadinya keguguran, kelahiran mati, kelahiran prematur, dan BBLR.'),
(23, NULL, 'P3', 'BKB', NULL),
(24, 23, 'P3.1', 'Pertemuan penyuluhan kegiatan kelompok BKB HI dilaksanakan minimal dalam kurun waktu...', '1 kali dalam sebulan'),
(25, 23, 'P3.2', 'Pelaksanaan program pengasuhan anak usia dini dalam rangka pencegahan stunting melalui kelompok bina keluarga balita meliputi...', 'Penyuluhan, kunjungan rumah, rujukan serta pencatatan dan pelaporan'),
(26, 23, 'P3.3', 'Bahwa keluarga sebagai tempat untuk mengembangkan proses interaksi dan tempat untuk belajar bersosialisasi serta berkomunikasi secara baik dan sehat, merupakan makna dari…', 'Fungsi Sosialisasi dan Pendidikan'),
(27, 23, 'P3.4', 'Orang Tua memberikan peneladanan dan menyertakan seluruh anggota keluarga dengan membersihkan rumah dan lingkungan, membersihkan saluran air agar udara bersih, sehat, rapi, indah dan nyaman untuk ditempati merupakan penerapan fungsi…', 'Fungsi Pembinaan Lingkungan'),
(28, 23, 'P3.5', 'Empati,  adil,  pemaaf,  suka  menolong,  pengorbanan  dan  tanggung  jawab, merupakan peran keluarga dalam membentuk kepribadian seorang anak melalui fungsi..', 'Cinta Kasih'),
(29, 23, 'P3.6', 'Orang Tua bertanggung jawab untuk memenuhi kebutuhan keluarga merupakan fungsi dari ...', 'Ekonomi'),
(30, 23, 'P3.7', 'Sampai usia berapa ASI Eksklusif diberikan...', 'sampai 6 bulan'),
(31, 23, 'P3.8', 'Keluarga adalah tempat bernaung atau berlindung bagi seluruh anggotanya,\ndan tempat untuk menumbuhkan rasa aman dan kehangatan merupakan bagian dari fungsi...', 'perlindungan'),
(32, 23, 'P3.9', 'Kehidupan manusia sangat dipengaruhi oleh pengasuhan pada 1000 HPK. Periode ini dimulai sejak awal konsepsi, yaitu...', 'sekitar 270 hari masa kehamilan serta 730 hari setelah lahir (hingga anak berusia 2 tahun)'),
(33, 23, 'P3.10', 'Perempuan yang hamil akan mengalami beberapa perubahan sebagai akibat adanya perubahan hormonal dari dalam tubuh. Perubahan-perubahan tersebut yaitu..', 'perubahan fisik dan emosional'),
(34, 23, 'P3.11', 'Pemeriksaan selama masa kehamilan disarankan sebanyak...', '6 kali'),
(35, 23, 'P3.12', 'WHO merekomendasikan  pemeriksaan postpartum dilakukan sebanyak...', '4 kali'),
(36, 23, 'P3.13', 'Periode penting yang terjadi selama 1000 HPK adalah...', 'Masa Emas, Masa Kritis, Masa Kesempatan'),
(37, 23, 'P3.14', 'IMD dilaksanakan minimal barapa lama...', '1 jam'),
(38, 23, 'P3.15', 'Bentuk makanan dilumatkan saat MP ASI diberikan untuk anak usia...', '6-8 bulan'),
(39, 23, 'P3.16', 'Tanda pelekatan yang baik', '1. Dagu bayi menempel pada payudara\n2. Anak dekat dengan payudara dengan mulut terbuka lebar\n3. Sebagian besar areola masuk ke mulut bayi\n4. Terdengar bunyi menelan, bukan berdecak'),
(40, 23, 'P3.17', 'Apa hal yang dapat dilakukan orang tua jika mendapati anak murung dan bersedih?', 'Memeluk, menanyakan perasaan anak, dan mengajaknya bercerita'),
(41, 23, 'P3.18', 'Anak ceria, lincah, berat badan sesuai garis petumbuhan merupakan salah satu ciri...', 'Anak sehat'),
(42, 23, 'P3.19', 'Empat tanda pelekatan yang baik', '1. Mulut anak terbuka lebar saat dekat payudara\n2. Dagu anak menyentuh payudara\n3. Bagian aerola diatas lebih banyak terlihat\n4. Bibir bawah anak memutar keluar'),
(43, 23, 'P3.20', 'Ciri-ciri camilan sehat untuk baduta mengandung bahan makanan ...', 'Kalori, Protein, Serat, secukupnya gula, garam dan lemak'),
(44, 23, 'P3.21', 'Menyelaraskan perkataan dan perbuatan merupakan salah satu cara...', 'Menjaga Kesehatan Mental Baduta'),
(45, 23, 'P3.22', 'Proses memberikan ASI segera setelah anak dilahirkan disebut..', 'IMD'),
(46, 23, 'P3.23', 'Gerakan yang memerlukan banyak tenaga dan mengandalkan otot disebut...', 'Motorik kasar'),
(47, 23, 'P3.24', 'Gerakan yang tidak memerlukan banyak tenaga dan mengandalkan otot-otot halus disebut...', 'Motorik halus'),
(48, 23, 'P3.25', 'Yang sebaiknya dilakukan oleh bumil pada trimester II', '1. Bumil sering mengajak berkomunikasi\n2. membacakan dongeng\n3. ayah berbicara kepada janin\n4. memperdengarkan musik'),
(49, 23, 'P3.26', 'Cara menstimulasi bayi baru lahir', '1. memperdengarkan suara ayah dan ibu pertama kali\n2. meletakkan bayi di dada ibu untuk inisiasi menyusu dini\n3. dipeluk\n4. didoakan'),
(50, 23, 'P3.27', 'Melatih duduk, marangkak, berdiri dan berjalan merupakan stimulasi..', 'Motorik Kasar'),
(51, 23, 'P3.28', 'Bersuara, menangis, berceloteh, mengucapkan satu kata merupakan stimulasi...', 'Komunikasi pasif'),
(52, 23, 'P3.29', 'Menunjukkan rasa takut, mengenali diri lewat cermin, tahu mana miliknya merupakan stimulasi...', 'Tingkah laku sosial'),
(53, 23, 'P3.30', 'Bayi sudah dapat belajar berdiri selama sekitar 30 detik pada usia…', '9-12 bulan'),
(54, 23, 'P3.31', 'Rangsangan yang dapat dilakukan pada trimester ketiga untuk mengembangkan emosi positif pada janin adalah…', 'Menciptakan suasana lingkungan yang nyaman dan menyenangkan'),
(55, 23, 'P3.32', 'Perhatian ayah dan interaksi langsung dapat berkontribusi pada perkembangan kognitif, sosial, dan emosional, serta mendukung kesiapan mereka untuk sekolah dan prestasi pendidikan selanjutnya.  Pernyataan di atas adalah salah satu manfaat pelibatan ayah dan anggota keluarga lainnya bagi...', 'Bagi anak'),
(56, 23, 'P3.33', 'Waktu terbaik untuk membangun kedekatan antara ayah dan anak harus dimulai sejak dini terutama saat anak berusia', '0-3 tahun'),
(57, 23, 'P3.34', 'Dalam pengasuhan anak kerjasama antar ayah dan ibu atau disebut juga', 'coparenting'),
(58, 23, 'P3.35', 'Mengapa usia dini merupakan periode emas (golden age)?', 'Karena usia dini merupakan periode emas (golden age) sekaligus masa kritis yang keberhasilannya sangat menentukan kualitas anak pada masa dewasanya.'),
(59, 23, 'P3.36', 'Apa saja kebutuhan tumbuh-kembang anak?', 'Kebutuhan tumbuh-kembang anak yang mencakup stimulasi, gizi dan kesehatan, pengasuhan, perlindungan dan perawatan wajib dipenuhi oleh keluarga, masyarakat, dan pemerintah dengan dipenuhi oleh keluarga, masyarakat, dan pemerintah dengan'),
(60, 23, 'P3.37', 'Tugas kader BKB adalah', '1.Memberikan penyuluhan sesuai dengan materi yang telah ditentukan\n2.Mengadakan pengamatan perkembangan peserta BKB dan anak balitanya\n3.Memberikan pelayanan dan mengadakan kunjungan rumah\n4.Memberikan pelayanan dan mengadakan kunjungan rumah yang memiliki anak'),
(61, 23, 'P3.38', 'Tujuan BKB Holistik Integratif adalah ....', 'meningkatkan pengetahuan dan keterampilan pengelola dan pelaksana tentang Penyelenggaraan Bina Keluarga Balita (BKB) yang holistik integratif, serta memantapkan dan menguatkan kelompok kegiatan BKB'),
(62, 23, 'P3.39', 'Apa yang dimaksud dengan BKB', 'Bina keluarga balita (BKB) adalah program yang dibuat oleh badan kependudukan dan keluarga berencana nasional (BKKBN) untuk meningkatkan pemahaman dan ketrampilan orang tua dalam mendidik anak usia balita. Program ini bertujuan untuk memberikan pemahaman yang baik kepada Orang Tua mengenai pola asuh balita, sehingga anak dapat tumbuh optimal di usia emas'),
(63, 23, 'P3.40', 'Apa tujuan berdirinya BKB', 'Tujuan umum dari program BKB adalah meningkatkan pengetahuan, ketrampilan dan sikap Orang Tua serta anggota keluarga lainnya dalam membina tumbuh kembang secara menyeluruh dan terpadu guna mencapai tumbuh kembang yang optimal'),
(64, 23, 'P3.41', 'Bagaimana menciptakan keluarga yang berkualitas', 'Menumbuh kembangkan harapan pada diri sendiri dan keluarga akan kehidupan yang lebih baik, memberikan teladan yang baik, senantiasa memberikan nasihat kebaikan dan teguran atas perilaku dan tindakan yang menyimpang, mencari dan membentuk lingkungan yang kondusif, melakukan pembiasaan dan pengulangan terhadap hal yang baik, memberikan hadiah berupa pujian'),
(65, 23, 'P3.42', 'Bagaimana melaksanakan fungsi keluarga', 'Dapat terwujud apabila masing-masing keluarga memiliki ketahanan keluarga yang tinggi dan ketahanan keluarga hanya dapat tercipta apabila masing-masing keluarga dapat melaksanakan fungsi-fungsi keluarga secara serasi selaras dan seimbang'),
(66, 23, 'P3.43', 'Apa tujuan pengasuhan bagi balita', 'Untuk meningkatkan keikutsertaan Orang Tua dalam pengasuhan ayah dan ibu harus menetapkan tujuan yang jelas dalam mengasuh anak agar tumbuh dan berkembang secara optimal. Ayah dan ibu perlu mendiskusikan dan menyepakati tujuan pengasuhan sesuai dengan kondisi anak dan harapan ayah dan ibu.'),
(67, 23, 'P3.44', 'Apa pengertian pola asuh', 'Pengertian dari pola asuh adalah pola perilaku yang diterapkan Orang Tua pada anak dan bersifat konsisten (tetap) dari waktu ke waktu, pola asuh juga merupakan sikap Orang Tua dalam berinteraksi dengan anaknya yang meliputi cara Orang Tua memberikan aturan-aturan hadiah maupun hukuman'),
(68, 23, 'P3.45', 'Apa itu stimulasi pada bayi atau balita', 'Stimulasi adalah adalah rangsangan yang dilakukan sejak bayi baru lahir (bahkan sebaiknya sejak di dalam kandungan) dilakukan setiap hari, untuk merangsang semua sistem indera (pendengaran, penglihatan, perabaan, pembauan, pengecapan). Selain itu harus pula merangsang gerak kasar dan halus kaki, tangan dan jari-jari, mengajak berkomunikasi, serta merangsang perasaan yang menyenangkan bayi dan anak-anak.'),
(69, 23, 'P3.46', 'Bagaimana prinsip-prinsip tumbuh kembang anak', 'Proses tumbuh kembang anak juga mempunyai prinsip-prinsip yang saling berkaitan. Prinsip-prinsip tumbuh kembang meliputi : Perkembangan merupakan hasil proses kematangan dan belajar Kematangan merupakan proses intrinsik yang terjadi dengan sendirinya, sesuai dengan potensi yang ada pada individu. Belajar merupakan perkembangan yang berasal dari latihan dan usaha. Melalui belajar, anak memperoleh kemampuan menggunakan sumber yang diwariskan dan potensi yang dimiliki anak.'),
(70, 23, 'P3.47', 'Apa saja faktor penting dalam pengasuhan', 'Disiplin adalah membentuk kebiasaan atau perilaku. Pembentukan kebiasaan ini akan berhasil jika dilakukan dengan kasih sayang. Komunikasi merupakan hal yang sangat penting dalam pengasuhan anak, karena menjadi dasar bagi hubungan Orang Tua dan anak.'),
(71, 23, 'P3.48', 'Apa yang mempengaruhi pengasuhan', 'Yang mempengaruhi pengasuhan pada anak adalah kepribadian Orang Tua, karakteristik anak, dukungan sosial dan pola dalam pengasuhan'),
(72, 23, 'P3.49', 'Mengapa keterlibatan ayah dalam pengasuhan penting', 'Ayah bisa sama baiknya dengan ibu dalam mengenali dan merespon kebutuhan kebutuhan bayi dan anak yang lebih besar. Ayah juga bisa berperan sebagai guru, panutan atau penasehat. Hanya ayah yang dapat bermain sebagai seorang ayah. Pengalaman anak bermain bersama ayah akan menjadi pengalaman yang penting bagi si anak yang terkait dengan ketrampilan sosial anak di kemudian hari.'),
(73, 23, 'P3.50', 'Apa manfaat keterlibatan ayah dalam pengasuhan', 'Keterlibatan ayah memiliki dampak positif terhadap perkembangan kognitif, perkembangan sosio emosional, perkembangan fisik.'),
(74, 23, 'P3.51', 'Apa yang bisa dilakukan ayah agar terlibat dalam pengasuhan', 'Yang bisa dilakukan ayah agar terlibat dalam pengasuhan antara lain yaitu mendampingi kehamilan, turut merawat bayi, melakukan aktivitas bersama anak, menciptakan komunikasi yang baik.'),
(75, 23, 'P3.52', 'Mengapa pertumbuhan dan perkembangan anak menjadi penting', 'Pada masa balita hampir seluruh sel-sel otak berkembang pesat, tidak ada orang yang paling berarti dalam kehidupan seorang balita selain Orang Tua nya yang dapat memenuhi segala pertumbuhan nya. Dengan kata lain, Orang Tua mempunyai peran yang sangat penting dalam menentukan arah serta mutu pertumbuhan dan perkembangan anak. Oleh karena itu kemampuan Orang Tua dalam memenuhi kebutuhan anak akan asuh, asih dan asah melalui komunikasi yang baik dan benar, akan mempengaruhi mutu kepribadian anak menuju manusia dewasa di kemudian hari.'),
(76, 23, 'P3.53', 'Hal-hal apa yang perlu dilakukan agar balita tumbuh dengan baik', 'Hal-hal yang perlu dilakukan agar balita tumbuh dengan baik antara lain meningkatkan kesehatan ibu hamil, berikan bayi ASI Eksklusif, biasakan hidup sehat, berikan anak makanan bergizi seimbang, berikan imunisasi sedini mungkin.'),
(77, 23, 'P3.54', 'Apa saja aspek-aspek perkembangan anak yang perlu mendapatkan perhatian', 'Beberapa aspek-aspek yang perlu diperhatikan antara lain yaitu perkembangan kemampuan gerak kasar, perkembangan kemampuan gerak halus, perkembangan kemampuan komunikasi pasif, perkembangan kemampuan komunikasi aktif, perkembangan kemampuan kecerdasan, perkembangan kemampuan menolong diri sendiri, perkembangan kemampuan tingkah laku sosial.'),
(78, 23, 'P3.55', 'Bagaimana Orang Tua dapat merangsang atau menstimulasi tumbuh kembang anak', 'Kebutuhan dasar anak yang harus dipenuhi Orang Tua yaitu kebutuhan kesehatan dan gizi, kebutuhan kasih sayang, kebutuhan stimulasi.'),
(79, 23, 'P3.56', 'Mengapa nutrisi 1000 hari pertama kelahiran penting untuk difokuskan?', 'Membentuk otak anak yang berisi dan menjadi bahan bakar pertumbuhan jiwa dan raga, pembentukan sistem kekebalan tubuh yang kuat\nMeningkatkan kesiapsiagaan untuk masuk sekolah dan memberi kesempatan untuk meraih potensi terbaik di kemudian hari\nMeningkatkan nutrisi untuk ibu dan anak selama periode 1000 hpk tersebut membantu memastikan bahwa anak mendapatkan awal kehidupan yang terbaik dan kesempatan untuk meraih potensi terbaik bagi anak mereka\nMengurangi kesenjangan pada aspek kesehatan, pendidikan, dan produktivitas generasi yang akan datang\nMenurunkan risiko terjangkit penyakit kronis seperti diabetes, penyakit jantung, dan beberapa tipe kanker di kemudian hari\nSecara global, menyelamatkan satu nyawa per tahun\nMeningkatkan total pendapatan suatu negara\nMemutus siklus kemiskinan antar generasi akibat wanita malnutrisi'),
(80, 23, 'P3.57', 'apa dampak era layar pada perkembangan anak', 'Dampak era layar pada perkembangan anak antara lain, mendapatkan informasi dan pengetahuan terbaru (berita), sebagai hiburan yang murah, memberikan tayangan yang layak ditonton anak anak misalnya film kartun yang mendidik dan menstimulasi otak anak, serta negatifnya antara lain, waktu menonton yang berlebihan, acara televisi tidak sesuai dengan usia, menghilangkan kesempatan anak untuk bersosialisasi dengan lingkungan.'),
(81, 23, 'P3.58', 'Upaya apa yang dapat dilakukan untuk mencegah dampak negatif media', 'Upaya yang dapat dilakukan untuk mencegah dampak negatif yaitu adanya pembatasan waktu dan aturan yang jelas mengenai lamanya menonton TV kapan dan jenis-jenis tayangan yang sesuai dengan anak, mengarahkan anak kepada kegiatan lain seperti olahraga, membaca, kegiatan budaya, kursus dan lain-lain.'),
(82, 23, 'P3.59', 'Apa tanda-tanda bahwa anak butuh bantuan dalam bermain media sosial', 'Tanda-tanda bahwa anak butuh bantuan antara lain yaitu keasyikan dengan game/menggunakan internet, kehilangan minat dalam kegiatan lainnya, penarikan sosial (hanya berkomunikasi dengan teman-teman online), sikap membela diri dan marah ketika upaya lain untuk mengurangi/menghentikan penggunaan, menyembunyikan jumlah penggunaan, berbohong atau mencuci curi waktu penggunaan meskipun ada konsekuensinya.'),
(83, 23, 'P3.60', 'Apa tanda-tanda bahwa anak mengalami kecanduan bermain media sosial', 'Tanda-tanda bahwa anak mengalami kecanduan pada gejala fisik antara lain, melepuh atau luka pada jari dan jempol, kering mata atau penglihatan berkurang, migrain sakit kepala, rentan sakit, kegagalan untuk mengurus kebersihan pribadi dan inkontinensia, tidur gangguan atau perubahan dalam pola tidur.'),
(84, 23, 'P3.61', 'Sejak usia berapa seharusnya anak diberikan pengetahuan mengenai edukasi seks dan kesehatan reproduksi?', 'Pendidikan seks dan kesehatan reproduksi sebaiknya diberikan kepada anak sedini mungkin, dimulai sekitar usia 3-4 tahun. Pada usia ini, anak mulai memperhatikan dunia di sekitarnya dan mulai mengenali tubuhnya sendiri, termasuk bagian-bagian tubuhnya yang sensitif.'),
(85, 23, 'P3.62', 'Bagaimana mengatasi masalah kecanduan', 'Cara mengatasi masalah kecanduan antara lain yaitu menempatkan komputer di daerah terbuka dan teramati, pasang filter di internet dalam memblokir semua situs, perlu pengawasan dan pertimbangan matang dalam pergaulan anak bersama teman-teman sebaya atau grup bermainnya, jika anak akan menginap di rumah, cek semua alat elektronik yang akan dibelikan untuk anak disesuaikan dengan fungsi dan kebutuhan.'),
(86, 23, 'P3.63', 'Mengapa Orang Tua harus memahami tentang kesehatan reproduksi', 'Karena terkadang Orang Tua justru menganggap membicarakan seksualitas dengan anaknya adalah suatu hal yang tabu atau tak pantas dibicarakan. Oleh sebab itu banyak yang kemudian memberikan pengetahuan tentang kesehatan reproduksi bagi anak dengan menggunakan istilah istilah lain seperti burung yang sering digunakan untuk menyebutkan alat kelamin laki-laki'),
(87, 23, 'P3.64', 'Apa tujuan BKKBN mengembangkan program BKB (Bina Keluarga Balita)?', 'Memberikan pembinaan kepada orang tua balita agar mampu mendukung pertumbuhan dan perkembangan anak secara optimal.'),
(88, 23, 'P3.65', 'Bagaimana tahapan perkembangan psikoseksual pada anak', 'Tahapan perkembangan psiko seksual  antara lain masa oral (0-1 tahun), masa anal (1-3 tahun), masa phalik (3-5 tahun)'),
(89, 23, 'P3.66', 'Bagaimana cara memperkenalkan alat-alat reproduksi kepada anak', 'Dalam hal ini Orang Tua perlu menghindari istilah istilah yang tidak benar untuk memberi nama alat kelamin, karena hal itu akan membingungkan anak. Contoh: tidak memberi nama alat kelamin perempuan dengan istilah dompet atau nama alat kelamin laki-laki dengan burung. Hal ini akan menyebabkan anak bingung kalau menghadapi dompet atau burung sebenarnya, jadi gunakanlah istilah istilah sebenarnya seperti kelamin atau kemaluan, penis, vagina, payudara, dan sebagainya. Dan untuk mengenalkan nama-nama tersebut sebaiknya pergunakan lah kesempatan uang baik'),
(90, 23, 'P3.67', 'Bagaimana ciri perkembangan fisik yang ideal bagi anak usia 6-10 tahun?', 'Idealnya anak berusia 6-10 tahun memiliki tinggi badan 114-140 cm (sepinggang sampai sepundak orang dewasa) dan berat badannya berkisar dari 21-33 kg.'),
(91, 23, 'P3.68', 'Bagaimana ciri perkembangan emosional yang ideal bagi anak usia 6-10 tahun?', 'Pada usia 6-10 tahun, anak sudah dapat mengenal perasaannya, mengenal perasaan orang lain, mulai belajar mengontrol perasaannya, dan mengekspresikan sesuai situasi/kondisi yang ada.'),
(92, 23, 'P3.69', 'Apa saja kemampuan yang harus sudah bisa dicapai oleh anak-anak berusia 6-10 tahun?', 'Berikut merupakan tugas-tugas perkembangan anak usia 6-10 tahun:\nMengenal Tuhan melalui ciptaanNya\nMemahami adanya kesertaan Tuhan dalam kesehariannya\nMampu beribadah sesuai agama masing-masing\nMembiasakan diri untuk membaca do’a-do’a sehari hari\nMembentuk hati nurani, nilai moral, dan nilai sosial dengan mengenal aturan dan adab sehari-hari berdasarkan budaya dan agama masing-masing.\nBelajar keterampilan fisik untuk melakukan permainan, seperti bermain sepak bola, loncat tali, berenang, bersepeda, dll.\nAnak belajar hidup sehat, dengan memperhatikan kebersihan diri dan lingkungannya.\nBelajar bergaul dengan teman-teman sebaya, dengan bermain bersama teman-temannya.\nBelajar bertingkah laku (berpakaian, berbicara dll) sesuai jenis kelaminnya.\nBelajar keterampilan dasar dalam membaca, menulis, berhitung\nBelajar mengembangkan konsep sehari-hari, seperti mengenal waktu, bahasa\nMemperoleh kebebasan yang bersifat pribadi dengan belajar mandiri dan dihargai sebagai dirinya sendiri.\nBelajar bekerjasama/gotong royong, bekerja dalam tim\nBelajar displin mematuhi aturan di keluarga, di sekolah dan di masyarakat\nBelajar bertanggung jawab atas konsekuensi dari pilihannya.'),
(93, 23, 'P3.70', 'Apa saja contoh kegiatan yang bisa dilakukan untuk memenuhi tugas perkembangan anak dalam pergaulannya dengan teman sebaya?', 'Orang tua dapat mengajarkan batasan bergaul, mengajarkan keamanan diri, mengenali teman yang baik dan tidak baik, serta belajar membela diri.'),
(94, 23, 'P3.71', 'Bagaimana cara mengatasi tantrum pada anak berusia 6-10 tahun?', 'Orang tua dapat mengabaikan dan tidak memenuhi keinginan saat anak tantrum, banyak memberikan kesempatan untuk mengungkapkan perasaan, lalu memuji anak saat ia berhasil melakukan sesuatu.'),
(95, 23, 'P3.72', 'Apa saja contoh permasalahan anak dalam aspek gangguan belajar terkait perkembangan daya pikir anak?', 'Keterbelakangan mental, anak kesulitan konsentrasi dan hiperaktif, serta anak kesulitan belajar.'),
(96, 23, 'P3.73', 'Bagaimana cara menumbuhkan iman yang kokoh pada anak?', 'Mencontohkan dalam kehidupan sehari-hari\nMemperlihatkan bukti-bukti adanya Tuhan\nMembiasakan ibadah\nMelibatkan anak dalam kegiatan keagamaan'),
(97, 23, 'P3.74', 'Bagaimana cara yang bisa dilakukan orang tua untuk menumbuhkan kemampuan berpikir kritis pada anak?', 'Orang tua dapat lebih banyak menggunakan kata tanya dalam berinteraksi anak, menghindari cara bicara yang memerintah anak, memberi pilihan-pilihan alternatif untuk anak, serta memberi kesempatan untuk memutuskan dan menerima konsekuensi dari sebuah keputusan.'),
(98, 23, 'P3.75', 'Bagaimana cara orang tua untuk menunjukkan cinta dan kasih sayangnya kepada anak?', 'Menerima anak seutuhnya, menghargai dan memuji anak, memeluk dan mencium anak, memanggil anak dengan panggilan baik, bermain dengan anak, dan menemani anak dalam kegiatan belajarnya.'),
(99, 23, 'P3.76', 'Bagaimana perkembangan sosial anak usia 6-10 tahun?', 'Anak idealnya merasa senang bermain dengan teman sebaya yang sejenis kelamin, bisa mengikuti aturan bermain, dan senang mengikuti permainan yang berkelompok dan menantang seperti kompetisi atau lomba.'),
(100, 23, 'P3.77', 'Bagaimana cara untuk mengoptimalkan kemampuan anak dalam perkembangan hati nurani dan nilai moral?', 'Orang tua dapat mengenalkan dan membiasakan anak dengan adab sehari-hari, mengajak anak untuk merasakan penderitaan orang lain, membiasakan anak untuk membantu dan menolong orang lain, serta melibatkan anak dalam berbagai kegiatan kemanusiaan.'),
(101, 23, 'P3.78', 'Apa yang perlu dilakukan masyarakat yang sebelumnya belum ber-KB dan ingin memulai untuk ber-KB?', 'Kita perlu berdiskusi dengan bidan mengenai metode KB apa yang cocok dan manfaat jangka panjangnya'),
(102, 23, 'P3.79', 'Bagaimana peran orang tua dalam membentuk karakter anak?', '6 langkah membentuk karakter anak: mengenali, mengembangkan,mengamati perilaku anak yang dihadapkan, pembiasaan dalam kehidupan sehari-hari, dan penguatan karakter anak melalui pujian dan motivasi kepada anak. Karakter yang baik adalah disiplin, jujur, mengetahui batas kemampuan diri sendiri, dan menghargai orang lain'),
(103, 23, 'P3.80', 'Apa tujuan stimulasi kemampuan menolong diri sendiri dan tingkah laku sosial bagi anak anak?', 'Anak anak dapat mudah berteman, tidak canggung serta mengerti disiplin, sopan santun, dan aturan-aturan baik di dalam maupun di luar rumah'),
(104, 23, 'P3.81', 'Mengapa peran orang tua sangat penting dalam menstimulasi kemampuan bergaul anak?', 'Proses belajar anak tidak hanya melalui latihan yang diberikan, tetapi juga melalui meniru tingkah laku orang dewasa atau anak yang lebih besar sehingga orang tua perlu menjadi tauladan baik bagi anak'),
(105, 23, 'P3.82', 'Bagaimana peran kakek nenek dalam memberikan pengasuhan yang baik kepada cucu?', 'Pola asuh yang diterapkan oleh kakek dan nenek sering kali kurang ketat dalam hal disiplin dan aturan, bahkan terkadang tidak konsisten dengan aturan yang sudah diterapkan sebelumnya. Oleh karena itu, kakek dan nenek perlu mempersiapkan diri untuk menjadi pengasuh yang baik. Mereka bisa memainkan berbagai peran dalam merawat cucu, seperti menjaga, menemani bermain, hingga mengantar ke sekolah. Semua hal ini perlu dikomunikasikan dengan jelas antara kedua Orang Tua anak, agar aturan pengasuhan yang diterapkan dapat disepakati bersama.'),
(106, 23, 'P3.83', 'Apa itu pengasuhan Disiplin Positif dalam grandparenting?', 'Disiplin positif merupakan bentuk penerapan disiplin tanpa kekerasan, mengkomunikasikan perilaku yang efektif antara kakek dan nenek dengan cucu, mengajarkan cucu untuk memahami konsekuensi dari perilaku mereka, mengajarkan cucu kita untuk bertanggung jawab dan rasa hormat ketika berinteraksi dengan lingkungannya, menaati/mematuhi peraturan yang berlaku di rumah, di jalan, di sekolah dan norma-norma yang berlaku di masyarakat, serta memiliki empati kepada sesama.'),
(107, 23, 'P3.84', 'Bagaimana konsep Rumah Ramah Cucu?', 'Pastikan Rumah Kakek Nenek merupakan tempat perlindungan yang aman dan ramah terjadap cucu. Beberapa hal yang perlu diperhatikan diantaranya: pastikan barang bagus atau pecah belah dan obat-obatan tidak terjangkau oleh anak-anak, pastikan ujung meja yang tajam aman, pengaman untuk stop kontak, pastikan kolam atau lobi atas diberi pembatas yang benar, tempat tidur yang aman untuk bayi, serta mengajari cucu menyimpan permainan dengan rapi dan benar di kotak penyimpanan alat permainan.'),
(108, 23, 'P3.85', 'Mengapa Ayah perlu terlibat dalam pengsuhan?', 'Ayah perlu tahu dan memahami proses tumbuh kembang anak sehingga kedua orang tua dapat ikut berperan aktif mendampingi proses tumbuh kembang yang bersalan singkat dan padat tersebut sehingga dapat memberikan hasil yang semaksimal mungkin. Ayah juga perlu menyadari bahwa proses tumbuh kembang anak membutuhkan waktu-waktu khusus dengan perhatian dan penanganan yang khusus.'),
(109, 23, 'P3.86', 'Apa saja karakter negatif yang tidak layak dilakukan seorang ayah?', 'Sombong, tidak teliti, tidak berani, egois, tidak amanah, tidak sopan, berkata kotor atau kasar, tidak mandiri atau berani, tidak bertanggung jawab, tidak menghargai orang tua, tidak taat aturan atau disiplin, tidak konsisten, tidak sabar, suka menyalahkan, berpikir susah atau rumi, tidak jujur, menolak kejadian, serta bereaksi secara berlebihan.'),
(110, 23, 'P3.87', 'Bagaimana cara membangunkan kesadaran yang produktif sehingga peran ayah dalam pengasuhan anak menjadi bertambah baik dan selalu baik?', '1. Identifikasi kebutuhan nyata ayah saat ini, baik untuk dirinya sendiri maupun keluarga. Setelah itu, pastikan kebutuhan tersebut terpenuhi, terutama yang paling mendesak, dengan mengecek kecukupan kebutuhan yang ada.\n\n2. Pahami kondisi ayah saat ini, baik dari cara pandang maupun cara merespon hidupnya. Berikan ruang agar ayah dapat memposisikan diri sesuai dengan tujuannya, dan bantu dia melihat dirinya sebagai individu yang berharga dan bermartabat, serta mendukungnya untuk menjalankan peran-perannya dengan baik.\n\n3. Bantu ayah menyadari peran-peran yang harus dijalankan sesuai dengan posisi dan ketetapan Tuhan. Selain itu, bantu ayah mengenali faktor-faktor internal dan eksternal yang memengaruhi usahanya, serta beri dukungan penuh untuk mencapai tujuan dan perannya dengan optimal.'),
(111, 23, 'P3.88', 'Bagaimana melakukan deteksi anak dengan kebutuhan khusus?', 'Saat anak lahir, akan dilakukan pemeriksaan oleh dokter atau bidan secara fisik. Saat bayi sudah dirawat di rumah, periksakan bayi sebulan sekali ke dokter atau ke posyandu. Setiap anggota BKB akan diberikan Kartu Kembang Anak (KKA) untuk memantau perkembangan anak usia 0-6 tahun'),
(112, 23, 'P3.89', 'Bagaimana tips bagi orang tua setelah mengetahui anaknya memiliki kebutuhan khusus?', '• Beri waktu pada diri untuk memiliki emosi negatif di awal\nketika mengetahui anak memiliki kebutuhan khusus.\nTidak perlu disangkal\n• Setelah beberapa saat, tenangkan diri bersama\npasangan dan coba cari tahu apa yang dialami anak\n• Terima anak dengan segala kekurangannya dan\npercaya bahwa ia juga memiliki kelebihan\n• Cari cara penanganan yang tepat agar anak\nbisa berkembang secara optimal, sesuai dengan\nkebutuhannya\n• Berikan pemahaman dan kasih sayang yang sama\nkepada anak-anak yang lainnya\n• Berikan pemahaman kepada keluarga besar dan\nmintalah dukungan\n• Dengan masa-masa baik dan buruk yang akan\ndihadapi dan dilalui, anggota keluarga sebaiknya\nselalu saling menguatkan.\n• Saat merasa ada di masa yang sangat buruk,\nberdoa kepada Tuhan dapat juga memberikan\nkekuatan dan ketenangan yang dibutuhkan.'),
(113, 23, 'P3.90', 'Jika terdapat perbedaan pola asuh dengan orang tua/mertua, bagaimana cara menyikapinya agar tidak konflik?', '1. Dengarkan Saran yang Diberikan Mertua\nLangkah pertama yang bisa dilakukan adalah mendengarkan saran yang diberikan oleh mertua. Walaupun pola asuh mereka mungkin berbeda dengan pola asuh yang Ayah dan Bunda jalani, mertua memiliki banyak pengalaman dalam membesarkan anak. Mendengarkan tidak berarti harus selalu menuruti, tapi setidaknya Ayah dan Bunda menunjukkan rasa hormat dengan bersedia mendengar pendapat mereka. Cobalah pahami sudut pandang mertua tanpa langsung menolak.\n2. Berpikiran Terbuka\nSetelah mendengarkan saran mertua, Ayah dan Bunda perlu berpikiran terbuka. Meskipun mertua lebih berpengalaman, Ayah dan Bunda tetap memiliki hak untuk menentukan pola asuh terbaik untuk anak-anak. Penting untuk diingat bahwa mendengar tidak selalu sama dengan menuruti 100%. Ayah dan Bunda bisa berdiskusi untuk memilih nasihat yang sesuai dengan visi dan misi keluarga, serta kebutuhan si kecil. Contohnya, jika mertua menyarankan penggunaan obat-obatan tradisional saat si kecil demam, Ayah dan Bunda bisa mempertimbangkannya, namun tetap memutuskan apakah cara tersebut sejalan dengan prinsip pengasuhan yang Ayah dan Bunda pilih.\n3. Komunikasikan dengan Pasangan dan Mertua\nSebelum mengomunikasikan perbedaan pola asuh dengan mertua, Ayah dan Bunda harus satu suara terlebih dahulu. Diskusikan bersama pasangan mana nasihat yang akan diterima dan mana yang tidak sesuai. Dengan begitu, Ayah dan Bunda bisa memberikan penjelasan kepada mertua dengan cara yang sopan dan penuh penghargaan. Misalnya, mertua Bunda menyarankan untuk memberikan makanan padat di usia 4 bulan karena menurut mereka dulu itu cara yang efektif agar si kecil cepat kenyang. Namun, berdasarkan rekomendasi dokter, Ayah dan Bunda ingin menunggu sampai si kecil berusia 6 bulan, sesuai dengan panduan kesehatan modern. Sebelum menanggapi saran tersebut, Ayah dan Bunda perlu berdiskusi terlebih dahulu dan sepakat akan mengikuti rekomendasi dokter. Setelah sepakat, Ayah bisa menyampaikan kepada orang tuanya dengan cara yang sopan. Dengan menyampaikan pendapat secara baik-baik, Ayah dan Bunda bisa menjaga hubungan yang harmonis tanpa menyinggung perasaan mertua. Penting untuk tidak terkesan menggurui atau menyalahkan pola asuh yang diterapkan mertua di masa lalu. Jelaskan bahwa keputusan yang diambil bertujuan untuk kepentingan terbaik bagi si kecil, bukan untuk mengkritik.\n4. Diam Adalah Emas\nTerkadang, ada saatnya diam menjadi pilihan terbaik. Ketika perbedaan pendapat dengan mertua semakin tajam dan sulit dijembatani, Ayah dan Bunda bisa memilih untuk tidak berdebat dan mengambil sikap tenang. Diam bukan berarti setuju, tetapi lebih kepada menghindari situasi yang bisa memperburuk keadaan. Misalnya, jika mertua terus memaksa pola asuh tertentu yang tidak sesuai dengan prinsip Ayah dan Bunda, terkadang lebih baik diam dan mengalihkan pembicaraan daripada memperpanjang argumen. Setelah suasana lebih tenang, Ayah dan Bunda bisa kembali mendiskusikan topik tersebut dan menentukan langkah apa yang selanjutnya akan diambil dalam menghadapi mertua.\n5. Prioritaskan Hubungan yang Harmonis\nPerbedaan pendapat dengan mertua tidak boleh sampai merusak hubungan keluarga. Selalu ingat bahwa Ayah dan Bunda adalah satu tim yang bekerja sama untuk membesarkan anak-anak. Jaga hubungan yang harmonis dengan mertua agar mereka tetap merasa dihargai sebagai bagian dari keluarga besar.  Jika hubungan tetap hangat dan penuh rasa hormat, mertua akan lebih mungkin mendukung pola asuh yang Ayah dan Bunda jalankan. Jangan ragu untuk mengajak mertua berdiskusi secara terbuka dan jujur, tanpa membuat mereka merasa tersinggung atau disingkirkan dari pengasuhan cucu mereka.  Perbedaan pola asuh dengan mertua adalah hal yang lumrah dan sering kali terjadi dalam setiap keluarga. Namun, dengan pendekatan yang penuh hormat, komunikasi yang baik, serta pikiran yang terbuka, Ayah dan Bunda bisa menjaga hubungan yang harmonis dengan mertua sekaligus menjalankan pola asuh yang sesuai dengan visi keluarga.\n\nJangan lupa, mendengarkan nasihat mertua bukan berarti harus menuruti semuanya. Yang penting, Ayah dan Bunda selalu berdiskusi dan satu suara dalam menentukan apa yang terbaik bagi si kecil, sambil tetap menjaga perasaan dan hubungan baik dengan mertua.'),
(114, NULL, 'P4', 'BKL', NULL),
(115, 114, 'P4.1', 'Cara komunikasi yang efektif pada Lansia', '1, Menunjukkan rasa hormat. 2, Mendengarkan dengan penuh perhatian. 3, Tetap tenang. 4, Gunakan kalimat sederhana dan jelas. 5, Hindari merendahkan atau menggurui. 6, Gunakan teknik komunikasi terapeutik. 7, Tunjukkan kasih sayang. 8, Hindari memberi saran kecuali diminta'),
(116, 114, 'P4.2', 'Tujuh dimensi lansia tangguh  adalah...', '(1) Spiritual; (2) Intelektual; (3) Fisik; (4)Emosional; (5) Sosial- Kemasyarakatan; (6) Profesional Vokasional; dan (7) Lingkungan'),
(117, 114, 'P4.3', 'Siapa yang disebut dengan lansia tangguh?', 'Lansia Tangguh adalah seseorang atau kelompok Lansia yang tetap sehat (secara fisik, sosial, dan mental), mandiri, aktif, dan produktif. Menurut WHO (2002), kata “aktif” berarti penduduk Lansia tetap  berpartisipasi dalam kegiatan sosial, ekonomi, budaya, spiritual dan kegiatan  kegiatan kemasyarakatan lainnya dan bukan berarti hanya kemampuan untuk  aktif secara fisik serta berpartisipasi dalam  angkatan kerja semata'),
(118, 114, 'P4.4', 'Apa yang dimaksud dengan program pembangunan lansia tangguh?', 'Suatu program pembangunan keluarga Lansia tangguh yang  dilaksanakan  melalui  penerapan  7  dimensi lansia tangguh: dimensi spiritual, dimensi intelektual, dimensi fisik, dimensi  emosional, dimensi sosial kemasyarakatan, dimensi vokasional, dan dimensi lingkungan'),
(119, 114, 'P4.5', 'Bagaimana peran lansia tangguh dalam pembangunan keluarga?', 'Dalam pembangunan keluarga, lansia tangguh dapat berperan sebagai motivator, grand parenting (pengasuhan kakek-nenek) bagi anak cucu, dan mengembangkan ekonomi produktif'),
(120, 114, 'P4.6', 'Apa saja langkah yang bisa dilakukan untuk menghadapi berbagai perubahan pada lansia?', 'Perubahan pada fase lansia dapat menyebabkan kerentanan bagi lansia. Akan tetapi, kondisi tersebut dapat dicegah dengan perilaku hidup sehat dan kesejahteraan. Penerapan 7 dimensi lansia tangguh (spiritual, intelektual, fisik, emosional, sosial, kemasyarakatan, vokasional, dan lingkungan) dapat menjadi upaya yang dilakukan untuk mengatasi perubahan pada proses menua.'),
(121, 114, 'P4.7', 'Sejauh mana agama berkontribusi terhadap kualitas kehidupan lansia?', 'Dalam periode lansia, seseorang akan rentan mengalami rasa cemas dan takut. Untuk mengurangi perasaan tersebut, bimbingan agama dapat melatih lansia untuk menjadi pendengar yang baik, lebih banyak berbicara dengan Tuhan melalui membaca kitab suci, meminta ampunan Tuhan, dan membaca doa. Hal tersebut dapat memberikan ketenangan dan kenyamanan batiniah, meningkatkan kepasrahan dan kesabaran, memperbaiki hubungan dengan Tuhan, serta memperbaiki hubungan dengan sesama manusia dan alam semesta.'),
(122, 114, 'P4.8', 'Apakah ada aktivitas yang dapat memberikan stimulasi otak untuk dilakukan lansia?', 'Ya, ada berbagai cara untuk memberikan stimulasi otak pada lansia. Aktivitas-aktivitas yang dapat dilakukan lansia untuk stimulasi otak antara lain membaca, menulis, melakukan permainan (teka teki silang, puzzle, catur, congklak), aktivitas seni (menyanyi, menari, bermain musik), aktivitas sosial (bertemu teman, rekreasi keluarga), meningkatkan kualitas spiritual, berkebun, menyulam, senam otak, dan bercerita atau mendongeng kepada anak-anak'),
(123, 114, 'P4.9', 'Bagaimana menghadapi lansia yang memiliki kepribadian yang sulit dimengerti dan emosi yang mudah berubah?', 'Untuk menghadapinya, perlu adanya pemahaman mengenai  penurunan  kondisi  fisik  dan perubahan psikologis yang merupakan hal wajar dalam proses penuaan. Selain itu, perlu memahami bahwa ada hubungan yang erat antara pikiran dan emosi. Maka keluarga/orang di sekitarnya harus mampu berkomunikasi efektif dengan Lansia, agar Lansia dapat mengubah pikiran dan persepsinya terhadap lingkungannya. Selain itu, perlu untuk lebih banyak mengalah, tetap berusaha menjelaskan sesuatu dengan bahasa yang sederhana dan dengan nada yang ramah, serta rela menyediakan waktu untuk mendengar. Lebih lanjut, melakukan aktivitas bersama Lansia seperti hobi(seni, musik, menyanyi, dansa, olah raga, \nsenam, memasak, berkebun, aktivitas lain) dan memberikan pujian tulus juga direkomendasikan. Bila gejala gangguan psikologis tampak terlalu berat, sebaiknya segera dirujuk ke dokter/ paramedis/psikolog.'),
(124, 114, 'P4.10', 'Apa kontribusi keluarga terhadap kesehatan emosional lansia?', 'Keluarga memiliki peran penting dalam mendukung dimensi emosional lansia. Salah satunya adalah dengan membantu lansia menemukan makna hidup di usia lanjut, serta menyediakan waktu untuk berbicara dari hati ke hati agar lansia dapat menyampaikan keluhan atau perasaannya. Upaya memahami apa yang dirasakan lansia, mencari penyebab masalah, dan berbagi pengalaman dengan keluarga lain juga menjadi langkah penting. Selain itu, keluarga perlu berusaha memenuhi kebutuhan lansia dengan memberikan perhatian, kasih sayang yang tulus, serta menciptakan rasa aman. Keluarga juga berperan sebagai pembina dan pembimbing dalam mendukung pengembangan diri lansia, sekaligus menciptakan suasana hidup yang menyenangkan. Jika lansia mengalami gangguan emosional yang cukup berat, penting untuk segera merujuk mereka kepada tenaga ahli.'),
(125, 114, 'P4.11', 'Bagaimana cara berinteraksi sosial yang baik dengan lansia?', 'Lansia perlu diajak berdialog dengan penuh kesabaran, memberikan waktu yang cukup bagi mereka untuk bercerita dan mengungkapkan keinginannya tanpa memotong pembicaraan. Dalam berinteraksi, mendengarkan dengan seksama jauh lebih baik daripada terlalu banyak berbicara. Jika perlu menjelaskan sesuatu, gunakan kata-kata yang santun, disertai mimik muka ceria dan penuh semangat, serta hindari kesan menggurui atau berbicara dengan terpaksa. Ketika lansia bertanya berulang-ulang, berbicara tidak jelas, atau mengatakan hal-hal yang kurang terarah, hal utama yang harus diperhatikan adalah menanggapinya secara positif, tanpa menunjukkan kejenuhan atau berbicara dengan nada keras.'),
(126, 114, 'P4.12', 'Bidang usaha apa saja yang dapat dilakukan oleh lansia agar tetap produktif secara ekonomi?', 'Lansia dapat mengembangkan usaha ekonomi produktif di berbagai bidang. Salah satu bidang yang potensial adalah ekonomi kreatif, seperti pembuatan batik dan berbagai bentuk kesenian lainnya. Selain itu, lansia juga bisa terlibat dalam bidang konsumsi barang, misalnya produksi mebel seperti meja, kursi, dan lemari. Lansia juga dapat produktif di bidang kesehatan dan pengobatan tradisional, seperti pembuatan jamu dan layanan pijat. Lansia juga dapat produktif di bisang kuliner, industri rumah tangga, dan bisnis sosial pengasuhan anak serta lansia rentan.'),
(127, 114, 'P4.13', 'Bagaimana ketangguhan lansia ditinjau dari Dimensi Emosional?', 'Emosi merupakan reaksi dari apa yang ada di pikiran. Secara garis besar emosi manusia dibedakan dalam dua bagian yaitu emosi positif dan emosi negative.  Secara umum setiap Lansia mengalami perubahan emosi dan masalah psikologis. Oleh sebab itu diperlukan upaya pembinaan dimensi emosional kepada kader, keluarga Lansia, dan Lansia itu sendiri. Kondisi emosional Lansia adalah keadaan psikologis Lansia meliputi aspek kemampuan berpikir, perasaan, maupun sikap yang tampak melalui perilaku yang dapat diamati'),
(128, 114, 'P4.14', 'Apa yang dimaksud dengan Lansia Tangguh?', 'Lansia Tangguh adalah seseorang atau kelompok lansia yang mampu beradaptasi terhadap proses penuaan secara positive sehingga masa tua berkualitas dalam lingkungan yang nyaman, sehat secara fisik, sosial dan mental melalui siklus hidupnya aktif, produktif dan mandiri. meskipun telah berusia di atas 60 sampai 70 tahun lansia tetap produktif ,tidak mudah memang menjadi seorang lansia tangguh, apalagi dengan keterbatasan aktivitas, cara berpikir , tingkat emosional dan intelegensia dan masalah pelik lainnya.'),
(129, NULL, 'P5', 'BKR', NULL),
(130, 129, 'P5.1', 'Apakah guru juga bisa melakukan bullying?', 'Seorang guru bisa melakukan bullying. Bullying oleh guru bisa berupa ancaman, tindakan mengucilkan, mengabaikan.');
INSERT INTO `faq` (`id`, `parent_id`, `key_name`, `question_text`, `answer_text`) VALUES
(131, 129, 'P5.2', 'Apa saja perubahan psikis yang dihadapi para remaja?', 'Remaja mengalami emosi tidak stabil, mempertanyakan identitas, berkumpul dengan kelompok sebaya, memiliki perasaan sensitif dan mudah tersinggung, merasa aneh dengan bentuk tubuh sehingga mempengaruhi kepercayaan dirinya, serta mulai tertarik dengan orang lain secara emosi dan seksual.'),
(132, 129, 'P5.3', 'Apa yang dimaksud dengan kesehatan reproduksi?', 'Keadaan sejahtera fisik, mental, dan sosial yang utuh; bukan hanya bebas dari penyakit atau kecacaran, namun dalam segala aspek yang berhubungan dengan sistem reproduksi, fungsi serta prosesnya.'),
(133, 129, 'P5.4', 'Bagaimana cara orang tua untuk mencegah dampak buruk remaja dalam hubungan romantisnya?', 'Orang tua dapat membangun kesadaran tentang batasan serta mengajarkan anak berkata tidak  untuk melakukan perbuatan yang membahayakan dirinya.'),
(134, 129, 'P5.5', 'Bagaimana peran orang tua untuk membantu remaja keluar dari toxic relationship?', 'Orang tua dapat: 1) menciptakan komunikasi terbuka agar remaja merasa aman bercerita, 2) memberikan dukungan emosional dengan mengakui emosi dan perasaan remaja, 3) membantu kepercayaan diri dengan mendorong remaja berkegiatan, dan 4) memberi pemahaman hubungan sehat dan cara mengenalinya.'),
(135, 129, 'P5.6', 'Apa saja penyebab remaja memiliki risiko untuk menjadi adiktif?', 'FOMO (Fear of Missing Out), terpengaruh oleh pergaulan yang tidak baik dari kelompok pertemanannya, dan keluarga yang tidak harmonis sehingga rumah menjadi ruang yang tidak aman dan nyaman bagi remaja.'),
(136, 129, 'P5.7', 'Bagaimana peran orang tua dalam mendampingi remaja sesuai dengan prinsip BKR?', 'Peran orang tua dalam mendampingi remaja sesuai dengan prinsip Bina Keluarga Remaja (BKR) sangat penting sesuai dengan prinsip BKR sebagai berikut:\n1.        Menjalin Komunikasi yang Terbuka dan Dua Arah: Orang tua harus membangun komunikasi yang intens dan terbuka dengan remaja agar anak merasa nyaman untuk berbagi cerita serta agar orang tua dapat memahami kebutuhan dan kondisi remaja secara menyeluruh serta memberikan arahan yang tepat.\n2.        Pengawasan dan Pembinaan: Orang tua perlu mengawasi perilaku remaja secara bersahabat agar mencegah terjerumus ke pergaulan negatif seperti kenakalan, narkoba, atau pergaulan bebas. Pengawasan ini disertai dengan pembinaan yang mendukung pengembangan kepribadian dan potensi remaja\n3.        Bekerja Sama dengan Sekolah dan Kelompok BKR: Orang tua juga perlu berkolaborasi dengan guru dan kelompok Bina Keluarga Remaja (BKR) untuk mendapatkan pembinaan, penyuluhan, dan bimbingan dalam mendampingi remaja. Kelompok BKR membantu orang tua memahami permasalahan remaja dan cara komunikasi yang efektif'),
(137, 129, 'P5.8', 'Bagaimana peran BKR dalam membentuk karakter remaja?', 'Peran Bina Keluarga Remaja (BKR) dalam membentuk karakter remaja, meliputi:\n1.        Meningkatkan Pengetahuan dan Kesadaran Keluarga BKR berfungsi sebagai wadah edukasi bagi orang tua dan keluarga mengenai pentingnya pola asuh yang tepat, pengawasan, dan pembinaan terhadap remaja agar tumbuh dengan karakter positif serta memiliki konsep diri yang sehat\n2.        Membina Perilaku Sehat dan Moral Remaja\nProgram BKR memfasilitasi remaja agar terhindar dari perilaku negatif seperti seks bebas, penyalahgunaan narkoba, dan HIV/AIDS, serta menunda pernikahan dini sampai kematangan lahir batin tercapai. Hal ini mendukung pembentukan karakter yang kuat dan bertanggung jawab\n3.        Mengembangkan Keterampilan dan Kaderisasi\nMelalui pelatihan kader dan pembentukan pengurus BKR, program ini meningkatkan kapasitas keluarga dan masyarakat dalam membina remaja secara berkelanjutan, sehingga peran keluarga sebagai lingkungan pendidikan pertama semakin optimal'),
(138, 129, 'P5.9', 'Apa pendekatan yang dapat digunakan kepada remaja?', '1.        Luangkan waktu berkualitas bersama anak, seperti melakukan aktivitas seperti membaca, olahraga, atau bermain untuk memperkuat ikatan emosional dan membuat remaja merasa diperhatikan\n2.        Menjaga komunikasi dua arah yang terbuka dan empatik. Orang tua perlu menjadi pendengar yang baik, mendengarkan dengan empati tanpa menghakimi, serta mengajak remaja berdiskusi secara terbuka agar mereka nyaman berbagi perasaan dan pikiran\n3.        Berikan dukungan emosional dan kasih sayang yang tulus, baik secara verbal maupun tindakan seperti pelukan atau hadiah kecil, untuk membangun rasa aman dan percaya diri\n4.        Hormati privasi dan individualitas remaja. Hal ini membantu remaja merasa dihargai dan dipercaya.\n5.        Bersikap seperti sahabat, bukan hanya pengontrol. Dekati remaja dengan rasa hormat dan kepercayaan, ciptakan ikatan yang menyenangkan agar mereka lebih leluasa mengekspresikan diri dan terbuka kepada orang tua'),
(139, 129, 'P5.10', 'Bagaimana berbicara dengan anak yang lebih mendengarkan teman sebaya yang kurang baik?', 'Remaja menganggap teman (sebaya) sangat penting karena mereka menerima remaja apa adanya. Orang Tua hanya perlu menerima dan mendengarkan remaja. Orang tua dapat melakukan tahapan berikut: \n1.        Komunikasi pada saat remaja sudah merasa nyaman dengan kehadiran Orang Tua, dan Orang Tua sudah siap untuk membahas. Mulai dengan bertanya apa yang membuat remaja tertarik berinteraksi dengan teman-temannya. Kemudian Orang Tua dapat menyampaikan kekhawatiran dengan menggunakan ‘I Message’. Mungkin pada diskusi pertama remaja tidak banyak berkomentar. Biarkan dulu, beri waktu untuk memikirkan pesan Orang Tua.\n2.        Usahakan terus untuk mendekat agar remaja serta tidak perlu menyindir atau berulang-kali menyampaikan pesan yang sama. Pada kesempatan diskusi lainnya, tanyakan pada remaja apakah ada kesulitan terkait melepaskan diri dari pertemanannya. Tawarkan bantuan agar remaja dapat memisahkan diri dari pertemanan tersebut, mungkin bisa dengan berkegiatan terkait hobi di tempat lain sehingga bertemu dengan teman yang\n lebih positif.\nKunci mengatasi hal ini ada pada Orang Tua. Apakah Orang Tua bersedia meluangkan waktu untuk melakukan proses pendekatan dengan anak remajanya, agar ia bisa melepaskan diri dari teman yang tidak sesuai harapan Orang Tua'),
(140, 129, 'P5.11', 'Apa saja kebutuhan dasar remaja yang perlu dipahami oleh orang tua?', 'Ada lima hal yang diinginkan remaja dari orang tuanya yang perlu diketahui sebagai berikut:\n1.        Perhatian dan dorongan: Remaja menginginkan perhatian dan sikap bersahabat dari orang tua. Selain itu, remaja menginginakan dorongan sebagai bentuk dukungan positif.\n2.        Mendengarkan: Remaja terkadang membutuhkan tempat untuk mencurahkan segala kegundahan atau menceritakan problem yang sedang menempa dirinya. Harapannya orang tua bisa mendengarkan isi hatinya.\n3.        Kasuh sayang: Perlu diketahui remaja masih menginginkan tindakan-tindakan sederhana dari orang tuanya baik memeluk dan mencium ataupun sekedar ucapan sederhana.\n4.        Kepercayaan: Kurangnya kepercayaan orang tua dapat mengganggu rasa aman bagi remaja, sehingga merasa dikekang dan tidak bisa bebas bergerak\n5.        Contoh dan teladan: Remaja tidak hanya butuh sebuah ucapan (materi) akan tetapi juga contoh nyata (modeling).'),
(141, 129, 'P5.12', 'Apa saja tanda-tanda remaja mengalami tekanan mental atau stres?', 'Tanda-tanda atau gejala orang yang mengalami stress, yaitu: merasa tidak berharga atau bersalah, gagasan ingin bunuh diri, percobaan bunuh diri, agitasi atau kelambanan psikomotor, insomnia atau hiperinsomnia, penurunan atau peningkatan berat badan, terganggunya konsentrasi, kesulitan berpikir, dan kehilangan tenaga.'),
(142, 129, 'P5.13', 'Bagaimana cara membantu remaja menghindari kekerasan dalam pacaran?', 'Remaja tertarik dengan lawan jenisnya adalah WAJAR. Ini indikator bahwa perkembangan fisik dan psikisnya sesuai usia. Perubahan hormon mendorong remaja mulai tertarik dengan lawan jenis. Maka dari itu orang tua perlu membimbing anak agar tidak mengalami pacaran yang tidak sehat. Orang tua perlu membuat remaja agar merasa nyaman dengan orang tuanya dengan cara:\n1.        Orang Tua hadir lebih sering dalam kehidupan remaja.\n2.        Luangkan waktu untuk menjemput sekolah, les, menemani belajar, dan lainnya.\n3.        abiskan waktu bersama.\n4.        Kencan berdua sambil nonton atau makan. Film-film tertentu baik ditonton bersama remaja, sekaligus sebagai sarana menerangkan dunia remaja, seperti film “Posesif” yang mengangkat kasus kekerasan dalam pacaran.'),
(143, 129, 'P5.14', 'Tindakan apa yang perlu dilakukan agar anak dapat terbuka kepada orang tua?', 'Cara anak agar dapat terbuka kepada orang tua adalah membangun kepercayaan kepada remaja. Orang Tua dan remaja dapat memaknai interaksi dan kebersamaannya bukan dalam konteks benar atau salah, melainkan untuk menemukan pola interaksi yang nyaman,membangun kepercayaan, dan saling memberikan umpan balik positif. Hukum aksi reaksi berlaku juga dalam hubungan Orang Tua dan anak. Jika perilaku remaja mendapat respon positif dari Orang Tua, maka kecenderungan ia mengulangi perilaku tersebut akan semakin besar sehingga akan menimbulkan rasa nyaman antar individu. Begitu pula sebaliknya.'),
(144, 129, 'P5.15', 'Bagaimana cara meningkatkan kepercayaan diri pada anak remaja yang dipengarui standar media sosial?', 'Berikut cara-cara yang dapat dilakukan untuk meningkatkan kepercayaan diri pada remaja yang terpengaruh oleh standar media sosial:\n1.        Ajarkan untuk berhenti membandingkan diri dengan orang lain, terutama yang terlihat sempurna di media sosial. Ingatkan bahwa setiap orang memiliki keunikan dan perjalanan hidup masing-masing, sehingga membandingkan diri hanya akan merusak kepercayaan diri\n2.        Dorong remaja untuk mengenali dan mengembangkan minat serta bakatnya, misalnya melalui seni, olahraga, atau kegiatan lain yang disukai. Aktivitas ini memberikan ruang ekspresi diri dan membangun rasa percaya diri.\n3.        Bantu remaja membangun pola pikir positif (growth mindset), yakni keyakinan bahwa kemampuan dapat berkembang melalui usaha dan pembelajaran. Pola pikir ini mengurangi rasa takut gagal dan meningkatkan keberanian mencoba hal baru\n4.        Batasi pengaruh negatif dari media sosial dengan mengajarkan penggunaan media sosial yang sehat, misalnya membatasi waktu penggunaan dan memilih konten yang positif serta realistis\n5.        Fasilitasi lingkungan sosial yang positif dan suportif, seperti teman dan keluarga yang menghargai dan mendukung remaja. Lingkungan yang positif membantu remaja merasa diterima dan percaya diri'),
(145, 129, 'P5.16', 'Bagaimana cara orang tua dapat berkomunikasi kepada anak dengan cara baik?', '1.        Dihayati: Ketika berinteraksi dan berkomunikasi dengan remaja, hendaknya Orang Tua mencurahkan segenap pikiran dan perasaan saat momen tersebut berlangsung. Orang tua dapat fokus pada anak dengan memandang matanya, menyentuh tangan atau punggung untuk menunjukkan kita peduli dengan yang ia rasa, pikir, dan katakana.\n2.        Diterima: Apapun yang disampaikan oleh remaja, terima tanpa menghentikan atau menunjukkan ketidaksetujuan secara langsung. Sikap penerimaan ini dapat dilakukan dengan cara berikut: 1) membiarkan remaja mengeluarkan emosi yang dirasakan; 2) membantu remaja mengelola emosi jika diperlukan; 3) menunjukkan rasa empati; 4) Jika orang tua tidak setuju dengan anak, usahalah menahan diri hingga saat giliran Orang Tua menanggapi\n3.        Didengarkan: Kadang remaja tidak perlu jawaban. Remaja hanya butuh didengarkan sehingga mereka merasa penting dan istimewa karena berhasil membuat Orang Tua meluangkan waktu mendengarkan mereka\n4.        Ditanggapi: Gunakan cara merespon yang tepat dengan memilih gaya komunikasi yang paling sesuai dengan situasi dan kondisi saat proses komunikasi berlangsung, tentunya agar efektif. Hindari gaya komunikasi yang dapat menimbulkan masalah di kemudian hari'),
(146, 129, 'P5.17', 'Bagaimana cara mengedukasi mengenai seks pada anak agar terhindar dari kejahatan seksual?', 'Ada empat tahapan dalam memperkenalan anak remaha mengeni seks, sebagai berikut:\n1.        Pilih Tempat dan Waktu yang Tepat: Pilih tempat yang nyaman dan cukup privat yang dapat membuat suasana hati menjadi baik dan lebih santai.\n2.        Pelan-Pelan dan Tidak Dalam Satu Waktu: Topik seks tidak bisa dibahas dalam sehari, lakukan secara bertahap dan sesuaikan dengan usianya.\n3.        Belajar Dari Contoh Kasus Sehari-Hari: Kejadian sehari-hari bisa menjadi bahan diskusi mengenai seks. Cari tahu tanggapan mereka dari contoh kasus tersebut.\n4.        Jangan Malu Berbicara: Hilangkan rasa malu atau menganggap hal ini tabu, karena anak berhak mendapatkan pendidikan seks dari Orang Tuanya'),
(147, 129, 'P5.18', 'Bagaimana cara menanamkan rasa tanggung jawab pada anak?', 'Berikut empat tahapan penerapan tanggung jawab pada anak:\n1.        Pengenalan: Tiap aktivitas harus dikenalkan lebih dahulu, dengan cara anak mengamati atau terlibat langsung dalam aktivitasnya.\n2.        Latihan: Ajari anak melakukan kegiatan dari awal hingga akhir beserta indikator keberhasilannya. Misalnya, menyiram halaman dianggap selesai bila seluruh permukaan tanah di pot sudah terlihat basah dan selang tergulung rapi, disimpan di sudut rumah Namun, standar hasil pengerjaan tidak bisa disamakan untuk semua usia.\n3.        Kesepakatan: Tugas rumah tangga bukan merupakan hukuman, melainkan sarana latihan dan peran aktif dalam keluarga. Beri pilihan tugas yang ingin dikerjakan anak, termasuk kapan dan bagaimana ia melakukannya. Sampaikan bahwa Orang Tua akan memantau pekerjaannya selama beberapa waktu.\n4.        Pelaksanaan dan pantauan: Orang Tua harus tetap memantau pelaksanaan tugas rumah tangga oleh anak tanpa komentar. Anak mungkin akan bekerja dengan caranya sendiri. Biarkan saja. Orang tua hanya perlu mengingatkan indikator keberhasilan. Dengan seringnya latihan, anak akan menemukan cara yang efektif dan efisien.\nBagaimana jika anak lalai?\nJangan ambil alih tugasnya. Anak atau anggota keluarga lainnya harus memahami akibat tidak menjalankan tugas. Tidak perlu mengomel atau menyindir. Tunjukkan saja apa yang terjadi dan bagaimana memperbaikinya. Tugas rumah tangga adalah sarana belajar anak. Wajar jika masih ada kekurangan atau kesalahan. Orang Tua perlu\nbersabar menikmati prosesnya karena suatu saat akan terlihat hasilnya.'),
(148, 129, 'P5.19', 'Bagaimana cara mengontrol anak yang menggunaan gawai secara berlebihan?', 'Paparan negatif gawai pasti memengaruhi perilaku dan Kesehatan penggunanya. Maka dari itu orang tua perlu mengawasi durasi penggunaan gawai. Jika gawai digunakan sesuai fungsinya, seperti komunikasi, penggunaan gawai maksimal hanya 3-5 jam dalam kurun waktu 24 jam. \nPenggunaan gawai yang berlebihan\nmerupakan indikasi awal kecanduan gawai. Sebelum lebih jauh terjerumus, penting bagi anak dan remaja untuk mampu mengendalikan diri, yakni tahu kapan harus berhenti dan Ganti mengerjakan aktivitas yang lain. Saat menggunakan gawai, gunakan aturan 20/20/20 yaitu setiap 20 menit, lepaskan mata dari gawai untuk memandang jauh sedikitnya 20 feet (6 meter) selama 20 detik. Hal ini dilakukan untuk menghindari sindrom mata lelah akibat terlalu lama melihat layar gawai.'),
(149, 129, 'P5.20', 'Siapa saja pihak yang terlibat dalam program BKR?', 'Pihak-pihak yang terlibat dalam program BKR, yaitu: Pokjanal (Kelompok Kerja Nasional) gerakan pembangunan keluarga sejahtera, Pokjanis Bina Keluarga Remaja, PPKBP (Petugas Pembantu Keluarga Berencana), Sub PPKBD, dan Lembaga Ketahanan Masyarakat Desa (LKMD/LPM) yang berperan sebagai pembina kelompok BKR. Selain itu terdapat kader dan fasilitator pada program BKR yang biasanya berasal dari anggota PKK, kader desa, atau masyarakat yang dilatih untuk membina keluarga dan remaja.'),
(150, 129, 'P5.21', 'Siapa saja pihak yang terlibat dalam program BKR?', 'Untuk mengajukan diri menjadi anggota Bina Keluarga Remaja (BKR), perlu melakukan langkah-langkah sebagai berikut:\n1.        Pastikan keluarga Anda memiliki anak usia 10-23 tahun yang belum menikah\n2.        Hubungi kader BKR atau fasilitator di wilayah desa atau kecamatan Anda. Kader biasanya melakukan pendataan keluarga dan potensi wilayah dengan mengunjungi rumah-rumah sasaran.\n3.        Ikuti pertemuan pembentukan kelompok BKR yang difasilitasi oleh tokoh pemerintah, tokoh masyarakat, dan kader BKR di desa atau kecamatan.\n4.        Setelah kelompok BKR terbentuk dan dikukuhkan dengan Surat Keputusan (SK) dari camat atau kepala desa, Anda secara resmi menjadi anggota kelompok tersebut.'),
(151, 129, 'P5.22', 'Bagaimana menyikapi anak remaja yang terlalu mendambakan idolanya?', 'Cara menyikapi anak remaja yang terlalu mendambakan idolanya, yaitu:\n1.        Perhatikan pengaruh idola terhadap perkembangan kepribadian anak. Jika mulai mengarah ke arah negatif, diingatkan.\n2.        Gali info lebih dalam tentang idola tersebut agar bisa mengajak anak berpikir dan melihat lebih dari sekedar fisik semata. Seperti apa yang menjadi inspirasi idola dalam menciptakan lagu tertentu atau motivasi terbesar idola dalam mengejar kesuksesan.\n3.        Ajari anak bedanya dunia nyata dan dunia artis Ketika anak terlalu mengidolakan seseorang, terkadang terdapat perbedaan tipis antara dunia nyata dan khayalan. Dunia artis tidak seindah yang dia bayangkan.'),
(152, 129, 'P5.23', 'Apa indikator yang digunakan dalam mengukur keberhasilan program BKR di suatu wilayah?', 'Indikator keberhasilan program Bina Keluarga Remaja (BKR) diantara lain:\n1.        Ketepatan Sasaran Program: Sejauh mana peserta program sesuai dengan target sasaran yang telah ditetapkan. \n2.        Pemahaman Program: Tingkat pemahaman masyarakat dan peserta terhadap tujuan, manfaat, dan pelaksanaan program BKR, yang mempengaruhi partisipasi dan keberhasilan program.\n3.        Ketepatan Waktu Pelaksanaan: Program dilaksanakan sesuai jadwal yang direncanakan sehingga kegiatan pembinaan berjalan konsisten dan berkelanjutan\n4.        Tercapainya Tujuan Program: Evaluasi pencapaian tujuan seperti peningkatan pengetahuan kesehatan reproduksi, pencegahan pernikahan dini, dan pembinaan remaja secara menyeluruh\n5.        Perubahan Nyata:Terjadi perubahan positif yang dapat diamati dalam perilaku remaja dan keluarga, misalnya penurunan angka pernikahan dini, peningkatan komunikasi keluarga, dan pengurangan perilaku risiko.'),
(153, 129, 'P5.24', 'Bagaimana peran BKR dalam membantu orang tua membina remaja?', 'BKR berperan memberdayakan orang tua melalui penyuluhan, bimbingan, dan pembinaan agar mereka memahami cara mengasuh dan membina anak remajanya dengan baik dan benar. Program ini juga meningkatkan komunikasi efektif antara orang tua dan remaja, sehingga tumbuh kembang remaja dapat terarah dan masalah-masalah seperti kenakalan remaja, pernikahan dini, dan perilaku risiko dapat diminimalisir.'),
(154, 129, 'P5.25', 'Bagaimana hubungan antara BKR dan Pusat Informasi dan Konseling (PIK) Remaja?', 'PIK R merupakan wadah kegiatan yang dikelola oleh dan untuk remaja, fokus pada pelayanan informasi dan konseling tentang perencanaan kehidupan berkeluarga serta masalah remaja lainnya. Sementara BKR adalah kelompok pembinaan keluarga yang memiliki remaja, berperan membantu orang tua memahami remaja dan permasalahannya serta meningkatkan komunikasi dalam keluarga. Dengan demikian, PIK R lebih berorientasi langsung pada remaja, sedangkan BKR lebih pada keluarga sebagai unit pembinaan. Sehingga BKR dan PIK R memperkuat upaya pembinaan remaja secara menyeluruh dari sisi keluarga dan individu remaja itu sendiri.'),
(155, 129, 'P5.26', 'Apa saja kegiatan yang dilakukan dalam kelompok BKR?', 'Kegiatan yang dilakukan dalam kelompok BKR, yaitu pertemuan rutin membahas materi seperti gerakan pembangunan keluarga sejahtera, konsep dasar bina keluarga anak dan remaja, pemanfaatan delapan fungsi keluarga, peran orang tua dalam pembinaan anak dan remaja, tumbuh kembang anak dan remaja, kesehatan reproduksi, pembinaan anak dan remaja, serta pengelolaan program BKR.'),
(156, 129, 'P5.27', 'Tindakan apa yang dilakukan BKR untuk membantu remaja dalam menghadapi masalah kesehatan reproduksi?', '1.        Peningkatan Pengetahuan dan Kesadaran\nBKR memberikan penyuluhan dan pembinaan kepada remaja dan orang tua tentang kesehatan reproduksi, termasuk pemahaman tentang sistem reproduksi, risiko perilaku seksual dini, pencegahan kehamilan tidak diinginkan, serta bahaya penyakit menular seksual. Hal ini membantu remaja memiliki informasi yang benar dan sikap yang positif terhadap kesehatan reproduksi\n2.        Fasilitasi Akses ke Layanan Kesehatan Reproduksi\nBKR mendukung remaja untuk mendapatkan akses ke layanan kesehatan reproduksi yang aman dan tepat, termasuk konseling dan pelayanan keluarga berencana yang sesuai dengan norma dan aturan yang berlaku'),
(157, 129, 'P5.28', 'Bagaimana cara kelompok BKR menjangkau anggota yang kurang aktif dalam kegiatan masyarakat?', 'Kader BKR dapat melakukan kunjungan rumah untuk memberikan penyuluhan dan bimbingan langsung kepada remaja dan keluarga. Kunjungan ini memungkinkan pendekatan yang lebih personal dan penyampaian informasi yang disesuaikan dengan kebutuhan keluarga.'),
(158, 129, 'P5.29', 'Bagaimana mekanisme pengawasan dan evaluasi pelaksanaan program BKR di lapangan?', 'Mekanisme pengawasan dan evaluasi pelaksanaan program Bina Keluarga Remaja (BKR) di lapangan dillakukan sebagai berikut:\n1.        Pengawasan secara langsung oleh kader BKR melalui kunjungan ke anggota kelompok secara informal, dengan mengamati kebiasaan dan partisipasi peserta dalam kegiatan BKR.\n2.        Kader bertugas memotivasi peserta dan menjaga konsistensi pelaksanaan kegiatan BKR agar tetap berjalan sesuai tujuan program.\n3.        Pengawasan juga dilakukan dengan komunikasi yang efektif antara kader dan peserta, serta koordinasi dengan pihak terkait guna memastikan kegiatan berjalan lancar dan tepat sasaran.'),
(159, 129, 'P5.30', 'Apa pola asuh yang tepat pada anak remaja?', 'Dalam program pengasuhan remaja dapat dilakukan dengan cara-cara berikut:\n1. Menggunakan pendekatan berbasis kekuatan yang menghargai keterampilan dan pengalaman yang dimiliki orang tua, dan kemudian mendukung orang tua untuk memelihara kekuatan anak remaja mereka\n2. Mendorong terciptanya norma-norma kesetaraan gender dan mengurangi paparan terhadap risiko-risiko spesifik gender\n3. Mendorong partisipasi remaja yang aman dan bermakna dalam keluarga dan masyarakat, sesuai dengan kapasitas mereka yang berkembang\n4. Melibatkan orang tua dengan berbagai latar belakang, termasuk yang paling terpinggirkan, untuk memenuhi kebutuhan anak remaja mereka\n5. Mengandalkan basis pengetahuan yang cukup besar tentang pengasuhan remaja.\nNamun, apapun gaya pengasuhan, remaja hanya butuh kenyamanan, dimengerti, dan merasa didengarkan oleh orang tua.'),
(160, 129, 'P5.31', 'Bagaimana peran orang tua dalam program BKR dalam menjaga ketahanan keluarga?', 'Orang tua berperan aktif dalam mempertahankan ketahanan keluarga melalui penerapan delapan fungsi keluarga dan membangun komunikasi yang efektif dengan remaja. Dengan demikian, orang tua dan remaja mendukung keharmonisan dan kekuatan keluarga sebagai unit sosial utama.'),
(161, 129, 'P5.32', 'Apa saja manfaat adanya program Bina Keluarga Remaja (BKR)?', '1. Perkembangan Seimbang: Membantu remaja mengembangkan keterampilan yang diperlukan untuk menjadi individu yang sehat dan mandiri.\n2. Dukungan Keluarga: Memberikan orang tua alat dan pengetahuan untuk mendukung perkembangan anak mereka dengan cara yang positif.\n3. Keterlibatan Sosial: Meningkatkan keterlibatan remaja dalam kegiatan komunitas dan sosial, yang dapat memperkuat rasa tanggung jawab dan kepemimpinan.'),
(162, 129, 'P5.33', 'Apa manfaat ikut BKR untuk memperbaiki hubungan antara orang tua dan remaja?', 'Program BKR bertujuan untuk meningkatkan kepedulian dan tanggung jawab orang tua dalam membimbing dan mengarahkan anak dan remaja melalui interaksi yang harmonis. Melalui kegiatan kelompok, orang tua mendapatkan informasi dan pembinaan untuk mendukung tumbuh kembang anak dan remaja secara baik dan terarah.​'),
(163, 129, 'P5.34', 'Kalau anak saya sudah mulai susah diatur, apakah BKR bisa membantu saya belajar caranya menghadapi?', 'Ya, BKR memberikan pembekalan kepada orang tua untuk meningkatkan bimbingan dan pembinaan tumbuh kembang anak dan remaja secara baik dan terarah. Melalui kegiatan kelompok, orang tua mendapatkan informasi dan strategi untuk menghadapi tantangan dalam mendidik remaja.​'),
(164, 129, 'P5.35', 'Apakah ikut BKR bisa membantu orang tua menyiapkan anak untuk masa depan, seperti pendidikan atau karier?', 'BKR membantu orang tua dalam memahami peran mereka dalam pembinaan anak dan remaja, termasuk dalam aspek pendidikan dan perencanaan masa depan. Melalui materi seperti \"Peran orang tua dalam pembinaan anak dan remaja\" dan \"Pemanfaatan 8 fungsi keluarga\", orang tua dibekali dengan pengetahuan untuk mendukung anak dalam meraih masa depan yang lebih baik.​'),
(165, 129, 'P5.36', 'Apakah ada program konseling keluarga lewat BKR kalau ada masalah serius antara orang tua dan anak?', 'BKR menyediakan kegiatan kelompok di mana orang tua mendapatkan informasi dan pembinaan dengan bantuan fasilitator dan kader. Meskipun tidak disebutkan secara spesifik sebagai \"konseling\", kegiatan ini memberikan dukungan kepada orang tua dalam menghadapi permasalahan keluarga.​'),
(166, 129, 'P5.37', 'Apa bentuk kegiatan BKR untuk menghindari anak dari pernikahan usia dini?', 'BKR menyelenggarakan pertemuan kelompok dengan materi yang mencakup \"Reproduksi sehat\", yang bertujuan untuk memberikan pemahaman kepada orang tua dan remaja tentang pentingnya kesehatan reproduksi dan dampak dari pernikahan usia dini. Dengan pemahaman ini, diharapkan dapat mencegah terjadinya pernikahan pada usia yang belum matang.​'),
(167, 129, 'P5.38', 'Bagaimana strategi  pola pengasuhan Remaja', 'Strategi dalam membimbing anak remaja agar mereka tetap merasa aman dan nyaman dengan gaya pengasuhan orang tuanya : \n1, Tentukan batasan yang harus dipatuhi\n2, Dengarkan apa yang ingin mereka sampaikan dan cobalah untuk tidak menginterupsi sampai mereka selesai berbicara\n3, Biarkan mereka belajar dari kesalahan mereka sendiri (selama mereka aman)\n4, Jangan tutupi kekhawatiran Anda, melainkan cobalah berbicara dengan tenang dan arahkan mereka pada informasi yang bermanfaat\n5, Biarkan mereka memiliki ruang dan privasi mereka sendiri'),
(168, 129, 'P5.39', 'Apa pengertia 8 fungsi keluarga?', '8 Fungsi Keluarga merupakan\nfungsi-fungsi yang diterapkan oleh seluruh anggota keluarga\nsesuai dengan perannya, agar keluarga tersebut dapat\nmembentuk pribadi berkarakter yang baik, badan yang sehat,\nberkemampuan, mandiri, andal dan bahagia'),
(169, 129, 'P5.40', 'Apa Nilai-nilai Fungsi Agama dalam 8 fungsi keluarga?', '1) Iman\nSeluruh anggota keluarga mempercayai\nadanya Allah SWT, Tuhan Yang Maha Esa\ndan mengamalkan ajarannya.\n2) Taqwa\nSeluruh anggota keluarga mengamalkan segala\nsesuatu yang diperintahkan dan menghindari\nsegala yang dilarang Allah SWT.\n3) Kejujuran\nSeluruh anggota keluarga dapat menyampaikan\nhal apapun secara apa adanya sesuai dengan\nkenyataan.\n4) Tenggang rasa\nSeluruh anggota keluarga mempunyai\nkesadaran bahwa setiap orang berbeda dalam\nsifat dan karakternya.\n5) Rajin\nSeluruh anggota Keluarga menyediakan waktu\ndan tenaga untuk menyelesaikan tugasnya dengan berusaha untuk mendapatkan hasil\nsecara tepat waktu dan yang terbaik.\n6) Kesalehan\nSeluruh anggota keluarga memiliki nilai moral\nyang tinggi dengan melakukan sesuatu yang\nbenar secara konsisten\n7) Ketaatan\nSeluruh anggota keluarga dapat melaksanakan\ntugas dan tanggung jawabnya dengan segera\ndan senang hati.\n8) Suka membantu\nSeluruh anggota keluarga memiliki kebiasaan\nmenolong dan membantu orang lain tanpa\nmengharapkan imbalan.\n9) Disiplin\nSeluruh anggota keluarga menepati waktu dan\nmematuhi aturan yang telah disepakati.\n10) Sopan santun\nSeluruh anggota keluarga berperilaku sesuai\ndengan norma-norma dan nilai-nilai agama.\n11) Sabar dan Ikhlas\nSeluruh anggota keluarga mempunyai\nkemampuan untuk menahan diri dalam\nmenginginkan sesuatu serta dalam menghadapi\nkesulitan.\n12) Kasih sayang\nSeluruh anggota keluarga mampu ungkapan\nperasaan dengan penuh perhatian, kesadaran\ndan kecintaan terhadap seseorang'),
(170, 129, 'P5.41', 'Bagaimana cara menghadapi remaja yang merokok?', 'Ungkapkan perasaan kita atas sikapnya.\nBerikan alasan mengapa kita merasakan hal tersebut.\nTanya pada remaja apa alasan ia mencoba merokok.\nBahas risiko atau akibat dari mencoba rokok.\nTentukan bersama konsekuensinya, buat kesepakatan jika belum ada.'),
(171, 129, 'P5.42', 'Bagaimana cara meminta izin ke orang tua ketika akan melakukan hal yang dianggap berbahaya oleh orang tua?', 'Sampaikan situasinya, apa rencanamu, kendala yang dihadapi, dan bagaimana caramu untuk mengatasi kendala.'),
(172, 129, 'P5.43', 'Bagaimana cara memantau remaja bermedia sosial?', 'Pahamkan remaja tentang cara kerja media sosial.\nAturan privasi: tidak membagikan data pribadi ke orang tak dikenal.\nTentukan batasan, baik soal waktu pemakaian hingga konten yang boleh dilihat.\nPahamkan tentang etika bermedia sosial, misal saat memberi komentar, memasang status.\nMengikuti akun media sosial remaja.\nBuat kesepakatan tentang kapan orang tua boleh melihat chat, browsing history HP remaja.\nTentukan bersama apa konsekuensinya jika kesepakatan dilanggar.\nGunakan mode terbatas (restricted mode) dan sejenisnya untuk menyaring konten negatif dan membatasi kolom komentar.'),
(173, 129, 'P5.44', 'Bagaimana cara mendengarkan anak ketika mereka curhat?', 'Beri perhatian penuh\nTunjukkan kita tertarik\nTunjukkan kita paham\nHindari memotong cerita\nBerikan respon yang sesuai'),
(174, 129, 'P5.45', 'Mengapa remaja suka berkata kasar?', 'Ingin terlihat dewasa\nIngin terlihat keren di depan teman-temannya\nAgar diterima oleh kelompoknya\nMeniru atau sering mendengar kata kasar (bisa orang tua, dari media sosial, game, film)'),
(175, NULL, 'P6', 'Bangga Kencana', NULL),
(176, 175, 'P6.1', 'Apa definisi dari keluarga?', 'Keluarga adalah unit terkecil dalam masyarakat yang terdiri dari suami istri, atau suami, istri dan anaknya, atau ayah dan anaknya, atau ibu dan anaknya'),
(177, 175, 'P6.2', 'Apa yang dimaksud dengan pembangunan keluarga?', 'Pembangunan keluarga adalah upaya mewujudkan keluarga berkualitas yang hidup dalam lingkungan yang sehat'),
(178, 175, 'P6.3', 'Apa tujuan dari pembangunan keluarga?', 'Tujuan pembangunan keluarga adalah mewujudkan keserasian, keselarasan, dan keseimbangan antara kuantitas, kualitas, dan persebaran penduduk dengan lingkungan hidup'),
(179, 175, 'P6.4', 'Apa yang dimaksud dengan keluarga berencana?', 'Keluarga berencana adalah upaya mengatur kelahiran anak, jarak, dan usia ideal melahirkan, mengatur kehamilan melalui promosi, perlindungan, dan bantuan sesuai dengan hak reproduksi untuk mewujudkan keluarga yang berkualitas'),
(180, 175, 'P6.5', 'Pengertian Bangga Kencana', 'Program Pembangunan Keluarga, Kependudukan dan Keluarga Berencana yang bertujuan untuk mengarahkan keluarga memiliki rencana berkeluarga, memiliki anak, pendidikan dan sebagainya sehingga terbentuk keluarga berkualitas. Diharapkan BKKBN dapat mewujudkan keserasian, keselarasan dan keseimbangan antara kuantitas, kualitas dan persebaran penduduk dan lingkungan hidup, serta meningkatkan kualitas keluarga agar dapat timbul rasa tentram dan harapan masa depan yang lebih baik atau mandiri dalam mewujudkan kesejahteraan lahir dan kebahagiaan batin.'),
(181, 175, 'P6.6', 'Apa saja indikator atau variabel bangga kencana', 'Kualitas Keluarga: Indikator ini mencakup aspek-aspek seperti kesehatan reproduksi, perencanaan keluarga, dan pendidikan anak; Pengendalian Penduduk: Indikator ini mencakup aspek-aspek seperti pertumbuhan penduduk, distribusi penduduk, dan komposisi penduduk; Kesejahteraan Ekonomi: Indikator ini mencakup aspek-aspek seperti pendapatan keluarga, pendidikan, dan kesehatan.'),
(182, 175, 'P6.7', 'Kapan program Bangga Kencana dikatakan berhasil', 'Kualitas Hidup Keluarga Meningkat: Keluarga memiliki kualitas hidup yang lebih baik melalui akses yang lebih baik terhadap pendidikan, kesehatan, dan pekerjaan; Pengendalian Penduduk Efektif: Pertumbuhan penduduk dapat dikendalikan melalui perencanaan keluarga yang efektif; Kesejahteraan Ekonomi Meningkat: Keluarga memiliki kesejahteraan ekonomi yang lebih baik melalui pendidikan dan kesehatan yang memadai.'),
(183, 175, 'P6.8', 'Strategi untuk mencapai program Bangga Kencana', 'Pendidikan Kependudukan: Menyediakan pendidikan kependudukan yang memadai untuk masyarakat; Pelayanan Kesehatan Reproduksi: Menyediakan pelayanan kesehatan reproduksi yang terjangkau dan berkualitas; Perencanaan Keluarga: Mendorong perencanaan keluarga yang efektif melalui akses yang lebih baik terhadap kontrasepsi dan pendidikan; Pemberdayaan Masyarakat: Melibatkan masyarakat dalam kegiatan-kegiatan yang mendukung pengendalian kependudukan.'),
(184, 175, 'P6.9', 'Tantangan menuju Bangga Kencana', 'Kurangnya Akses terhadap Pendidikan dan Kesehatan: Masyarakat yang kurang mampu mungkin tidak memiliki akses yang memadai terhadap pendidikan dan kesehatan; Kurangnya Kesadaran Masyarakat: Masyarakat mungkin kurang sadar akan pentingnya perencanaan keluarga dan kesehatan reproduksi; Keterbatasan Sumber Daya: Keterbatasan sumber daya dapat menjadi hambatan dalam pelaksanaan program Bangga Kencana'),
(185, 175, 'P6.10', 'Jelaskan Ruang Lingkup mekanisme Operasional program Bangga Kencana di lini lapangan', '1. Komitmen, yang membahas bagaimana membangun komitmen dari \n stakeholders di tingkat kabupaten/kota hingga ke tingkat RW dalam \n pelaksanaan Program Bangga Kencana. \n 2. Persiapan data program Bangga Kencana, yang membahas persiapan dan \n pemanfaatan data untuk Peta Kerja Program Bangga Kencana yang akan \n digunakan untuk percepatan capaian Program Pembangunan Nasional di lini \n lapangan. \n 3. Pelaksanaan mekanisme operasional, yang membahas tentang bagaimana \n pelaksanaan mekanisme operasional program Bangga Kencana di setiap \n tingkatan wilayah. \n 4. Monitoring dan evaluasi terhadap pelaksanaan mekanisme operasional.'),
(186, 175, 'P6.11', 'Sebutkan strategi penggerakan lini lapangan dapat dikelompokkan ke dalam 3 \n (tiga) bagian, yaitu:', 'a. Strategi Pendayagunaan Tenaga Lini Lapangan \n b. Strategi Penguatan Institusi Masyarakat Pedesaan/ Perkotaan\n c. Strategi Penguatan Mekanisme Operasional Lini Lapangan'),
(187, 175, 'P6.12', 'Sebutkan Fungsi Pokok Penyuluh KB', '1. Penyuluhan\n 2. Pelayanan\n 3. Penggerakan \n 4. Pengembangan'),
(188, 175, 'P6.13', 'Jelaskan apakah yang dimaksud dengan Mekanisme Operasional Program \n Bangga Kencana?', 'langkah‐langkah operasional Program Bangga Kencana yang bekerja atau berfungsi \n dengan baik, teratur, terencana dan terus‐menerus, yang satu sama lain saling \n berkaitan, berkesinambungan, bersinergi, dan berkelanjutan, dengan melibatkan \n seluruh potensi yang ada di kecamatan, desa/kelurahan, RW/dusun dan RT \n dalam upaya mencapai sasaran Program Bangga Kencana.'),
(189, 175, 'P6.14', 'Jelaskan apakah yang dimaksud dengan Lini Lapangan?', 'Lini Lapangan adalah satuan wilayah yang melaksanakan aktivitas penyelenggaraan \n operasional Program Bangga Kencana di wilayah yang paling dekat dengan \n sasaran (keluarga/masyarakat) di kecamatan, desa/ kelurahan, RW/dusun dan \n RT'),
(190, 175, 'P6.15', 'dalam konteks pelaksanaan, mekanisme operasional dapat dilihat dari beberapa perspektif', '1. Perspektif Tingkatan Wilayah Pelaksana dan Pengelola \n 2. Perspektif Rangkaian Kegiatan Mekanisme Operasional'),
(191, 175, 'P6.16', 'Berdasarkan tingkatan wilayah, pelaksanaan program Bangga Kencana dan \n mekanisme operasional di lini lapangan terbagi atas tiga tingkatan, yaitu:', '1. Mekanisme Operasional tingkat Kecamatan \n 2. Mekanisme Operasional tingkat Desa \n 3. Pelaksanaan Program Bangga Kencana di tingkat Dusun/ RW, dan RT'),
(192, 175, 'P6.17', 'Sebutkan unsur pelaksana dan pengelola Program Bangga Kencana Tingkat Kecamatan', '1) Camat \n 2) Anggota Musyawarah Pimpinan tingkat Kecamatan (Muspika) lainnya \n 3) Kepala UPT/ Koordinator PKB/ Pengawas PLKB \n 4) Kepala Puskesmas \n 5) Kepala Organisasi Perangkat Daerah (OPD) bidang KB \n 6) Tokoh masyarakat/ Tokoh agama \n 7) Pimpinan LSOM \n 8) Ketua Tim Penggerak PKK \n 9) Pimpinan organisasi swasta dan pengusaha'),
(193, 175, 'P6.18', 'Sebutkan Unsur pelaksana dan pengelola Program Bangga Kencana di tingkat \n desa/kelurahan', '1) Kepala Desa/Lurah \n 2) Anggota Pamong desa \n 3) PKB/PLKB \n 4) Bidan di Desa \n 5) PPKBD \n 6) Tokoh masyarakat/tokoh agama \n 7) Ketua Tim Penggerak PKK \n 8) Institusi perdesaan lainnya.'),
(194, 175, 'P6.19', 'Sebutkan kegiatan Mekop tingkatan wilayah Kecamatan dan Desa', '1. Staff Meeting (Pertemuan Internal) \n 2. Rakor Kecamatan \n 3. Rakor Desa\n 4. Pembinaan IMP (Pertemuan Lengkap) \n 5. Komunikasi, Informasi, dan Edukasi\n 6. Pelayanan \n 7. Pencatatan dan Pelaporan \n 8. Pertemuan Pokja Kampung KB \n 9. Pembinaan \n 10. Monitoring dan Evaluasi'),
(195, 175, 'P6.20', 'Kegiatan yang \n dapat dilakukan oleh IMP dikelompokkan ke dalam tiga bagian utama,', 'pencatatan dan pelaporan, KIE, serta pelayanan.'),
(196, 175, 'P6.21', 'Berdasarkan tingkatan wilayah, pelaksanaan program Bangga Kencana dan \n mekanisme operasional di lini lapangan terbagi atas tiga tingkatan, yaitu:', 'a. Strategi Pendayagunaan Tenaga Lini Lapangan \n b. Strategi Penguatan Institusi Masyarakat Pedesaan/ Perkotaan\n c. Strategi Penguatan Mekanisme Operasional Lini Lapangan'),
(197, 175, 'P6.22', 'Bagaimana monitoring dan evaluasi Mekop Lini Lapangan', '1. Monitoring Langsung\n a. Camat melihat pelaksanaan staff meeting, menghadiri pelayanan, ikut \n membentuk kelompok‐kelompok kegiatan. \n b. Kepala Desa memantau kegiatan BKB, BKR dan BKL. \n c. Kepala UPT menghadiri KIE di tingkat RT. \n d. PLKB memantau pemberian materi kutbah Jumat di salah satu masjid.. \n e. PPKBD mengecek keberadaan akseptor melalui kunjungan rumah (sebaiknya \n membawa kartu K/IV/KB dari klinik). \n f. Camat menghadiri kegiatan-kegiatan di Kampung KB. \n 2. Monitoring Tidak Langsung \n a. Evaluasi melalui staff meeting, oleh Kepala UPT (atau yang setara) bersama \n PKB/ PLKB, dengan melihat perkembangan Program Bangga Kencana di \n wilayah kerja. \n 75\n b. Kepala UPT melakukan analisa atas kesesuaian Rencana Kerja Program \n Bangga Kencana di wilayahnya.\n c. Kepala Desa mengevaluasi pada Rakor Desa\n d. Camat mengevaluasi pada Rakor Kecamatan \n e. Kepala UPTD Kesehatan memantau ketersediaan kontrasepsi di Puskesmas \n juga memantau di Dokter dan Bidan Praktik Swasta (BPS). \n f. Monev melalui Aplikasi MONEV MEKOP Lini Lapangan'),
(198, 175, 'P6.23', 'Jelaskan PPKBD dan Sub PPKBD', 'PPKBD (Pembantu Pembina Keluarga Berencana Desa) adalah seorang kader \n atau beberapa orang kader yang secara sukarela berperan aktif melaksanakan dan \n mengelola program Bangga Kencana ditingkat Desa/Kelurahan. Sub PPKBD (Sub \n Pembantu Pembina Keluarga Berencana Desa) adalah seorang kader atau beberapa \n orang kader dalam wadah organisasi yang secara sukarela berperan aktif \n melaksanakan dan mengelola program Bangga Kencana ditingkat Dusun/Rukun \n Warga (RW).'),
(199, 175, 'P6.24', 'Jelaskan Apa Itu IMP', 'IMP (Institusi Masyarakat Pedesaan/Perkotaan) adalah wadah masyarakat \n yang berperan serta dalam pengelolaan program Bangga Kencana, di tingkat \n Desa/kelurahan, Dusun/RW dan RT kebawah yang secara nasional disebut \n Pembantu Pembina Keluarga Berencana Desa (PPKBD), Sub Pembantu \n Pembina Keluarga Berencana Desa (Sub PPKBD) dan Kelompok Keluarga \n Berencana (kelompok KB).'),
(200, 175, 'P6.25', 'Jelaskan PPKBD (Pembantu Pembina Keluarga Berencana Desa)', 'PPKBD (Pembantu Pembina Keluarga Berencana Desa) adalah seorang kader \n atau beberapa orang kader yang secara sukarela berperan aktif melaksanakan \n dan mengelola program Bangga Kencana ditingkat Desa/Kelurahan. \n Memiliki tugas, tanggungjawab, wewenang dan hak secara penuh oleh pejabat \n berwenang sebagai pembantu pembina penyelenggaraan program KB di \n Desa/Kelurahan untuk melaksanakan kegiatan penyuluhan dan pelayanan KB \n dan KS, membina kelompok KB, mencatat dan melaporkan kegiatan yang \n dilakukan secara rutin'),
(201, 175, 'P6.26', 'Jelaskan Sub PPKBD (Sub Pembantu Pembina Keluarga Berencana Desa)', 'Sub PPKBD (Sub Pembantu Pembina Keluarga Berencana Desa) adalah\n seorang kader atau beberapa orang kader dalam wadah organisasi yang \n secara sukarela berperan aktif melaksanakan dan mengelola program Bangga \n Kencana ditingkat Dusun/Rukun Warga (RW).'),
(202, 175, 'P6.27', 'Jelaskan Kelompok KB', 'kelompok peserta KB dalam wadah organisasi yang \n secara sukarela berperan aktif melaksanakan/mengelola Program Bangga \n Kencana di tingkat RT. \n Kelompok KB merupakan bagian kegiatan dari PPKBD dan Sub PPKBD'),
(203, 175, 'P6.28', 'Sebutkan 6 peran bakti IMP', '(1. Pengorganisasian, 2. Pertemuan, 3. KIE dan Konseling, 4. Pencatatan, \n Pendataan dan Pemetaan sasaran, 5. Pelayanan Kegiatan, 6. Kemandirian).'),
(204, 175, 'P6.29', 'Jelaskan tujuan IMP', 'IMP bertujuan untuk meningkatkan kepedulian dan peran serta \n institusi masyarakat untuk menjadi pengelola dan pelaksana Program Bangga \n Kencana yang dinamis dan mandiri. Sedangkan secara khusus diharapkan dapat \n meningkatkan dan memantapkan kepedulian dan peran serta PPKBD, Sub PPKBD \n dalam menyelenggarakan berbagai kegiatan yang berkaitan dengan kebijakan \n program Bangga Kencana (Pembangunan Keluarga, Kependudukan dan Keluarga \n Berencana)'),
(205, 175, 'P6.30', 'Jelaskan cara monitoring dan evaluasi IMP!', 'Monitoring dan Evaluasi dilakukan dengan cara antara lain:\n 1. Pemantauan terhadap IMP;\n 2. Pemantauan Database online IMP;\n 3. Pemantauan Database Poktan;\n 4. Monitoring Pengendalian Lapangan (Dalap);\n 5. Pengamatan langsung di lapangan;\n 6. Pembinaan secara berjenjang dan berkesinambungan.'),
(206, 175, 'P6.31', 'Apa dasar hukum Islam dalam penolakan Gratifikasi?', 'QS Al Anfal : 27\n\'Hai orang-orang yang beriman, janganlah kamu mengkhianati Allah dan Rasul (Muhammad) dan juga janganlah kamu mengkhianati amanat-amanat yang dipercayakan kepadamu, sedang kamu mengetahui\nQS Al A\'raf : 33'),
(207, 175, 'P6.32', 'Bagaimana gratifikasi yang dianggap suap?', 'Gratifikasi yang diterima oleh Pegawai Negeri atau Penyelenggara Negara yang berhubungan dengan jabatannya dan yang berlawanan dengan kewajiban atau tugasnya.'),
(208, 175, 'P6.33', 'Apa pentingnya peran ayah pada karakter tumbuh kembang anak?', 'Pentingnya peran ayah pada karakter tumbuh kembang anak adalah:\n1. Menjadi Role Model Bagi Anak\n2. Pelindung dan Penyedia Kebutuhan Anak\n3. Pelengkap Simulasi Perkembangan Anak'),
(209, 175, 'P6.34', 'Bagaiman bentuk peran Ayah dalam menjadi role model bagi anak?', 'Peran ayah membentuk karakter anak yang pertama dapat dilakukan sebagai role model. Ayah adalah panutan bagi anak-anaknya, karena mereka akan belajar bagaimana seharusnya teladan seorang pria. Anak laki-laki akan meniru perilaku ayahnya dan berkembang menjadi pribadi yang baik.'),
(210, 175, 'P6.35', 'Bagaiman bentuk peran Ayah dalam menjadi Pelindung dan Penyedia Kebutuhan Anak?', 'Peran ayah membentuk karakter anak selanjutnya adalah memberikan rasa aman, baik fisik, emosional, mental, atau spiritual. Ketika ayah mendukung anak untuk menjalani kehidupan dalam situasi apa pun, akan membangun percaya diri dan rasa aman yang tidak akan tergantikan.'),
(211, 175, 'P6.36', 'Bagaiman bentuk peran Ayah dalam menjadi Pelengkap Simulasi Perkembangan Anak?', 'Peran ayah membentuk karakter anak yang terakhir adalah menjadi pelengkap simulasi perkembangan anak. Berkaitan dengan hal tersebut, ayah dapat melakukan beberapa hal Meningkatkan Akal, Meningkatkan Keyakinan, dan Pelengkap Simulasi Perkembangan Anak'),
(212, 175, 'P6.37', 'Apa dampak tidak adanya peran ayah dalam keluarga?', 'Ketiadaan peran atau kurang terlibatnya ayah dalam keluarga dapat memunculkan hambatan dalam proses perkembangan anak. Beberapa persoalan yang bisa muncul antara lain hambatan dalam pembentukan identitas gender dan peran seksual, penurunan performa akademis, kesulitan penyesuaian psikosoial, kontrol diri rendah, dan self esteem rendah.\nSelain itu, kurangnya keterlibatan ayah dapat menjadi faktor risiko munculnya psikopatologi pada anak. Salah satunya kecanduan terhadap zat ataupun aktivitas yang menimbulkan kesenangan seperti kecanduan gadget, game online, napza, rokok dan lainnya.\n\nSelain itu juga memunculkan ganguan perilaku menyimpang, perilaku seksual dan gangguan mood serta bunuh diri.'),
(213, 175, 'P6.38', 'Apa itu Ovulasi dan Masa Subur?', 'Ovulasi adalah fase dalam siklus menstruasi ketika ovarium melepaskan sel telur (ovum) yang sudah matang.\nSetelah sel telur matang meninggalkan indung telur, sel telur tersebut bergerak ke saluran tuba falopi. \nKemudian, sel telur matang aka menunggu terjadinya pembuahan oleh sperma.\nJika tidak terjadi pembuahan, sel telur dan lapisan dinding rahim akan luruh sehingga keluar sebagai darah menstruasi. Ovulasi rata-rata terjadi pada hari ke 14 dari 28 hari siklus menstruasi.'),
(214, 175, 'P6.39', 'Bagaimana Terjadinya Proses Kehamilan?', 'Proses kehamilan terjadi setelah adanya pembuahan pada sel telur. Peluang terjadinya kehamilan menjadi lebih besar jika hubungan intim dilakukan pada masa ovulasi. Namun, sebenarnya proses kehamilan bisa terjadi kapan saja selama ada pembuahan pada sel telur yang telah matang. Wanita dikatakan hamil jika pembuahan berhasil terjadi. \nPeluang kehamilan menjadi lebih tinggi jika hubungan intim dilakukan pada masa ovulasi alias masa subur. Pada wanita, ovulasi umumnya berlangsung sekitar 2 minggu sebelum hari pertama periode menstruasi berikutnya dimulai. Pada masa ovulasi, indung telur atau ovarium akan mengeluarkan sel telur yang telah matang dan siap untuk dibuahi.'),
(215, 175, 'P6.40', 'Bisakah Hamil saat Haid?', 'Ketika kamu dan pasangan melakukan hubungan intim saat tengah menstruasi, ternyata kondisi ini masih memungkinkan terjadinya kehamilan. Meskipun begitu, kesempatan untuk hamil saat menstruasi sangat kecil.\nNamun, kemungkinan tersebut dapat terjadi karena beberapa faktor, seperti:\nPerdarahan yang terjadi sebenarnya bukanlah perdarahan menstruasi, melainkan perdarahan tanda ovulasi. Ketika ovulasi, wanita akan melepaskan sel telur. Kemudian, saat sel sperma masuk maka keduanya akan bertemu dan terjadi pembuahan. Hal ini yang memungkinkan terjadinya kehamilan.\nBerhubungan intim saat menstruasi juga bisa menyebabkan kehamilan, ketika ovulasi terjadi sebelum perdarahan menstruasi selesai.\nKehamilan juga dapat terjadi saat menstruasi, jika ovulasi terjadi dengan cepat setelah menstruasi selesai. Sel sperma mampu bertahan selama beberapa hari setelah ejakulasi dalam vagina. Jika ovulasi terjadi saat sel sperma masih sehat, maka pembuahan dapat terjadi.'),
(216, 175, 'P6.41', 'Apa saja kegiatan yang bisa Ayah lakukan agar dekat dengan Balitanya?', '1. Menyuapi Anak\nSalah satu kegiatan sederhana yang dapat dilakukan sebagai cara agar ayah bisa dekat dengan balita adalah memberi makan atau menyuapinya. Dengan berpartisipasi dalam mengasuh dan merawat anak, dapat menciptakan ikatan yang kuat antara Orang Tua pada anak. Cobalah untuk meletakkan anak di tempat makannya, lalu dengan sabar berikan sesuap makanannya. Keakraban akan timbul dengan sendirinya karena terbiasa untuk berinteraksi.\n\n2. Membaca Buku\nKebanyakan anak sangat menyukai membaca buku bergambar. Dengan lebih banyak membaca, pengetahuan anak tentang hal-hal yang baru juga dapat bertambah. Pada anak yang lebih besar, dirinya dapat memperluas kosakata dan belajar lebih banyak tentang banyak hal baru di dunia. Pastikan untuk menyesuaikan dengan usianya, jangan memaksakan anak agar harus mengerti semua hal yang dibacakan. Ayah juga harus membuat dirinya agar senang untuk membaca terlebih dahulu.\n\n3. Permainan Puzzle\nAyah juga dapat memainkan puzzle bersama dengan Si Kecil yang memang sangat bagus untuk membentuk kedekatan. Cobalah untuk membeli puzzle yang agak besar agar dapat dimainkan berdua. Pilih puzzle dengan gambar dari karakter favoritnya agar anak lebih semangat saat bermain. Satukan semua potongan-potongan yang ada hingga selesai dan anak akan merasa bangga terhadap hasil kerja kerasnya.\n\n4. Membantu saat Cuci dan Lipat Pakaian\nCara lainnya agar ayah bisa dekat dengan anak balitanya adalah mengajaknya untuk membantu saat mencuci dan melipat pakaian. Dirinya akan belajar tentang pentingnya melakukan pekerjaan rumah dan kebiasaan ini dapat tertanam hingga besar. Ayah dapat menjadikan kesempatan ini untuk bersenang-senang bersama dan mengajarkannya keterampilan baru yang tidak diajarkan di sekolah.');
INSERT INTO `faq` (`id`, `parent_id`, `key_name`, `question_text`, `answer_text`) VALUES
(217, 175, 'P6.42', 'Apa saja cara menguatkan hubungan Ayah dan Anak agar makin akrab?', '1. Tunjukan kasih sayang\nKasih sayang ternyata berperan besar dalam perkembangan emosi dan neurobiologis anak. Ayah bisa menunjukan kasih sayangnya dengan sering menyentuh Si Kecil secara lembut. Atau, peluk anak dalam beberapa kali sehari, misalnya sebelum berangkat bekerja atau saat anak pergi tidur. Sapa mereka dengan ekspresi hangat, berikan kontak mata dan tersenyum.\n\n2. Ungkapkan rasa cinta\nSetiap orang tua pasti mencintai anaknya. Coba ungkapkan rasa cinta ini setiap hari kepada Si Kecil. Bahkan ketika Si Kecil sulit atau melakukan sesuatu yang tidak orang tua sukai. Hal tersebut bisa menjadi kesempatan bagus untuk mengingatkan mereka bahwa ayahnya mencintainya tanpa syarat. \n\n3. Tetapkan batasan, aturan, dan konsekuensi\nAnak saat membutuhkan bimbingan untuk tumbuh dan belajar tentang dunia di sekitarnya. Bicarakan pada anak tentang batasan, aturan dan konsekuensi dari setiap perilakunya. Ketika aturan dilanggar, berikan konsekuensi yang sesuai dengan usia anak secara konsisten.\n\n4. Dengarkan dan berikan empati\nAkui perasaan anak dan tunjukan ayah mengerti apa yang dirasakannya. Yakinkan anak bahwa ayah akan selalu ada untuk membantu apa pun yang mereka butuhkan. Lihat sesuatu dari sudut pandang anak untuk menumbuhkan rasa saling menghormati.\n\n5. Makan bersama\nLuangkan waktu untuk makan bersama di rumah bersama keluarga. Biasanya, waktu makan seringkali menghasilkan percakapan yang menyenangkan sehingga mempererat hubungan keluarga. Matikan televisi dan letakan ponsel untuk menikmati kebersamaan satu sama lain. Waktu makan juga bisa menjadi kesempatan besar bagi ayah untuk mengajari anak-anak pentingnya pola makan yang sehat dan seimbang.'),
(218, 175, 'P6.43', 'Bagaimana cara Quality Time dengan anak bagi Ayah yang bekerja?', 'Meski sibuk bekerja, Ayah bisa dicoba  memberi perhatian pada Si Kecil dan menghabiskan waktu berkualitas, di antaranya: \n\n1.Cari Tahu tentang Anak \nMeski tidak bisa menghabiskan banyak waktu dengan Si Kecil, pastikan ayah tidak kehilangan kesempatan untuk memberi perhatian. Di tengah perkembangan teknologi, ayah bisa mencari tahu tentang Si Kecil dengan mudah, misalnya melalui media sosial. Jika dibutuhkan, luangkan waktu untuk menelpon atau sekadar mengirim pesan dan mendengarkan cerita sang buah hati. \n\n2.Tentukan Prioritas \nBagaimanapun, keluarga dan karir sebaiknya dijalani dengan seimbang. Agar lebih banyak waktu yang bisa dihabiskan, ayah bekerja perlu menentukan apa yang menjadi prioritas dan kapan harus mendahulukan hal-hal tertentu. Sebagai contoh, pada akhir pekan ayah bisa menjadikan anak sebagai prioritas dan hal itu berarti tidak ada gangguan dari kantor meskipun hanya sebuah telepon atau pesan. \n\n3.Aktivitas Seru \nSaat memiliki waktu luang yang cukup, pastikan ayah menghabiskannya dengan cara yang berkesan. Rencanakan untuk melakukan aktivitas yang seru dengan Si Kecil, seperti berkebun, pergi ke pantai, atau hanya membersihkan rumah dan mengubah tata letak ruangan. \n\n4.Rencanakan Perjalanan \nSelain melakukan aktivitas seru, ayah juga bisa merencanakan perjalanan yang menyenangkan untuk menghabiskan quality time bersama anak dan istri. Jika tidak memiliki banyak waktu, ayah bisa merencanakan perjalanan singkat ke luar kota dan menikmati pemandangan yang berbeda dari biasanya. \n\n5.Antar atau Jemput Sekolah \nSatu hal kecil yang bisa ayah lakukan untuk membangun kedekatan dengan anak adalah usahakan untuk mengantar atau menjemput di sekolah, saat ada waktu. Ayah bisa memanfaatkan waktu di perjalanan untuk bertanya aktivitas seharian anak dan mendengarkan keluh kesahnya.'),
(219, 175, 'P6.44', 'Apa manfaat peran Ayah dalam perkembangan psikologis Anak?', 'Bukan hanya ibu, peran ayah juga diperlukan untuk perkembangan psikologis anak. Dengan begitu, anak dapat menjadi sosok yang penuh kepercayaan diri dan jiwa sosial yang tinggi.\nBerikut manfaat peran Ayah dalam perkembangan psokologis anak:\n\n1. Meningkatkan Kepercayaan Diri\nAnak yang mendapatkan dukungan dari ayahnya dapat merasakan jika dirinya dihargai dan dicintai. Sehingga, ia memiliki harga diri yang tinggi serta berhubungan dengan kepercayaan diri yang lebih baik.\nBahkan, mendapatkan pendidikan dari sang ayah juga membuat anak memiliki toleransi lebih baik terhadap perasaan stres. Mereka juga mampu untuk menghadapi situasi baru dan membela diri sendiri dengan teman sebayanya.\n\n2. Memiliki Perilaku yang Baik\nAyah dapat memberikan teladan bagi anak-anaknya dan mengajarkan tentang perilaku baik. Alhasil, anak memiliki kontrol perilaku dan impuls yang lebih baik, serta tingkat sosialisasi yang lebih baik.\nSelain itu, anak-anak juga cenderung menjadi seseorang yang lebih penyayang dan murah hati. Peran ayah yang dilakukan dengan benar dapat membuat anak sadar akan kebutuhan dan hak dari orang lain.\n\n3. Memiliki Banyak Perspektif\nAnak-anak memiliki banyak sekali pertanyaan di dalam benaknya dan bisa jadi mendapatkan jawaban yang berbeda dari ayah dan ibunya. Anak dengan Orang Tua yang aktif dalam pengasuhan bisa memiliki pemikiran dan pemecahan masalah dengan perspektif yang berbeda-beda.\nPeran ayah dalam mendidik anak juga dapat memberikan kesempatan untuk memberikan pandangan tentang hidup, serta mengajari Si Kecil terkait berbagai macam keterampilan hidup yang berharga. Pembelajaran ini sangat aplikatif pada kehidupan dan bisa dibawa hingga mereka dewasa.\n\n4. Kepercayaan Diri yang Tinggi\nAnak-anak yang mendapatkan perhatian dari ayahnya membuat mereka merasa dicintai. Saat merasakan cinta dari ayah dan ibunya, anak merasakan cinta yang berlebih dan dapat tumbuh lebih bahagia dan sehat. Sehingga, tingkat kepercayaan dirinya lebih baik.\nMaka dari itu, jangan pernah mengabaikan anak, terutama sedang masa pertumbuhan. Saat peran pendidikan hanya didapat dari ibunya, tentu tidak sebanyak yang dipelajari ketika didapatkan dari kedua Orang Tuanya.'),
(220, 175, 'P6.45', 'Apa saja tips bonding agar Ayah dan Anak Laki-Laki (Remaja) lebih dekat?', 'Membangun Kembali Kedekatan Ayah dan Anak \nAyah dan anak bisa mencoba beberapa tips bonding berikut agar tetap nyambung dan bisa menghabiskan waktu bersama.\n\n1. Permainan Kesukaan Anak \nSaat masih kecil, Orang Tua lebih mudah mengetahui apa saja kesukaan anak, seperti permainan, buku yang dibaca, hingga karakter kartun favorit. Semua itu mungkin berubah saat anak beranjak dewasa, tetapi ayah tetap bisa mengetahuinya. Cari tahu apa saja yang ia akses di internet, seperti apa pergaulannya, serta apa saja koleksi buku yang sering ia baca. Setelah mengetahuinya, ayah bisa coba untuk ikut masuk ke dunia anak dan menjadi teman diskusi yang menyenangkan. Hal ini bisa membangun kedekatan dan membuat ayah lebih mengenali karakter anak. \n\n2. Aktivitas di Luar Ruangan \nAyah bisa membangun kedekatan dengan anak laki-laki dengan mengajaknya melakukan aktivitas di luar ruangan, seperti berolahraga dan bertualang. Perhatikan apa saja jenis olahraga atau aktivitas yang disukai anak, kemudian cari celah supaya ayah bisa masuk. Jika anak menyukai sepak bola, sementara ayah ada penggemar basket, cobalah untuk memilih jenis olahraga yang sama-sama bisa dinikmati seperti berlari atau bersepeda. \n\n3. Beri Kejutan \nJarak yang ada antara ayah dan anak laki-laki bisa saja muncul karena kesibukan masing-masing. Jangankan untuk bermain bersama, ayah dan anak mungkin saja tidak lagi memiliki waktu untuk saling bertemu dan ngobrol. Saat memiliki waktu luang, cobalah untuk memberi kejutan pada anak. Misalnya, saat ayah tidak memiliki banyak pekerjaan dan anak tidak dalam masa ujian, jemput ia di sekolah kemudian ajak menonton pertandingan olahraga atau sekadar menghabiskan waktu bersama. \n\n4. Ajarkan Kebaikan \nTidak harus selalu bersenang-senang, ayah juga bisa membangun kedekatan dengan anak sambil mengajarkan kebaikan. Saat ada waktu luang, cobalah untuk memberi pandangan dan fondasi yang kuat secara spiritual pada anak. Ayah juga bisa membagi pengalaman-pengalaman semasa muda, untuk menjadi pelajaran anak dalam menjalani hidup. Ajarkan setiap kebaikan yang ada di dunia, sehingga hidupnya jadi lebih bermakna. \n\n5. Habiskan Waktu Berdua \nSalah satu cara paling ampuh untuk kembali membangun kedekatan ayah dengan anak laki-laki adalah menghabiskan waktu berdua. Terkadang, tidak perlu melakukan hal apapun. Ayah dan anak bisa menghabiskan waktu yang berkualitas dengan bercengkrama dan membicarakan hal-hal yang sebelumnya tidak sempat dibahas bersama.'),
(221, 175, 'P6.46', 'Apa saja peran Ayah yang dalam Keluarga?', 'Peran ayah sangat dibutuhkan untuk menjaga keluarga tetap utuh dan memastikan anak-anak mendapatkan pendidikan, bukan hanya dari ibunya saja.\nPeran Ayah yang perlu dipenuhi dalam keluarga yaitu:\n1. Pelindung Keluarga\nSeorang ayah perlu mengambil peran sebagai pelindung keluarga. Pada anak, sosok ayah menanamkan nilai dan moral pada anak, agar dapat tumbuh menjadi seseorang yang terhormat sekaligus dihormati.\nAyah mengajari anak tentang kemampuan untuk menghadapi kesulitan dengan cara berani, serta tidak berkompromi tentang keyakinannya dengan orang lain. Ayah merupakan alasan anak menjadi seseorang yang percaya diri dan mandiri, sehingga mampu melindungi diri sendiri.\nAyah juga perlu melindungi keselamatan pasangan dan anak-anaknya saat mengalami sesuatu yang membahayakan. Pria ini juga memiliki peran untuk menjauhkan berbagai risiko bahaya yang bisa terjadi.\n\n2. Menjadi Contoh\nAyah dapat memberikan berbagai contoh baik bagi anak, terutama pada kesehariannya saat di rumah. Salah satunya adalah dengan mendukung pasangan, atau ibu dalam rumah tangga, dalam memberikan pendidikan pada anak-anak.\nSaat anak melihat jika ayahnya memperlakukan ibunya dengan cinta dan rasa hormat, anak jadi paham seperti apa hubungan yang sehat sejalan dengan semakin bertambahnya usianya.\n\n3. Motivator\nSeorang ayah juga dapat mengambil peran dalam memberikan pengajaran terkait dasar-dasar kehidupan pada anak-anak. Kepala keluarga ini kerap mengingatkan anak jika tidak ada manusia yang sempurna dan melakukan kesalahan adalah sesuatu yang manusiawi.\nTidak apa untuk jatuh atau gagal dalam hidup selama bisa bangkit kembali. Beritahu anak jika seorang ayah akan selalu ada saat ia sedang jatuh untuk menangkapnya dan memberikan dukungan untuk bangkit kembali. Maka dari itu, cobalah menjadi sosok ayah sekaligus teman yang bisa mendengarkan cerita-ceritanya.\n\n4. Menjadi Pendengar yang Baik\nCobalah menjadi seseorang yang selalu berada di sampingnya, saat anak sedang ‘terbang’ atau ‘terjatuh’. Tunjukkan minat pada kehidupan Si Kecil, termasuk mengetahui teman-temannya dan sesuatu yang membuatnya khawatir.\nJika seorang ayah selalu mendengarkan apa yang diceritakan anak tanpa penghakiman, maka ia dapat tumbuh dengan menerapkan berbagai nasihat yang diberikan oleh Orang Tuanya.\n\n5. Membuat Aturan\nAyah adalah seorang pemimpin di dalam keluarga yang mampu membuat aturan dan batasan di dalam rumah. Hal ini tentu dapat membuat pekerjaan ibu menjadi lebih mudah.\nAnak juga menjadi lebih paham terkait sesuatu yang harus, boleh, atau dilarang dilakukan di rumah. Namun, ayah juga perlu konsisten dengan aturan yang dibuat, sebab anak juga melakukan penilaian terhadap orang tuanya juga.\nItulah beberapa peran ayah yang perlu dilakukan selain mencari nafkah. Memang terkadang tidak mudah untuk meluangkan waktu melakukan semua hal tersebut saat pekerjaan kantor terlalu banyak. Namun dengan melakukan hal ini, kamu sebagai ayah, dapat mendorong anak untuk tumbuh dengan lebih baik.'),
(222, 175, 'P6.47', 'Apa dampak jika tumbuh kembang Anak tanpa peran Ayah?', 'Anak dengan fatherless bisa menimbulkan dampak negatif terhadap perkembangannya seperti pada emosi, perilaku, kepercayaan diri, hubungan sosial, dan dukungan sosial dan finansial. berikut dampak yang ditimbulkan dari ketiadaan peran Ayah dalam perkembangan anak:\n1. Gangguan emosi\nAnak dengan fatherless cenderung mengalami gangguan emosi seperti depresi, kecemasan, dan kesulitan dalam mengontrol emosi mereka. Kondisi ini terjadi karena adanya perasaan kehilangan, kesepian, dan ketidakamanan yang anak rasakan.\n\n2. Perkembangan perilaku yang buruk\nAnak yang tidak memiliki figur ayah dalam hidupnya sering kali mengalami masalah dalam perkembangan perilaku mereka. Mereka dapat menjadi sulit untuk diatur, tidak taat aturan, dan cenderung terlibat dalam perilaku merugikan diri sendiri seperti bolos sekolah, penyalahgunaan narkoba atau alkohol.\n\n3. Rendahnya tingkat kepercayaan diri\nAnak yang tumbuh tanpa ayah akan merasa tidak mendapatkan rasa saling menghargai dari orang lain. Hal ini dapat mengakibatkan menurunnya tingkat kepercayaan dan ketidakpercayaan diri pada kemampuan mereka sendiri.\n\n4. Kesulitan dalam hubungan sosial\nAnak yang tidak memiliki sosok ayah cenderung mengalami kesulitan dalam membangun hubungan sosial dengan orang lain. Mereka merasa tidak mendapatkan kepercayaan atau sulit untuk menunjukkan perhatian kepada orang lain. Hal ini dapat menyebabkan kesulitan dalam menjalin hubungan dengan teman sebaya atau pasangan di masa depan.\n\n5. Kurangnya dukungan sosial dan finansial\nAnak yang tidak memiliki figur ayah cenderung mengalami dukungan sosial dan finansial yang kurang. Ayah sering kali menjadi sumber penghasilan utama dalam keluarga dan ketika mereka tidak hadir, bisa membuat situasi keuangan keluarga menjadi sulit.\n\nSelain itu, anak dengan fatherless juga dapat merasa kekurangan dukungan emosional dan bantuan praktis dari sosok ayah.'),
(223, 175, 'P6.48', 'Salah satu output yang dihasilkan melalui Generasi Berencana (Genre), adalah remaja yang memiliki perencanaan dalam mempersiapkan dan melewati 5 (lima) transisi kehidupan.  5 (lima) transisi kehidupan tersebut adalah', '(1) mempraktikkan hidup bersih dan sehat, (2) melanjutkan pendidikan, (3) memulai berkarir, (4) menjadi anggota masyarakat yang baik, serta (5) membangun keluarga yang berkualitas.'),
(224, 175, 'P6.49', 'Mengapa Kemendukbangga/BKKBN perlu melakukan kerjasama dalam melaksanakan program kependudukan dan pembangunan keluarga?', 'Penanganan masalah kependudukan dan pembangunan keluarga tidak bisa diatasi secara parsial, tetapi harus dilakukan secara terkoordinasi dan terpadu lintas sektor.'),
(225, 175, 'P6.50', 'Apakah tahapan dalam kerjasama?', 'Tahapan yang dilalui dalam kerjasama program kependudukan dan pembangunan keluarga meliputi :\n 1. Perencanaan kerjasama\n 2. Penyusunan naskah kerjasama\n 3. Pelaksanaan kerjasama\n 4. Pembinaan\n 5. Monitoring dan evaluasi\n 6. Pelaporan'),
(226, 175, 'P6.51', 'Apakah yang dimaksud dengan Kesepahaman Bersama/Memorandum of Understanding (MoU)', 'Merupakan pernyataan masing-masing pihak untuk bekerjasama dalam subyek tertentu dan dengan ruang lingkup tertentu.\n Dengan kata lain, MoU pada dasarnya merupakan perjanjian pendahuluan, yang mengatur dan\n memberikan kesempatan kepada para pihak untuk mengadakan studi kelayakan terlebih dahulu sebelum membuat perjanjian yang lebih terperinci dan mengikat para pihak.'),
(227, 175, 'P6.52', 'Apakah yang dimaksud dengan Kesepahaman Bersama/Memorandum of Understanding (MoU)', 'Perjanjian Kerjasama merupakan kesepakatan hukum antara dua pihak yang sama-sama merupakan subyek hukum yang memuat rincian ruang lingkup serta hak dan kewajiban yang harus dilaksanakan masing-masing pihak. Perjanjian Kerjasama membawa konsekwensi hukum.'),
(228, 175, 'P6.53', 'Hal-hal apa saja yang harus termuat dalam Perjanjian Kerjasama?', '1. Tujuan yang akan dicapai melalui perjanjian kerjasama\n 2. Ruang lingkup, yaitu batasan substansi perjanjian kerjasama yang disepakati oleh kedua belah pihak\n 3. Tugas dan tanggung jawab, yaitu berisi tugas dan tanggung jawab kedua belah pihak dalam pelaksanaan perjanjian kerjasama yang dilakukan\n 4. Pelaksanaan, mengatur tentang mekanisme pelaksanaan kerjasama secara teknis \n 5. Pembiayaan, yaitu penjelasan tentang sumber pembiayaan untuk pelaksanaan perjanjian kerjasama\n 6. Jangka waktu, yaitu lamanya waktu yang disepakati kedua belah pihak dalam pelaksanaan perjanjian kerjasama dan mekanisme perpanjangan serta pengakhiran perjanjian kerjasama\n 7. Monitoring dan evaluasi, berisi kesepakatan kedua belah pihak terkait jangka waktu dalam melakukan monitoring dan evaluasi sesuai kesepakatan \n 8. Penyelesaian perselisihan, mengatur mekanisme penyelesaian perselisihan bilamana dalam pelaksanaan perjanjian kerjasama terjadi perselisihan antar pihak\n 9. Penutup, menjelaskan bahwa perjanjian kerjasama\n ditandatangani dan dibuat rangkap 2 (dua) serta apabila terdapat perubahan atau tambahan atas ketentuan-ketentuan serta pengaturan atas hal-hal yang belum cukup diatur dalam perjanjian kerjasama hanya dapat dilakukan dengan suatu addendum yang disepakati oleh kedua belah pihak serta hal-hal lain yang perlu ditambahkan'),
(229, 175, 'P6.54', 'Dengan pihak mana saja Kemendukbangga/BKKBN dapat bekerjasama?s', 'Kemendukbangga dapat melakukan kerjasama dengan pihak manapun yang merupakan subyek hukum dan memiliki kepedulian terhadap program kependudukan dan pembangunan keluarga.'),
(230, 175, 'P6.55', 'Apakah yang dimaksud dengan Kerjasama Pentahelix?', 'Kerjasama Pentahelix adalah konsep kerjasama atau kolaborasi yang melibatkan lima unsur kunci yaitu Pemerintah, Perguruan Tinggi/Akademisi, dunia usaha, lomunitas/lembaga kemasyarakatan, dan Media. Kelima unsur ini memiliki peran dan keunggulannya masing-masing yang dapat disinergikan.'),
(231, 175, 'P6.56', 'Apa peran masing-masing unsur Pentahelix dalam keberhasilan program kependudukan dan pembangunan keluarga?', '1. Pemerintah berperan berperan sebagai fasilitator, regulator, dan koordinator dengan menyediakan infrastruktur dan layanan publik yang memadai, mendorong terciptanya regulasi yang kondusif, dan mengkoordinasikan kegiatan para pemangku kepentingan.\n 2. Perguruan Tinggi/Akademisi berperan sebagai konseptor dan sumber pengetahuan, melakukan penelitian, identifikasi permasalahan, potensi, dan peluang pengembangan. \n 3. Dunia Usaha berperan membantu pencapaian tujuan melalui proses bisnis yang menghasilkan nilai tambah dan pertumbuhan berkelanjutan.\n 4. Komunitas mendukung dengan mempromosikan produk dan layanan masyarakat, serta bertindak sebagai penghubung antar pemangku kepentingan.\n 5. Media berperan menginspirasi perubahan perilaku masyarakat dengan membangun membangun brand image, serta mendukung publikasi dan promosi produk dan layanan masyarakat.'),
(232, 175, 'P6.57', 'Apa yang dimaksud dengan Advokasi?', 'Advokasi adalah proses mempengaruhi keputusan dan kebijakan publik untuk mencapai tujuan tertentu.'),
(233, 175, 'P6.58', 'Apakah tujuan advokasi dalam konteks program kependudukan dan pembangunan keluarga?', 'Tujuan advokasi yang dilaksanakan oleh Kemendukbangga/BKKBN adalah :\n 1. Mengubah kebijakan dan peraturan \n 2. Meningkatkan kesadaran masyarakat\n 3. Meningkatkan akses terhadap layanan\n 4. Melindungi hak-hak dan masyarakata'),
(234, 175, 'P6.59', 'Kemendukbangga melaksanakan advokasi melalui cara apa saja?', 'Advokasi program kependudukan dan pembagunan keluaraga dilaksanakan melalui :\n 1. Kampanye media\n 2. Lobi kepada instansi pusat maupun pemerintah daerah provinsi dan kabupaten/kita\n 3. Kerjasama dengan stakeholder\n 4. Pendidikan dan pelatihan\n 5. Kegiatan besama komunitas'),
(235, 175, 'P6.60', 'Apa itu KIE?', 'KIE adalah singkatan dari Komunikasi, Informasi, dan Edukasi'),
(236, 175, 'P6.61', 'Apa tujuan KIE?', 'Tujuan KIE adalah untuk menyampaikan pesan atau pengetahuan kepada masyarakat agar mereka Menerima informasi dengan benar'),
(237, 175, 'P6.62', 'Apa saja bentuk KIE?', 'Bentuk KIE bisa berupa poster, brosur, leaflet, video pendek, taklshow, media sosial, website'),
(238, 175, 'P6.63', 'Apa yg dimaksud KIE Lini Bawah?', 'KIE lini bawah adalah bentuk Komunikasi, Informasi, dan Edukasi yang dilakukan secara langsung kepada masyarakat di tingkat akar rumput (grassroot)'),
(239, 175, 'P6.64', 'Apa yg dimaksud KIE Lini Tengah?', 'KIE lini tengah adalah kegiatan Komunikasi, Informasi, dan Edukasi yang menyasar tokoh-tokoh kunci di tingkat menengah'),
(240, 175, 'P6.65', 'Apa yg dimaksud KIE Lini Atas?', 'KIE lini atas adalah Komunikasi, Informasi, dan Edukasi yang dilakukan di tingkat pembuat kebijakan atau pimpinan institusi'),
(241, 175, 'P6.66', 'Siapa sasaran KIE lini bawah?', 'Sasaran KIE (Komunikasi, Informasi, dan Edukasi) lini bawah adalah masyarakat umum di tingkat akar rumput atau grassroots'),
(242, 175, 'P6.67', 'Siapa sararan KIE lini tengah?', 'Kelompok yang berpengaruh langsung terhadap masyarakat umum'),
(243, 175, 'P6.68', 'Siapa sasaran KIE lini atas?', 'Para pengambil keputusan atau pihak yang membuat kebijakan'),
(244, 175, 'P6.69', 'Apa yang dimaksud dengan media digital/ online?', 'Semua media komunikasi yang menggunakan internet atau platform digital untuk menyampaikan pesan. Jadi, bukan lewat kertas atau radio biasa, tapi lewat gadget (HP, laptop, tablet) dan jaringan internet.'),
(245, 175, 'P6.70', 'Apa yang dimaksud media cetak?', 'Semua alat komunikasi yang dibuat dengan dicetak di atas bahan fisik, biasanya kertas. Jadi pesan disampaikan lewat tulisan, gambar, atau ilustrasi yang bisa dibaca atau dilihat langsung tanpa butuh listrik atau internet.'),
(246, 175, 'P6.71', 'Apa yang dimaksud media elektroik?', 'Media komunikasi yang menggunakan alat elektronik atau listrik untuk menyampaikan pesan ke sasaran. Jadi butuh alat seperti TV, radio, atau perangkat audio-visual lainnya untuk menerima pesannya.'),
(247, 175, 'P6.72', 'Apa yang dimaksud dengan iklan layanan masyarakat?', 'Iklan Layanan Masyarakat (ILM) adalah iklan yang dibuat untuk memberikan informasi, mengedukasi, atau mengajak masyarakat melakukan sesuatu yang bermanfaat untuk umum — bukan untuk jualan produk.'),
(248, 175, 'P6.73', 'Apa tujuan iklan layanan Masyarakat?', 'Tujuan iklan layanan masyarakat adalah untuk memberikan informasi, mengedukasi, dan mengajak masyarakat berperilaku positif demi kebaikan bersama.'),
(249, 175, 'P6.74', 'Apa saja yang termasuk media cetak?', 'Media cetak meliputi koran, majalah, buku, brosur, leaflet, poster, dan spanduk.'),
(250, 175, 'P6.75', 'Apa saja yang termasuk media elektronik?', 'Media elektronik mencakup radio, televisi, film, video, podcast, dan alat presentasi digital seperti proyektor.'),
(251, 175, 'P6.76', 'Apa yang dimaksud dengan media social?', 'Media sosial adalah platform online yang memungkinkan pengguna untuk berinteraksi, berbagi konten, dan membentuk jaringan sosial melalui teks, gambar, video, dan berbagai format lainnya.'),
(252, 175, 'P6.77', 'Apa contoh media social?', 'Media sosial adalah platform online yang memungkinkan pengguna untuk berinteraksi, berbagi konten, dan membentuk jaringan sosial melalui teks, gambar, video, dan berbagai format lainnya. Contohnya seperti Facebook, Instagram, Twitter, TikTok, dan LinkedIn.'),
(253, 175, 'P6.78', 'Apa bentuk KIE pada media cetak?', 'Bentuk KIE pada media cetak meliputi poster, brosur, leaflet, spanduk, dan buku panduan untuk menyampaikan informasi secara visual.'),
(254, 175, 'P6.79', 'Apa yang dimaksud dengan poster?', 'Poster: Materi visual besar yang dipasang di tempat umum untuk menyampaikan pesan singkat dan menarik perhatian.'),
(255, 175, 'P6.80', 'Apa yang dimaksud dengan flyer?', 'Flyer adalah Selebaran kecil yang berisi informasi singkat, biasanya dibagikan langsung kepada orang untuk promosi atau acara.'),
(256, 175, 'P6.81', 'Apa yang dimaksud dengan leaflet?', 'Leaflet adalah Lembar informasi yang biasanya dilipat, memberikan detail lebih lengkap dari flyer, dan sering digunakan untuk edukasi atau promosi.'),
(257, 175, 'P6.82', 'Apa yang dimaksud dengan spanduk?', 'Spanduk adalah kain panjang yang dipasang di tempat umum, berisi pesan atau informasi yang jelas dan mudah dibaca, sering digunakan untuk promosi, kampanye, atau acara tertentu.'),
(258, 175, 'P6.83', 'Apa yang dimaksud dengan audio visual?', 'Audio visual adalah media yang menggabungkan elemen suara (audio) dan gambar bergerak (visual) untuk menyampaikan informasi atau pesan, seperti dalam film, video, presentasi multimedia, atau iklan TV.'),
(259, 175, 'P6.84', 'Apa yang dimaksud dengan penyuluhan?', 'Penyuluhan adalah Kegiatan untuk memberikan informasi edukatif kepada masyarakat agar mereka memahami dan mengubah perilaku atau pengetahuan terkait suatu isu.'),
(260, 175, 'P6.85', 'Apa yang dimaksud dengan podcast?', 'Podcast adalah Rekaman audio digital yang bisa didengarkan secara online, sering berisi diskusi atau informasi edukatif dalam format episodik.'),
(261, 175, 'P6.86', 'Apa yang dimaksud dengan talkshow?', 'Talkshow adalah Acara percakapan di media (TV, radio, atau online) yang melibatkan pembicara atau tamu untuk berdiskusi tentang topik tertentu, seringkali dengan tujuan edukasi atau hiburan.'),
(262, 175, 'P6.87', 'Apa yang dimaksud dengan iklan?', 'Iklan adalah pesan yang disampaikan melalui berbagai media untuk mempromosikan produk, layanan, atau ide, dengan tujuan mempengaruhi audiens agar mengambil tindakan tertentu, seperti membeli atau menggunakan sesuatu.'),
(263, 175, 'P6.88', 'Apa saja yang termasuk iklan di radio?', 'Iklan di radio mencakup spot iklan, pesan layanan masyarakat, iklan produk, dan sponsor acara yang disampaikan melalui siaran audio.'),
(264, 175, 'P6.89', 'Apa saja yang termasuk iklan di Televisi/ TV?', 'Iklan di TV mencakup spot iklan komersial, iklan layanan masyarakat, program sponsor, dan iklan produk atau layanan yang ditayangkan selama program siaran.'),
(265, 175, 'P6.90', 'Bagaimana menjaga kesehatan mental dalam rumah tangga?', 'Kesehatan mental yang baik dalam rumah tangga dapat dijaga dengan komunikasi terbuka, mengelola emosi dengan baik, serta menghargai perbedaan pasangan. Lingkungan yang mendukung juga berperan penting. Jika mengalami tekanan atau konflik berkepanjangan, jangan ragu untuk mencari bantuan dari konselor atau psikolog.'),
(266, 175, 'P6.91', 'Sudah pacaran lama tetapi sampai sekarang tidak ada kejelasan mengenai jenjang pernikahan, apa yang perlu dilakukan?', 'Jika hubungan sudah berjalan lama tetapi belum ada kepastian, komunikasikan dengan pasangan mengenai rencana pernikahan. Perhatikan apakah pasangan memang serius tetapi masih menunggu waktu yang tepat atau justru menghindari komitmen. Jika tidak ada kejelasan setelah diskusi, pertimbangkan apakah hubungan ini masih sesuai dengan tujuan hidup Anda.'),
(267, 175, 'P6.92', 'Tinggal bersama mertua membuat adanya beberapa gesekan konflik, sedangkan belum memiliki rumah untuk tinggal sendiri. Bagaimana cara mengelola ketidaknyamanan ini?', 'Komunikasi adalah Kunci\n\nYang paling penting adalah tetap menjaga komunikasi yang baik dengan suami maupun dengan mertua. Saling percaya, sikap terbuka dan saling memahami satu sama lain antar suami istri bisa menjadi kunci keberhasilan suatu hubungan. Berkomunikasi dengan menggunakan bahasa yang baik, tutur kata yang sopan, nada yang lemah lembut dan pada situasi yang tepat bisa menjadi salah satu faktor yang membuat suatu hubungan menjadi lebih baik dan harmonis.\n\nKomunikasi adalah kunci dari setiap masalah. Lakukan komunikasi dengan baik dan tepat. Tepat disini diartikan bisa pada moment yang tepat misalnya saat suami dalam keadaan santai rileks. Mulailah dengan cerita cerita mimpi-mimpi membangun rumah tangga bersama pasangan. Perhatikan juga pendapat dari pasangan, artinya meskipun niatnya untuk mandiri namun harus tetap mendengarkan pendapat dari perspektif suami. Win win solution adalah tujuannya.\n\nBegitu pula jika pada akhirnya ingin mandiri dan pisah tinggal dengan mertua. Coba cari waktu yang tepat dimana suasana hati suami dalam kondisi senang dan nyaman. Sampaikan alasan alasan kenapa ingin mandiri dan terpisah dengan Orang Tua.\n\nHindari alasan yang menjelek-jelekkan atau menceritakan hal-hal buruk yang terjadi selama tinggal bersama mertua. Karena bagaimanapun, suami sebagai anak mertua tetap memiliki ego dan tidak ingin Orang Tuanya dijelek-jelekkan.\n\nFokuslah pada tujuan dan mimpi keluarga yang ingin dibangun ketika mandiri. Selain itu bisa dicarikan pilihan alternatif bagaimana bisa tetap berbakti pada mertua meskipun tidak tinggal bersama mertua lagi.'),
(268, 175, 'P6.93', 'Dalam program Bangga Kencana, apa fokus utama BKKBN?', 'Fokus pada peningkatan kualitas keluarga melalui pengendalian kelahiran, pembangunan keluarga, dan kependudukan.'),
(269, 175, 'P6.94', 'Apa itu SIGA?', 'Sistem Informasi Keluarga yang selanjutnya disebut\nSIGA adalah seperangkat tatanan yang meliputi Data,\ninformasi, indikator, prosedur, perangkat, teknologi\ndan sumber daya manusia yang saling berkaitan dan\ndikelola secara terpadu untuk mengarahkan tindakan\natau keputusan yang berguna dalam mendukung\npembangunan Keluarga'),
(270, 175, 'P6.95', 'Apa itu Verval KRS?', 'Pemutakhiran, Verifikasi dan Validasi Data Keluarga Berisiko Stunting dapat diartikan sebagai proses pelaksanaan kegiatan membandingkan data keluarga berisiko stunting yang bersumber dari hasil Pendataan Keluarga dan pemutakhirannya dengan kondisi terkini di lapangan agar data yang digunakan sebagai peta kerja pendampingan keluarga adalah data yang terakhir dan terbaru'),
(271, 175, 'P6.96', 'Apa itu Keluarga Beresiko Stunting?', 'Keluarga sasaran yang memiliki faktor risiko untuk melahirkan anak stunting'),
(272, 175, 'P6.97', 'Siapa keluarga sasaran Verval KRS?', 'Keluarga sasaran Verval Risiko adalah :\n1. Pasangan Usia Subur\n2. Ibu Hamil\n3. Keluarga dengan anak usia 0-23 bulan\n4. Keluarga dengan anak usia 24-59 bulan'),
(273, 175, 'P6.98', 'Apa alamat website SIGA?', 'https://siga.bkkbn.go.id/'),
(274, 175, 'P6.99', 'Apa saja jenis user SIGA', 'Administrator, Operator, Supervisor'),
(275, 175, 'P6.100', 'Apa saja tahapan Verval KRS?', '1. Persiapan \n    a. Penyusunan Panduan\n    b. Penyiapan Cetak Output\n    c. Cetak Output\n    d. Sosialisasi/Orientasi\n2. Pengorganisasian Lapangan\n3. Pekaksanaan \n    a. Identifikasi Sasaran\n    b. Pengumpulan Data\n    c. Pengolahan Data'),
(276, 175, 'P6.101', 'Siapa saja SDM Pelaksana Verval KRS?', 'A. Tingkat Pusat\n    1. BKKBN\n    2. Mitra kerja terkait :\n        - Pemerintah\n        - Non Pemerintah\nB. Tingkat Provinsi\n     1. Perwakilan BKKBN Provinsi\n     2. Mitra kerja terkait :\n         - Pemerintah\n         - Non Pemerintah\nC. Tingkat Kabupaten/Kota :\n     1. Perangkat Daerah/PD KB\n     2. Mitra Kerja terkait :\n         - Pemerintah\n         - Non Pemerintah\nD. Tingkat Lini Lapangan :\n     1. Kepala UPT KB/Koordinator PKB\n     2. PKB/PLKB\n     3. Tim Pendamping Keluarga/Kader KB Lainnya\n     4. Mitra Kerja Terkait'),
(277, 175, 'P6.102', 'Siapa saja SDM Verval KRS di lini lapangan?', '1. Verifikator Kecamatan\n2. Pengolah Data\n3. Pengumpul Data'),
(278, 175, 'P6.103', 'Siapakah Verifikator Kecamatan?', 'Verifikator Kecamatan adalah seseorang yang bertugas untuk memastikan proses manajemen data pelaksanaan pemutakhiran, verifikasi dan validasi keluarga beresiko stunting (pengumpulan, pemeriksaan, pengolahan dan pemberian umpan balik) di kecamatan yang menjadi tanggung jawabnya. Verifikator Kecamatan ditunjuk dan ditetapkan oleh PD KB Kabupaten/Kota melalui Surat Keputusan yang dapat berasal dari unsur :\n1. Kepala UPT KB/Koordinator KB\n2. Penyuluh KB\n3. Petugas Lapangan KB PNS/Non PNS\n4. Petugas Kecamatan/mitra yang terlatih'),
(279, 175, 'P6.104', 'Apa tugas pokok Verifikator Kecamatan?', 'Tugas Pokok Verfikator Kecamatan adalah sebagai berikut :\n 1) Mengoordinasikan perencanaan pelaksanaan Verifikasi dan Validasi KRS kepada camat\n 2) Melakukan pengorganisasian lapangan Verifikasi dan Validasi KRS\n 3) Melakukan pengelolaan administrasi serta distribusi sarana dan prasarana\n 4) Melakukan pembinaan, pemantauan, evaluasi dan pengawasan pelaksanaan Verifikasi dan Validasi KRS\n 5) Membentuk tim pengolah data yang ditetapkan melalui Surat Keputusan PD KB Kabupaten dan Kota dengan mempertimbangkan jumlah pengolah data dengan jumlah data yang diolah serta jangka waktu pelaksanaan Verifikasi dan Validasi Keluarga Berisiko Stunting yang ditetapkan\n 6) Melakukan persetujuan/ approval terhadap data yang akan dikirim ke server setelah dilakukan pemeriksaan data berdasarkan laporan hasil pelaksanaan pengolahan data oleh Pengolah Data.'),
(280, 175, 'P6.105', 'Siapakah Pengolah Data?', 'Pengolah Data adalah seseorang yang menjalankan fungsi pengolahan data dalam pelaksanaan Verifikasi dan Validasi Keluarga Beresiko Stunting serta memastikan data yang terkumpul di tingkat desa/kelurahan telah benar dan lengkap. Pengolah Data ditunjuk oleh Verifikator Kecamatan dan ditetapkan dengan SK PD KB Kabupaten/Kota yang dapat berasal dari unsur :\n1. Pejabat Fungsional Penyuluh KB\n2. Petugas Lapangan KB PNS/Non PNS\n3. Mitra Kerja terkait Lainnya'),
(281, 175, 'P6.106', 'Apa tugas pokok Pengolah Data', 'Tugas Pokok Pengolah Data adalah sebagai berikut :\n 1) Registrasi Ketua tim pengumpul data, Ketua tim pengolah data dan Verifikator sesuai SK Pengorganisasian Verifikasi dan Validasi Keluarga Berisiko Stunting Tahun 2023\n 2) Memvalidasi formulir terisi hasil pendataan oleh Pengumpul data\n 3) Mengoordinir proses penginputan data yang dilakukan oleh pengumpul data\n 4) Melakukan input data bagi wilayah yang menggunakan formulir\n 5) Memasukkan rekapitulasi hasil Verval KRS per Desa ke aplikasi\n 6) Melakukan pelaporan perkembangan pelaksanaan verifikasi dan validasi keluarga berisiko stunting di desa/kelurahan sesuai kecamatan yang menjadi wilayahnya kepada verifikator kecamatan'),
(282, 175, 'P6.107', 'Siapakah Pengumpul Data?', 'Pengumpul Data adalah orang atau kumpulan orang yang sukarela berperan aktif melaksanakan/\n mengelola Program Bangga Kencana dalam hal ini pelaksanaan Verifikasi dan Validasi Keluarga \nBerisiko Stunting tahun 2023 dan telah ditetapkan dengan SK PD KB Kabupaten dan Kota. \nPengumpul Data berada di tingkat desa, dengan kriteria :\n a. Diutamakan Tim Pendamping Keluarga (TPK), kader pendata Pendataan Keluarga, kader KB\n lainnya;\n b. Mengenal dan dikenal masyarakat;\n c. Mampu berkomunikasi dengan baik;\n d. Menguasai wilayah kerja;\n e. Memahami tata cara pencatatan verifikasi dan validasi keluarga berisiko stunting;'),
(283, 175, 'P6.108', 'Jenis formulir apa saja yang ada di SIGA?', '1. K/0/KB/20, yaitu Kartu Pendaftaran Tempat Pelayan KB\n2. R/I/KB/20 yaitu Formulir Register Pelayanan KB\n3. R/II/KB/20, yaitu Formulir Register Alat dan Obat Kontrasepsi'),
(284, 175, 'P6.109', 'Apa yang dimaksud dengan Pemutakhiran PK?', 'Pemutakhiran Pendataan Keluarga adalah kegiatan untuk memutakhirkan data keluarga Indonesia dengan cara melengkapi, memperbaiki, memperbaharui, mencatat mutasi, mencatat migrasi dan mendata keluarga baru yang belum ada dalam Basis Data Keluarga Indonesia hasil PK21, Pemutakhiran PK-22 dan pemutakhiran PK-23.'),
(285, 175, 'P6.110', 'Apa tujuan umum dari Pemutakhiran PK?', '1. Tersedianya acuan bagi pengelola data Bangga Kencana di seluruh tingkatan wilayah dalam penyelenggaraan pemutakhiran pendataan keluarga sehingga tersedia basis data keluarga Indonesia yang valid dan akurat. \n 2. Tersedianya acuan bagi pengelola data bangga kencana di wilayah sample terpilih ECDI dalam penyelenggaran pengumpulan data anak usia dini pada umur 24-59 bulan.'),
(286, 175, 'P6.111', 'Apa tujuan khusus dari Pemutakhiran PK?', 'Tersedianya panduan langkah-langkah penyelenggaraan pemutakhiran pendataan keluarga dan ECDI yang meliputi persiapan, pelaksanaan, penyebarluasan data dan informasi, pemantauan dan evaluasi hasil pemutakhiran pendataan keluarga di setiap tingkatan wilayah.'),
(287, 175, 'P6.112', 'Apa saja manfaat dari Pemutakhiran PK-24?', 'Secara garis besar, data hasil Pemutakhiran Pendataan Keluarga bermanfaat \n untuk:\n Peta Sasaran\n 1. Penentuan sasaran yang lebih tajam berdasarkan kondisi, potensi dan kebutuhan aktual dari masing-masing keluarga yang ada di setiap tingkatan wilayah\n 2. Pemutakhiran peta keluarga berdasarkan indikator strategis\n 3. Pemetaan sampel keluarga \n 4. Tersedianya data prelist Penyandang Disabilitas secara BNBA\n 5. Tersedianya data anak usia 24-59 bulan untuk pengukuran indeks perkembangan anak usia dini\n \n Program Dukungan dan Sarana Motivasi\n 1. Penentuan program dukungan yang sesuai untuk setiap keluarga dan setiap wilayah tertentu.\n 2. Peningkatan kualitas kesertaan ber-KB untuk penggunaan metode kontrasepsi yang lebih efektif, aman, dan nyaman. \n 3. Data pensasaran upaya percepatan penghapusan kemiskinan ekstrem dan stunting\n 4. Sarana motivasi untuk mendorong setiap keluarga mengikuti kelompok kegiatan bagi keluarga yang memiliki sasaran pembinaan\n 5. Sarana motivasi untuk mendorong setiap keluarga mengikuti kelompok kegiatan bagi keluarga yang memiliki sasaran pembinaan.\n \n Program Pembangunan terkait lainnya\n Pemanfaatan hasil Pemutakhiran Pendataan Keluarga tahun 2024 untuk kepentingan pembangunan keluarga melalui keterlibatan sektor lain.'),
(288, 175, 'P6.113', 'Siapa sasaran Pemutakhiran PK-24?', '- Sasaran keluarga yang didata adalah seluruh keluarga pada wilayah Pemutakhiran PK-24 dengan memprioritaskan keluarga baru, keluarga memiliki Pasangan Usia Subur (PUS), keluarga memiliki balita umur 0-59 bulan serta ibu hamil. \n- Khusus 1.500 desa/kelurahan terpilih sebagai sampel pengukuran indikator ECDI, WAJIB melaksanakan Pra Pelaksanaan Pemutakhiran PK-24.'),
(289, 175, 'P6.114', 'Apa saja Variabel dan Indikator Pemutakhiran PK-24?', 'a. Penambahan variabel identifikasi disabilitas pada anggota keluarga. \nb. Pengukuran indikator ECDI (Early Chilhood Development Index) pada 15.000 KK memiliki anak usia 2-4 tahun yang terpilih sebagai sampel.'),
(290, 175, 'P6.115', 'Apa yang dimaksud dengan desa/kelurahan sampel pada Lokus dan Sasaran Pemutakhiran PK-24?', 'Desa/kelurahan sampel merupakan desa/kelurahan yang terpilih sebagai sampel berdasarkan kerangka sampel dan target keluarga terdata yang sudah ditentukan. Pemutakhiran PK-24 pada wilayah sampel ditujukan agar hasil Pemutakhiran PK-24 dapat menggambarkan populasi sehingga Pemutakhiran PK-24 dapat menyediakan data untuk perhitungan indikator kinerja Program Bangga Kencana.'),
(291, 175, 'P6.116', 'Apa yang dimaksud dengan Target KK pada desa/kelurahan sampel pada Lokus dan Sasaran Pemutakhiran PK-24?', 'Target KK pada desa/kelurahan sampel adalah seluruh keluarga yang ada pada desa/kelurahan sampel baik yang sudah terdata pada Pemutakhiran PK-22 maupun keluarga baru dan keluarga yang tidak terdata pada Pemutakhiran PK-23.'),
(292, 175, 'P6.117', 'Apa yang dimaksud dengan desa/kelurahan prioritas pada Lokus dan Sasaran Pemutakhiran PK-24?', 'Desa/kelurahan prioritas merupakan desa/kelurahan yang terpilih sesuai arah kebijakan pelaksanaan Pemutakhiran PK-24 yaitu peningkatan cakupan dan perbaikan kualitas data basis keluarga, sehingga dipilih berdasarkan kriteria tertentu.'),
(293, 175, 'P6.118', 'Apa saja Sarana Pengumpulan Data Pemutakhiran PK-24?', '1. Formulir\n Pengumpulan data keluarga dan anggota keluarga pada desa/kelurahan yang ditentukan menggunakan formulir Pemutakhiran Pendataan Keluarga tahun 2024 (F/I/Pemutakhiran PK/24) yang terdiri dari: \n - Formulir dengan data untuk memutakhirkan data keluarga yang sudah ada pada Basis Data \n - Formulir kosong untuk mendata keluarga baru \n - Formulir survey ECDI dengan data yang sudah ada pada Pemutakhiran PK-24 dengan sasaran anak usia 24-59 bulan \n \n 2. Smartphone\n- Aplikasi Pemutakhiran PK-24\n Merupakan sarana untuk pengumpulan, penginputan dan perekaman data keluarga dan anggota keluarga pada desa/kelurahan yang ditentukan menggunakan aplikasi berbasis android. Penggumpulan data menggunakan android sebesar 80% disetiap provinsi dari seluruh sasaran (kecuali Provinsi Papua, Papua Barat, Maluku, Maluku Utara dan NTT).\n\n- Aplikasi Pemutakhiran PK24 - ECDI\nMerupakan sarana untuk mengumpulkan, menginput dan perekaman data keluarga dan anggota keluarga pada desa/kelurahan yang sudah ditentukan menggunakan aplikasi berbasis android pada desa terpilih sampel ECDI yang sudah dilengkapi validasi (pengaturan otomatis).'),
(294, 175, 'P6.119', 'Bagaimana pengolahan data Pemutakhiran PK-24?', 'Pengolahan data setelah dilakukan pengumpulan data oleh kader disesuaikan dengan sarana/tools pengumpulan data yaitu: \n- Pengolahan data dengan smartphone langsung oleh kader \npendata\n- Pengolahan data pada wilayah yang menggunakan metode pengumpulan dengan formulir (paper based) penginputan data dapat dilakukan di tingkat kabupaten/kota jika sarana dan prasarana pengolahan data di kecamatan tidak memadai yang dibuktikan dengan surat pernyataan dari Manajer Pengelolaan Pemutakhiran PK-24 tingkat kecamatan; atau di tingkat provinsi jika di kabupaten/kota tidak terdapat sarana dan prasarana pengolahan data yang memadai yang dibuktikan dengan surat pernyataan dari Kepala PD KB Kabupaten/kota.'),
(295, 175, 'P6.120', 'Apa saja strategi yang digunakan dalam pelaksanaan Pemutakhiran PK-24?', '1. Memanfaatkan teknologi informasi dalam pengelolaan dan Pemutakhiran PK-24;\n 2. Mendayagunakan sumber daya yang ada di lini lapangan dengan mengutamakan SDM lini lapangan yang berpartisipasi pada PK21 maupun Pemutakhiran PK-22 dan Pemutakhiran PK-23;\n 3. Mendayagunakan sumber daya yang ada di lini lapangan dengan mengutamakan SDM lini lapangan yang berpartisipasi pada PK21 maupun Pemutakhiran PK-22 dan Pemutakhiran PK-23;\n 4. Melakukan pengendalian pembayaran terhadap honor SDM lini lapangan pelaksanaan Pemutakhiran PK-24 dengan memperhatikan prinsip akuntabel dan transparan; \n 5. Melakukan pertemuan koordinasi intensif Tim Posko Pemutakhiran PK-24 dalam memantau dan mengevaluasi perkembangan persiapan pelaksanaan, cakupan dan kualitas keluarga terdata; \n 6. Pemanfaatan anggaran sesuai dengan ketentuan peraturan yang berlaku;\n 7. Pengorganisasian lapangan, pengumpulan dan pengolahan data ECDI pada Pemutakhiran PK-24 secara detil ada di dalam Panduan Pemutakhiran PK-24 ECDI yang tidak terpisahkan dari kebijakan dan strategi Pemutakhiran PK-24.'),
(296, 175, 'P6.121', 'Siapa saja sumber daya manusia yang terlibat dalam pelaksanaan Pemutakhiran PK-24 di tingkat pusat?', 'Tingkat Pusat : \n1) BKKBN \n2) Mitra Kerja Terkait : \n- Pemerintah \n- Non Pemerintah'),
(297, 175, 'P6.122', 'Siapa saja sumber daya manusia yang terlibat dalam pelaksanaan Pemutakhiran PK-24 di tingkat provinsi?', 'Tingkat Provinsi : \n1) Perwakilan BKKBN Provinsi \n2) Mitra Kerja Terkait : \n- Pemerintah \n- Non Pemerintah'),
(298, 175, 'P6.123', 'Siapa saja sumber daya manusia yang terlibat dalam pelaksanaan Pemutakhiran PK-24 di tingkat kabupaten/kota?', 'Tingkat Kabupaten dan Kota : \n1) Perangkat Daerah/PD KB Kabupaten dan Kota \n2) Mitra Kerja Terkait : \n- Pemerintah \n- Non Pemerintah'),
(299, 175, 'P6.124', 'Siapa saja sumber daya manusia yang terlibat dalam pelaksanaan Pemutakhiran PK-24 di tingkat lini lapangan?', 'Tingkat Lini Lapangan: \n1) Kepala UPT KB/Koordinator KB \n2) PKB/PLKB \n3) PPKBD \n4) Sub PPKBD \n5) Kader Pelaksana Pemutakhiran PK-24 \n6) Mitra Kerja Terkait'),
(300, 175, 'P6.125', 'Apa yang dimaksud dengan Pelaksana Pengumpulan Data/Pewawancara?', 'Kegiatan pelaksanaan pengumpulan data atau yang melakukan wawancara terhadap keluarga yang didata dilakukan oleh para kader masyarakat, yang terdiri dari kader KB, kader Posyandu, kader Dasa Wisma/PKK, karang Taruna, Saka Kencana/Pramuka dan atau tokoh-tokoh masyarakat setempat.'),
(301, 175, 'P6.126', 'Apa yang dimaksud dengan Pembina Pengumpulan Data?', 'Kegiatan pembinaan pengumpulan data dilakukan oleh Penyuluh KB/PLKB atau petugas yang ditunjuk oleh pejabat yang berwenang. Di tingkat desa/kelurahan pengumpulan data dibina oleh Supervisor. Di tingkat kecamatan pengumpulan data dibina oleh Manajer Pengelolaan dan Manajer Data.'),
(302, 175, 'P6.127', 'Apa yang dimaksud dengan Penanggungjawab Wilayah?', 'Penanggungjawab kegiatan pendataan keluarga di tingkat \ndesa/kelurahan ke bawah adalah Ketua RT, Kepala Dusun/RW, Kepala Desa/Kelurahan, dan Camat.'),
(303, 175, 'P6.128', 'Apa yang dimaksud dengan Pengawas Pengumpulan Data?', 'Kegiatan pengawasan pengumpul data dilakukan oleh Manajer Pengelolaan, PKB/PLKB atau petugas yang ditunjuk oleh pejabat yang berwenang.'),
(304, 175, 'P6.129', 'Apa yang dimaksud dengan Manajer Pengelolaan?', 'Manajer Pengelolaan adalah seseorang yang melakukan fungsi koordinasi, pengelolaan, \npengorganisasian, pembinaan pengawasan dan pelaksanaan pemutakhiran pendataan keluarga di kecamatan yang menjadi tanggung jawabnya. Kriteria seseorang yang dapat ditunjuk menjadi Manajer Pengelolaan adalah menguasai kemampuan manajerial dan kepemimpinan.'),
(305, 175, 'P6.130', 'Apa saja tugas Manajer Pengelolaan?', 'Tugas pokok manajer pengelolaan adalah sebagai berikut:\n- Mengoordinasikan perencanaan pelaksanaan Pemutakhiran PK-24 kepada pejabat daerah setempat (Camat); \n- Melakukan pengorganisasian lapangan Pemutakhiran PK-24; \n- Melakukan pengelolaan administrasi serta distribusi sarana dan prasarana; \n- Melakukan pembinaan, pemantauan, evaluasi dan pengawasan pelaksanaan Pemutakhiran PK-24; \n- Melakukan persetujuan/approval terhadap data yang akan dikirim ke server setelah dilakukan pemeriksaan data berdasarkan laporan hasil pelaksanaan pengolahan data oleh manajer data.'),
(306, 175, 'P6.131', 'Apa kriteria seseorang yang dapat ditunjuk menjadi Manajer Pengelolaan?', 'Manajer Pengelolaan ditunjuk, ditugaskan dan ditetapkan oleh PD KB Kabupaten dan Kota melalui Surat Keputusan. Manajer Pengelolaan dapat \nberasal dari unsur:  \na. Kepala UPT KB/Koordinator KB; \nb. Penyuluh KB;  \nc. Petugas Lapangan KB PNS/ Non PNS; \nd. Petugas Kecamatan/mitra yang terlatih.'),
(307, 175, 'P6.132', 'Apa yang dimaksud dengan Manajer Data?', 'Manajer Data seseorang yang bertugas untuk memastikan proses manajemen data pelaksanaan pemutakhiran pendataan keluarga (pengumpulan, pemeriksaan, \npengolahan dan pemberian umpan balik) di kecamatan yang menjadi tanggung jawabnya.  Manajer Data ditunjuk oleh Manajer Pengelolaan kemudian ditetapkan oleh PD KB Kabupaten/ Kota melalui Surat Keputusan'),
(308, 175, 'P6.133', 'Apa saja tugas Manajer Data?', 'Tugas pokok manajer data adalah sebagai berikut: \n- Melakukan registrasi dan perapihan databasis wilayah; \n- Melakukan registrasi supervisor dan kader pendata Pemutakhiran PK-24 yang ditugaskan sesuai SK Pengorganisasian Pemutakhiran PK-24; \n- Memasukkan target KK per RT dan jumlah target KK maksimal per kecamatan;\n- Memasukkan desa berdasarkan metode pendataan yang melekat pada \nuser supervisor;\n- Membentuk tim pengolah data yang ditetapkan melalui Surat Keputusan PD KB Kabupaten dan Kota dengan mempertimbangkan jumlah pengolah data dengan jumlah data yang diolah serta jangka waktu pelaksanaan Pemutakhiran PK-24 yang ditetapkan;\n- Mengkoordinir proses penginputan data yang dilakukan oleh tim pengolah data; \n- Melakukan monitoring data indikator strategis melalui aplikasi berbasis web portal Pemutakhiran PK-24; \n- Memberikan umpan balik kepada supervisor jika ditemukan ketidaksesuaian data untuk dilakukan perbaikan atau kunjungan ulang oleh kader pendata; \n- Melaporkan perkembangan pelaksanaan pengumpulan serta pengolahan data hasil Pemutakhiran PK-24 kepada Manajer Pengelolaan; \n- Memberikan informasi dan solusi terkkait permasalahan penggunaan smartphone dan aplikasi pengolahan data.'),
(309, 175, 'P6.134', 'Apa kriteria seseorang yang dapat ditunjuk menjadi Manajer Data?', 'Kriteria seseorang yang dapat ditunjuk menjadi Manajer Data adalah menguasai kemampuan manajerial, menguasai Teknologi Informasi (IT) dan \ndiutamakan menguasai dasar-dasar analisis.  Manajer Data dapat berasal \ndari unsur:\na. Kepala UPT KB/Koordinator KB; \nb. Penyuluh KB;  \nc. Petugas Lapangan KB PNS/ Non PNS; \nd. Petugas Kecamatan/mitra yang terlatih;\n\nManajer Data menunjuk dan mengkoordinir Tim Pengolah Data. Tim Pengolah data ditetapkan dengan SK PD KB Kabupaten dan Kota dengan kriteria menguasai Teknologi Informasi (IT) dan diutamakan menguasai dasar-dasar aplikasi office atau aplikasi sejenis.'),
(310, 175, 'P6.135', 'Apa yang dimaksud dengan Supervisor?', 'Supervisor adalah seseorang pengorganisasian, yang menjalankan fungsi pengelolaan, pembinaan dan pengawasan terhadap kader pendata pemutakhiran PK24 serta memastikan data yang terkumpul di tingkat desa/kelurahan telah benar dan lengkap.'),
(311, 175, 'P6.136', 'Apa saja tugas Supervisor?', 'Supervisor ditunjuk oleh Manajer Pengelolaan tingkat Kecamatan dan ditetapkan dengan SK PD KB Kabupaten dan Kota yang dapat berasal dari unsur: \na. Pejabat Fungsional Penyuluh KB; \nb. Petugas Lapangan KB PNS/NON PNS; \nc. Pembantu Pembina KB Desa/Kelurahan (PPKBD); \nd. Petugas Desa/Kelurahan yang terlatih; atau \ne. Mitra Kerja terkait lainnya.'),
(312, 175, 'P6.137', 'Apa kriteria seseorang yang dapat ditunjuk menjadi Supervisor?', 'Tugas pokok supervisor adalah sebagai berikut: \n- Melakukan pengorganisasian dan pengelolaan pelaksanaan Pemutakhiran PK-24 di desa/kelurahan \n- Memverifikasi dan memvalidasi formulir terisi hasil Pemutakhiran PK-24 oleh kader; \n- Melakukan receiving (penerimaan) dan batching (pengelompokan formulir berdasarkan satuan wilayah terkecil); \n- Melakukan pelaporan perkembangan pelaksanaan Pemutakhiran PK-24 di desa/kelurahan yang menjadi wilayahnya kepada manajer pengelolaan dan manajer data tingkat kecamatan; \n- Bagi desa/kelurahan formulir, menginput rekap RT ke dalam Portal Pemutakhiran PK-24.'),
(313, 175, 'P6.138', 'Apa yang dimaksud dengan Kader Pendata?', 'Kader Pendata adalah orang atau kumpulan orang yang sukarela berperan aktif melaksanakan/mengelola Program Bangga Kencana dalam hal ini pelaksanaan Pemutakhiran Pendataan Keluarga Tahun 2024 dan telah ditetapkan dengan SK PD KB Kabupaten dan Kota.');
INSERT INTO `faq` (`id`, `parent_id`, `key_name`, `question_text`, `answer_text`) VALUES
(314, 175, 'P6.139', 'Apa saja tugas Kader Pendata?', 'Tugas pokok Kader Pendata adalah sebagai berikut:\n- Mempelajari buku Pedoman Pemutakhiran PK-24;\n- Mengikuti orientasi;\n- Melakukan persiapan bersama supervisor dengan membuat list keluarga yang didata untuk memastikan dan verifikasi lokasi keluarga sasaran \nPemutakhiran PK-24 berada pada desa wilayah kader;\n- Melakukan kunjungan rumah ke rumah untuk wawancara keluarga \nsasaran;\n- Memastikan semua pertanyaan yang ada dalam formulir atau aplikasi \nPemutakhiran PK-24 sudah diajukan dan terisi jawabannya;\n- Memaksimalkan waktu pengumpulan data Pemutakhiran PK-24 agar \nseluruh sampel keluarga sasaran dapat terdata tepat waktu;\n- Melakukan pelaporan seluruh hasil Pemutakhiran PK-24 kepada supervisor, bagi yang mendata dengan formulir sertakan seluruh bunder hasil Pemutakhiran PK-24.'),
(315, 175, 'P6.140', 'Apa kriteria seseorang yang dapat ditunjuk menjadi Kader Pendata?', 'Kader pendata berada di tingkat dusun/RW/setara atau RT/ setara, dengan kriteria : \na. Diutamakan SLTA; \nb. Mengenal dan dikenal masyarakat; \nc. Mampu berkomunikasi dengan baik; \nd. Menguasai wilayah kerja; \ne. Memahami tata cara pencatatan pendataan keluarga; \nf. Bagi kader yang melaksanakan pemutakhiran menggunakan perangkat smartphone diharuskan memiliki smartphone, dan mampu mengoperasionalkan aplikasi Pemutakhiran PK-24 berbasis android pada perangkat smartphone yang digunakan.'),
(316, 175, 'P6.141', 'Apa saja Sarana dan Prasarana Pemutakhiran PK-24?', 'a. Paket Pemutakhiran PK-24 Kit untuk wilayah smartphone terdiri dari:\n- Name tag\n- tali name tag\n- formulir listing\n\nb. Paket Pemutakhiran PK-24 Kit untuk wilayah formulir (paper based) terdiri dari:\n- Name tag\n- tali name tag\n- Formulir F/I/Pemutakhiran-PK/24 dengan Data (Disesuaikan dengan pagu anggaran masing-masing provinsi)\n- Formulir F/I/Pemutakhiran-PK/24 tanpa Data\n- Formulir Listing \n- Formulir Rekapitulasi RT/Rek. RT\n- Formulir Rekapitulasi Desa/Rek. Desa\n\nc. Buku Pedoman dan Panduan Teknis Pemutakhiran PK-24\n\nd. Formulir F/I/Pemutakhiran-PK/24 \n\ne. Formulir Pengukuran Perkembangan Anak Usia Dini atau Early Childhood Development Index (ECDI) pada Pemutakhiran PK-24\n\nf. Telepon pintar (smartphone) \n\ng. Rekapitulasi Hasil Pemutakhiran Pendataan Keluarga'),
(317, 175, 'P6.142', 'Apakah yang dimaksud dengan Aplikasi Elsimil SIGA?', 'Aplikasi Elsimil merupakan aplikasi yang digunakan untuk deteksi faktor risiko stunting yang digunakan dalam pendampingan kepada Calon Pengantin (Catin), Ibu Hamil, Ibu Pascapersalinan dan Balita (0-59 Bulan).'),
(318, 175, 'P6.143', 'Apakah Aplikasi Elsimil SIGA dapat digunakan untuk semua sasaran (Catin, Ibu Hamil, Ibu Pascapersalinan, dan Balita 0-59 bullan)?', 'Bisa'),
(319, 175, 'P6.144', 'Siapa yang akan mendampingi setiap sasaran dalam penggunaan Aplikasi Elsimil SIGA?', 'Setiap saran akan mendapatkan pendampingan dari Tim Pendamping Keluarga (TPK) yang berada di Desa/Kelurahan yang sama dengan wilayah domisili sasaran.'),
(320, 175, 'P6.145', 'Apakah basis data Elsimil?', 'Elsimil memanfaatkan basis data Hasil Verifikasi dan Validasi Keluarga Berisiko Stunting (Verval KRS)'),
(321, 175, 'P6.146', 'Bagaimana langkah-langkah Catin Mandiri mengunduh sertifikat SIAP NIKAH?', 'i. Catin mengunduh Aplikasi Elsimil Calon Pengantin dari Playstore \nii. Catin secara mandiri mengisi variabel skrining kesehatan \niii. Catin secara mandiri mengunduh sertifikat SIAP NIKAH'),
(322, 175, 'P6.147', 'Bagaimana langkah-langkah Catin Mandiri mengunduh sertifikat SIAP NIKAH?', '- TPK mengunduh Aplikasi Elsimil SIGA dari Playstore \n- TPK melakukan pendampingan kepada sasaran Catin, Ibu Hamil, Ibu Pascapersalinan, Balita 0-59 bulan yang dicatat melalui Aplikasi Elsimil \n- Petugas Pendamping yang terdiri dari TPKKB, TPK PKK, dan Bidan/Tenaga Kesehatan \n- TPK bertugas mendampingi dan mencatat data pendampingan melalui aplikasi Elsimil SIGA'),
(323, 175, 'P6.148', 'Apa arti notifikasi hijau dan merah pada aplikasi Elsimil SIGA?', 'Setelah Catin dan TPK melakukan input data ke dalam sistem Elsimil SIGA, selanjutnya sistem akan melakukan analisis secara otomatis terhadap hasil pemeriksaan tersebut. \nApabila angka hasil pemeriksaan berada di kategori \'normal/ideal\', maka aplikasi Elsimil SIGA akan memberikan notifikasi Hijau atau Sehat. Namun apabila ada indikator atau variabel  yang hasilnya  \'diluar angka normal/Tidak Ideal\", maka akan muncul notofikasi Merah atau Beresiko. \nSehingga sasaran maupun Petugas Pendamping bisa mengetahui adanya risiko stunting lebih dini dan melakukan langkah-langkah untuk mencegahnya.'),
(324, 175, 'P6.149', 'Bagaimana cara unduh Aplikasi Elsimil V3?', 'https://play.google.com/store/apps/details?id=com.bkkbn.elsimilsiga&hl=id'),
(325, 175, 'P6.150', 'Bagaimana cara mendapatkan user Elsimil bagi TPK?', 'Hubungi PKB/PLKB/Balai Penyuluh KB Kapanewon/Kemantren/Kecamatan'),
(326, 175, 'P6.151', 'Bagaimana jika wilayah kerja elsimil TPK tidak sesuai/ada yang tidak muncul?', 'Cek juga K/0 TPK di SIGA, jika wilayahnya ada di TPK lain, hapus dulu wilayah tersebut dari TPK saat ini baru ditambahkan ke TPK yang sesuai.'),
(327, 175, 'P6.152', 'Apa itu iBangga?', 'iBangga adalah suatu pengukuran kualitas keluarga yang ditunjukkan melalui ketentraman, kemandirian dan kebahagiaan keluarga dan menggambarkan peran dan fungsi keluarga utuk semua wilayah di Indonesia. iBangga merupakan indikator penting untuk mengukur keberhasilan dalam upaya membangun kualitas keluarga'),
(328, 175, 'P6.153', 'Apa manfaat iBangga?', 'Manfaat iBangga adalah\n 1. iBangga merupakan data strategis sebagai ukuran kinerja Pemerintah\n 2. iBangga dapat menjadi dasar bagi para pemangku kepentingan dan pengambil kebijakan dalam merumuskan kebijakan/ program kegiatan\n 3. iBangga dapat menentukan peringkat atau level pembangunan keluarga suatu wilayah'),
(329, 175, 'P6.154', 'Apa saja dimensi iBangga?', 'Dimensi iBangga ada 3 yaitu:\n 1. Dimensi kententraman, yaitu kondisi keluarga yang di dalamnya memiliki rasa aman, tenang, baik hati maupun pikiran dalam kehidupan berkeluarga\n 2. Dimensi kemandirian, yaitu kemampuan keluarga untuk bertindak sesuai dengan keadaan dan mampu memenuhi kebutuhan hidup tanpa meminta atau bergantung pada keluarga lain\n 3. Dimensi kebahagiaan, yaitu kondisi keluarga yang di dalamnya terdapat unsur kasih saying, menerima kondisi keluarga dan lingkungannya serta mampu mengaktualisasi diri'),
(330, 175, 'P6.155', 'Apa saja indikator dimensi ketentraman?', 'Dimensi ketentraman terdapat 4 indikator yaitu kegiatan ibadah, legalitas keluarga, jaminan kesehatan, dan keharmonisan keluarga'),
(331, 175, 'P6.156', 'Apa saja indikator dimensi kemandirian?', 'Dimensi kemandirian terdapat 5 indikator yaitu pemenuhan kebutuhan dasar, jaminan keuangan, keberlangsungan pendidikan, kesehatan keluarga, dan akses media online/daring'),
(332, 175, 'P6.157', 'Apa saja indikator dimensi kebahagiaan?', 'Dimensi kebahagiaan terdapat 2 indikator yaitu interaksi keluarga dan interaksi sosial'),
(333, 175, 'P6.158', 'Apa saja 8 fungsi keluarga?', '8 fungsi keluarga meliputi:\n1. Fungsi agama\n2. Fungsi sosial budaya\n3. Fungsi cinta kasih\n4. Fungsi perlindungan\n5. Fungsi reproduksi\n6. Fungsi sosialisasi Pendidikan\n7. Fungsi ekonomi\n8. Fungsi pembinaan lingkungan'),
(334, 175, 'P6.159', 'Penyelenggaraan pembangunan keluarga dapat dilaksanakan melalui kelompok kegiatan apa saja?', '1. BKB\n2. BKR\n3. PIK R\n4. BKL\n5. PPKS\n6. Kelompok UPPKA'),
(335, 175, 'P6.160', 'Apa yang dimaksud dengan Demografi ?', 'Studi ilmiah tentang populasi manusia\n (penduduk), termasuk jumlah, persebaran, komposisi, dan\n faktor-faktor yang menentukan perubahan dalam jumlah,\n persebaran, dan komposisinya. Jadi, demografi fokus pada lima\n aspek dari penduduk: (1) jumlah, (2) distribusi, (3) komposisi, (4)\n komponen utama pertumbuhan penduduk (fertilitas, mortalitas,\n dan migrasi), dan (5) determinan dan konsekuensi dari\n perubahan penduduk.'),
(336, 175, 'P6.161', 'Apa yang dimaksud dengan Data Kependudukan?', 'Infromasi berupa angka karakteristik penduduka suatu populasi yang terdiri dari jumlah, pertumbuhan, distribusi umur, distribusi jenis kelamin, tingkat kelahiran, tingkat kematian, dan tingkat migrasi penduduk serta kondisi sosial, ekonomi, budaya, lingkungan, politik, hukum, keamanan, dan lain-lain'),
(337, 175, 'P6.162', 'Apa tujuan utama program Sensus Penduduk (SP) 2020 di Indonesia?', 'Tujuannya adalah menyediakan data jumlah, komposisi, distribusi, dan karakteristik penduduk menuju satu data kependudukan Indonesia dengan memanfaatkan data administrasi kependudukan dan metode kombinasi (CAWI, CAPI, PAPI).'),
(338, 175, 'P6.163', 'Kapan Indonesia pertama kali melaksanakan Sensus Penduduk setelah kemerdekaan?', 'Tahun 1961. Hingga 2020, Indonesia telah melaksanakan 7 kali Sensus Penduduk (1961, 1971, 1980, 1990, 2000, 2010, 2020).'),
(339, 175, 'P6.164', 'Kapan Indonesia pertama kali melaksanakan Sensus Penduduk setelah kemerdekaan?', 'Tahun 1961. Hingga 2020, Indonesia telah melaksanakan 7 kali Sensus Penduduk (1961, 1971, 1980, 1990, 2000, 2010, 2020).'),
(340, 175, 'P6.165', 'Bagaimana metode kombinasi yang digunakan dalam Sensus Penduduk 2020?', 'CAWI (Computer Aided Web Interviewing) untuk penduduk dengan akses internet.\n \n CAPI (Computer-Assisted Personal Interviewing) menggunakan gadget petugas.\n \n PAPI (Paper and Pencil Interviewing) untuk wilayah terpencil.'),
(341, 175, 'P6.166', 'Apa yang dimaksud dengan Survei Penduduk?', 'Survei penduduk adlah pengumpulan data yang dilakukan melalui pencacahan sebagian dari penduduk (sampel) untuk memperoleh data kependudukan yang lebih terperinci pada waktu tertentu'),
(342, 175, 'P6.167', 'Apa keunggulan dan keterbatasan survei penduduk?', 'Keunggulan survei ialah informasi kependudukan yang dikumpulkan lebih terperinci dan terkini. Keterbatasannya ialah informasi dikumpulkan dari sebagian penduduk (sampel) sehingga terdapat kemungkinan terjadi kesalahan dalam pemilihan sampel (sampling errors).'),
(343, 175, 'P6.168', 'Kapan Survei Penduduk Antar Sensus (SUPAS) dilaksanakan?', 'SUPAS dilaksanakan setipa lima tahun sekali setelah Survei Penduduk terakhir untuk menghasilkan data kependudukan antara dua Survei Penduduk.'),
(344, 175, 'P6.169', 'Apa yang dimaksud dengan fertilitas dan fekunditas?', 'Fertilitas adalah kemampuan menghasilkan keturunan yang dikaitkan dengan kesuburan wanita, sedangkan fekunditas adalah potensi fisik seorang perempuan untuk melahirkan anak.'),
(345, 175, 'P6.170', 'Apa yang dimaksud kelahiran hidup (live birth) dan kelahiran mati (still birth)?', 'Live birth adalah kelahiran seorang bayi tanpa memperhitungkan lamanya di dalam kandungan, dimana si bayi menunjukkan tanda-tanda kehidupan pada saat dilahirkan yaitu bernafas, ada denyut jantung, atau ada gerakan-gerakan otot. Sedangkan still birth adalah kelahiran seorang bayi dari kandungan yang sudah berumur paling sedikit 28 minggu tanpa menunjukkan tanda-tanda kehidupan saat dilahirkan.'),
(346, 175, 'P6.171', 'Apa yang dimaksud dengan masa reproduksi?', 'Masa reproduksi adalah periode dimana seorang perempuan memiliki potensi untuk menghasilkan keturunan yang berawal dari sejak mendapatkan haid pertama (menarche) dan berakhir pada saat berhenti haid (menopause)'),
(347, 175, 'P6.172', 'Apa itu angka reproduksi?', 'Angka reproduksi merupakan ukuran yang berkenaan dengan kemampuan seorang perempuan untuk menggantikan dirinya'),
(348, 175, 'P6.173', 'Apa itu mortalitas (kematian)?', 'Mortalitas adalah keadaan menghilangnya semua tanda-tanda kehidupan secara permanen yang bisa terjadi setiap saat setelah kelahiran hidup.'),
(349, 175, 'P6.174', 'Apa saja sumber data mortalitas?', 'Data mortalitas diperoleh dari sistem registrasi vital, sensus penduduk, survei penduduk, survei kesehatan, dan administrasi rumah sakit.'),
(350, 175, 'P6.175', 'Apa manfaat data mortalitas?', 'Data mortalitas bermanfaat untuk mengevaluasi dan meningkatkan pelaksanaan program kesehatan masyarakat.'),
(351, 175, 'P6.176', 'Apa yang dimaksud dengan migrasi?', 'Migrasi adalah perpindahan penduduk dengan tujuan untuk menetap dari suatu tempat ke tempat lain melampaui batas politik/negara ataupun batas administrasi/batas bagian dalam suatu negara.'),
(352, 175, 'P6.177', 'Apa saja faktor pendorong migrasi?', '1. Makin berkurangnya sumber-sumber kehidupan\n 2. Menyempitnya lapangan pekerjaan di daerah asal\n 3. Adanya tekanan politik, agama dan suku\n 4. Alasan pendidikan, pekerjaan atau perkawinan\n 5. Adanya bencana alam seperti banjir, kebakaran, gempa bumi'),
(353, 175, 'P6.178', 'Apa saja faktor penarik migrasi?', '1. Adanya harapan akan memperoleh kesempatan untuk meningkatkan taraf hidup\n 2. Adanya kesempatan untuk memperoleh pendidikan yang lebih baik\n 3. Keadaan lingkungan dan keadaan hidup yang menyenangkan\n 4. Adanya aktivitas-aktivitas di kota besar, tempat-tempat hiburan dan pusat kebudayaan sebagai daya tarik'),
(354, 175, 'P6.179', 'Apa saja tempat pelayanan KB yang terdaftar di SIGA?', 'A. Fasilitas Kesehatan (Faskes)\n 1. Rumah Sakit Umum\n 2. Rumah Sakit Khusus\n 3. Klinik Utama\n 4. Puskesman\n 5. Praktk Dokter\n 6. Klinik Pratama \n 7. Rumah akit Tipe D Pratama\nB. Setara Faskes\n 1. Praktik Mandiri Bidan (Setara Faskes)\nC. Jaringan/Jejaring\n 1. Pustu\n 2. Pusling\n 3. Poskesdes/Polindes\n 4. Praktik Mandiri Bidan Jejaring'),
(355, 175, 'P6.180', 'Apa perbedaan antara Praktik Mandiri Bidan (PMB) Jejaring dan Praktik Mandiri Bidan (PMB) Setara Faskes?', '- Praktik Mandiri Bidan (PMB) Jejaring\nMerupakan bidan yang melaksanakan praktik secara mandiri/perorangan dan merupakan jejaring dari suatu faskes. PMB jenis ini mendapatkan distribusi alokon melalui faskes yang menjadi induknya. \n- Praktik Mandiri Bidan (PMB) Setara Faskes\nMerupakan bidan yang melaksanakan praktik secara mandiri/perorangan namun belum bekerjasama dengan BPJS kesehatan dan tidak menjadi jejaring dari suatu faskes. PMB jenis ini mendapatkan distribusi alokon langsung dari PD-KB.'),
(356, 175, 'P6.181', 'Kapan bisa dilakukan update data K/0/KB/20 di SIGA?', 'Update data K/0/KB/20 di SIGA dapat dilakukan setiap saat'),
(357, 175, 'P6.182', 'Nomor register tempat pelayanan KB di SIGA didapatkan dari manakah?', 'Nomor register tempat pelayanan KB di SIGA akan muncul setelah K/0/KB dientri ke dalam aplikasi (generated by sistem)'),
(358, 175, 'P6.183', 'Siapa yang melakukan register tempat pelayanan KB di SIGA?', 'Faskes diregister di SIGA oleh PD-KB, Jaringan diregister di SIGA oleh Puskesmas, Jejaring diregister di SIGA oleh Faskes Induk'),
(359, 175, 'P6.184', 'Kapan dilakukan Register Tempat Pelayanan KB?', 'Setiap bulan'),
(360, 175, 'P6.185', 'Apa saja hasil pelayanan KB yang dicatatkan di SIGA?', 'Hasil pelayanan KB yang dicatat meliputi Peserta KB Baru, Peserta KB Ganti Cara, Peserta KB Ulangan dan Kasus Komplikasi Berat/Kegagalan/Pencabutan'),
(361, 175, 'P6.186', 'Apa identitas yang dibutuhkan pasien untuk mengisi kartu peserta KB?', 'KTP Istri'),
(362, 175, 'P6.187', 'Apa kepanjangan dari Data DALLAP?', 'Data Pengendalian Lapangan'),
(363, 175, 'P6.188', 'Apa saja Data DALLAP yang ada di SIGA?', 'Data SDM, POKTAN, Setara POKTAN dan SARANA'),
(364, 175, 'P6.189', 'Siapa yang bertanggung jawab meregister data DALLAP di SIGA?', 'Berikut yang bertanggung jawab untuk meregister data DALLAP di SIGA :\n1. PKB/PLKB : diregister oleh PD-KB Kabupaten/Kota\n2. POKTAN : diregister oleh PKB/PLKB/PPKBD/SUB PPKBD/Lainnya\n3. PPKS : diregister oleh PD-KB Kabupaten/Kota atau Perwakilan BKKBN Provinsi\n4. Kampung KB : diregister oleh PKB/PLKB/PPKBD/SUB PPKBD/Lainnya\n5. Rumah Dataku : PKB/PLKB/Pemerintah Desa/Kelurahan/Lainnya'),
(365, 175, 'P6.190', 'Kapan bisa dilakukan update data Kartu Pendaftaran DALLAP di SIGA?', 'Update data Kartu Pendaftaran DALLAP di SIGA dapat dilakukan setiap saat'),
(366, 175, 'P6.191', 'Apa saja formulir kartu pendaftaran DALLAP?', '- K/0/BKB\n- K/0/BKR\n- K/0/BKL\n- K/0/UPPKA\n- K/0/PIKR\n- K/0/KAMPUNGKB\n- K/0/RUMAHDATAKU\n- K/0/PPKS\n- K/0/BalaiPenyuluhan\n- K/0/PKB\n- K/0/PPKBD\n- K/0/SUBPPKBD\n- K/0/POK KB\n- K/0/TPK'),
(367, 175, 'P6.192', 'Apa saja klasifikasi PPKBD?', 'Klasifikasi PPKBD adalah sebagai berikut :\n1. PPKBD Klasifikasi Dasar\n2. PPKBD Klasifikasi Berkembang\n3. PPBKD Klasifikasi Mandiri'),
(368, 175, 'P6.193', 'Apa saja klasifikasi SUB PPKBD?', 'Klasifikasi SUB PPKBD adalah sebagai berikut :\n1. SUB PPKBD Klasifikasi Dasar\n2. SUB PPKBD Klasifikasi Berkembang\n3. SUB PPBKD Klasifikasi Mandiri'),
(369, 175, 'P6.194', 'Apa saja tahapa dalam pengumpulan data Verval KRS?', '1. Identifikasi Sasaran\n2. Penambahan Data Sasaran Baru\n3. Perbaikan Data Sasaran'),
(370, 175, 'P6.195', 'Apakah yang dimaksud dengan PUS dalam keluarga sasaran Verval KRS?', 'PUS (Pasangan Usia Subur) adalah keluarga yang memiliki istri dengan usia 15 s.d 49 tahun'),
(371, 175, 'P6.196', 'Apakah yang dimaksud dengan PUS hamil dalam keluarga sasaran Verval KRS?', 'PUS (Pasangan Usia Subur) hamil, adalah keluarga yang memiliki istri dengan usia 15 s.d 49 tahun dan sedang hamil'),
(372, 175, 'P6.197', 'Apakah yang dimaksud dengan Keluarga punya Baduta dalam keluarga sasaran Verval KRS?', 'Keluarga punya baduta, adalah keluarga yang memiliki anak dengan usia 0 s.d 23 bulan'),
(373, 175, 'P6.198', 'Apakah yang dimaksud dengan Keluarga punya Balita dalam keluarga sasaran Verval KRS?', 'Keluarga punya balita, adalah keluarga yang memiliki anak dengan usia 24 s.d 59 bulan'),
(374, 175, 'P6.199', 'Siapa yang bisa melakukan aktif/non aktif K/0 Pelayanan KB dan K/0 DALLAP?', 'Aktif/Non Aktif data K/0, baik pelayanan KB maupun DALLAP bis dilakukan oleh PKB/PLKB Kecamatan dengan menggunakan user administrator kecamatan'),
(375, 175, 'P6.200', 'Apa yang bisa dilakukan dengan user Administrator SIGA?', 'User Administrator SIGA ada 2, yaitu :\n1. Administrator SR : Hak akses aplikasi SIGA semua formulir (Lihat, Cetak)\n2. Administrator Wilayah : Hak akses portal (Pengaturan)'),
(376, 175, 'P6.201', 'Apa yang bisa dilakukan dengan user Operator SIGA?', 'USer Operator SIGA ada 10, yaitu :\n1. Operator SR : Hak akses Aplikasi new SIGA Semua Formulir \n2. Operator BKB : Hak askes K/0/BKB & R/I/BKB \n3. Operator BKR : Hak akses K/0/BKR & R/I/BKR \n4. Operator BKL : Hak akses K/0/BKL & R/I/BKL \n5. Operator UPPKA : Hak akses K/0/UPPKA & R/I/UPPKA \n6. Operator PIK R : Hak akses K/0/PIK & R/I/PIK\n7. Operator SDM : Hak akses K/0 & R/I SDM \n8. Operator Setara Poktan : Hak akses K/0 & R/I (Kampung KB, Rumahdataku, PPKS) \n9. Operator Sarana : Hak Akses K/0 (BP, MPC, Mupen) & R/I (BP)\n10. Operator Yan KB : Hak Akses K/0/KB, R/I/KB & R/II/KB'),
(377, 175, 'P6.202', 'Apa yang bisa dilakukan dengan user Supervisor SIGA?', 'Hak Akses Aplikasi new SIGA Semua Formulir (Lihat, Cetak)'),
(378, 175, 'P6.203', 'Pencatatan dan pelaporan pelayanan KB mencakup:', 'Data Potensi Tempat Pelayanan KB, Data Pelayanan KB, Data Alat dan Obat Kontrasepsi.'),
(379, 175, 'P6.204', 'Pengelolaan data rutin Pelayanan KB adalah', 'Suatu kegiatan pencatatan, pengumpulan, pengolahan, analisis, serta penyajian data rutin pelayanan KB dengan sistem yang telah ditetapkan'),
(380, 175, 'P6.205', 'Pengelolaan Data Rutin Pengendalian Lapangan adalah', 'Kegiatan yang berhubungan dengan pencatatan, pengumpulan, pengolahan, analisis, serta penyajian yang berkaitan dengan data rutin pengendalian lapangan.'),
(381, 175, 'P6.206', 'Tujuan Pengelolaan Data Rutin Pengendalian Lapangan,yaitu', 'memudahkan pelaksanaan tugas para pelaksana di lapangan dan para pengelola pengelolaan data di semua tingkatan wilayah dalam penyediaan data dan informasi bagi pengelolaan Program Kependudukan, Keluarga Berencana, dan Pembangunan Keluarga.'),
(382, 175, 'P6.207', 'Tenaga yang didaftarkan pada K/0/KB/20 adalah', 'Tenaga yang melakukan pelayanan KB dan RR pada tempat pelayanan KB'),
(383, 175, 'P6.208', 'Fasilitas Kesehatan Tingkat Pertama (FKTP) adalah fasilitas kesehatan yang termasuk didalamnya berupa', 'Puskesmas, Praktek Dokter Mandiri, Klinik Pratama, Rumah Sakit Klas D Pratama'),
(384, 175, 'P6.209', 'Bagaimana cara registrasi Elsimil Catin Mandiri?', 'Klik tombol Daftar \nIsi data-data sampai dengan step terakhir\nKlik Daftar \nLakukan verifikasi Email'),
(385, 175, 'P6.210', 'Bagaimana jika registrasi Catin di Elsimil gagal?Applicatioan exception', 'Dalam beberapa kasus yang ditemui, hal ini diduga terjadi kesalahan notifikasi \nJadi solusinya: \n1. Langsung dicoba login saja menggunakan email dan password yang didaftarkan \n2. Jika tetap mengalami kendala, hubungi PKB/PLKB atau TPK untuk diinputkan datanya menggunakan akun TPK sesuai alamat catin perempuan.'),
(386, 175, 'P6.211', 'Bagaimana solusi jika Catin mengalami kendala login elsimil?', 'Hubungi PKB/PLKB atau TPK untuk diinputkan datanya menggunakan akun TPK sesuai alamat catin perempuan.'),
(387, 175, 'P6.212', 'Bagaimana solusi jika catin mengalami kendala input data di Elsimil?', 'Hubungi PKB/PLKB atau TPK untuk diinputkan datanya menggunakan akun TPK sesuai alamat catin perempuan.'),
(388, 175, 'P6.213', 'Bagaimana solusi jika catin mengalami kendala unduh sertifikat Elsimil?', 'Hubungi PKB/PLKB atau TPK untuk diinputkan datanya menggunakan akun TPK sesuai alamat catin perempuan.'),
(389, 175, 'P6.214', 'Bagaimana solusi jika terjadi salah input data Elsimil catin?', 'Data dapat diedit menggunakan Elsimil catin ataupun TPK sesuai alamat catin perempuan'),
(390, 175, 'P6.215', 'Bagaimana langkah edit data Elsimil catin oleh TPK?', 'Login > Catin > Data Catin > Edit Catin (icon kertas hijau) > Riwayat kunjungan > Lakukan edit data sekaligus input pendampingan'),
(391, 175, 'P6.216', 'Bagaiaman langkah unduh sertifikat Elsimil catin oleh TPK?', 'Login > Catin > Data Catin > Edit Catin (icon kertas hijau) > unduh sertifikat'),
(392, 175, 'P6.217', 'Bagaimana jika data tidak ditemukan di Elsimil Data Bumil?', 'Data Bumil pada modul Bumil menampilkan data yang telah dilakukan input pendampingan bumil baik yang berstatus Masa Pendampingan ataupun yang telah Melahirkan. \nCek Data Sasaran Bumil. \nKlik icon pensil untuk mulai melakukan input data pendampingan Ibu Hamil.'),
(393, 175, 'P6.218', 'Apa saja tahap persiapan Pemutakhiran PK-24 di tingkat pusat?', 'a. BKKBN Pusat (c.q. unit yang menangani pelaporan dan statistik) \nmelakukan: \n1) Menyiapkan bahan kebijakan dan strategi serta mekanisme terkait pelaksanaan Pemutakhiran PK-24; \n2) Melakukan advokasi kepada kementerian/lembaga terkait dukungan kebijakan, teknis maupun anggaran pelaksanaan Pemutakhiran PK-24;  \n3) Menyiapkan dan mendistribusikan pedoman dan panduan teknis mekanisme pelaksanaan Pemutakhiran PK-24 paling sedikit mencakup: \n   a) Pedoman Pemutakhiran Pendataan Keluarga Tahun 2024; \n   b) Panduan Teknis Manajemen Data Pemutakhiran Pendataan Keluarga 2024 bagi Manajer; \n  c) Panduan Teknis Pengumpulan Data Pemutakhiran Pendataan Keluarga 2024 bagi Supervisor;\n  d) Panduan Teknis Pengumpulan Data Pemutakhiran Pendataan Keluarga 2024 bagi Kader; \n  e) Panduan Pelaksanaan Anggaran Pemutakhiran PK-24; \n  f) Panduan Pengumpulan Data Pengukuran Perkembangan Anak \nUsia Dini atau Early Childhood Development Index (ECDI) Pada \nPemutakhiran PK-24 Bagi Tenaga Lini Lapangan\n4) Menyiapkan pembentukan Pos Koordinasi (Posko) di tingkat pusat serta penetapan sekretariatnya untuk memantau perkembangan penyelenggaraan Pemutakhiran PK-24. \n\nb. BKKBN Pusat (c.q. unit yang menangani lini lapangan) menyiapkan \npemetaan Sumber Daya Manusia (SDM) lini lapangan yang akan terlibat \ndalam pelaksanaan Pemutakhiran PK-24 serta melakukan pembinaan dan penguatan kepada Ikatan Penyuluh Keluarga Berencana (IPeKB) \nIndonesia sebagai organisasi profesi jabatan fungsional Penyuluh KB terkait persiapan, pelaksanaan dan monitoring evaluasi SDM lini lapangan yang terlibat dalam Pemutakhiran PK-24;\n\nc.  BKKBN Pusat (c.q. unit yang menangani perencanaan) memfasilitasi perencanaan anggaran untuk penyelenggaraan Pemutakhiran PK-24; \n\nd. BKKBN Pusat (c.q. unit yang menangani teknologi informasi dan data) \nmenyiapkan sistem aplikasi serta infrastruktur TI untuk kebutuhan monitoring data, operasional pengumpulan dan pengolahan data serta pemanfaatan data hasil Pemutakhiran PK-24;\n\ne. BKKBN Pusat (c.q. unit yang menangani advokasi dan KIE) mengembangakan dan mendistribusikan disain isi pesan dan strategi KIE\nPemutakhiran PK-24 serta melakukan KIE secara nasional melalui media\nyang mempunyai jangkauan jaringan nasional.'),
(394, 175, 'P6.219', 'Apa saja tahap persiapan Pemutakhiran PK-24 di tingkat provinsi?', 'a. Kepala Perwakilan BKKBN Provinsi melakukan advokasi kepada Gubernur untuk dukungan Pelaksanaan Pemutakhiran PK-24.\nb. Perwakilan BKKBN Provinsi (cq. unit yang menangani advokasi, penggerakan dan informasi) melakukan: \n  1) Sosialisasi kebijakan, strategi dan mekanisme Pemutakhiran PK-24 ke \nseluruh kabupaten dan kota; \n  2) Penyiapan dan pendistribusian sarana dan prasarana Pemutakhiran \nPK-24; \n  3) Pembentukan Pos Koordinasi (Posko) melalui Surat Keputusan Kepala Perwakilan BKKBN Provinsi sebagai pusat rujukan yang diharapkan dapat memberikan dukungan dan memantau perkembangan pelaksanaan Pemutakhiran PK-24; \n  4) Koordinasi dengan PD KB Kabupaten dan Kota serta dinas terkait \nlainnya untuk penyiapan data wilayah sasaran Pemutakhiran PK-24; \n  5) Koordinasi dengan PD KB Kabupaten dan Kota dalam rangka penyiapan kebutuhan SDM pelaksana lini lapangan Pemutakhiran PK-24; \n  6) Melakukan workshop/orientasi Pemutakhiran PK-24 bagi Pengelola \nData Tingkat kabupaten/kota; \n  7) Melakukan sosialisasi kepada masyarakat melalui media yang mempunyai jangkauan jaringan provinsi; \n  8) Melakukan bimbingan teknis, monitoring dan evaluasi.'),
(395, 175, 'P6.220', 'Apa saja tahap persiapan Pemutakhiran PK-24 di tingkat kabupaten/kota?', 'a. Kepala PD-KB Kabupaten/Kota melakukan advokasi kepada Bupati/ walikota untuk dukungan Pelaksanaan Pemutakhiran PK-24;\nb. Mendistribusikan sarana dan prasarana Pemutakhiran PK-24 melalui Manajer tingkat kecamatan untuk dibagikan para supervisor dan kader pendata; \nc. Melakukan workshop/orientasi Pemutakhiran PK-24 tingkat kecamatan;  \nd. Melakukan sosialisasi kepada masyarakat, serta advokasi dan KIE melalui berbagai media, misalnya di radio, berita di surat kabar di wilayahnya; \ne. Melakukan koordinasi dengan manajer tingkat kecamatan untuk perhitungan kebutuhan kader pendata per desa/kelurahan beserta pemetaan pemilihan tools/alat pengumpulan data; \nf. Menetapkan dan menerbitkan surat keputusan SDM pelaksana lini lapangan yang meliputi manajer pengelolaan dan manajer data tingkat kecamatan, supervisor tingkat desa, kader pendata dan operator pengolahan data; \ng. Membentuk Tim Pos Koordinasi (Posko) serta penetapan sekretariatnya melalui surat Keputusan Kepala PD KB untuk memantau perkembangan pelaksanaan Pemutakhiran PK-24 di wilayahnya; \nh. Melakukan bimbingan teknis, monitoring dan evaluasi'),
(396, 175, 'P6.221', 'Apa saja tahap persiapan Pemutakhiran PK-24 di tingkat kecamatan?', 'a. Manajer Pengelolaan \n1) Manajer Pengelolaan membuat perencanaan pelaksanaan \nPemutakhiran PK-24:\n- Menyusun daftar nama dan kode wilayah dari tingkat Desa/Kelurahan, tingkat Dusun/RW, dan tingkat RT bersama dengan penyuluh KB, kader IMP dan pihak terkait lainnya. \n- Melakukan perincian jumlah KK tingkat desa/kelurahan, tingkat Dusun/RW, dan tingkat RT untuk disahkan menjadi target sasaran KK yang akan didata\n- Melakukan pemetaan desa/kelurahan berdasarkan sarana pengumpulan data yang akan digunakan pada Pemutakhiran PK24 (smartphone atau formulir)\n- Menunjuk Manajer Data dan Supervisor tingkat Desa/Kelurahan sesuai dengan kriteria yang sudah ditentukan. Membuat daftar usulan Pengorganisasian Pelaksanaan Pemutakhiran PK-24 yang terdiri dari: \n Manajer Data \n Supervisor tingkat Desa/Kelurahan  \n Kader pendata (ditunjuk oleh supervisor) \n Tim pengolah data (ditunjuk oleh manajer data)\nDaftar usulan tersebut selanjutnya dikirim ke PD KB Kabupaten dan \nKota sebagai Pengorganisasian dasar pembuatan Surat Keputusan \nPelaksanaan Pemutakhiran Pendataan Keluarga Tahun 2024.\n- Menyusun jadwal pelaksanaan Pemutakhiran PK-24 di wilayahnya mulai dari tahap persiapan sampai dengan penyebarluasan informasi. \n- Menyiapkan rencana distribusi sarana dan prasarana Pemutakhiran PK-24 kepada Supervisor tingkat desa/kelurahan.  \n2) Mengoordinasikan pelaksanaan Pemutakhiran PK-24 kepada Camat sebagai penanggungjawab wilayah. \n3) Menyelenggarakan orientasi terhadap supervisor, kader pendata Pemutakhiran PK-24.  \n4) Melaksanakan promosi, advokasi dan sosialisasi Pemutakhiran PK-24. \n\nb. Manajer Data\n- Manajer Data mengoordinasikan perencanaan pelaksanaan Pemutakhiran PK-24 bersama manajer pengelolaan; \n- Melakukan pemutakhiran wilayah, target KK dan SDM lini lapangan \npada aplikasi portal; \n- Manajer data membentuk Tim Pengolah Data yang ditetapkan melalui Surat Keputusan dari PD KB Kabupaten dan Kota dengan mempertimbangkan jumlah pengolah data dengan data yang akan diolah serta jangka waktu pelaksanaan Pemutakhiran PK-24 yang telah ditetapkan'),
(397, 175, 'P6.222', 'Apa saja tahap persiapan Pemutakhiran PK-24 di tingkat desa/kelurahan?', 'a. Supervisor menyusun pembagian tugas Tim, meliputi: \n1) Menyesuaikan jumlah kader pendata dengan memperhatikan target KK yang akan didata dan jangka waktu pengumpulan data; \n2) Melakukan pembagian tugas kepada kader dengan memperhatikan beban kerja dengan kemampuan kader, batas wilayah yang akan didata oleh kader; \n3) Menyusun jadwal pelaksanaan pendataan di wilayahnya agar target KK terdata terpenuhi selama jangka waktu pengumpulan data yang ditentukan.\nb. Menyiapkan dan mendistribusikan Pemutakhiran PK-24 Kit kepada kader \npendata; \nc. Mengoordinasikan pelaksanaan Pemutakhiran PK-24 kepada Kepala\nDesa/Lurah, Ketua RW, dan Ketua RT terkait informasi pelaksanaan Pemutakhiran PK-24 dan mengkonfirmasi jumlah KK per desa/kelurahan, per RW, dan per RT.'),
(398, 175, 'P6.223', 'Apa saja tahap persiapan Pemutakhiran PK-24 di tingkat Dusun/RW dan tingkat RT?', 'a. Kader pendata berkoordinasi dengan Ketua RT perihal pelaksanaan Pemutakhiran PK-24 dan memperoleh estimasi jumlah KK yang ada di RT masing-masing; \nb. Kader Pendata Pemutakhiran PK-24 menerima sarana dan prasarana Pemutakhiran Pendataan Keluarga Tahun 2024 sedikitnya terdiri dari: \n   1) Formulir F/I/Pemutakhiran-PK/24 (bagi kader yang mendata menggunakan formulir) \n   2) Pemutakhiran PK-24 Kit \nc. Kader Pendata didampingi Supervisor membuat list/daftar keluarga sesuai dengan pembagian tugas kader pendata.'),
(399, 175, 'P6.224', 'Apa dasar hukum pelaksanaan Pemutakhiran PK-24?', 'Berdasarkan Undang-Undang Nomor 52 Tahun 2009 tentang Perkembangan Kependudukan  dan Pembangunan Keluarga  (Pasal 49 \ndan  50) serta dipertegas dengan  Peraturan  Pemerintah  Nomor 87 Tahun 2014 tentang Perkembangan Kependudukan dan Pembangunan  Keluarga,  Keluarga  Berencana dan  Sistem Informasi Keluarga bahwa Pendataan Keluarga yang dilakukan serentak oleh Pemerintah Daerah Kabupaten/Kota setiap 5  (lima) tahun sekali  wajib dilakukan pemutakhiran setiap tahun (Pasal 53).'),
(400, NULL, 'P7', 'Dashat', NULL),
(401, 400, 'P7.1', 'Apakah yang dimaksud DASHAT', 'DASHAT adalah singkatan dari Dapur Sehat Atasi Stunting. Merupakan kegiatan pemberdayaan masyarakat dalam upaya pemenuhan gizi seimbang bagi keluarga beresiko stunting melalui sumberdaya lokal yang dipadukan dengan sumberdaya/kontribusi kemitraan lainnya'),
(402, 400, 'P7.2', 'Siapakah target DASHAT?', 'Target DASHAT adalah Ibu hamil, Baduta/Balita, Ibu menyusui, dan Calon pengantin'),
(403, 400, 'P7.3', 'Siapa pelaksana DASHAT?', 'Kegiatan DASHAT diharapkan dapat menghasilkan hal-hal sebagai berikut :  1. Terpenuhinya kebutuhan gizi anak stunting, bumil/busui dan keluarga risiko stunting 2. Diperolehnya keterampilan penyiapan pangan sehat dan bergizi berbasis sumber daya lokal\n 3. Meningkatnya kesejahteraan keluarga, melalui keterlibatan dalam kelompok usaha keluarga/masyarakat yang berkelanjutan'),
(404, 400, 'P7.4', 'Apa tujuan umum kegiatan DASHAT?', 'Tujuan umum kegiatan DASHAT adalah meningkatkan kualitas gizi masyarakat melalui optimalisasi sumberdaya pangan lokal dalam rangka mempercepat upaya penurunan stunting di tingkat desa/kelurahan'),
(405, 400, 'P7.5', 'Dimanakah DASHAT dilaksanakan?', 'DASHAT dilaksanakan di Desa/Kelurahan, RW atau dusun atau RT terutama yang menjadi lokasi Kampung Keluarga Berkualitas(Kampung KB)'),
(406, 400, 'P7.6', 'Darimana sumber dana kegiatan DASHAT?', 'Sumber pendanaan DASHAT dapat berasal dari : 1. Modal Pribadi/Kelompok  2.Dana Desa 3. Dana Kemitraan dan CSR (Corporate Social Responsibility 4. APBD 5. DAK 6. APBN 7. Lembaga Keuangan bukan bank dan bank'),
(407, 400, 'P7.7', 'Mengapa penting menggunakan pangan lokal?', 'Karena pangan lokal lebih segar, bergizi, terjangkau, mendorong perekonomian lokal, serta meningkatkan kedaulatan dan ketahanan pangan bangsa.'),
(408, 400, 'P7.8', 'Sebutkan contoh pangan lokal pengganti beras!', 'Jagung, singkong, ubi, kentang, sagu, talas, dan labu kuning.'),
(409, 400, 'P7.9', 'Metode pengolahan apa yang paling baik untuk mempertahankan gizi makanan?', 'Mengukus. Metode ini dapat mempertahankan vitamin yang larut dalam air seperti vitamin B dan C.'),
(410, 400, 'P7.10', 'Sebutkan 13 pesan umum gizi seimbang!', 'Ada 13 Pesan umum Gizi Seimbang, yaitu :1) Makan aneka ragam makanan2) Makan makanan yang memenuhi kebutuhan energi3) Makan sumber karbohidrat setengah dari kebutuhan energi 4) Batasi lemak seperempat dari kecukupan energi5) Gunakan garam beryodium6) Makan makanan sumber zat besi7) Beri ASI pada bayi sampai umur enam bulan8) Biasakan makan pagi9) Minum air bersih, aman dan cukup jumlahnya10) Beraktifitas fisik dan olah raga secara teratur11) Hindari minum minuman beralkohol12) Makan makanan yang aman bagi kesehatan13) Baca informasi gizi pada kemasan makanan'),
(411, 400, 'P7.11', 'Apa itu sociopreneurship dalam DASHAT?', 'Konsep wirausaha sosial yang menggabungkan kegiatan bisnis dengan tujuan sosial, yaitu menyediakan makanan bergizi sambil memberdayakan ekonomi masyarakat.'),
(412, 400, 'P7.12', 'Sebutkan lima metode pengolahan makanan dan pengaruhnya terhadap kandungan gizi!', 'Rebus: Mengurangi vitamin B dan C karena larut air.       Kukus: Mempertahankan vitamin lebih baik daripada merebus.        Tumis: Menjaga vitamin larut lemak (A, D, E, K), tapi tergantung jumlah minyak.     Goreng: Dapat merusak vitamin/mineral karena suhu tinggi.    Panggang/Bakar: Vitamin B bisa hilang, tapi gizi lain relatif aman jika dilakukan dengan baik.'),
(413, 400, 'P7.13', 'Apakah yang dimaksud DASHAT', 'DASHAT adalah singkatan dari Dapur Sehat Atasi Stunting. Merupakan kegiatan pemberdayaan masyarakat dalam upaya pemenuhan gizi seimbang bagi keluarga beresiko stunting melalui sumberdaya lokal yang dipadukan dengan sumberdaya/kontribusi kemitraan lainnya'),
(414, NULL, 'P8', 'Elsimil', NULL),
(415, 414, 'P8.1', 'Apa itu Elsimil?', 'Aplikasi skrining dan pendampingan bagi calon pengantin, ibu hamil, ibu pasca persalinan, pasangan usia subur, dan baduta'),
(416, 414, 'P8.2', 'Siapa saja pihak yang dapat menggunakan Elsimil?', 'Calon pengantin, pasangan usia subur, ibu hamil, ibu pasca persalinan, baduta'),
(417, 414, 'P8.3', 'Dalam program Elsimil, apa kontribusi BKKBN untuk calon pengantin?', 'Menyediakan aplikasi Elsimil untuk skrining kesehatan calon pengantin dan memberikan rekomendasi perbaikan sebelum menikah.'),
(418, 414, 'P8.4', 'Cara Unduh Aplikasi Elsimil V3', 'Aplikasi Elsimil V3 dapat diunduh di Playstore dengan dengan kata kunci SIKA MOBILE  atau melalui tautan https://play.google.com/store/apps/details?id=com.bkkbn.elsimilsiga&hl=en-US&pli=1'),
(419, 414, 'P8.5', 'Aplikasi Elsimil Catin', 'Aplikasi Elsimil Catin menggunakan Elsimil V3 yang dapat diunduh di Playstore.'),
(420, 414, 'P8.6', 'Aplikasi Elsimil TPK', 'Aplikasi Elsimil TPK menggunakan Elsimil V3 yang dapat diunduh di Playstore.'),
(421, 414, 'P8.7', 'Cara mendapatkan user Elsimil bagi TPK', 'Hubungi PKB/PLKB/Balai Penyuluh KB Kapanewon/Kecamatan/Kelurahan.'),
(422, 414, 'P8.8', 'Wilayah kerja Elsimil TPK tidak sesuai/ada yang tidak muncul', 'Cek ID KTP TPK di SIGA. Jika wilayahnya ada di TPK lain, hubungi admin untuk perbaikan wilayah agar sesuai.'),
(423, 414, 'P8.9', 'Cara registrasi Elsimil Catin mandiri', 'Klik tombol Daftar, isi data sampai langkah terakhir, klik Daftar, lalu lakukan verifikasi email.'),
(424, 414, 'P8.10', 'Registrasi Catin di Elsimil gagal: Application Exception', 'Biasanya karena gangguan jaringan atau kesalahan notifikasi. Coba login ulang menggunakan email dan password terdaftar. Jika masih gagal, hubungi TPK sesuai alamat catin perempuan.'),
(425, 414, 'P8.11', 'Solusi jika catin mengalami kendala login Elsimil', 'Hubungi PKB/PLKB atau TPK untuk dilakukan reset akun menggunakan akun TPK sesuai alamat catin perempuan.'),
(426, 414, 'P8.12', 'Solusi jika catin mengalami kendala input data di Elsimil', 'Hubungi PKB/PLKB atau TPK untuk dilakukan pendampingan dan pengecekan data wilayah.'),
(427, 414, 'P8.13', 'Solusi jika catin mengalami kendala unduh sertifikat Elsimil', 'Hubungi PKB/PLKB atau TPK untuk dilakukan pembaruan data atau pengulangan proses sinkronisasi.'),
(428, 414, 'P8.14', 'Solusi jika terjadi salah input data di Elsimil Catin', 'Data dapat diedit menggunakan akun catin atau TPK sesuai alamat catin perempuan.'),
(429, 414, 'P8.15', 'Langkah edit data Elsimil Catin oleh TPK', 'Login > Catin > Data Catin > Edit Catin (ikon kertas hijau) > Riwayat Kunjungan → Lakukan edit data sekaligus input pendampingan.'),
(430, 414, 'P8.16', 'Langkah unduh sertifikat Elsimil Catin oleh TPK', 'Login > Catin > Data Catin > Edit Catin (ikon kertas hijau) > Unduh Sertifikat.'),
(431, 414, 'P8.17', 'Data Tidak Ditemukan di Elsimil Data Bumil', 'Data bumil pada modul Bumil menampilkan data yang telah dilakukan input pendampingan bumil baik yang berstatus masa pendampingan atau yang telah melahirkan.'),
(432, 414, 'P8.18', 'Data Sasaran Bumil tidak muncul di Elsimil modul Bumil', 'Cek Data Sasaran Bumil. Klik ikon pensil untuk mulai melakukan input data pendampingan ibu hamil.'),
(433, 414, 'P8.19', 'Data Tidak Ditemukan di Elsimil Data Baduta', 'Cek Data Sasaran Baduta. Klik ikon pensil untuk melakukan input pendampingan Baduta.'),
(434, 414, 'P8.20', 'Data Sasaran Baduta tidak muncul di Elsimil modul Baduta', 'Cek data keluarga di Elsimil Verwal atau Rekapitulasi Data Keluarga SIGA. Jika status bumil sudah “Melahirkan”, maka Baduta akan muncul otomatis.'),
(435, 414, 'P8.21', 'Data Elsimil atau Verwal tidak muncul', 'Coba lakukan sinkronisasi ulang, pastikan jaringan internet stabil, atau hubungi admin wilayah jika masih belum muncul.'),
(436, 414, 'P8.22', 'Penjelasan ikon di aplikasi Elsimil Verwal', 'Panduan lengkap ikon dapat diakses di: https://rfan.cyou/penjelasan-icon-di-aplikasi-elsimil-verval/'),
(437, 414, 'P8.23', 'Core data keluarga jika tidak muncul di Keluarga Sasaran Elsimil Verwal', '1) Login ke Elsimil Verwal, cek Data Keluarga di SIGA. \n2) Pastikan status perkawinan terisi. \n3) Lakukan verifikasi data ulang jika belum tersinkron.'),
(438, 414, 'P8.24', 'Data bumil atau baduta hilang/tidak terinput di SIGA padahal sudah input di Elsimil', 'Data akan tersinkron otomatis setelah beberapa saat, atau bisa dilakukan sinkronisasi manual via SIGA oleh admin wilayah.'),
(439, 414, 'P8.25', 'Akses tabulasi data input pendampingan Elsimil', 'Tabulasi hasil pendampingan Elsimil dapat diakses melalui SIGA. Jika tidak memiliki user login, bisa diakses melalui SIGA PUBLIK: https://new.siga-bkkbn.go.id/#/tabulasi/siga.'),
(440, 414, 'P8.26', 'Cara mengubah dari catin ke bumil', 'Untuk mengubah catin menjadi sasaran bumil di Elsimil, lakukan verval terlebih dahulu. \nEdit data keluarga melalui icon edit (pensil) di tab Sasaran Gerting atau Semua Keluarga, lalu ubah status pengisian menjadi Ya dan simpan.'),
(441, 414, 'P8.27', 'Ada data dobel pada Data Sasaran, apa yang harus dilakukan?', 'Buka Elsimil - Verval, cari data yang dobel tersebut. Cek secara detail satu per satu, termasuk cek NIK, Nama, Istri, dan semua anggota-anggota keluarga lainnya.\n \n Jika ternyata isinya persis sama baik Kepala Keluarga maupun semua anggota keluarga lainnya, \n maka pilih salah satu untuk diverval dengan status “Keluarga Ada”, dan sisanya diverval dengan status “Keluarga Tidak Ditemukan”.\n \n Jika ternyata nama Kepala Keluarganya sama, namun NIK-nya berbeda, istri dan anggota lainnya juga berbeda, berarti itu adalah kondisi dimana kebetulan saja nama Kepala Keluarganya sama tetapi sebenarnya bukan orang yang sama,\n maka tiap data Keluarga tersebut harus diverval sendiri-sendiri, karena anggota keluarganya berbeda.\n \n Jika ternyata nama Kepala Keluarga dan NIK sama, namun nama istrinya berbeda, berarti itu adalah kondisi dimana seorang suami memiliki lebih dari 1 istri,\n maka tiap data Keluarga tersebut harus diverval sendiri-sendiri, karena anggota keluarganya berbeda.\n \n Jika ada salah satu data Keluarga yang isinya paling lengkap, sedangkan data Keluarga yang lainnya tidak lengkap (misal: hanya ada Kepala Keluarganya saja),\n maka keluarga yang ditemukan isi datanya paling lengkap tersebut diverval dengan status “Keluarga Ada”, dan sisanya diverval dengan status “Keluarga Tidak Ditemukan”.'),
(442, NULL, 'P9', 'GDPK', NULL),
(443, 442, 'P9.1', 'Apa definisi dari Grand Design Pembangunan Kependudukan (GDPK)?', 'Grand Design Pembangunan Kependudukan (GDPK) adalah kerangka utama atau rencana induk pembangunan yang memuat visi, misi, arah kebijakan, tujuan dan sasaran pembangunan di bidang kependudukan untuk jangka waktu 25 tahun, yang diderivasi dari RPJPN dan menjadi acuan dalam penyusunan roadmap pembangunan kependudukan.'),
(444, 442, 'P9.2', 'Apa dasar hukum Grand Design Pembangunan Kependudukan (GDPK)?', 'Peraturan Presiden No. 153 Tahun 2014 tentang GDPK'),
(445, 442, 'P9.3', 'Apa saja lima pilar utama dalam Grand Design Pembangunan Kependudukan menurut Peraturan Presiden No. 153 Tahun 2014?', 'Lima pilar utama dalam GDPK adalah:\n 1. Pengendalian kuantitas penduduk,\n 2. Peningkatan kualitas penduduk,\n 3. Pembangunan keluarga,\n 4. Penataan persebaran dan pengarahan mobilitas penduduk,\n 5. Penataan administrasi dan data kependudukan.'),
(446, 442, 'P9.4', 'Apa peran GDPK dalam perencanaan pembangunan kependudukan di daerah?', 'GDPK berperan sebagai dokumen strategis yang menjadi rujukan bagi pemerintah daerah dalam menyusun kebijakan, strategi, dan program kependudukan. GDPK juga mendukung integrasi antara perencanaan pusat dan daerah dalam kurun waktu 25 tahun, melalui tahapan lima tahunan (roadmap).'),
(447, 442, 'P9.5', 'Apa definisi Peta Jalan Pembangunan Kependudukan?', 'Peta Jalan Pembangunan Kependudukan adalah dokumen operasionalisasi GDPK selama 5 tahun yang memuat analisis situasi kependudukan, kebijakan dan strategi, sasaran, indikator, target per tahun, dan rencana aksi untuk mencapai target pembangunan kependudukan.'),
(448, 442, 'P9.6', 'Bagaimana kedudukan/internalisasi Peta Jalan Pembangunan Kependudukan dalam pembangunan kependudukan di daerah?', 'Muatan dalam dokumen Peta Jalan Pembangunan Kependudukan perlu diinternalisasikan ke dalam dokumen perencanaan pembangunan daerah yaitu RPJMD, RKPD, Renstrada dan Renja Perangkat Daerah dari sejak persiapan penyusunan sampai dengan penetapan dokumen RPJMD dan RKPD'),
(449, 442, 'P9.7', 'Bagaimana perkembangan GDPK  yang ada di DIY baik tingkat provinsi maupun kabupaten/kota?', 'Seluruh pemerintah daerah baik provinsi maupun kabupaten/kota yang ada di DIY sudah menyusun GDPK 5 Pilar dengan periode sebagai berikut : \n1. Provinsi DIY : 2023 - 2045 (review pada tahun 2022)\n2. Kabupaten Kulon Progo : 2018 - 2035 \n3. Kabupaten Bantul : 2018 - 2035 \n4. Kabupaten Gunungkidul : 2023 - 2045  (review pada tahun 2023)\n5. Kabupaten Sleman : 2022 - 2045 (review pada tahun 2022)\n6. Kota Yogyakarta : 2020 - 2045 (review pada tahun 2024)'),
(450, 442, 'P9.8', 'Bagaimana legalitas dokumen GDPK  yang ada di DIY baik tingkat provinsi maupun kabupaten/kota?', 'Dokumen GDPK yang telah memiliki legalitas baik berupa Peraturan Daerah maupun Peraturan Kepala Daerah baru di tingkat provinsi dan 2 kabupaten sebagai berikut : \n1. Peraturan Gubernur Nomor 20 Tahun 2024 untuk Dokumen GDPK DIY\n2. Peraturan Bupati Nomor 53 Tahun 2018 untuk Dokumen GDPK Kab. Kulon Progo \n3. Peraturan Daerah Nomor 4 Tahun 2022 untuk Dokumen GDPK Kab. Sleman'),
(451, NULL, 'P10', 'Gizi Seimbang', NULL),
(452, 451, 'P10.1', 'Apa itu Stunting-Obesitas?', 'Stunting-obesitas (stunted-obesity) adalah obesitas yang terjadi pada anak stunting, Anak stunting bisa mengalami obesitas juga dipengaruhi oleh faktor risiko obesitas, yakni kurangnya aktivitas fisik, konsumsi makanan yang tinggi lemak dan karbohidrat, dan kebiasaan makan makanan cepat saji.'),
(453, 451, 'P10.2', 'Apa itu Gizi Seimbang?', 'Gizi Seimbang adalah susunan makanan sehari-hari yang mengandung zat gizi dalam jenis dan jumlah yang sesuai kebutuhan tubuh, dengan tetap memperhatikan aktivitas fisik, perilaku hidup bersih, dan pemantauan berat badan.'),
(454, 451, 'P10.3', 'Apa saja pilar Gizi Seimbang?', '1) Makan beragam makanan, 2) Aktivitas fisik, 3) Perilaku hidup bersih, 4) Memantau berat badan.'),
(455, 451, 'P10.4', 'Mengapa penting menerapkan Gizi Seimbang?', 'Untuk menjaga kesehatan, mencegah penyakit, mendukung pertumbuhan, dan meningkatkan kualitas hidup'),
(456, 451, 'P10.5', 'Apa perbedaan Gizi Seimbang dan 4 Sehat 5 Sempurna?', 'Gizi Seimbang lebih kompleks, mencakup porsi, aktivitas fisik, dan kebersihan, bukan sekadar jenis makanan'),
(457, 451, 'P10.6', 'Kapan konsep Gizi Seimbang mulai dikenalkan di Indonesia?', 'Tahun 1995, menggantikan konsep 4 Sehat 5 Sempurna.'),
(458, 451, 'P10.7', 'Apa tujuan memantau berat badan secara teratur?', 'Untuk memastikan berat badan tetap dalam rentang normal dan mencegah obesitas atau malnutrisi.'),
(459, 451, 'P10.8', 'Apa peran susu dalam Gizi Seimbang?', 'Menyediakan kalsium, vitamin D, dan protein untuk kesehatan tulang.'),
(460, NULL, 'P11', 'IPeKB Indonesia', NULL),
(461, 460, 'P11.1', 'Apa saja ruang lingkup kewenangan IPeKB Indonesia?', 'Menetapkan kode etik, advokasi terkait Penyuluh KB, serta memberikan rekomendasi atas pelanggaran kode etik.'),
(462, NULL, 'P12', 'Informasi Gizi', NULL),
(463, 462, 'P12.1', 'Definisi Gizi', 'Gizi adalah ilmu yang mempelajari tentang nutrisi dan zat-zat yang terkandung dalam makanan yang dibutuhkan oleh tubuh untuk pertumbuhan, perkembangan, dan pemeliharaan kesehatan.'),
(464, 462, 'P12.2', 'Jenis-jenis Nutrisi untuk dikatakan bergizi mengandung apa saja', 'Karbohidrat: Sumber energi utama bagi tubuh; Protein: Penting untuk pertumbuhan dan perbaikan jaringan tubuh; Lemak: Sumber energi dan membantu penyerapan vitamin; Vitamin: Penting untuk berbagai fungsi tubuh, seperti metabolisme dan kekebalan tubuh; Mineral: Penting untuk berbagai fungsi tubuh, seperti pembentukan tulang dan fungsi otot.'),
(465, 462, 'P12.3', 'Dampak Kekurangan Gizi', 'Kekurangan gizi dapat menyebabkan berbagai masalah kesehatan, seperti: Kekurangan energi: Kelelahan, kelemahan, dan penurunan produktivitas; Kekurangan protein: Pertumbuhan terhambat, penurunan massa otot, dan edema; Kekurangan vitamin dan mineral: Berbagai masalah kesehatan, seperti anemia, osteoporosis, dan gangguan penglihatan.'),
(466, 462, 'P12.4', 'Apa yang dimaksud dengan makan beraneka ragam makanan?', 'Mengonsumsi berbagai jenis makanan agar zat gizi yang dibutuhkan tubuh tercukupi.'),
(467, 462, 'P12.5', 'Kenapa aktivitas fisik penting dalam Gizi Seimbang?', 'Untuk membakar kalori, menjaga berat badan ideal, dan meningkatkan metabolisme tubuh.'),
(468, 462, 'P12.6', 'Mengapa perilaku hidup bersih menjadi bagian dari Gizi Seimbang?', 'Untuk mencegah infeksi yang dapat mengganggu penyerapan zat gizi.'),
(469, 462, 'P12.7', 'Apa contoh perilaku hidup bersih?', 'Cuci tangan, menjaga kebersihan makanan, kebersihan diri, dan lingkungan.'),
(470, 462, 'P12.8', 'Apa itu makanan pokok?', 'Sumber energi utama seperti nasi, roti, jagung, singkong.'),
(471, 462, 'P12.9', 'Apa fungsi lauk pauk?', 'Sebagai sumber protein, baik nabati maupun hewani.'),
(472, 462, 'P12.10', 'Mengapa sayuran penting?', 'Sumber vitamin, mineral, dan serat.'),
(473, 462, 'P12.11', 'Apa manfaat buah-buahan dalam diet Gizi Seimbang?', 'Memberi asupan vitamin, mineral, dan antioksidan.'),
(474, 462, 'P12.12', 'Apa itu \"Isi Piringku\"?', 'Pedoman visual untuk pembagian makanan dalam satu piring: 50% sayur dan buah, 50% makanan pokok dan lauk.'),
(475, 462, 'P12.13', 'Berapa persen porsi sayuran dalam Isi Piringku?', '35% dari isi piring.'),
(476, 462, 'P12.14', 'Berapa persen porsi buah dalam Isi Piringku?', '15% dari isi piring.'),
(477, 462, 'P12.15', 'Berapa persen makanan pokok dalam Isi Piringku?', '35%.'),
(478, 462, 'P12.16', 'Berapa persen lauk-pauk dalam Isi Piringku?', '0.15'),
(479, 462, 'P12.17', 'Apa itu zat gizi makro?', 'Zat gizi yang dibutuhkan dalam jumlah besar seperti karbohidrat, protein, dan lemak.'),
(480, 462, 'P12.18', 'Apa itu zat gizi mikro?', 'Vitamin dan mineral yang dibutuhkan dalam jumlah kecil tetapi penting untuk kesehatan.'),
(481, 462, 'P12.19', 'Apa sumber utama karbohidrat?', 'Nasi, roti, kentang, jagung.'),
(482, 462, 'P12.20', 'Apa contoh sumber protein hewani?', 'Daging, ikan, telur, susu.'),
(483, 462, 'P12.21', 'Apa contoh sumber protein nabati?', 'Tempe, tahu, kacang-kacangan'),
(484, 462, 'P12.22', 'Berapa lama aktivitas fisik minimal untuk orang dewasa per minggu?', '150 menit aktivitas intensitas sedang'),
(485, 462, 'P12.23', 'Apa contoh aktivitas fisik intensitas sedang?', 'Jalan cepat, bersepeda santai, berenang'),
(486, 462, 'P12.24', 'Apa indikator berat badan ideal?', 'Indeks Massa Tubuh (IMT) antara 18,5–24,9'),
(487, 462, 'P12.25', 'Bagaimana cara menghitung IMT?', 'Berat badan (kg) dibagi kuadrat tinggi badan (m²).'),
(488, 462, 'P12.26', 'Apa risiko IMT di atas normal?', 'Peningkatan risiko diabetes, hipertensi, jantung koroner');
INSERT INTO `faq` (`id`, `parent_id`, `key_name`, `question_text`, `answer_text`) VALUES
(489, 462, 'P12.27', 'Apa itu obesitas?', 'Kondisi kelebihan lemak tubuh akibat ketidakseimbangan antara asupan energi dan pengeluaran energi'),
(490, 462, 'P12.28', 'Apa itu wasting?', 'Kondisi berat badan sangat rendah dibandingkan tinggi badan'),
(491, 462, 'P12.29', 'Berapa kali makan ideal dalam sehari?', '3 kali makan utama dan 2 kali selingan'),
(492, 462, 'P12.30', 'Kenapa sarapan penting?', 'Memberikan energi untuk memulai aktivitas dan mencegah makan berlebihan di siang hari.'),
(493, 462, 'P12.31', 'Apa contoh camilan sehat?', 'Buah segar, yoghurt rendah lemak, kacang tanpa garam'),
(494, 462, 'P12.32', 'Berapa banyak air yang harus dikonsumsi setiap hari?', 'Sekitar 2 liter atau 8 gelas per hari'),
(495, 462, 'P12.33', 'Apa bahaya konsumsi makanan tinggi gula dan garam berlebihan?', 'Risiko diabetes, hipertensi, dan obesitas meningkat.'),
(496, 462, 'P12.34', 'Mengapa balita membutuhkan Gizi Seimbang?', 'Untuk mendukung pertumbuhan optimal dan perkembangan otak'),
(497, 462, 'P12.35', 'Apa kebutuhan khusus gizi pada ibu hamil?', 'Asupan zat besi, kalsium, asam folat lebih tingg'),
(498, 462, 'P12.36', 'Bagaimana prinsip gizi seimbang pada lansia?', 'Makan makanan rendah garam, cukup serat, dan kaya nutrisi mikro'),
(499, 462, 'P12.37', 'Kenapa remaja butuh perhatian khusus terhadap Gizi Seimbang?', 'Karena fase pubertas meningkatkan kebutuhan energi dan zat gizi'),
(500, 462, 'P12.38', 'Bagaimana Gizi Seimbang mencegah diabetes?', 'Dengan mengontrol asupan karbohidrat sederhana dan memperbanyak serat'),
(501, 462, 'P12.39', 'Apa hubungan Gizi Seimbang dan kesehatan jantung?', 'Mengurangi lemak jenuh dan memperbanyak konsumsi buah, sayur, serta ikan'),
(502, 462, 'P12.40', 'Bagaimana Gizi Seimbang membantu mencegah kanker?', 'Antioksidan dalam buah dan sayur membantu melawan radikal bebas'),
(503, 462, 'P12.41', 'Bagaimana cara membantu anggota keluarga yang mengalami kecemasan?', 'Mendengarkan tanpa menghakimi, memberi dukungan emosional, dan mendorong mereka untuk mencari bantuan profesional jika perlu'),
(504, 462, 'P12.42', 'Bagaimana cara mendukung anggota keluarga yang mengalami kecanduan?', 'Menawarkan dukungan tanpa menghakimi, dan membantu mereka mencari bantuan profesional atau kelompok pendukung.'),
(505, 462, 'P12.43', 'Bagaimana cara membantu anak menghadapi perceraian orang tua?', 'Menyediakan dukungan emosional, berbicara dengan mereka secara terbuka tentang perasaan mereka, dan tetap menjaga rutinitas'),
(506, 462, 'P12.44', 'Apa peran BKKBN dalam penyediaan informasi gizi kepada keluarga?', 'Menyediakan edukasi gizi seimbang untuk berbagai siklus kehidupan keluarga.'),
(507, NULL, 'P13', 'Jabatan Fungsional Penyuluh KB', NULL),
(508, 507, 'P13.1', 'Pelaksana Pengumpulan data Pendataan Keluarga di lapangan dilakukan oleh siapa?', 'Kader'),
(509, 507, 'P13.2', 'Apa yang dimaksud Penyuluh Keluarga Berencana?', 'Penyuluh KB merupakan salah satu jabatan fungsional yang pembinaannya \n berada di bawah BKKBN, dimana salah satu indikator pencapaian kinerja mereka \n dibuktikan dengan pencapaian angka kredit dalam tiap tahunnya.'),
(510, 507, 'P13.3', 'Apa yang dimaksud dengan Program Bangga Kencana?', 'Program Bangga Kencana adalah program pelayanan masyarakat dalam mewujudkan penduduk tumbuh seimbang dan menjadikan manusia berkualitas.'),
(511, 507, 'P13.4', 'Penyuluh KB harus memiliki kompetensi dasar dalam melaksanakan tugas dan \n fungsinya. Kompetensi dasar tersebut terdiri dari?', 'Kompetensi dasar tersebut terdiri dari kompetensi teknis, kompetensi \n manajerial dan kompetensi sosial kultural'),
(512, 507, 'P13.5', 'Melaksanakan Advokasi, KIE, dan Penggerakan Program Bangga\n Kencana merupakan salah satu kompetensi apa bagi PKB?', 'Kompetensi teknis'),
(513, 507, 'P13.6', 'Integritas, inovatif, berfikir analisis dan berorientasi pada pelayanan merupakan beberapa kompetensi yang harus dimiliki PKB, tergolong dalam kompetensi apa bagi PKB?', 'Kompetensi manajerial'),
(514, 507, 'P13.7', 'Sebutkan yang termasuk kompetensi sosial kultural bagi PKB!', 'Wawasan Kebangsaan, mengelola keberagaman agama, suku dan budaya'),
(515, 507, 'P13.8', 'Apa yang dimaksud tugas jabatan penyuluh KB?', 'Tugas jabatan Penyuluh KB adalah melakukan pengelolaan Program Bangga \n Kencana yang meliputi penyuluhan, pelayanan, penggerakan dan pengembangan \n program di bidang pengendalian penduduk dan keluarga berencana.'),
(516, 507, 'P13.9', 'Sebutkan Peraturan BKKBN yang mengatur tentang Petunjuk Teknis Pelaksanaa Jabatan Fungsional Penyuluh Keluarga Berencana yang terbaru!', 'Peraturan Badan Kependudukan dan Keluarga Berencana Nasional Nomor 10 tahun 2023'),
(517, 507, 'P13.10', 'Sebutkan alasan seorang Penyuluh Keluarga Berencana dapat diberhentikan dari \n jabatannya!', 'a. mengundurkan diri dari jabatan; \n b. diberhentikan sementara sebagai pegawai negeri \n sipil; \n c. menjalani cuti di luar tanggungan negara; \n d. menjalani tugas belajar lebih dari 6 (enam) bulan; \n e. ditugaskan secara penuh pada jabatan pimpinan \n tinggi, jabatan administrator, jabatan pengawas, \n dan jabatan pelaksana; atau \n f. tidak memenuhi persyaratan sebagai Penyuluh \n Keluarga Berencana'),
(518, 507, 'P13.11', 'Pejabat Fungsional Penyuluh Keluarga Berencana mendapatkan tugas, tanggung\n jawab, dan wewenang pada 3 hal, sebutkan !', 'Pejabat Fungsional Penyuluh Keluarga Berencana diberi tugas, tanggung \n jawab, dan wewenang secara penuh untuk melaksanakan \n pengelolaan perkembangan kependudukan, pembangunan \n keluarga, dan keluarga berencana.'),
(519, 507, 'P13.12', 'Apa yang dimaksud perkembangan kependudukan yang menjadi tugas PKB di lapangan?', 'Perkembangan Kependudukan adalah kondisi yang berhubungan \n dengan perubahan keadaan kependudukan yang dapat \n berpengaruh dan dipengaruhi oleh keberhasilan pembangunan \n berkelanjutan.'),
(520, 507, 'P13.13', 'Apa yang dimaksud pembangunan keluarga yang menjadi tugas PKB di lapangan?', 'Pembangunan Keluarga adalah upaya mewujudkan keluarga \n berkualitas yang hidup dalam lingkungan yang sehat'),
(521, 507, 'P13.14', 'Apa yang dimaksud keluarga berencana yang menjadi tugas PKB di lapangan?', 'Keluarga Berencana adalah upaya mengatur kelahiran anak, jarak \n dan usia ideal melahirkan, mengatur kehamilan, melalui promosi, \n perlindungan, dan bantuan sesuai dengan hak reproduksi untuk \n mewujudkan keluarga yang berkualitas.'),
(522, 507, 'P13.15', 'Apa yang dimaksud penyuluhan yang menjadi program PKB di lapangan?', 'Penyuluhan adalah kegiatan penyampaian komunikasi, informasi,\n dan edukasi tentang Program dalam rangka meningkatkan\n pengetahuan, sikap, dan perilaku individu, keluarga, dan/atau\n masyarakat.'),
(523, 507, 'P13.16', 'Apa yang dimaksud pelayanan yang menjadi program PKB di lapangan?', 'Pelayanan adalah kegiatan pelayanan dan fasilitasi program untuk \n memenuhi kebutuhan individu, keluarga dan/atau masyarakat \n dalam Perkembangan Kependudukan, Pembangunan Keluarga, dan \n Keluarga Berencana.'),
(524, 507, 'P13.17', 'Apa yang dimaksud penggerakan yang menjadi program PKB di lapangan?', 'Penggerakan adalah kegiatan pengelolaan sumber daya yang ada \n untuk mencapai tujuan penduduk tumbuh seimbang dan keluarga \n berkualitas melalui program Perkembangan Kependudukan, \n Pembangunan Keluarga, dan Keluarga Berencana'),
(525, 507, 'P13.18', 'Apa yang dimaksud pengembangan yang menjadi program PKB di lapangan?', 'Pengembangan adalah proses meningkatkan atau menciptakan \n produk konseptual secara sistematis dan bertahap untuk mencapai \n model dalam Perkembangan Kependudukan, Pembangunan \n Keluarga, dan Keluarga Berencana.'),
(526, 507, 'P13.19', 'Bilamana ASN tidak memenuhi persayaratan diangkat sebagai sebagai Penyuluh Keluarga Berencana?', 'a. hasil predikat kinerja tahunan kurang atau sangat \n kurang dan tidak dapat menunjukkan perbaikan \n kinerja setelah diberikan kesempatan selama 6 \n (enam) bulan untuk memperbaiki kinerja; \n dan/atau : b. tidak dapat memenuhi standar kompetensi yang \n ditentukan pada jenjang jabatan fungsional \n Penyuluh Keluarga Berencana yang diduduki.'),
(527, 507, 'P13.20', 'Apakah seorang Penyuluh Keluarga Berencana dapat dipindahkan ke jabatan lain untuk kepentingan organisasi', 'Pasal 4 ayat 2 Peraturan Badan Kependudukan dan Keluarga Berencana Nomor 10 Tahun 2023 dapat dilakukan/ dipindahkan ke jabatan lain.'),
(528, 507, 'P13.21', 'sebutkan aturan yang menyebutkan bahwa Penyuluh Keluarga dilarang merangkap dengan jabatan administrasi', 'Pasal 4 ayat 1 Peraturan Badan Kependudukan dan Keluarga Berencana Nomor 10 Tahun 2023'),
(529, 507, 'P13.22', 'Apa nama Organisasi Profesi bagi ASN Penyuluh KB', 'Ikatan Penyuluh Keluarga Berencana Indonesia (IPeKB)'),
(530, 507, 'P13.23', 'Sebutkan peraturan BKKBN yang mengatur tentang Petunjuk Teknis Pelaksanaa Jabatan Fungsional Petugas Lapangan Keluarga Berencana yan terbaru!', 'Peraturan Badan Kependudukan dan Keluarga Berencana Nasional Nomor 9 tahun 2023'),
(531, 507, 'P13.24', 'Apa nama organisasi profesi bagi ASN Petugas Lapangan Keluarga Berencana?', 'Ikatan Penyuluh Keluarga Berencana Indonesia (IPeKB)'),
(532, 507, 'P13.25', 'Apa saja ruang lingkup jabatan PLKB?', 'ruang lingkup jabatan meliputi kegiatan Pencatatan dan Pelaporan, Komunikasi, \n Informasi, dan Edukasi, dan Pelayanan Program.'),
(533, 507, 'P13.26', 'Sebutkan jenjang Jabatan Fungsional PLKB Kategori Keterampilan dari jenjang terendah sampai enjang tertinggi !', 'a. PLKB Pemula; \n b. PLKB Terampil; \n c. PLKB Mahir; dan \n d. PLKB Penyelia.'),
(534, 507, 'P13.27', 'Sebutkan kegiatan-kegiatan dalam ruang\n lingkup jabatan PLKB Pemula!', 'a. memvalidasi data dalam Pendataan Keluarga dan\n pemutakhiran data keluarga;\n b. mendata kelompok kegiatan;\n c. mendata tempat Pelayanan Keluarga Berencana dan\n melaporkan melalui sistem berbasis teknologi dan informasi;\n d. mencatat dan melaporkan data hasil kegiatan melalui sistem\n berbasis teknologi dan informasi;\n e. mempromosikan Program secara langsung melalui kunjungan\n rumah;\n f. menyusun naskah media sederhana promosi Program;\n g. melakukan Komunikasi, Informasi, dan Edukasi secara\n perorangan;\n h. mendistribusikan alat obat kontrasepsi non metode\n kontrasepsi jangka panjang kepada akseptor atau peserta\n Keluarga Berencana aktif melalui fasilitas kesehatan;\n i. mendampingi ibu hamil untuk mendapatkan Pelayanan\n kesehatan; dan\n j. melakukan kemitraan dengan tokoh formal/informal'),
(535, 507, 'P13.28', 'Sebutkan kegiatan-kegiatan dalam ruang\n lingkup jabatan PLKB Terampil!', 'a. mendata sarana balai penyuluhan Keluarga Berencana melalui \n sistem informasi berbasis teknologi dan informasi; \n b. mendata institusi masyarakat pedesaan/perkotaan, pembantu \n pembina Keluarga Berencana desa/kelurahan, sub pembantu \n pembina Keluarga Berencana desa/kelurahan, dan/atau \n kelompok Keluarga Berencana melalui sistem berbasis \n teknologi informasi; \n c. mempromosikan Program melalui forum pertemuan; \n d. menyusun naskah media kompleks promosi Program; \n e. melakukan Komunikasi, Informasi, dan Edukasi secara \n kelompok; \n f. memfasilitasi Pelayanan alat kontrasepsi non metode \n kontrasepsi jangka panjang; \n g. mendampingi peserta Keluarga Berencana pasca persalinan \n baik secara metode kontrasepsi jangka panjang maupun non \n metode kontrasepsi jangka panjang; \n h. membentuk kelompok kegiatan, setara kelompok kegiatan \n dan/atau kelompok kegiatan penguatan lainnya pada \n Program; dan \n i. melakukan kemitraan dengan organisasi masyarakat \n dan/atau lintas sektor.'),
(536, 507, 'P13.29', 'Sebutkan kegiatan-kegiatan dalam ruang\n lingkup jabatan PLKB Mahir!', 'a. mengolah data kelompok kegiatan dan/atau setara kelompok \n kegiatan; \n b. menyusun rencana kebutuhan alat obat kontrasepsi di fasilitas \n kesehatan; \n c. membuat desain media sederhana promosi Program; \n d. melakukan Komunikasi, Informasi, dan Edukasi secara massa; \n e. memfasilitasi Pelayanan alat kontrasepsi dengan metode \n kontrasepsi jangka panjang; dan \n f. melakukan pembinaan terhadap institusi masyarakat \n pedesaan/perkotaan, pembantu pembina Keluarga Berencana \n desa/kelurahan, sub pembantu pembina Keluarga Berencana \n desa/kelurahan, dan/atau kelompok Keluarga Berencana, \n kelompok kegiatan dan/atau kelompok kegiatan sosial lainnya.'),
(537, 507, 'P13.30', 'Sebutkan kegiatan-kegiatan dalam ruang\n lingkup jabatan PLKB Penyelia!', 'a. mengolah data institusi masyarakat pedesaan/perkotaan, \n pembantu pembina Keluarga Berencana desa/kelurahan, sub \n pembantu pembina Keluarga Berencana desa/kelurahan, \n dan/atau kelompok Keluarga Berencana; \n b. menyusun Pencatatan dan Pelaporan hasil Pelayanan Keluarga \n Berencana di fasilitas kesehatan melalui sistem berbasis \n teknologi dan informasi; \n c. membuat desain media kompleks promosi Program; \n d. memfasilitasi Pelayanan KB pasca persalinan atau pasca \n keguguran dengan metode kontrasepsi jangka panjang; \n e. memfasilitasi Pelayanan komplikasi dan/atau kegagalan \n dengan metode kontrasepsi jangka panjang; dan- 12 - \n f. melakukan advokasi Program kepada para pemangku \n kepentingan'),
(538, 507, 'P13.31', 'Apa saja target output hasil kerja dari ruang lingkup kegiatan PLKB Pemula?', 'a. tersedianya rekap data yang valid dalam Pendataan Keluarga \n dan pemutakhiran data keluarga per 3 (tiga) bulan sekali pada \n kecamatan wilayah binaan; \n b. tersedianya data kelompok kegiatan; \n c. tersedianya data tempat Pelayanan Keluarga Berencana \n melalui sistem berbasis teknologi dan informasi; \n d. tersedianya data yang tercatat dan terlapor hasil kegiatan \n melalui sistem berbasis teknologi dan informasi; \n e. terselenggaranya kegiatan promosi Program melalui \n kunjungan rumah; \n f. tersedianya naskah media sederhana promosi Program dalam \n tingkat kecamatan sesuai substansi kegiatan; \n g. terselenggaranya kegiatan komunikasi, informasi dan edukasi \n secara perorangan untuk pasangan usia subur di tempat \n layanan Keluarga Berencana minimal 3 (tiga) pasangan usia \n subur setiap minggu; \n h. terselenggaranya distribusi alat obat kontrasepsi non metode \n kontrasepsi jangka panjang kepada akseptor atau peserta \n Keluarga Berencana aktif melalui fasilitas kesehatan; \n i. tersedianya data pendampingan ibu hamil untuk \n mendapatkan Pelayanan kesehatan; dan/atau \n j. terselenggaranya kegiatan kemitraan dengan tokoh \n formal/informal'),
(539, 507, 'P13.32', 'Apa saja target output hasil kerja dari ruang lingkup kegiatan PLKB Terampil?', 'a. tersedianya data sarana balai penyuluhan Keluarga Berencana\n melalui sistem informasi berbasis teknologi dan informasi;\n b. tersedianya data institusi masyarakat pedesaan/perkotaan\n yang meliputi pembantu pembina Keluarga Berencana\n desa/kelurahan, sub pembantu pembina Keluarga Berencana\n desa/kelurahan, dan/atau kelompok Keluarga Berencana\n melalui sistem berbasis teknologi informasi;\n c. terselenggaranya kegiatan promosi Program melalui forum\n pertemuan;\n d. tersedianya naskah media kompleks promosi Program;\n e. terselenggaranya kegiatan Komunikasi, Informasi, dan\n Edukasi secara kelompok;\n f. terselenggaranya fasilitasi Pelayanan alat kontrasepsi non\n metode kontrasepsi jangka panjang;\n g. terselenggaranya pendampingan peserta Keluarga Berencana\n pasca persalinan baik secara metode kontrasepsi jangka\n panjang maupun non metode kontrasepsi jangka panjang;\n h. terbentuknya kelompok kegiatan, setara kelompok kegiatan\n dan/atau kelompok kegiatan penguatan lainnya pada\n Program; dan/atau\n i. terselenggaranya kegiatan kemitraan dengan organisasi\n masyarakat dan/atau lintas sektor.'),
(540, 507, 'P13.33', 'Apa saja target output hasil kerja dari ruang lingkup kegiatan PLKB Mahir?', 'a. tersedianya hasil olah data kelompok kegiatan dan/atau setara \n kelompok kegiatan; \n b. tersedianya data rencana kebutuhan alat obat kontrasepsi di \n fasilitas kesehatan; \n c. tersedianya desain media sederhana promosi Program; \n d. terselenggaranya kegiatan Komunikasi, Informasi, dan \n Edukasi secara massa; \n e. terselenggaranya fasilitasi Pelayanan alat kontrasepsi dengan \n metode kontrasepsi jangka panjang; dan/atau \n f. terlaksananya pembinaan dan peningkatan kapasitas SDM \n pada institusi masyarakat pedesaan/perkotaan, pembantu \n pembina Keluarga Berencana desa/kelurahan, sub pembantu \n pembina Keluarga Berencana desa/kelurahan, dan/atau \n kelompok Keluarga Berencana, kelompok kegiatan dan/atau \n kelompok kegiatan sosial lainnya terhadap Program.'),
(541, 507, 'P13.34', 'Apa saja target output hasil kerja dari ruang lingkup kegiatan PLKB Penyelia?', 'a. tersedianya hasil olah data institusi masyarakat \n pedesaan/perkotaan, pembantu pembina Keluarga Berencana \n desa/kelurahan, sub pembantu pembina Keluarga Berencana \n desa/kelurahan, dan/atau kelompok Keluarga Berencana; \n b. tersedianya data yang tercatat dan terlapor hasil Pelayanan \n Keluarga Berencana di fasilitas kesehatan melalui sistem \n berbasis teknologi dan informasi; \n c. tersedianya desain media kompleks promosi Program; \n d. terselenggaranya fasilitasi Pelayanan Keluarga Berencana \n pasca persalian atau pasca keguguran dengan metode \n kontrasepsi jangka panjang; \n e. terselenggaranya fasilitasi Pelayanan komplikasi dan/atau \n kegagalan dengan metode kontrasepsi jangka panjang; \n dan/atau \n f. terselenggaranya advokasi Program kepada para pemangku \n kepentingan yang dirumuskan dalam bentuk memorandum of \n understanding/perjanjian kerja sama/kesepakatan kerja sama \n lainnya.'),
(542, 507, 'P13.35', 'Apa syarat kenaikan jenjang jabatan fungsional PLKB?', 'Kenaikan jenjang Jabatan Fungsional PLKB 1 (satu) tingkat lebih \n tinggi harus memenuhi Angka Kredit Kumulatif yang \n dipersyaratkan dan telah lulus dalam Uji Kompetensi Jabatan \n Fungsional PLKB pada jenjang jabatan yang akan diduduki.'),
(543, 507, 'P13.36', 'Apa yang dimaksud Uji Kompetensi jabatan fungsional PLKB?', 'Uji Kompetensi adalah proses pengukuran dan penilaian terhadap \n kompetensi teknis, manajerial, dan sosio kultural dari PLKB dalam \n melaksanakan tugas dan fungsi dalam jabatan'),
(544, 507, 'P13.37', 'Sebutkan ruang lingkup jabatan Penyuluh KB Ahli Pertama!', 'a. melaksanakan komunikasi, informasi, dan edukasi melalui\n media sosial dan media massa;\n b. menyusun instrumen pemantauan dan evaluasi;\n c. melaksanakan konseling Program secara perorangan;\n d. menyusun analisa dan evaluasi pasca Pelayanan non metode\n kontrasepsi jangka panjang;\n e. melaksanakan Pelayanan rujukan terkait komplikasi dan\n kegagalan;\n f. menyusun/mengembangkan materi terkait Program; dan\n g. menyusun profil keluarga, profil kelompok kegiatan atau profil\n setara kelompok kegiatan.'),
(545, 507, 'P13.38', 'Sebutkan ruang lingkup jabatan Penyuluh KB Ahli Muda!', 'a. melaksanakan pemantauan dan evaluasi Program; \n b. melaksanakan konseling Program secara kelompok; \n c. menyusun analisa pasca Pelayanan metode kontrasepsi jangka \n panjang dan evaluasi komplikasinya di fasilitas kesehatan; \n d. meningkatkan kapasitas institusi masyarakat \n pedesaan/perkotaan, pembantu pembina Keluarga Berencana \n desa, sub pembantu pembina Keluarga Berencana desa, \n kelompok Keluarga berencana, kader kelompok kegiatan \n dan/atau setara kelompok kegiatan; \n e. melaksanakan kemitraan dengan tokoh formal/informal dan \n organisasi masyarakat tingkat lokal dan regional; \n f. mengembangkan model kegiatan Program; \n g. mengembangkan media komunikasi, informasi, dan edukasi \n berbasis teknologi dan informasi; dan \n h. menyusun analisa hasil pendataan keluarga.'),
(546, 507, 'P13.39', 'Sebutkan ruang lingkup jabatan Penyuluh KB Ahli Madya!', 'a. melaksanakan promosi Program secara lokal dan regional; \n b. membuat inovasi model kegiatan Program; \n c. melaksanakan fasilitasi Pelayanan kelompok kegiatan; \n d. membentuk kelompok kegiatan percontohan dalam \n peningkatan Program; \n e. menyusun analisa dan merancang strategi percepatan \n Program; \n f. melaksanakan advokasi kepada mitra-mitra Program; dan \n g. menyusun rekomendasi hasil analisa pengembangan Program.'),
(547, 507, 'P13.40', 'Sebutkan ruang lingkup jabatan Penyuluh KB Ahli Utama!', 'a. melaksanakan promosi Program secara nasional; \n b. melaksanakan diseminasi data capaian Program; \n c. melaksanakan advokasi Program kepada pemangku \n kepentingan; \n d. melaksanakan kemitraan dengan tokoh formal/informal \n dan/atau organisasi masyarakat tingkat nasional dan \n internasional; \n e. menyusun inovasi berbasis teknologi informasi dalam \n mendukung percepatan Program; \n f. menyusun grand design Pembangunan Kependudukan dengan \n melibatkan mitra; dan \n g. merancang dan mengembangkan strategi kebijakan dalam \n percepatan pelaksanaan Program.'),
(548, 507, 'P13.41', 'Sebutkan hasil kerja dari ruang lingkup kegiatan Penyuluh KB Ahli Pertama!', 'a. terlaksananya komunikasi, informasi, dan edukasi melalui \n media sosial dan media massa; \n b. tersedianya instrumen pemantauan dan evaluasi; \n c. tersedianya data konseling Program secara perorangan; \n d. tersedianya hasil analisa dan evaluasi pasca Pelayanan non \n metode kontrasepsi jangka panjang; \n e. terlaksananya Pelayanan rujukan terkait komplikasi dan \n kegagalan; \n f. tersedianya materi pengembangan terkait Program; dan/atau \n g. tersedianya profil keluarga, profil kelompok kegiatan atau profil \n setara kelompok kegiatan.'),
(549, 507, 'P13.42', 'Sebutkan hasil kerja dari ruang lingkup kegiatan Penyuluh KB Ahli Muda!', 'a. terselenggaranya pemantauan dan evaluasi Program; \n b. tersedianya data konseling Program secara kelompok; \n c. tersedianya hasil analisa pasca Pelayanan metode kontrasepsi \n jangka panjang dan evaluasi komplikasinya di fasilitas \n kesehatan; \n d. tersedianya data peningkatan kapasitas institusi masyarakat \n pedesaan/perkotaan, pembantu pembina Keluarga Berencana \n desa, sub pembantu pembina Keluarga Berencana desa, \n kelompok Keluarga berencana, kader kelompok dan/atau \n setara kelompok kegiatan; \n e. terselenggaranya kegiatan kemitraan bersama tokoh \n formal/informal dan organisasi masyarakat tingkat lokal dan \n regional dalam berbagai kegiatan terkait Program; \n f. tersedianya model pengembangan kegiatan Program; \n g. tersedianya media komunikasi, informasi, dan edukasi \n berbasis teknologi dan informasi yang telah dikembangkan; \n dan/atau \n h. tersedianya data analisa hasil pendataan keluarga.'),
(550, 507, 'P13.43', 'Sebutkan hasil kerja dari ruang lingkup kegiatan Penyuluh KB Ahli Madya!', 'a. terselenggaranya kegiatan promosi Program secara lokal dan \n regional; \n b. terbentuknya inovasi model kegiatan Program; \n c. terselenggaranya fasilitasi Pelayanan kelompok kegiatan; \n d. terbentuknya kelompok kegiatan percontohan dalam \n peningkatan Program; \n e. tersedianya data analisa dan rancangan strategi percepatan \n Program; \n f. tersedianya memorandum of understanding dari hasil advokasi \n kepada mitra-mitra Program; dan/atau \n g. tersedianya data rekomendasi hasil analisa pengembangan \n Program.'),
(551, 507, 'P13.44', 'Sebutkan hasil kerja dari ruang lingkup kegiatan Penyuluh KB Ahli Utama!', 'a. terselenggaranya promosi Program secara nasional; \n b. terselenggaranya diseminasi data capaian Program dan hasil \n diseminasinya; \n c. tersedianya memorandum of understanding dari hasil advokasi \n Program kepada pemangku kepentingan; \n d. terselenggaranya kegiatan kemitraan bersama dengan tokoh \n formal/informal dan/atau organisasi masyarakat tingkat \n nasional dan internasional dalam berbagai kegiatan terkait \n Program; \n e. terbentuknya inovasi berbasis teknologi informasi dalam \n mendukung percepatan Program; \n f. terbentuknya grand design Pembangunan Kependudukan \n dengan melibatkan mitra; dan/atau \n g. terbentuknya rancangan dan strategi kebijakan dalam \n percepatan pelaksanaan Program.'),
(552, 507, 'P13.45', 'Sebutkan 10 Langkah Penyuluh KB', '. Pendekatan Tokoh Formal\n 2. Pendataan dan Pemetaan Sasaran\n 3. Pendekatan Tokoh Informal\n 4. Pembentukan Kesepakatan\n 5. Penguatan Hasil Kesepakatan\n 6. KIE/Penyuluhan bersama Tokoh Masyarakat\n 7. Pembentukan Grup Pelopor\n 8. Pemberian Pelayanan Teknis Terpadu\n 9. Pencatatan dan Pelaporan\n 10. Pembinaan dan Evaluasi'),
(553, NULL, 'P14', 'KBKR', NULL),
(554, 553, 'P14.1', 'Apa pentingnya USG kandungan?', 'USG kandungan penting untuk memantau perkembangan janin, mendeteksi kelainan, dan menentukan usia kehamilan.'),
(555, 553, 'P14.2', 'Kapan waktu yang tepat untuk USG kandungan?', 'Waktu yang tepat untuk USG kandungan bervariasi, biasanya dilakukan pada trimester pertama (11-14 minggu) dan trimester kedua (18-22 minggu).'),
(556, 553, 'P14.3', 'Apa itu tes kehamilan?', 'Tes kehamilan adalah prosedur untuk mendeteksi keberadaan hormon hCG (human chorionic gonadotropin) yang dihasilkan saat kehamilan.'),
(557, 553, 'P14.4', 'Kapan waktu yang tepat untuk tes kehamilan?', 'Waktu yang tepat untuk tes kehamilan adalah setelah terlambat menstruasi minimal satu minggu.'),
(558, 553, 'P14.5', 'Apa itu konseling pranikah?', 'Konseling pranikah adalah sesi konseling untuk pasangan yang akan menikah, membahas persiapan pernikahan, keluarga berencana, dan kesehatan reproduksi.'),
(559, NULL, 'P15', 'Kampung KB', NULL),
(560, 559, 'P15.1', 'Apa yang dimaksud Kampung Keluarga Berkualitas ?', 'Satuan wilayah  setingkat desa dimana terdapat  integrasi dan konvergensi  penyelenggaraan pemberdayaan dan  penguatan institusi keluarga dalam  seluruh dimensinya, guna  meningkatkan kualitas sumber daya  manusia, keluarga, dan masyarakat'),
(561, 559, 'P15.2', 'Apa yang menjadi dasar hukum pelaksanaan Optimalisasi Penyelenggaraan Kampung Keluarga Berkualitas ?', 'Instruksi Presiden Republik Indonesia Nomor 3 Tahun 2022'),
(562, 559, 'P15.3', 'Siapa saja yang diintruksikan untuk berperan aktif dalam optimalisasi penyelenggaraan Kampung Keluarga Berkualitas ?', '1. Menteri Koordinator Bidang Pembangunan Manusia dan Kebudayaan\n2. Menteri Dalam Negeri\n3. Menteri Agama\n4. Menteri Pendidikan, Kebudayaan, Riset, dan Teknologi\n5. Menteri Kesehatan\n6. Menteri Sosial\n7. Menteri Pekerjaan Umum dan Perumahan Rakyat\n8. Menteri Kelautan dan Perikanan\n9. Menteri Desa dan Pembangunan Daerah Tertinggal dan Transmigrasi\n10. Menteri Perencanaan Pembangunan Nasional/Kepala Badan Perencanaan Pembangunan Nasional\n11. Menteri Koperasi dan Usaha Kecil dan Menengah\n12. Menteri Pemberdayaan Perempuan dan Perlindungan Anak\n13. Kepala Badan Kependudukan dan Keluarga Berencana Nasional\n14. Gubernur\n15. Bupati/Wali Kota'),
(563, 559, 'P15.4', 'Berdasarkan Inpres Nomor 3 Tahun 2022, pengoptimalan penyelenggaran Kampung Keluarga Berkualitas dilakukan melalui apa saja ?', '1. Penyediaan data keluarga dan dokumen kependudukan; \n2. perubahan perilaku keluarga;\n3. peningkatan cakupan layanan dan rujukan pada keluarga;                                                                                                                                                  4. Penataan lingkungan keluarga'),
(564, 559, 'P15.5', 'Kementrian/ Lembaga mana saja yang berperan dan bertanggungjawab terhadap penyediaan data keluarga dan dokumen kependudukan di Kampung Keluarga Berkualitas ?', '1. BKKBN\n2. Kementerian Dalam Negeri\n3. Kementrian Desa dan Pembangunan Daerah Tertinggal dan Transmigrasi\n4. Pemerintah Provinsi \n5. Pemerintah Kabupaten/ Kota\n6. Pemerintah Desa'),
(565, 559, 'P15.6', 'Kementrian/ Lembaga mana saja yang berperan dan bertanggungjawab terhadap perubahan perilaku keluarga di Kampung Keluarga Berkualitas ?', '1. Kementerian Kesehatan \n2. BKKBN \n3. Kementerian Agama\n4. Menteri Pemberdayaan Perempuan dan Perlindungan Anak'),
(566, 559, 'P15.7', 'Kementrian/ Lembaga mana saja yang berperan dan bertanggungjawab terhadap peningkatan cakupan dan rujukan pada keluarga di Kampung Keluarga Berkualitas ?', '1. BKKBN\n2. Kementerian Kesehatan \n3. Kementerian Dalam Negeri \n4. Kementerian Sosial \n5. Pemerintah Provinsi \n6. Pemerintah Kabupaten/ Kota \n7. Kementerian pendidikan dan kebudayaan \n8. Kementerian Agama\n9. Kementerian Koperasi dan Usaha Kecil dan Menengah\n10. Kementerian Kelautan dan Perikanan'),
(567, 559, 'P15.8', 'Kementrian/ Lembaga mana saja yang berperan dan bertanggungjawab terhadap penataan lingkungan keluarga di Kampung Keluarga Berkualitas ?', '1. Kementerian Pekerjaan Umum dan Perumahan Rakyat\n2. Kementerian Desa dan Pembangunan Daerah Tertinggal dan Transmigrasi\n3. Pemerintah Daerah'),
(568, 559, 'P15.9', 'Seperti apakah struktur pokja Kampung Keluarga Berkualitas di tingkat Desa/ Kelurahan ?', 'Struktur pokja Kampung Keluarga Berkualitas di tingkat Desa/ Kelurahan minimal terdiri atas : 1. Pengarah, 2. Pelaksana, 3. Seksi Penyediaan Data dan Dokumen Kependudukan, 4. Seksi Perubahan Perilaku Keluarga, 5. Seksi Peningkatan Cakupan Pelayanan dan Rujukan pada Keluarga, 6. Seksi Penataan Lingkungan Keluarga dan Masyarakat'),
(569, 559, 'P15.10', 'Bagaimana cara untuk melihat profil Kampung Keluarga Berkualitas ?', 'Profil Kampung Keluarga Berkualitas (KKB) dapat dilihat di situs : kampungkb.bkkbn.go.id.'),
(570, 559, 'P15.11', 'Apa yang dimaksud dengan pencatatan dan pelaporan Kampung Keluarga Berkualitas ?', 'Kegiatan mendokumentasikan seluruh kegiatan yang dilaksanakan di Kampung Keluarga berkualitas, baik dalam bentuk tulisan, gambar, video dan mengunggahnya di website Kampung Keluarga Berkualitas melalui tautan https://kampungkb.bkkbn.go.id'),
(571, 559, 'P15.12', 'Apa yang dimaksud dengan Kelompok Kerja (Pokja) Kampung Keluarga Berkualitas ?', 'Pokja Kampung Keluarga\nBerkualitas adalah sekumpulan orang yang terpilih dan\nmewakili unsur masyarakat di Kampung Keluarga\nBerkualitas yang bertugas melaksanakan penggerakan\nindividu, keluarga, dan masyarakat.'),
(572, 559, 'P15.13', 'Bagaimanakah cara Pembentukan Kampung Keluarga Berkualitas di wilayah setingkat desa/kelurahan', 'Pembentukan Kampung Keluarga Berkualitas di wilayah\nsetingkat desa/kelurahan dilakukan melalui kegiatan:\na. sosialisasi;\nb. koordinasi;\nc. penetapan kebijakan;\nd. penyiapan sumber daya manusia; dan\ne. pembentukan Pokja Kampung Keluarga Berkualitas.'),
(573, 559, 'P15.14', 'Siapa yang melakukan pencatatan dan pelaporan Kampung Keluarga Berkualitas ?', 'Pencatatan dan pelaporan Kampung Keluarga Berkualitas dapat dilakukan oleh : 1). Pokja Kampung KB, 2). Penyuluh KB dan PLKB berdasarkan hasil pencatatan yang dilakukan oleh Pokja Kampung Keluarga Berkualitas., 3). Apabila tidak tersedianya Penyuluh KB dan PLKB pada desa/kelurahan Kampung Keluarga Berkualitas, pencatatan dan pelaporan dilakukan oleh petugas yang diberi wewenang oleh perangkat daerah yang membidangi urusan pengendalian penduduk dan/atau keluarga berencana berdasarkan hasil pencatatan yang dilakukan oleh Pokja Kampung Keluarga Berkualitas'),
(574, 559, 'P15.15', 'Berapa kali pencatatan dan pelaporan Kampung Keluarga Berkualitas dilakukan ?', 'Pencatatan dan Pelaporan dilaksanakan paling sedikit 1 (satu) kali dalam 1 (satu) bulan melalui website Kampung Keluarga Berkualitas https://kampungkb.bkkbn.go.id/.'),
(575, 559, 'P15.16', 'Pendanaan penyelenggaraan Kampung Keluarga Berkualitas bersumber dari mana ?', 'Pendanaan penyelenggaraan Kampung Keluarga Berkualitas bersumber dari: 1). anggaran pendapatan dan belanja negara, 2). anggaran pendapatan dan belanja daerah; dan/atau, 3). sumber lain yang sah dan tidak mengikat sesuai dengan ketentuan peraturan perundang-undangan.'),
(576, 559, 'P15.17', 'Susunan keanggotaan Pokja Kampung Keluarga Berkualitas tingkat Desa/Kelurahan ditetapkan melalui apa ?', 'Susunan keanggotaan Pokja Kampung Keluarga Berkualitas tingkat  Desa/ Kelurahan ditetapkan dengan keputusan kepala desa/lurah atau yang disebut dengan nama lain.'),
(577, 559, 'P15.18', 'Klasifikasi Kampung KB terdiri dari apa saja ?', 'Klasifikasi Kampung KB terdiri dari : 1). Dasar, 2). Berkembang, 3). Mandiri, dan 4). Berkelanjutan'),
(578, 559, 'P15.19', 'Apa saja yang menjadi penilaian indikator keberhasilan Kampung Keluarga Berkualitas ?', 'Indikator keberhasilan Kampung Keluarga Berkualitas dinilai dari Indeks Pembangunan Keluarga (iBangga). Selain itu, diharapkan dapat berkontribusi terhadap peningkatan Indeks Desa Membangun (IDM), penurunan angka kemiskinan dan jumlah kejadian Stunting.'),
(579, 559, 'P15.20', 'Mengapa Kampung Keluarga Berencana berubah menjadi Kampung Keluarga Berkualitas ?', 'Perubahan ini bertujuan untuk memperluas cakupan dan sasaran program dari wilayah tertentu menjadi seluruh desa dan kelurahan di Indonesia, serta lebih berfokus pada penguatan institusi keluarga dalam seluruh dimensinya untuk meningkatkan kualitas sumber daya manusia.'),
(580, 559, 'P15.21', 'Apa saja 3 Dimensi Indeks Pembangunan Keluarga (iBangga) ?', 'Indeks Pembangunan Keluarga (iBangga), yang mencakup 3 dimensi, yaitu: 1). Ketenteraman, 2). Kemandirian, 3).Kebahagiaan Keluarga'),
(581, 559, 'P15.22', 'Apa fungsi dari Rapat Koordinasi dalam pelaksanaan Kampung Keluarga Berkualitas ?', 'Untuk menyinkronkan program, membangun komitmen, menyepakati rencana kegiatan, serta mengevaluasi pelaksanaan program antar sektor dan pihak terkait.'),
(582, 559, 'P15.23', 'Apa saja program/kegiatan kementerian/lembaga yang bisa diintegrasikan ke dalam Kampung Keluarga Berkualitas ?', 'Beberapa contoh program atau kegiatan yang dapat diintegrasikan ke dalam Kampung Keluarga Berkualitas antara lain : 1). PKH (Kemensos), 2). STBM (Kemenkes), 3). Desa Mandiri (Kemendesa), 4). Desa Sakinah (Kemenag), 5). Kampung Iklim (KLHK), 6). Sanimas/Pamsimas (KemenPUPR) dan program lainnya'),
(583, NULL, 'P16', 'Kehamilan', NULL),
(584, 583, 'P16.1', 'Apakah pengertian jumlah anak lahir hidup?', 'Jumlah kelahiran bayi hidup dengan menunjukkan tanda-tanda kehidupan, seperti menangis, bernafas, atau bergerak, walaupun bayi yang dilahirkan hanya bertahan selama beberapa menit'),
(585, 583, 'P16.2', 'Berapa Angka Kematian Ibu (AKI) di Indonesia?', 'Angka Kematian Ibu (AKI) di Indonesia telah mengalami penurunan yang signifikan dari 346 per 100.000 kelahiran hidup pada tahun 2010 (hasil SP2010) menjadi 189 per 100.000 kelahiran hidup pada tahun 2020 (hasil Long Form SP2020) atau turun sebesar 45 persen dalam sepuluh tahun terakhir. Target RPJMN tahun 2024 untuk AKI sebesar 183 kematian per 100.000 kelahiran hidup. Sedangkan Target 3.1. Sustainable Development Goals (SDGs)  yaitu pada tahun 2030 mengurangi rasio AKI hingga kurang dari 70 kematian per 100.000 kelahiran hidup.'),
(586, 583, 'P16.3', 'Berapa Angka Kematian Bayi (AKB) di Indonesia?', 'Angka Kematian Bayi (AKB) di Indonesia mengalami penurunan dari 26 per 1.000 kelahiran hidup pada tahun 2010 (hasil SP2010) menjadi 16,85 per 1.000 kelahiran hidup pada tahun 2020 (hasil SP2020) (BPS, 2023). Meskipun demikian, untuk mencapai Target 3.2 pada SDGs, pelayanan kesehatan untuk anak dan pengurangan risiko penyebab kematian bayi juga perlu terus ditingkatkan.'),
(587, 583, 'P16.4', 'Berapa kenaikan berat badan ibu hamil yang ideal?', 'Rata-rata, berat badan ibu hamil akan naik sebanyak 11,5–16 kilogram selama masa kehamilan'),
(588, NULL, 'P17', 'Kelompok Kegiatan', NULL),
(589, 588, 'P17.1', 'Wadah bentukan BKKBN dalam pembinaan ketahanan keluarga remaja adalah', '1.Bina Ketahanan Remaja (BKR)\n2.Pusat Informasi dan Konseling Remaja (PIK Remaja)\n3.Generasi Berencana (GenRe)\n4.PIK Mahasiswa'),
(590, 588, 'P17.2', 'Dalam kategori kelompok kegiatan, apa saja jenis kelompok binaan yang dikelola oleh BKKBN?', 'BKB (Bina Keluarga Balita), BKR (Bina Keluarga Remaja), dan BKL (Bina Keluarga Lansia).'),
(591, NULL, 'P18', 'Keluarga Berencana', NULL),
(592, 591, 'P18.1', 'Apa yang dimaksud dengan Peserta keluarga berencana', 'pasangan usia subur (suami ataupun istri) yang pada saat pendataan sedang memakai atau menggunakan salah satu alat/cara kontrasepsi modern. Dalam pengertian ini tidak termasuk cara-cara kontrasepsi tradisional, seperti pijat urut, jamu dan juga tidak termasuk cara-cara KB alamiah seperti pantang berkala, senggama terputus dan sebagainya.'),
(593, 591, 'P18.2', 'Apa yang dimaksud dengan Peserta KB pemerintah', 'peserta KB yang memperoleh pelayana KB melalui tempat-tempat pelayanan pemerintah. Misalnya : Puskesmas, Fasilitas Kesehatan KB/Rumah Sakit Pemerintah.'),
(594, 591, 'P18.3', 'Apa yang dimaksud dengan Peserta KB Swasta', 'peserta KB yang memperoleh pelayanan KB melalui tempat-tempat pelayanan swasta. Misalnya : Praktik Dokter/Bidan Mandiri, Apotek, Toko Obat dan lain-lainnya.'),
(595, 591, 'P18.4', 'Apa yang dimaksud dengan Peserta KB Implant yang implantnya perlu dicabut.', 'peserta KB implant pada saat dilaksanakan Pendataan Keluarga implantnya perlu dicabut tahun depan.'),
(596, 591, 'P18.5', 'Apa yang dimaksud dengan Pasangan usia subur “Hamil”', 'Pasangan Usia Subur yang istrinya sedang hamil.'),
(597, 591, 'P18.6', 'Apa yang dimaksud dengan Pasangan usia subur bukan peserta KB “Ingin Anak Segera”', 'pasangan usia subur yang sedang tidak menggunakan salah satu alat/cara kontrasepsi dan masih menginginkan anak dengan batas Waktu kurang dari dua tahun.'),
(598, 591, 'P18.7', 'Apa yang dimaksud dengan Pasangan usia subur bukan peserta KB “Ingin Anak Tunda”', 'pasangan usia subur yang sedang tidak menggunakan salah satu alat/cara kontrasepsi dan menginginkan kelahiran anak ditunda dengan batas waktu dua tahun lebih.'),
(599, 591, 'P18.8', 'Apa yang dimaksud dengan Pasangan usia subur bukan peserta KB “Tidak Ingin Anak”', 'pasangan usia subur yang sedang tidak menggunakan salah satu alat/cara kontrasepsi dan tidak ingin anak.'),
(600, 591, 'P18.9', 'Apa itu Definisi Kehamilan Tidak Diinginkan/KTD pada Pasangan Usia Subur/PUS ?', 'KTD atau Kehamilan Tidak Diinginkan (unintended pregnancy) adalah kondisi kehamilan dimana salah satu pihak atau kedua belah pihak pasangan usia subur yang sebenarnya belum menginginkan atau sudah tidak menginginkan hamil lagi karena belum merencanakan kehamilan yang akan terjadi.'),
(601, 591, 'P18.10', 'Apa penyebab terjadinya Kehamilan Tidak Diinginkan/KTD pada Pasangan Usia Subur/PUS?', '1) Tidak menggunakan kontrasepsi meskipun metode kontrasepsi sudah tersedia namun masih ada keraguan dan tetap tidak ingin menggunakannya karena kurangnya pengetahuan terkait kontrasepsi (manfaat, jenis alat dan obat, serta cara pakai), faktor agama, budaya, dan sosial seperti keluarga tidak mengizinkan menggunakan kontrasepsi, kesulitan akses pelayanan kontrasepsi. 2) Kegagalan pemakaian kontrasepsi meskipun menggunakan metode yang paling efektif namun terdapat kemungkinan gagal karena berbagai faktor yaitu menggunakan metode kontrasepsi tradisional, kurangnya kepatuhan dalam menggunakan metode kontrasepsi jangka pendek, seperti lupa minum pil KB, penggunaan kontrasepsi tidak sesuai dengan kondisi kesehatan. 3) Unmeet Need yaitu tidak terpenuhinya kebutuhan ber-KB pada PUS yang sudah tidak ingin anak lagi. 4) Pemerkosaan. 5) Kurangnya pengetahuan kesehatan reproduksi tentang risiko melakukan hubungan seksual yang tidak aman.'),
(602, 591, 'P18.11', 'Apa dampak dari Kehamilan Tidak Diinginkan/ Pasangan Usia Subur/PUS?', 'Dampak dari KTD adalah meningkatnya resiko terjadinya aborsi yang tidak aman, terjadinya anemia pada ibu hamil, terjadinya kekurangan nutrisi pada ibu hamil dan janin, terjadinya bayi lahir prematur, terjadinya berat bayi lahir rendah (BBLR), meningkatnya peluang tidak memberikan ASI eksklusif pada bayi, kurangnya kasih sayang dan pengasuhan karena anak tidak diinginkan, terjadinya stunting, kondisi gagal tumbuh yang diakibatkan oleh adanya gangguan asupan gizi dalam waktu yang lama (kronis) pada 1000 hari pertama kehidupan (HPK), meningkatnya resiko kematian ibu dan anak.'),
(603, 591, 'P18.12', 'Bagaimana Cara Mencegah Kehamilan Tidak Diinginkan/KTD pada Pasangan Usia Subur/PUS?', '1) Merencanakan kehamilan dengan melakukan screening layak hamil untuk mengetahui kondisi 4 terlalu dan masalah kesehatan secara dini. 4 terlalu yaitu terlalu muda (usia ibu <20 tahun), terlalu tua (usia ibu >35 tahun), terlalu banyak (jumlah anak >2 orang), terlalu dekat (jarak kehamilan <3 tahun). 2) menggunakan alat/obat kontrasepsi secara tepat dan efesien untuk mencegah kehamilan.'),
(604, 591, 'P18.13', 'Bagaimana Jika Sudah Terjadi Kehamilan Tidak Diinginkan/KTD pada Pasangan Usia Subur/PUS?', 'Menerima kehamilannya, menjaga kehamilannya, memberikan dan saling mendukung dengan pasangan, melakukan konsultasi untuk mendapatkan konseling lebih lanjut dari petugas yang kompeten, memeriksakan kehamilan pada petugas kesehatan secara teratur, minimal 6 kali.'),
(605, 591, 'P18.14', 'Apa itu Definisi Kehamilan Tidak Diinginkan/KTD pada Remaja ?', 'KTD pada Remaja adalah kehamilan yang terjadi pada remaja tanpa adanya ikatan pernikahan umumnya menjadi masalah yang kompleks dan perlu menjadi perhatian yang serius. Kondisi kehamilan ini terjadi pada remaja usia 10-24 tahun.'),
(606, 591, 'P18.15', 'Apa Perilaku Berisiko pada Remaja yang Menyebabkan Kehamilan Tidak Diinginkan/KTD?', 'Perilaku yang menyebabkan terjadinya KTD pada Remaja adalah seks pranikah dan pemerkosaan.'),
(607, 591, 'P18.16', 'Apa Saja Karakteristik Remaja yang Perlu Diwaspadai ?', 'Ketidakstabilan emosi, senang mencoba sesuatu yang baru (bereksperimen dan bereksplorasi), adanya sikap melawan dan menantang orang tua (hubungan remaja dan orang tua kurang harmonis), kecenderungan membentuk kelompok teman sebaya, remaja masa terjadinya krisis identitas (masih proses mencari jati diri) sehingga mudah dipengaruhi lingkungan, kegelisahan, karena banyak yang diinginkan tetapi tidak mampu memenuhi (eksploitasi diri).'),
(608, 591, 'P18.17', 'Siapa Saja yang Berperan dalam Mencegah Kehamilan Tidak Diinginkan/KTD pada Remaja ?', 'Pencegahan KTD dapat dimulai dari peran remaja itu sendiri dengan menghargai dan bertanggungjawab terhadap diri sendiri, peran orang tua, peran pendidik/guru, dan penggunaan sosial media secara bijak'),
(609, 591, 'P18.18', 'Apa Ancaman/Risiko Kesehatan pada Remaja yang Mengalami Kehamilan Tidak Diinginkan/KTD?', 'Mengalami penyulit saat kehamilan: tekanan darah tinggi, anemia (kurang darah), dll, keguguran, mengalami penyulit saat persalinan: panggul sempit, pendarahan, dll, berisiko melahirkan bayi dengan kecacatan, bayi prematur, dan BBLR, melahirkan bayi yang berisiko stunting, risiko kematian janin dalam rahim, risiko kematian ibu, risiko tinggi terkena kanker leher rahim.'),
(610, 591, 'P18.19', 'Apa Dampak Kehamilan Tidak Diinginkan/KTD pada Remaja ?', 'Putus sekolah, mendapatkan sanksi sosial dari lingkungan sekitar, tekanan psikologis seperti stress hingga depresi, meninbgkatnya aborsi tidak aman yang dapat mengancam kesehatan, rentan mengaalmi gangguan kesehatan organ reproduksi, terjadinya kehamilan dan persalinan yang berisiko.'),
(611, 591, 'P18.20', 'Apakah benar jika mitos Jika anak rewel saat diberi ASI artinya ASI sedikit dan harus di ganti susu botol', 'Faktanya adalah ASI diproduksi sesuai dengan hisapan si bayi, jadi banyak atau sedikitnya ASI ditentukan oleh bayi itu sendiri. Bayi yang banyak minum ASI akan membuat produksi ASI meningkat. Tidak ada istilah ASI sedikit'),
(612, 591, 'P18.21', 'Apakah benar jika mitos ASI pertama (kolostrum) adalah ASI basi yang harus dibuang.', 'Faktanya adalah Kolostrum harus diberikan pada bayi karena memiliki antibodi yang dapat meningkatkan kekebalan tubuh'),
(613, 591, 'P18.22', 'Apa yang disebut kantung mani (vesikula seminaris) ?', 'Kantung yang memproduksi cairan untuk membentuk air mani. • Terdiri dari 2 buah'),
(614, 591, 'P18.23', 'Apa yang dimaksud kelenjar prostat ?', 'Memproduksi cairan encer yang berwarna putih menyerupai susu hingga keabu-abuan dan akan bersatu dengan cairan mani pada saat ejakulasi.'),
(615, 591, 'P18.24', 'Apa itu Bakti Sosial ?', 'Bakti Sosial adalah wujud pengabdian BKKBN dengan mitra kerja dalam memberikan kontribusi pembangunan bangsa melalui pelayanan KB dan kesehatan reproduksi.'),
(616, 591, 'P18.25', 'Apa itu Fasilitas Kesehatan ?', 'Fasilitas Kesehatan adalah fasilitas pelayanan kesehatan yang digunakan untuk menyelenggarakan upaya pelayanan kesehatan perorangan, baik promotif, preventif, kuratif maupun rehabilitatif yang dilakukan oleh Pemerintah, Pemerintah Daerah, dan atau masyarakat yang telah memiliki perjanjian kerja sama dengan BPJS kesehatan dan teregister dalam Sistem Informasi Manajemen (SIM) BKKBN.'),
(617, 591, 'P18.26', 'Apa itu Informed Consent ?', 'Informed Consent adalah persetujuan yang diberikan oleh calon peserta/peserta KB atau keluarganya atas dasar informasi dan penjelasan mengenai tindakan medis yang akan dilakukan terhadap calon peserta/peserta KB.'),
(618, 591, 'P18.27', 'Apa itu Mobil Unit Pelayanan (MUYAN) KB?', 'Mobil Unit Pelayanan (MUYAN) KB adalah fasilitas pelayanan KB bergerak yang dipergunakan oleh tim pelayanan kesehatan/KB terlatih, mencakup satu unit mobil guna mendapatkan akses pelayanan kepada masyarakat khususnya masyaralkat yang belum tersedia fasilitas kesehatan yang memenuhi syarat dan tidak tersedia tenaga media yang kompeten ataupun daerah yang memerlukan bantuan pelayanan KB bergerak seperti dalam rangka bakti sosial atau sejenisnya.'),
(619, 591, 'P18.28', 'Apa itu Pelayanan Keluarga Berencana Bergerak ?', 'Pelayanan Keluarga Berencana Bergerak adalah pelayana KB yang dilaksanakan disuatu daerah yang belum tersedia fasilitas kesehatan yang memenuhi syarat atau tidak tersedia tenaga media yang kompeten ataupu daerah yang memerlukan bantuan pelayanan KB bergerka seperti pelayanan dalam rangka bakti sosial atau sejenisnya dengan maksud mendekatakan akses pelayana KB yang bisa dilakukan dengan kunjungan pelayanan dan menggunakan fasilitas pelayanan KB bergerak (MUYAN KB).'),
(620, 591, 'P18.29', 'Apa itu Fasilitas Kesehatan Tingkat Pertama (FKTP) ?', 'Fasilitas Kesehatan Tingkat Pertama (FKTP) adalah fasilitas kesehatan yang termasuk didalamnya berupa puskesmas atau yang setara, praktik dokter, klinik pratama atau yang setara dan rumah sakit kelas D pratama atau setara.'),
(621, 591, 'P18.30', 'Apa itu Fasilitas Kesehatan Rujukan Tingkat Lanjutan (FKRTL) ?', 'Fasilitas Kesehatan Rujukan Tingkat Lanjutan (FKRTL) adalah fasilitas kesehatan yang termasuk didalamnya berupa klinik utama atau yang setara, rumah sakit umum dan rumah sakit khusus.'),
(622, 591, 'P18.31', 'Apa itu Motivator KB ?', 'Motivator KB adalah orang yang menggerakkan masyarakat/orang lain untuk menjadi peserta KB.'),
(623, 591, 'P18.32', 'Siapa Tenaga Kesehatan Pelayanan KB ?', 'Dokter atau bidan yang sudah dilatih dan memberikan pelayanan KB serta perawat dan tenaga promosi kesehatan yang memberikan konseling KB'),
(624, 591, 'P18.33', 'Dimana bisa mendapatkan Pelayanan KB PP atau KB PK ?', 'Pelayanan KB PP atau KB PK dapat dilakukan di fasilitas yang menangani pelaynan persalinan, baik difasilitas kesehatan tingkat pertama ataupun fasilitas kesehatan lanjutan tingkat rujukan.'),
(625, 591, 'P18.34', 'Apa yang dimaksud AKDR ?', 'AKDR atau Alat Kontrasepsi Dalam Rahim adalah perangkat kontrasepsi yang dimasukkan ke dalam rahim untuk mencegah kehamilan.'),
(626, 591, 'P18.35', 'Bagaimana Cara Kerja IUD ( Alat Kontrasepsi Dalam Rahim) ?', 'IUD adalah alat Kecil yang dimasukan ke dalam Rahim, Mencegah sperma mencapai sel telur dan dapat bertahan antara 5- 10 tahun'),
(627, 591, 'P18.36', 'Apa Efek samping dari pemakaian Kontrasepsi IUD ?', '1.Mentruasi yang banyak dan lama \n 2.Kram dan nyeri perut \n 3.Anemia\n 4. Pasangan dapat merasakan benang AKDR cooper T saat Senggama\n 5.Mentruasi Irriguler/tidak teratur'),
(628, 591, 'P18.37', 'Apa Itu Kontraspsi Jangka Panjang (MKJP) ?', 'Metode kontrasepsi jangka Panjang Seperti : IUD,Implant,MOW dan MOP yang efektif digunakan dalam jangka waktu lama 3-10 atau permanen'),
(629, 591, 'P18.38', 'Bagaimana Kerja Kontrasepsi IUD ?', 'IUD Non-Hormonal:\n • IUD non-hormonal, seperti IUD tembaga, bekerja dengan mencegah sperma mencapai sel telur di tuba falopi. \n • Tembaga yang dilepaskan oleh IUD tembaga dapat menghambat pergerakan sperma dan membuat sel telur lebih sulit dibuahi di dalam rahi\n IUD Hormonal:\n • IUD hormonal melepaskan hormon progestin (seperti levonorgestrel) yang mengentalkan lendir serviks, sehingga sperma sulit masuk ke rahim. \n • Hormon progestin juga menipiskan lapisan rahim, sehingga sel telur yang telah dibuahi akan sulit menempel dan berkembang.'),
(630, 591, 'P18.39', 'Apa yang dimaksud Kontrasepsi Implant ?', 'Implant adalah obat kontraspsi yang mengandung hormon yang diletakkan di bawah Kulit lengan atas dan merupakan batang plastic berukuran kecil dan lentur yang melepaskan progestin yang menyerupai hormon progesteron alami di tubuh Perempuan'),
(631, 591, 'P18.40', 'Apa Saja Jenis Jenis Kontrasepsi Dalam Rahim (AKDR)?', '1. AKDR Cooper adalah Suatu Rangka Plastik yang Lentur dan Kecil dengan lengan atau Kawat Cooper (Tembaga) di sekitarnya.\n 2. AKDR Levonorgestrel ( AKDR-LNG) adalah suatu alat berbahan plastic berbentuk T yang secara terus menerus Melepasskan sejumlah kecil hormon progestin (levonogestrel) setiap hari'),
(632, 591, 'P18.41', 'Apa Keuntungan Pemakaian Kontrasepsi IUD (AKDR)?', '1. Tidak Mengaggu Hubungan Seksual \n 2. Tidak Mempengaruhi Kualitas dan Produksi ASI \n 3. Kesuburan segera Kembali setelah IUD (AKDR) dilepas \n 4. Mencegah Kehamilan dengan sangat efektif kurang dari 1 kehamilan per 100 perempuan yang menggunakan AKDR selama tahun pertama'),
(633, 591, 'P18.42', 'Apa saja Jenis Jenis Implant ?', '1. Norplant, 2. Implanon, 3. Indoplant, 4. Sinoplan, 5. Jadena'),
(634, 591, 'P18.43', 'Bagaimana cara kerja implant ?', '1. Mencegah pelepasan telur dari ovarium (menekan Ovulasi)\n 2. Mengentalkan lendir servik (menghambat bertemunya sperma dan telur)'),
(635, 591, 'P18.44', 'Apa Keuntungan Pemakaian Kontrasepsi implant ?', '1. Mencegah Kehamilan dengan sangat efektif kurang dari 1 kehamilan per 100 perempuan yang menggunakan AKDR selama tahun pertama\n 2. Merupakan kontrasepsi jangka Panjang untuk 3-5 tahun tergantung jenis implant \n 3. Mengurangi nyeri haid \n 4. Kesuburan dapat Kembali dengan segera setelah implant dilepas \n 5. Tidak mengaggu hubungan seksual');
INSERT INTO `faq` (`id`, `parent_id`, `key_name`, `question_text`, `answer_text`) VALUES
(636, 591, 'P18.45', 'Apa Kontrasidikasi (tidak bisa menggunakan) Implant ?', '1. Hamil atau di duga hamil\n 2. sedang menderita penyakit kanker payudara\n 3. mengalami pendarahan dari vagina yang tidak diketahui sebabnya\n 4. sedang minum obat untuk Tuberkolosis,infeksi jamur dan epilepsi.'),
(637, 591, 'P18.46', 'Siapa yang bisa memberikan pelayanan KB Implant ?', 'Tenaga Kesehatan yang memiliki kompetensi dan kewenangan dalam pelayanan KB AKDR (IUD) yaitu : \n 1. Dokter spesialis Obgyn \n 2. Dokter umum yang terlatih \n 3. Bidan ( Bidan yang lulus Profesi S1 atau bidan Vokasi D3 yang sudah menapatkan pelatihan'),
(638, 591, 'P18.47', 'Dimana saja pelayanan KB Implant dapat diperoleh ?', '1.Fasilitas Kesehatan Tk. Pertama (FKTP) antara lain puskesmas,Klinik Pratama,Praktek mandiri dokter, Praktek Mandiri Bidan \n 2.Fasilitas Kesehatan Rujukan Tingkat Lanjutan (FKRTL) antara lain Klinik Utama,Rumah sakit umum dan Rumah sakit Khusus'),
(639, 591, 'P18.48', 'Apa efek samping pemakaian KB Implant ?', '1. Mentruasi Irriguler/tidak teratur\n 2. Tidak ada Mentruasi \n 3. Perubahan berat badan \n 4. Jerawat \n 5. Nyeri Setelah pemasangan/pencabutan \n 6. Nyeri payudara'),
(640, 591, 'P18.49', 'Apa yang dimaksud dengan Kontrasepsi Suntik Kombinasi (KSK)?', 'Kontrasepsi Suntik Kombinasi (KSK) mengandung 2 hormon – yaitu progestin dan estrogen – seperti hormon progesteron dan estrogen alami pada tubuh perempuan'),
(641, 591, 'P18.50', 'Bagaimana cara kerja Kontrasepsi Suntik Kombinasi?', 'Cara Kerja Kontrasepsi Suntik Kombinasi :\n 1. Mencegah pelepasan telur dari ovarium (menekan ovulasi).\n 2. Membuat lendir serviks menjadi kental sehingga penetrasi sperma terganggu \n 3. Perubahan pada endometrium (atrofi) sehingga implantasi terganggu\n 4. Menghambat transportasi gamet oleh tuba'),
(642, 591, 'P18.51', 'Apa keuntungan Kontrasepsi Suntik Kombinasi?', 'Keuntungan Kontrasepsi Suntik Kombinasi :\n 1. Tidak perlu pemakaian setiap hari\n 2. Dapat dihentikan kapan saja\n 3. Tidak berpengaruh pada hubungan suami istri\n 4. Baik untuk menjarangkan kehamilan'),
(643, 591, 'P18.52', 'Apakah pil kombinasi boleh digunakan oleh wanita yang sedang menyusui bayi usia kurang dari 6 minggu?', 'Tidak boleh.'),
(644, 591, 'P18.53', 'Metode kontrasepsi apa yang paling tepat untuk wanita dengan riwayat kanker serviks yang belum diobati?', 'Kontrasepsi sementara non-hormonal seperti kondom'),
(645, 591, 'P18.54', 'Bolehkah wanita dengan HIV menggunakan IUD tembaga?', 'Boleh, jika tidak ada infeksi aktif.'),
(646, 591, 'P18.55', 'Metode kontrasepsi apa yang sesuai untuk wanita dengan epilepsi yang mengonsumsi obat antikonvulsan?', 'IUD tembaga atau DMPA (suntik 3 bulanan)'),
(647, 591, 'P18.56', 'Sebutkan satu metode kontrasepsi yang aman digunakan oleh wanita dengan tekanan darah normal tetapi berisiko hipertensi.', 'POP'),
(648, 591, 'P18.57', 'Metode kontrasepsi mana yang paling cocok untuk wanita pasca keguguran trimester pertama?', 'Semua metode dapat digunakan segera, kecuali ada kontraindikasi'),
(649, 591, 'P18.58', 'Apa risiko penggunaan pil kombinasi pada wanita dengan gangguan fungsi hati berat?', 'Risiko tinggi, tidak boleh digunakan'),
(650, 591, 'P18.59', 'Apakah pil progestin memengaruhi kualitas ASI?', 'Tidak.'),
(651, 591, 'P18.60', 'Apakah kontrasepsi darurat dapat digunakan lebih dari sekali dalam satu siklus?', 'Ya, tetapi sebaiknya tidak dijadikan metode rutin'),
(652, 591, 'P18.61', 'Metode kontrasepsi apa yang paling cocok untuk wanita yang sering mengalami diare kronis?', 'Metode non-oral seperti implan atau IUD'),
(653, 591, 'P18.62', 'Apa efek samping yang umum dari kontrasepsi suntik DMPA?', 'Gangguan haid dan peningkatan berat badan'),
(654, 591, 'P18.63', 'Apa yang harus dilakukan jika seseorang muntah dalam 2 jam setelah minum kontrasepsi darurat?', 'Ulangi dosis.'),
(655, 591, 'P18.64', 'Apakah kontrasepsi hormonal memengaruhi kesuburan jangka panjang?', 'Tidak.'),
(656, 591, 'P18.65', 'Apakah IUD dapat dipasang segera setelah melahirkan?', 'Ya, dalam waktu 10 menit setelah melahirkan'),
(657, 591, 'P18.66', 'Apakah penggunaan pil kombinasi meningkatkan risiko trombosis vena?', 'Ya.'),
(658, 591, 'P18.67', 'Apa kelebihan dari metode implan dibanding pil?', 'Lebih efektif dan tidak tergantung kepatuhan harian.'),
(659, 591, 'P18.68', 'Apakah semua wanita bisa menggunakan kontrasepsi implan?', 'Tidak, tergantung kondisi medis'),
(660, 591, 'P18.69', 'Apa risiko utama penggunaan IUD pada wanita dengan beberapa pasangan seksual?', 'Risiko infeksi panggul.'),
(661, 591, 'P18.70', 'Metode kontrasepsi apa yang bisa bertahan paling lama dalam tubuh?', 'IUD tembaga (bisa sampai 10 tahun).'),
(662, 591, 'P18.71', 'Apakah IUD dapat digunakan oleh wanita yang belum pernah melahirkan?', 'Bisa, dengan pertimbangan dan penilaian medis.'),
(663, 591, 'P18.72', 'Apa efek samping yang umum dari penggunaan pil progestin saja?', 'Perubahan pola haid, perdarahan tidak teratur.'),
(664, 591, 'P18.73', 'Apakah penggunaan kontrasepsi hormonal bisa menunda kembalinya kesuburan setelah dihentikan?', 'Bisa, tapi bersifat sementara.'),
(665, 591, 'P18.74', 'Apa Pengertian pertumbuhan dan perkembangan anak', 'Pertumbuhan adalah bertambahnya ukuran dan jumlah sel serta jaringan interseluler, berarti bertambahnya ukuran fisik dan struktur tubuh sebagian atau keseluruhan, sehingga dapat diukur dengan satuan panjang dan berat.\nPerkembangan adalah bertambahnya struktur dan fungsi tubuh yang lebih kompleks dalam kemampuan gerak kasar, gerak halus, bicara dan bahasa serta sosialiasi dan kemandirian'),
(666, 591, 'P18.75', 'Apa yang dimaksud dengan Angka Partisipasi Sekolah (APS)', 'Angka partisipasi sekolah merupakan ukuran daya serap sistem pendidikan terhadap penduduk usia sekolah. Angka tersebut memperhitungkan adanya perubahan penduduk terutama usia muda. Ukuran yang banyak digunakan di sektor pendidikan seperti pertumbuhan jumlah murid lebih menunjukkan perubahan jumlah murid yang mampu ditampung di setiap jenjang sekolah. Oleh karena itu, naiknya persentase jumlah murid tidak dapat diartikan sebagai semakin meningkatnya partisipasi sekolah. Kenaikan tersebut dapat pula dipengaruhi oleh semakin besarnya jumlah penduduk usia sekolah yang tidak diimbangi dengan ditambahnya infrastruktur sekolah serta peningkatan akses masuk sekolah sehingga partisipasi sekolah seharusnya tidak berubah atau malah semakin rendah.'),
(667, 591, 'P18.76', 'Apa saja capaian penting dalam upaya dalam penurunan prevalensi kekerasan terhadap anak?', 'capaian penting dalam upaya dalam penurunan prevalensi kekerasan terhadap anak adalah dengan menguatnya sistem perlindungan anak yang mencakup pencegahan, penanganan, dan rehabilitasi anak korban tindak kekerasan, eksploitasi, penelantaran, dan perlakuan salah'),
(668, 591, 'P18.77', 'Bagaimana pola asuh agar menjadi generasi yang berintegritas?', 'Pola asuh yang diterapkan sebagai upaya dalam membentuk generasi yang berintegritas adalah :1, Menepati janji : Integritas sebagai fondasi. 2, Ajarkan kerja keras : Membentuk mental pejuang. 3, Jangan ambil hak orang lain : Menghindari mental korupsi. 4, Hidup sederhana : Melawan hedonisme. 5, Mengajarkan keadilan dalam pola asuh : Hak, kebutuhan dan menghindari penyelewengan. 6, Jangan nyontek.'),
(669, 591, 'P18.78', 'Usia berapa yang ideal untuk menikah bagi perempuan?', 'usia ideal menikah bagi perempuan yaitu 21 (dua puluh satu) tahun dan bagi laki-laki yaitu 25 (dua puluh lima) tahun.'),
(670, 591, 'P18.79', 'Dalam program Kampung KB, apa tugas utama BKKBN?', 'Menyusun, membina, dan mengoordinasikan pelaksanaan program-program Bangga Kencana di tingkat desa/kelurahan.'),
(671, 591, 'P18.80', 'Apa Landasan Dasar SIGA?', 'Ketersediaan data dan informasi yang dikelola dalam Sistem Informasi Keluarga (SIGA) merupakan perwujudan amanat UU Nomor 52 Tahun 2009, UU Nomor 23 Tahun 2015, PP Nomor 87 Tahun 2014 dan Peraturan Kepala BKKBN tentang Pengelolaan Data Rutin Program Bangga Kencana. Data rutin dan informasi yang dihasilkan dijadikan sebagai dasar perencanaan, monitoring kinerja serta peta kerja intervensi pada setiap tingkatan wilayah; sehingga dibutuhkan data yang valid dan akurat untuk mendukung pengambilan kebijakan secara tepat.'),
(672, 591, 'P18.81', 'Apa yang harus dilakukan jika ada anggota keluarga yang merasa kesepian?', 'Memberikan perhatian lebih, mengajak berbicara, dan melibatkan mereka dalam aktivitas keluarga'),
(673, 591, 'P18.82', 'Apa dampak perceraian terhadap anak?', 'Perceraian dapat mempengaruhi kesejahteraan emosional dan perkembangan anak, menyebabkan stres dan perasaan tidak aman'),
(674, 591, 'P18.83', 'Apa saja tanda-tanda keluarga mengalami disfungsi?', 'Kurangnya komunikasi, sering terjadinya konflik, dan ketidakmampuan untuk menyelesaikan masalah bersama'),
(675, 591, 'P18.84', 'Apa itu toxic family?', 'Toxic family adalah keluarga yang memiliki pola hubungan yang tidak sehat, di mana anggota keluarga saling menyakiti secara emosional atau fisik'),
(676, 591, 'P18.85', 'Bagaimana cara mengatasi konflik antara orang tua dan anak?', 'Menghargai perasaan satu sama lain, berbicara dengan tenang, dan mencari solusi bersama'),
(677, 591, 'P18.86', 'Apa yang dapat dilakukan jika ada anggota keluarga yang mengalami depresi?', 'Memberikan dukungan emosional, mendorong untuk berkonsultasi dengan psikolog atau psikiater'),
(678, 591, 'P18.87', 'Apa yang harus dilakukan jika orang tua terlalu otoriter?', 'Menyampaikan perasaan secara terbuka dengan cara yang sopan, atau mencari konseling keluarga untuk membantu komunikasi'),
(679, 591, 'P18.88', 'Apa peran keluarga dalam pendidikan anak?', 'Keluarga berperan penting dalam memberikan dasar pendidikan moral, emosional, dan intelektual yang baik bagi anak'),
(680, 591, 'P18.89', 'Bagaimana cara keluarga membantu anak yang sedang mengalami bullying di sekolah?', 'Mendengarkan cerita anak, memberi dukungan emosional, dan membantu mencari solusi dengan pihak sekolah atau profesional'),
(681, 591, 'P18.90', 'Bagaimana cara orang tua mendidik anak dengan bijak di era digital?', 'Mengajarkan anak tentang penggunaan teknologi yang sehat, mengatur waktu layar, dan memantau konten yang mereka akses'),
(682, 591, 'P18.91', 'Apa dampak orang tua yang terlalu sibuk bekerja terhadap anak?', 'Anak bisa merasa diabaikan secara emosional dan kurangnya perhatian dapat mempengaruhi perkembangan sosial dan emosional mereka'),
(683, 591, 'P18.92', 'Bagaimana cara menjaga hubungan dengan anak remaja yang sedang mencari identitas?', 'Memberikan ruang untuk anak mengembangkan identitas mereka, tetapi tetap terbuka untuk komunikasi dan memberikan bimbingan yang positif'),
(684, 591, 'P18.93', 'Apa yang bisa dilakukan jika anak terlalu terobsesi dengan media sosial?', 'Mengatur waktu penggunaan media sosial, berbicara mengenai dampak negatif media sosial, dan mencari cara untuk menggantikan waktu media sosial dengan kegiatan produktif.'),
(685, 591, 'P18.94', 'Apa dampak dari kurangnya pendidikan seks yang baik dalam keluarga?', 'Bisa menyebabkan kurangnya pemahaman tentang hubungan yang sehat, kesehatan reproduksi, dan berisiko lebih tinggi terhadap perilaku berisiko'),
(686, 591, 'P18.95', 'Apakah kekerasan dalam rumah tangga bisa diselesaikan dalam keluarga?', 'Tidak, kekerasan dalam rumah tangga harus dilaporkan kepada pihak berwenang dan tidak bisa dibiarkan begitu saja.'),
(687, 591, 'P18.96', 'Apa yang harus dilakukan jika ada anggota keluarga yang terlibat dalam narkoba?', 'Memberikan dukungan emosional, membawa mereka ke konselor atau rehabilitasi, dan menciptakan lingkungan yang mendukung pemulihan.'),
(688, 591, 'P18.97', 'Apa saja alasan generasi muda menunda pernikahan dan memiliki anak?', 'Fokus pada pendidikan, karier, dan keinginan untuk mencapai stabilitas ekonomi dan emosional sebelum menikah dan memiliki anak'),
(689, 591, 'P18.98', 'Apa itu childfree?', 'Childfree adalah pilihan hidup di mana seseorang atau pasangan memutuskan untuk tidak memiliki anak, baik secara permanen maupun sementara'),
(690, 591, 'P18.99', 'Mengapa semakin banyak orang yang memilih untuk menjadi childfree?', 'Faktor-faktor seperti fokus pada karier, kebebasan finansial, kepedulian terhadap lingkungan, dan pengalaman hidup yang lebih fleksibel menjadi alasan utama'),
(691, 591, 'P18.100', 'Apa perbedaan antara childfree dan tidak ingin punya anak?', 'Childfree merujuk pada keputusan untuk tidak memiliki anak secara sadar, sedangkan tidak ingin punya anak bisa jadi hanya keputusan sementara atau berdasarkan alasan tertentu.'),
(692, 591, 'P18.101', 'Apakah memilih untuk childfree berdampak negatif terhadap keluarga?', 'Pilihan untuk childfree tidak selalu berdampak negatif, tergantung pada pandangan keluarga dan bagaimana mereka menerima keputusan tersebut.'),
(693, 591, 'P18.102', 'Bagaimana pandangan masyarakat terhadap orang yang memilih childfree?', 'Pandangan masyarakat bisa beragam, ada yang mendukung, namun ada juga yang menganggapnya tidak sesuai dengan norma sosial yang ada, terutama dalam budaya tertentu.'),
(694, 591, 'P18.103', 'Apa itu KDRT?', 'KDRT adalah segala bentuk kekerasan yang terjadi dalam hubungan rumah tangga, baik secara fisik, verbal, emosional, seksual, maupun ekonomi'),
(695, 591, 'P18.104', 'Apa saja jenis kekerasan dalam rumah tangga?', 'Jenis-jenis KDRT meliputi kekerasan fisik, kekerasan emosional atau psikologis, kekerasan seksual, dan kekerasan ekonomi.'),
(696, 591, 'P18.105', 'Apa yang dimaksud dengan kekerasan fisik dalam KDRT?', 'Kekerasan fisik melibatkan tindakan yang menyebabkan cedera tubuh, seperti pemukulan, penendangan, atau penggunaan senjata terhadap pasangan.'),
(697, 591, 'P18.106', 'Apa itu kekerasan psikologis dalam KDRT?', 'Kekerasan psikologis atau emosional adalah tindakan yang merusak mental atau perasaan pasangan, seperti penghinaan, ancaman, atau isolasi sosial.'),
(698, 591, 'P18.107', 'Bagaimana cara membedakan KDRT dengan perselisihan biasa dalam rumah tangga?', 'KDRT melibatkan perilaku yang merusak fisik, psikologis, atau emosional dengan niat untuk mengontrol atau mendominasi pasangan, sedangkan perselisihan biasa bersifat sementara dan tidak berkelanjutan.'),
(699, 591, 'P18.108', 'Bagaimana cara mengetahui apakah seseorang mengalami KDRT?', 'Perubahan perilaku, ketakutan terhadap pasangan, memar atau luka tubuh, serta kecemasan berlebihan bisa menjadi tanda-tanda bahwa seseorang mengalami KDRT.'),
(700, 591, 'P18.109', 'Apakah korban KDRT selalu harus melaporkan kejadian tersebut?', 'Tidak selalu. Keputusan untuk melapor atau tidak melapor adalah hak pribadi korban. Namun, melaporkan KDRT dapat membantu untuk mendapatkan perlindungan hukum dan dukungan.'),
(701, 591, 'P18.110', 'Apakah ada hukuman bagi pelaku KDRT?', 'Ya, pelaku KDRT dapat dijerat dengan hukum pidana sesuai dengan Undang-Undang Perlindungan Anak dan Undang-Undang KDRT di Indonesia.'),
(702, 591, 'P18.111', 'Apa yang harus dilakukan jika menjadi saksi KDRT?', 'Sebagai saksi, Anda bisa melaporkan kejadian tersebut kepada pihak berwajib atau memberikan dukungan moral kepada korban.'),
(703, 591, 'P18.112', 'Bagaimana cara mencegah KDRT dalam rumah tangga?', 'Pencegahan KDRT dapat dilakukan melalui pendidikan yang mengedepankan kesetaraan gender, komunikasi yang baik, dan pemahaman terhadap hak-hak individu dalam hubungan.'),
(704, 591, 'P18.113', 'Apa dampak KDRT bagi korban anak-anak?', 'Anak-anak yang menyaksikan atau menjadi korban KDRT berisiko mengalami gangguan mental, seperti kecemasan, depresi, dan gangguan perilaku.'),
(705, 591, 'P18.114', 'Apa dampak jangka panjang bagi anak-anak yang tumbuh dalam lingkungan KDRT?', 'Anak-anak yang tumbuh dalam lingkungan KDRT berisiko tinggi mengalami gangguan emosional, kesulitan membangun hubungan yang sehat, dan kecenderungan untuk meniru perilaku kekerasan.'),
(706, 591, 'P18.115', 'Meliputi kapan saja 1000 HPK itu?', '270 hari selama dalam kandungan dan 730 hari masa menyusui hingga usia 2 tahun'),
(707, 591, 'P18.116', 'Apa yang harus dilakukan ketika baru seorang ibu baru memiliki anak?', 'Menyesuaikan peran\nMenerima dan menyesuaikan tuntutan\nBelajar merawat bayi dengan kompeten\nMembangun dan mempertahankan rutinitas keluarga yang sehat\nMemberikan kesempatan penuh untuk perkembangan anak\nBerbagi tanggung jawab dengan suami\nMempertahankan hubungan yang romantis dengan suami'),
(708, 591, 'P18.117', 'Apa yang harus dilakukan orang tua ketika anak menemui permasalahan?', 'Orang tua dapat mendengarkan curahan/cerita anak terutama saat anak sedang merasa tidak nyaman (sedih, marah, takut, kecewa, dll.)'),
(709, 591, 'P18.118', 'Bagaimana pasangan suami istri yang bekerja membagi peran mereka dalam mengasuh anak usia dini?', 'Orang tua harus memegang prinsip:\nAnak adalah tanggung jawab orang tua yang harus diasuh dan dilindungi setiap hari, khususnya anak umur 0-6 tahun.\nSuami-istri harus bertanggung jawab secara bersama dalam mengasuh anak.\nSuami-istri bekerjasama dalam menjalankan tugas keluarga dengan saling menghormati dan saling membutuhkan.\nPengasuhan anak dilandaskan atas pedoman agama, norma dan budaya setempat serta nilai universal.'),
(710, 591, 'P18.119', 'Apa itu 4 Terlalu ?', '1.Terlalu Muda; 2. Terlalu Tua; 3. Terlalu Banyak; 4.Terlalu Dekat'),
(711, 591, 'P18.120', 'Apa pentingnya perencanaan kehamilan?', 'Perencanaan kehamilan penting untuk memastikan kehamilan yang sehat dan mengurangi risiko komplikasi.'),
(712, NULL, 'P19', 'Kependudukan', NULL),
(713, 712, 'P19.1', 'Apa yang dimaksud dengan kependudukan?', 'Kependudukan adalah hal-hal yang berkaitan dengan jumlah, pertumbuhan, persebaran, komposisi, dan mobilitas penduduk serta faktor-faktor yang memengaruhinya.'),
(714, 712, 'P19.2', 'Mengapa Isu kependudukan penting untuk generasi muda', 'Karena generasi muda merupakan kelompok usia produktif yang akan menentukan arah pembangunan dan kualitas penduduk di masa depan.'),
(715, 712, 'P19.3', 'Apa itu bonus demografi?', 'Bonus demografi adalah kondisi di mana jumlah penduduk usia produktif (15-64 tahun) lebih besar dibandingkan usia non-produktif.'),
(716, 712, 'P19.4', 'Bagaimana cara memanfaatkan bonus demografi?', 'Dengan meningkatkan kualitas pendidikan, kesehatan, serta menciptakan lapangan kerja untuk usia produktif.'),
(717, 712, 'P19.5', 'Apa dampak bonus demografi bila tidak dimanfaatkan dengan baik?', 'Bisa menyebabkan ledakan pengangguran, kemiskinan, dan masalah sosial lainnya.'),
(718, 712, 'P19.6', 'Apa peran BKKBN dalam pendidikan kependudukan?', 'BKKBN menyusun kebijakan dan program untuk menyosialisasikan pentingnya pengendalian penduduk dan keluarga berencana.'),
(719, 712, 'P19.7', 'Apa hubungan antara kependudukan dan pembangunan berkelanjutan?', 'Jumlah dan kualitas penduduk sangat memengaruhi pemanfaatan sumber daya alam, lingkungan, dan arah pembangunan.'),
(720, 712, 'P19.8', 'Apa kaitan antara kependudukan dan kualitas hidup?', 'Pengelolaan penduduk yang baik meningkatkan akses terhadap pendidikan, layanan kesehatan, dan lapangan kerja.'),
(721, 712, 'P19.9', 'Apa peran keluarga dalam pengendalian penduduk?', 'Keluarga dapat menentukan jumlah anak ideal dan memberikan pendidikan kependudukan sejak dini.'),
(722, 712, 'P19.10', 'Mengapa generasi muda harus peduli terhadap isu kependudukan?', 'Karena mereka adalah pemegang estafet pembangunan dan akan terdampak langsung oleh kondisi demografi masa depan.'),
(723, 712, 'P19.11', 'Apa yang dimaksud Angka Harapan Hidup (AHH) ?', 'Angka Harapan Hidup (AHH) adalah perkiraan rata-rata tambahan umur seseorang yang diharapkan dapat terus hidup. AHH juga dapat didefinisikan sebagai rata-rata jumlah tahun yang dijalani oleh seseorang setelah orang tersebut mencapai ulang tahun yang ke-x. Ukuran yang umum digunakan adalah angka harapan hidup saat lahir yang mencerminkan kondisi kesehatan pada saat itu. Sehingga pada umumnya ketika membicarakan AHH, yang dimaksud adalah rata-rata jumlah tahun yang akan dijalani oleh seseorang sejak orang tersebut lahir'),
(724, 712, 'P19.12', 'Berapa Angka Harapan Hidup di DIY?', 'Angka harapan hidup di wilayah DIY mengalami kenaikan pada tahun 2018 menjadi 74,82 tahun yang mulanya pada tahun 2017 sebesar 74,74 tahun. Angka harapan hidup menurut jenis kelamin laki-laki mengalami peningkatan di tahun 2018 menjadi 73,03 tahun. Sedangkan menurut jenis kelamin perempuan naik menjadi 76,65 tahun'),
(725, 712, 'P19.13', 'Berapa jumlah penduduk DIY berdasarkan survey terbaru?', 'Jumlah penduduk Provinsi Daerah Istimewa Yogyakarta pada tahun 2023 berdasarkan Hasil Proyeksi Penduduk 2020–2035 (Pertengahan tahun/Juni) berjumlah sekitar 3.736 ribu jiwa. Kepadatan penduduk per km2 sebesar 1,17 ribu jiwa/km2. Jumlah penduduk tahun 2023 yang paling banyak terdapat di Kabupaten Sleman dengan jumlah penduduk sekitar 1,157 juta jiwa. Sedangkan jumlah penduduk paling sedikit ada di Kota Yogyakarta dengan jumlah penduduk sekitar 375,7 ribu jiwa.'),
(726, 712, 'P19.14', 'Apa yang dimaksud dengan Laju Pertumbuhan Penduduk?', 'Laju pertumbuhan penduduk per tahun adalah angka yang menunjukkan rata-rata tingkat pertambahan penduduk per tahun dalam jangka waktu tertentu.'),
(727, 712, 'P19.15', 'Berapa laju pertumbuhan penduduk DIY?', 'Laju pertumbuhan penduduk per tahun antara tahun 2020-2023 yang paling tinggi ada di Kabupaten Sleman dengan laju pertumbuhan 3,20 persen. Sedangkan laju pertumbuhan terendah ada di Kabupaten Gunungkidul dengan laju pertumbuhan sebesar 0,59 persen.'),
(728, NULL, 'P20', 'Kesehatan Reproduksi', NULL),
(729, 728, 'P20.1', 'Apa upaya BKKBN dalam edukasi tentang kesehatan reproduksi bagi remaja?', 'Melalui PIK Remaja dan materi edukasi tentang kesehatan reproduksi dan kehidupan berkeluarga.'),
(730, NULL, 'P21', 'Kontrasepsi', NULL),
(731, 730, 'P21.1', 'Apa itu vasektomi?', 'Tindakan pengikatan dan pemutusan saluran sperma kanan dan kiri, sehingga saat ejakulasi cairan mani yang keluar tidak lagi mengandung sperma, maka kehamilan tidak terjadi'),
(732, 730, 'P21.2', 'Berapa lama tindakan vasektomi dilakukan?', 'Umumnya dilakukan sekitar 10-15 menit'),
(733, 730, 'P21.3', 'Siapa saja yang dapat menjadi peserta vasektomi?', 'Suami dari Pasangan Usia Subur (PUS) dengan syarat tidak ingin menambah jumlah anak dan terpenuhinya syarat sukarela, bahagia, dan sehat'),
(734, 730, 'P21.4', 'Apakah alat kontrasepsi dari Kemendubangga/BKKBN boleh diakses oleh semua orang?', 'Alat dan obat kontrasepsi dari Kemendubangga/BKKBN hanya diperuntukkan untuk Pasangan Usia Subur (PUS)'),
(735, 730, 'P21.5', 'Kapan vasektomi dapat dilakukan?', 'Kapan saja bila calon peserta menginginkan dan telah siap, serta telah mendapatkan pelayanan konseling untuk menetapkan persyaratan sukarela, bagahia, dan sehat dan bila pasangan suami isteri memutuskan tidak ingin punya anak lagi'),
(736, 730, 'P21.6', 'Apakah laki-laki dengan hernia (turun berok) bisa mengikuti vasektomi?', 'Tidak'),
(737, 730, 'P21.7', 'Seberapa efektif KB vasektomi?', 'Vasektomi adalah salah satu metode kontrasepsi paling efektif dimana angka kegagalannya umumnya kurang dari 0.1%'),
(738, 730, 'P21.8', 'Apakah vasektomi sama dengan kebiri?', 'Tidak, kebiri adalah pemotongan buah zakar/ testis sehingga tidak dapat lagi memproduksi sperma dan hormon testosteron. Sedangkan vasektomi hanya memotong saluran sperma kiri dan kanan saja, agar cairan mani yang dikeluarkan pada saat ejakulasi tidak lagi mengandung sperma'),
(739, 730, 'P21.9', 'Apa arti kontrasepsi?', 'Kontrasepsi adalah sebuah metode yang digunakan untuk mencegah terjadi kehamilan'),
(740, 730, 'P21.10', 'Apa saja kebijakan jaminan ketersediaan kontrasepsi?', 'Kebijakan ketersediaan kontrasepsi meliputi 5 aspek, yaitu : \n 1. Pemberdayaan \n 2. Penguatan kemitraan \n 3. penajaman segmentasi sasaran \n 4. perluasan jangkauan \n 5. pembinaan'),
(741, 730, 'P21.11', 'Apa saja komponen untuk memperhitungkan dalam menjalankan program jaminan ketersedian kontrasepsi?', 'Komponen untuk memperhitungkan dalam menjalankan program jaminan ketersedian kontrasepsi antara lain:\n 1. Komponen Pelayanan KB \n 2. Komponen kebijakan \n 3. Komponen Manajemen Logistik \n 4. Komponen Pemasok \n 5. Komponen Pendanaan'),
(742, 730, 'P21.12', 'Apa saja jenis kontrasepsi?', 'Jenis kontrasepsi antara lain:\n 1. IUD (Intra Uterine Device) Coper T \n 2. Implan\n 3. Pil KB \n 4. Suntik \n 5. Kondom \n 6. Koyo \n 7. Cincin vagina \n 8. Spermisida \n 9. Diafragma \n 10. tudung serviks \n 11. MOP \n 12. MOW'),
(743, 730, 'P21.13', 'Apa itu Metode Kontrasepsi Non Hormonal?', 'Pencegahan kehamilan yang dilakukan dengan menggunakan metode kimiawi untuk membunuh sperma.'),
(744, 730, 'P21.14', 'Apa saja jenis Metode kontrasepsi Non Hormonal?', 'Kondom Pria, Kondom Wanita, AKDR cooper, Spermisida, Diafragma, Tudung Serviks, MOP, MOW'),
(745, 730, 'P21.15', 'Apakah penggunaan alat kontrasepsi akan mempengaruhi pola menstruasi?', 'Alat kontrasepsi non hormonal umumnya tidak akan mengubah pola siklus menstruasi, sedangkan alat kontrasepsi hormonal dapat mengubah pola siklus menstruasi.'),
(746, 730, 'P21.16', 'Apa batasan siklus menstruasi seorang perempuan yang normal?', 'Siklus menstruasi seorang perempuan umumnya berkisar 28 hari, siklus terpendek seorang perempuan adalah 21 hari, sementara siklus terpanjangnya adalah 35 hari.'),
(747, 730, 'P21.17', 'Apakah alat kontrasepsi mempengaruhi siklus menstruasi ?', 'Penggunaan alat kontrasepsi hormonal dapat mempengaruhi pola siklus menstruasi, dan kadang mengalami henti menstruasi.'),
(748, 730, 'P21.18', 'Apa yang dimaksud dengan KB Pasca Persalinan (KBPP)', 'Penggunaan suatu metode kontrasepsi sesudah melahirkan sampai 6 minggu / 42 hari melahirkan'),
(749, 730, 'P21.19', 'Apa itu kontrasepsi darurat dan apa saja jenis kontrasepsi darurat?', 'Kontrasepsi darurat adalah pilihan Kontrasepsi yang diberikan dalam 3-5 hari pasca senggama yang tidak terlindung dengan kontrasepsi yang tepat dan konsisten. Pilihannya ada Pil Kontrasepsi Darurat (Pil Kondar) atau Alat Kontrasepsi Dalam Rahim (AKDR)/IUD.'),
(750, 730, 'P21.20', 'Berapa lama jangka waktu pemasangan kontrasepsi?', 'Setiap alat dan obat kontrasepsi memiliki jangka waktu masing-masing, seperti IUD untuk 8-10 tahun, Implant untuk 3 tahun, kondom sekali penggunaan, suntik KB ada yang untuk setiap bulan dan ada yang 3 bulanan. Khusus kontrasepsi Vasektomi dan Tubektomi merupakan kontrasepsi mantap sehingga sekali dilakukan tindakan tidak ada batas waktu pemasangan.'),
(751, 730, 'P21.21', 'Apa metode Kontrasepsi yang bersifat jangka panjang?', 'Metode Kontrasepsi Jangka Panjang atau yang biasa disebut MKJP terdiri dari Implant, IUD, Vasektomi dan Tubektomi.'),
(752, 730, 'P21.22', 'Apakah kontrasepsi alami (KB kalender) efektif?', 'Metode kontrasepsi alami seperti metode kalender memiliki tingkat efektivitas yang lebih rendah dibanding metode modern. Efektivitasnya hanya sekitar 76% dalam penggunaan umum. Kegagalan sering disebabkan oleh variasi panjang siklus menstruasi dan kesulitan memperkirakan masa subur. Metode ini lebih cocok untuk pasangan yang sangat teratur dan disiplin. WHO menyarankan metode ini hanya pada pasangan dengan pemahaman yang baik tentang kesuburan.'),
(753, 730, 'P21.23', 'Apakah pemakaian KB jangka panjang memengaruhi berat badan?', 'Beberapa metode kontrasepsi hormonal, terutama suntik DMPA, memang dapat menyebabkan kenaikan berat badan pada sebagian wanita. Namun, pil KB kombinasi dan IUD tidak menunjukkan bukti kuat menyebabkan peningkatan berat badan yang signifikan. Efek tersebut bervariasi tergantung individu. WHO menyatakan bahwa manfaat kontrasepsi tetap lebih besar dibanding efek samping ringan ini. Pemantauan berat badan secara rutin tetap dianjurkan.'),
(754, 730, 'P21.24', 'Metode kontrasepsi apa yang aman digunakan oleh ibu menyusui dalam 6 minggu pertama setelah melahirkan?', 'Pil progestin saja atau metode non-hormonal seperti kondom'),
(755, 730, 'P21.25', 'Apakah kontrasepsi suntik kombinasi boleh digunakan oleh wanita dengan hipertensi tidak terkontrol?', 'Tidak boleh.'),
(756, 730, 'P21.26', 'Apa metode kontrasepsi jangka panjang yang aman untuk wanita dengan anemia?', 'Implan atau pil progestin'),
(757, 730, 'P21.27', 'Apakah IUD hormon boleh digunakan oleh wanita dengan riwayat kanker payudara?', 'Tidak'),
(758, 730, 'P21.28', 'Sebutkan satu metode kontrasepsi darurat yang direkomendasikan WHO.', 'Pil levonorgestrel dosis tinggi'),
(759, 730, 'P21.29', 'Apa metode kontrasepsi yang paling cocok untuk wanita dengan lupus tanpa antibodi antifosfolipid?', 'Pil progestin atau implan.'),
(760, 730, 'P21.30', 'Apa itu vaksin HPV?', 'Vaksin HPV: Vaksin untuk mencegah HPV.'),
(761, 730, 'P21.31', 'Apa pentingnya vaksin HPV?', 'Vaksin HPV: Penting dilakukan untuk mencegah terjadinya kanker serviks dan menurunkan keparahan akibat penyakit kanker serviks'),
(762, 730, 'P21.32', 'Kapan waktu yang tepat untuk vaksin HPV?', 'Waktu yang tepat untuk vaksin HPV adalah sebelum seseorang aktif secara seksual, idealnya pada usia 9-13 tahun. Vaksin ini juga dapat diberikan hingga usia 26 tahun.'),
(763, 730, 'P21.33', 'Apa itu pap smear?', 'Pap smear adalah prosedur pemeriksaan untuk mendeteksi perubahan sel pada serviks (leher rahim) yang dapat mengarah pada kanker serviks.'),
(764, 730, 'P21.34', 'Apa pentingnya pap smear?', 'Pap smear penting untuk mendeteksi dini perubahan sel serviks, sehingga dapat dilakukan penanganan sebelum berkembang menjadi kanker.'),
(765, 730, 'P21.35', 'Kapan waktu yang tepat untuk pap smear?', 'Waktu yang tepat untuk pap smear adalah mulai usia 21 tahun, dan diulang setiap 3 tahun hingga usia 65 tahun jika hasilnya normal.'),
(766, 730, 'P21.36', 'Apa itu USG kandungan?', 'USG kandungan adalah prosedur pemeriksaan menggunakan gelombang suara untuk melihat kondisi janin dan organ reproduksi wanita selama kehamilan.'),
(767, 730, 'P21.37', 'Apa pentingnya konseling pranikah?', 'Konseling pranikah penting untuk membantu pasangan memahami satu sama lain, mempersiapkan diri untuk pernikahan, dan merencanakan keluarga.'),
(768, 730, 'P21.38', 'Apa itu KB pascasalin?', 'KB pascasalin adalah penggunaan alat kontrasepsi setelah melahirkan.'),
(769, 730, 'P21.39', 'Kapan waktu yang tepat untuk KB pascasalin?', 'Waktu yang tepat untuk KB pascasalin adalah segera setelah melahirkan, sesuai dengan jenis kontrasepsi yang dipilih.'),
(770, 730, 'P21.40', 'Apa itu KB pascakeguguran?', 'KB pascakeguguran adalah penggunaan alat kontrasepsi setelah mengalami keguguran.'),
(771, 730, 'P21.41', 'Kapan waktu yang tepat untuk KB pascakeguguran?', 'Waktu yang tepat untuk KB pascakeguguran adalah segera setelah keguguran, setelah berkonsultasi dengan dokter.'),
(772, 730, 'P21.42', 'Apa itu perencanaan kehamilan?', 'Perencanaan kehamilan adalah proses mempersiapkan diri secara fisik, mental, dan finansial sebelum hamil.'),
(773, 730, 'P21.43', 'Apa itu kehamilan tidak diinginkan?', 'Kehamilan tidak diinginkan adalah kehamilan yang terjadi tanpa direncanakan atau diinginkan.'),
(774, 730, 'P21.44', 'Apa itu kekerasan seksual?', 'Kekerasan seksual adalah tindakan seksual yang dilakukan tanpa persetujuan.'),
(775, 730, 'P21.45', 'Apa itu pelecehan seksual?', 'Pelecehan seksual adalah tindakan atau ucapan yang bersifat seksual dan tidak diinginkan.'),
(776, 730, 'P21.46', 'Apa itu kesehatan reproduksi pria?', 'Kesehatan reproduksi pria adalah kondisi kesehatan organ reproduksi pria yang optimal.'),
(777, 730, 'P21.47', 'Apa saja aspek kesehatan reproduksi pria?', 'Aspek kesehatan reproduksi pria antara lain kesuburan, fungsi seksual, dan kesehatan prostat.'),
(778, 730, 'P21.48', 'Apa itu disfungsi ereksi?', 'Disfungsi ereksi adalah ketidakmampuan untuk mencapai atau mempertahankan ereksi yang cukup untuk berhubungan seksual.'),
(779, 730, 'P21.49', 'Apa itu ejakulasi dini?', 'Ejakulasi dini adalah ejakulasi yang terjadi terlalu cepat, sebelum atau segera setelah penetrasi.'),
(780, 730, 'P21.50', 'Apa itu varikokel?', 'Varikokel adalah pembengkakan pembuluh darah vena di dalam skrotum.'),
(781, 730, 'P21.51', 'Apa itu hidrokel?', 'Hidrokel adalah penumpukan cairan di sekitar testis.'),
(782, 730, 'P21.52', 'Apa itu kanker testis?', 'Kanker testis adalah pertumbuhan sel kanker di dalam testis.'),
(783, 730, 'P21.53', 'Apa itu kesehatan reproduksi transgender?', 'Kesehatan reproduksi transgender adalah kondisi kesehatan reproduksi individu yang identitas gendernya berbeda dengan jenis kelamin yang ditetapkan saat lahir.'),
(784, 730, 'P21.54', 'Apa saja tantangan kesehatan reproduksi transgender?', 'Tantangan kesehatan reproduksi transgender antara lain akses layanan kesehatan yang terbatas, diskriminasi, dan kurangnya informasi.'),
(785, 730, 'P21.55', 'Apa itu hak-hak transgender?', 'Hak-hak transgender antara lain hak untuk mendapatkan layanan kesehatan yang sesuai dengan identitas gender mereka.'),
(786, 730, 'P21.56', 'Apa itu kesehatan reproduksi disabilitas?', 'Kesehatan reproduksi disabilitas adalah kondisi kesehatan reproduksi individu dengan disabilitas.'),
(787, 730, 'P21.57', 'Apa saja tantangan kesehatan reproduksi disabilitas?', 'Tantangan kesehatan reproduksi disabilitas antara lain akses layanan kesehatan yang terbatas, kurangnya informasi, dan diskriminasi.'),
(788, 730, 'P21.58', 'Apa itu inklusi dalam kesehatan reproduksi?', 'Inklusi dalam kesehatan reproduksi adalah memastikan bahwa semua individu, termasuk mereka dengan disabilitas atau identitas gender yang berbeda, memiliki akses yang sama terhadap layanan kesehatan reproduksi yang berkualitas.'),
(789, 730, 'P21.59', 'Apa itu stigma dalam kesehatan reproduksi?', 'Stigma dalam kesehatan reproduksi adalah pandangan negatif atau diskriminasi terhadap individu atau kelompok terkait dengan kesehatan reproduksi mereka.'),
(790, 730, 'P21.60', 'Apa itu mitos tentang KB?', 'Mitos tentang KB adalah informasi yang salah atau tidak akurat tentang alat kontrasepsi.'),
(791, 730, 'P21.61', 'Apa itu fakta tentang KB?', 'Fakta tentang KB adalah informasi yang benar dan akurat tentang alat kontrasepsi.'),
(792, 730, 'P21.62', 'Apa itu mitos tentang kesehatan reproduksi?', 'Mitos tentang kesehatan reproduksi adalah informasi yang salah atau tidak akurat tentang kesehatan reproduksi.'),
(793, 730, 'P21.63', 'Apa itu fakta tentang kesehatan reproduksi?', 'Fakta tentang kesehatan reproduksi adalah informasi yang benar dan akurat tentang kesehatan reproduksi.'),
(794, 730, 'P21.64', 'Apa itu peran pemerintah dalam KB dan kesehatan reproduksi?', 'Peran pemerintah dalam KB dan kesehatan reproduksi antara lain menyediakan layanan kesehatan yang berkualitas, memberikan edukasi, dan membuat kebijakan yang mendukung kesehatan reproduksi.'),
(795, 730, 'P21.65', 'Apa itu peran masyarakat dalam KB dan kesehatan reproduksi?', 'Peran masyarakat dalam KB dan kesehatan reproduksi antara lain mendukung program pemerintah, memberikan edukasi kepada keluarga dan teman, dan menciptakan lingkungan yang mendukung kesehatan reproduksi.'),
(796, 730, 'P21.66', 'Apakah KB Itu Wajib?', 'Pemerintah tidak memberikan aturan wajib bagi masyarakat untuk menjalankan program KB. Sebab, masyarakat memiliki hak-hak dalam membentuk keluarga dan melanjutkan keturunan. Namun, program KB hadir sebagai saran untuk membantu masyarakat dalam mewujudkan keluarga yang berkualitas.'),
(797, 730, 'P21.67', 'Apakah KB Bisa Membuat Mandul?', 'Progam KB dengan metode kontrasepsi tidak dapat membuat mandul. Namun terdapat dua metode kontrasepsi yang permanen. KB ini disarankan untuk pasangan yang sudah yakin tidak ingin memiliki anak kembali. Terdapat dua jenis KB permanen, yakni sterilisasi untuk wanita (tubektomi) dan sterilisasi untuk pria (vasektomi). Sterilisasi wanita bekerja dengan mencegah sel telur mengalir ke saluran tuba, yang menghubungkan ovarium ke rahim (uterus). Sedangkan vasektomi adalah prosedur pembedahan dengan memotong atau menutup saluran yang membawa sperma pria untuk mencegah kehamilan secara permanen.'),
(798, 730, 'P21.68', 'Apakah ada metode KB alami?', 'Ya, ada metode KB alami seperti perhitungan kalender'),
(799, 730, 'P21.69', 'Di mana saya bisa mendapatkan informasi lebih lanjut tentang KB?', 'Anda bisa mendapatkan informasi lebih lanjut tentang KB di puskesmas, bidan, klinik keluarga berencana, atau bertanya kepada petugas kesehatan atau penyuluh keluarga berencana.'),
(800, 730, 'P21.70', 'Mengapa harus menggunakan KB?', 'KB (Keluarga Berencana) adalah program pemerintah Indonesia sejak tahun 1970. Program tersebut bertujuan untuk mengendalikan pertambahan jumlah penduduk, membatasi angka kelahiran, dan mengatur jarak kelahiran sehingga dapat menciptakan keluarga sehat sejahtera. Program ini juga diharapkan dapat menurunkan angka kematian ibu dan bayi karena kehamilan yang tidak diinginkan ataupun jarak kelahiran yang terlalu dekat. Upaya dalam mendukung program tersebut adalah dengan menggunakan alat kontrasepsi untuk menunda kehamilan dan menjarangkan atau mengatur jarak kelahiran.'),
(801, 730, 'P21.71', 'Apa saja jenis kontrasepsi yang BKKBN sarankan untuk pasangan yang ingin memberi jarak kelahiran pada anak?', 'Pil, Suntik KB, Implan, AKDR (Alat kontrasepsi dalam rahim), kondom, vasektomi dan tubektomi'),
(802, NULL, 'P22', 'PIK Remaja', NULL),
(803, 802, 'P22.1', 'Apa itu kesehatan reproduksi remaja?', 'Kesehatan reproduksi remaja adalah kondisi kesehatan reproduksi remaja yang optimal.'),
(804, 802, 'P22.2', 'Apa saja tantangan kesehatan reproduksi remaja?', 'Tantangan kesehatan reproduksi remaja antara lain kurangnya informasi, akses layanan kesehatan yang terbatas, dan tekanan teman sebaya.'),
(805, 802, 'P22.3', 'Apa pentingnya edukasi seks untuk remaja?', 'Edukasi seks untuk remaja penting untuk memberikan informasi yang benar tentang kesehatan reproduksi, mencegah perilaku seksual berisiko, dan melindungi dari IMS dan KTD.'),
(806, 802, 'P22.4', 'Di mana remaja bisa mendapatkan informasi tentang kesehatan reproduksi?', 'Remaja dapat memperoleh informasi tentang kesehatan reproduksi dari dokter, guru BK, orang tua, atau situs web kesehatan terpercaya.'),
(807, 802, 'P22.5', 'Pengertian dari Pusat Informasi dan Konseling Remaja (PIK Remaja) adalah', 'Wadah kegiatan yang dikelola dari, oleh dan untuk remaja guna memberikan akses informasi, pendidikan, konseling, dan pelayanan tentang perencanaan kehidupan berkeluarga bagi remaja serta kegiatan-kegiatan penunjang lainnya'),
(808, 802, 'P22.6', 'Saat ini banyak kasus perundungan yang terjadi, kenapa mereka tega melakukan perundungan?', '1. Mencari kekuasaan. \n2. Popularitas\n3. Balas dendam\n4. Korban beda dari yang lain\n5. Masalah di rumah\n6. Mencari kesenangan\n7. Peer pressure\nMeskipun begitu, perundungan bukanlah tidakan yang dibenarkan.'),
(809, 802, 'P22.7', 'Saat ini marak beredar konten pornografi di media sosial sehingga beberapa remaja rentan kecanduan pornografi. Bagaimana cara agar terhindar dari kecanduan pornografi pada remaja?', '1. Perkuat dan pegang teguh agama serta nilai keluarga. Cari tahu alasan di balik nilai-nilai tersebut supaya kamu lebih paham dan lebih mudah menerapkannya.\n2. Olahraga. Aktivitas fisik bisa menjadi penyaluran sekaligus pengalih perhatian yang sehat. Setelah berolahraga, otak juga mengeluarkan hormon yang membuatmu merasa lebih bahagia.\n3. Jaga batasan fisik dengan orang lain.\n4. Sibukkan dirimu. Ikuti ekstrakurikuler, organisasi, jadi panitia event, belajar, mengerjakan hobi, membuat proyek, ngobrol dengan keluarga—apa pun yang penting kamu suka.\nKarena gabut dan mager (malas gerak) bisa membuka jalan menuju pornografi. Iseng buka HP, tiba-tiba kepikir video yang lagi viral, penasaran, klik — sesederhana itu sekarang akses ke konten porno.\nDulu, generasi orang tua kamu mungkin harus cari VCD di rental atau ke warnet untuk akses seperti itu.\n5. Perkuat pengendalian diri (self-control). Tujuannya agar kamu bisa segera mengalihkan perhatian atau menahan diri ketika bertemu konten berbau seksual.'),
(810, 802, 'P22.8', 'Apa sih PIK R itu? dan kenapa PIK R penting buat kita para remaja?', 'PIK R atau Pusat Informasi dan Konseling Remaja merupakan salah satu wadah kegiatan yang dikembangkan dalam program GenRe yang dikelola dari, oleh, dan untuk remaja guna memberikan pelayanan informasi dan konseling tentang tentang pendewasaan usia perkawinan, delapan fungsi keluarga, TRIAD KRR (seksualitas, HIV dan AIDS serta Napza), keterampilan hidup (life skills), gender dan keterampilan advokasi dan KIE. Keberadaan dan peranan PIK R dilingkungan remaja sangat penting karena dapat memberikan informasi dan pelayanan konseling yang cukup dan benar tentang penyiapan kehidupan berkeluarga bagi remaja.'),
(811, 802, 'P22.9', 'Apa yang dimaksud dengan \"Pendidik Sebaya\" dan \"Konselor Sebaya\" di PIK R?', 'Pendidik Sebaya (PS) adalah remaja/mahasiswa yang secara fungsional mempunyai komitmen dan motivasi yang tinggi, sebagai nara sumber bagi kelompok remaja/mahasiswa sebayanya, telah mengikuti pelatihan/orientasi Pendidik Sebaya atau yang belum dilatih dengan mempergunakan Paduan Kurikurum dan Modul Pelatihan yang telah disusun oleh BKKBN, serta bertanggung Jawab kepada ketua PIK R/M. Sedangkan, Konselor Sebaya (KS) adalah Pendidikan Sebaya yang secara fungsional punya komitmen dan motivasi yang tinggi untuk memberikan konseling bagi kelompok remaja/mahasiswa sebayanya, telah mengikuti pelatihan/orentasi konseling atau yang belum dilatih dengan mempergunakan Panduan kurikulum dan Modul pelatihan yang telah disusun oleh BKKBN,serta bertanggung jawab kepada ketua PIK R/M.'),
(812, 802, 'P22.10', 'Siapa saja pengelola PIK R/M?', 'Pengelolan PIK Remaja/mahasiswa adalah remaja/mahasiswa berusia maksimal 24 tahun, belum menikah dan punya komitmen dalam mengelola dan melaksanakan PIK Remaja/mahasiswa terdiri dari ketua, Sekretaris, Bendahara, dan ketua bidang. Pengelola PIK R/M bisa dari Pendidik Sebaya maupun Konselor Sebaya.'),
(813, 802, 'P22.11', 'Program GenRe itu sebenernya buat apa sih? Apa hubungannya dengan kita sebagai anak muda zaman sekarang?', 'Secara umum program GenRe bertujuan untuk memfasilitasi remaja belajar memahami dan mempraktikan perilaku hidup sehat dan berakhlak (healthy and ethical life behaviors) untuk mencapai ketahanan remaja (adolescent resilience) sebagai dasar mewujudkan Keluarga Kecil Bahagia dan Sejahtera. Kemudian secara khusus bertujuan agar remaja memahami dan mempraktikan pola hidup sehat dan berakhlak, remaja memahami dan mempraktikan pola hidup yang berketahanan, remaja memahami dan mempersiapkan diri menjadi GenRe Indonesia. Salah satu program turunan yang di berikan oleh BKKBN dan bersentuhan langsung dengan Gen-Z ialah program Generasi Berencana (GenRe). Program GenRe merupakan program yang dicanangkan oleh Badan Kependudukan dan Keluarga Berencana Nasional (BKKBN). Program ini dikembangkan oleh Sub Bidang Bina Ketahanan Remaja, Advokasi dan KIE juga berkoordinasi juga dengan Sub Bagian Umum dan Humas dan mitra BKKBN yang lain. Sasaran program ini ditujukan bagi remaja dan keluarga yang memiliki remaja sebagai wadah dan sumber informasi bagi orang tua untuk memperoleh pengetahuan tentang pembinaan remaja agar terwujudnya remaja yang berakhlak mulia dan terciptanya keluarga sejahtera.'),
(814, 802, 'P22.12', 'Apa sih yang menjadi fokus kegiatan dari program GenRe?', 'Yang menjadi fokus kegiatan dari program GenRe diantaranya:\na. Promosi penundaan usia kawin utamakan sekolah dan berkarya \nb. Penyediaan informasi kesehatan reproduksi seluas luasnya (PIK Remaja/Mahasiswa) shg tdk terjebak NARKOBA, HIV/AIDS, dan kehamilan yang tidak diinginkan \nc. Promosi merencanakan kehidupan berkeluarga dengan sebaik-baiknya (kapan menikah, kapan mempunyai anak, berapa jumlah anaknya dsb)'),
(815, 802, 'P22.13', 'Bagaimana cara Gen Z berkontribusi dalam program GenRe?', 'Gen-Z sangat berpengaruh dalam pelaksanaan program GenRe. Pemerintah merangkul remaja-remaja yang termasuk dalam kategori Gen-Z, dengan harapan dapat memberikan pengaruh yang signifikan dalam melaksanakan program GenRe. Pengaruh Gen-Z ini bisa dilihat perkembangannya dari banyaknya generasi remaja yang awalnya kurang aktif dalam berinteraksi sosial menjadi lebih aktif. Hal ini terbukti dengan adanya organisasi-organisasi yang didalamnya banyak remaja-remaja yang berpartisipasi untuk memberikan perubahan di lingkungan masyarakat khususnya pada remaja. Dalam mewujudkan program GenRe ini, para remaja yang tergabung dalam forum GenRe ini bisa merangkul teman-teman sebayanya untuk ikut serta dalam menyukseskan program GenRe yang berkualitas sesuai dengan tujuan dari program GenRe.'),
(816, 802, 'P22.14', 'Apa yang dimaksud dengan KTD?', 'KTD adalah singkatan dari Kehamilan Tidak Diinginkan. Merupakan kehamilan saat dimana salah satu atau kedua belah pihak dari pasangan tidak menginginkan terjadinya kehamilan sama sekali atau kehamilan yang sebenarnya diinginkan tapi tidak pada saat itu.'),
(817, 802, 'P22.15', 'Apa saja dampak KTD pada remaja?', 'Tekanan psikologis sanksi sosial, putus sekolah, kerentanan terjadinya gangguan pada Kesehatan organ reproduksi, perasaan malu, sensitif atau mudah marah, dan peningkatan kasus aborsi.'),
(818, 802, 'P22.16', 'Apakah ada karakteristik remaja yang berpotensi terjadi KTD?', 'Ya, ada. Diantaranya yaitu:\n-Krisis identitas atau pencarian identitas diri, sehingga pengaruh lingkungan yang tidak baik dan kurangnyainformasi yang benar menyebabkan permasalahan termasuk KTD.\n-Kecenderungan membentuk kelompok \n-Senang bereksperimen \n-Ketidakstabilan emosi\n-Adanya sikap menentang dan menantang orang tua \n-Kegelisahan karena banyak hal yang diinginkan tetapi remaja tidak sanggup memenuhi semuanya \n-Senang bereksplorasi'),
(819, 802, 'P22.17', 'Bagaimana jika sudah terlanjur terjadi KTD? Apa yang harus dilakukan?', '-Sebaiknya beritahu kehamilan yang terjadi pada orang yang dipercaya, terutama keluarga kedua belah pihak\n-Tetap mempertahankan kehamilan\n-Perlu dipikirkan apakah akan menikah, membesarkan anak seorang diri, ataupun memberikan anak tersebut untuk diadopsi hal ini berlaku untuk kasus khusus seperti pemerkosaan dan kekerasan). Jika dirawat sendiri maka remaja harus siap secara ekonomi, psikis, dan sosial\n-Tidak meneruskan kehamilan\n-Perlu dipertimbangkan risiko yang terjadi, kemungkinan timbulnya penyesalan dan perasaan bersalah, kemungkinan terjadinya infeksi yang dapat mengakibatkan peradangan dan risiko kemungkinan terjadinya mandul. Maka, carilah informasi yang benar agar tahu untuk mencari pertolongan yang tepat dan aman.\n-Bagi mereka yang mengalami KTD, dukungan lingkungan sangat diperlukan. Kepedulian, perhatian serta pengertian sangat dibutuhkan khususnya bagi remaja.\n-Bagi para remaja, mulailah untuk bertanggung jawab terhadap diri sendiri karena masa depan berada di tangan remaja itu sendiri. Hargailah dirimu sendiri dan mulai belajar untuk mempertimbangkan segala tindakan dengan masak masak dan jangan menutup diri terhadap nasehat atau masukan positif dari lingkungan sekitar.'),
(820, 802, 'P22.18', 'Jika mengalami KTD kemudian memilih aborsi apa bahayanya buat perempuan usia remaja?', 'Praktik aborsi memiliki bahaya terhadap kesehatan atau keselamatan Perempuan. Diantaranya:\n1.	Resiko pada Kesehatan dan keselamatan\nDalam buku “Facts of Life” yang ditulis oleh Brian Clowes, Phd, terdapat beberapa bahaya yang dihadapi perempuan ketika melakukan aborsi. Bahaya tersebut antara lain:\n-Kematian akibat pendarahan hebat.\n-Terjadi infeksi di sekitar kandungan.\n-Kerusakan leher rahim sehingga bisa menyebabkan anak berikutnya mengalami cacat.\n-Bisa menyebabkan kanker payudara, karena terjadi ketidakseimbangan hormon estrogen pada wanita.\n-Bisa menyebabkan kanker indung telur.\n-Bisa menyebabkan kanker leher rahim.\n-Bisa menyebabkan kanker hati.\n-Bisa menyebabkan kelainan pada placenta (ari-ari), sehingga menyebabkan anak berikutnya mengalami cacat atau pendarahan ketika menjalani kehamilan berikutnya.\n-Memiliki resiko mengalami kemandulan.\n-Bisa menyebabkan infeksi rongga panggul.\n-Bisa menyebabkan infeksi lapisan rahim\n2.	Resiko gangguan psikologis\nAborsi selain memiliki resiko kesehatan dan keselamatan, juga memiliki dampak negatif terkait mental seorang perempuan. Gejala tersebut termuat dalam “Psychological Reactions Reported After Abortion” di dalam penerbitan The Post-Abortion Review (1994). Lantas resiko mental apa saja yang bisa dialami?\n-Pelaku aborsi bisa kehilangan harga diri.\n-Pelaku aborsi seperti merasa diasing oleh masyarakat.\n-Pelaku aborsi bisa mengalami mimpi buruk mengenai bayi.\n-Pelaku aborsi bisa memiliki keinginan bunuh diri.\n-Pelaku aborsi bisa mulai mencoba mengkonsumsi obat-obat terlarang.\n-Pelaku aborsi mungkin tidak bisa lagi menikmati lagi hubungan seksual.'),
(821, 802, 'P22.19', 'Bagaiman cara kita Gen Z untuk menghindari terjadinya seks pra-nikah?', '1. Memiliki pondasi keimanan yang kuat\n2. Komunikasi yang baik dan informasi yang tepat mengenai pendidikan seks yang didapat dari orang tua dan pendidik, atau P/R (Pusat Informasi Konseling Remaja)\n3. Memilih teman pergaulan melalui komunitas kegiatan positif\n4. Hindari menonton film pornografi dan pembicaraan yang berbau seksual'),
(822, 802, 'P22.20', 'Apa itu PUP dan kenapa kita Gen Z harus peduli?', 'PUP adalah singkatan dari Pendewasaan Usia Perkawinan sebagai upaya untuk meningkatkan usia pada perkawinan pertama, sehingga pada saat perkawinan mencapai usia minimal 20 tahun bagi perempuan dan 25 tahun bagi laki-laki. Gen-Z perlu peduli dengan PUP karena usia kawin yang terlalu muda berisiko pada kesehatan ibu dan anak, seperti Resiko pada proses kehamilan misalnya keguguran pre-eklamsia dan eklamsia infeksi anemia kanker rahim dan kematian bayi serta dapat beresiko pada proses persalinan misalnya prematur BBLR (berat bayi lahir rendah) kelian bawaan kematian bayi dan kematian ibu. Selain itu, menunda usia perkawinan memberi kesempaatan bagi remaja untuk menyelesaikan Pendidikan, mencapai kematangan emosional dan ekonomi, serta dapat merencanakan keluarga secara lebih baik sehingga dapat mewujudkan keluarga yang bahagia dan Sejahtera.');
INSERT INTO `faq` (`id`, `parent_id`, `key_name`, `question_text`, `answer_text`) VALUES
(823, 802, 'P22.21', 'Mengapa pendewasaan usia perkawinan (PUP) dikatakan penting untuk kita sebagai remaja?', 'Penundaan atau pendewasaan usia perkawinan sangat penting agar setiap pasangan mempunyai kematangan dalam segala aspek diantaranya kesiapan psikis, fisik, ekonomi, sosial, dan pendidikan sebelum mengarungi bahtera rumah tangga agar tercipta stabilitas perkawinan dan mencegah kegagalan perkawinan yang dapat dihindari.'),
(824, 802, 'P22.22', 'Bagaimana cara kita sebagai Gen Z membantu mencegah pernikahan dini di lingkungan kita?', 'PIK R dan Genre efektif untuk mencegah perkawinan anak karena didasari oleh peran teman sebaya yang cenderung lebih mudah didengarkan oleh remaja dibandingkan melalui orang tua karena yang mengkampanyekan kepada mereka adalah mereka sendiri, jadi pendewasaan usia perkawinan itu remaja sendiri yang mengajak teman sebaya untuk menghindarinya, ketika yang menyampaikan adalah konselor dan pendidik sebaya di kalangan mereka sendiri, maka akan lebih efektif karena mereka bisa merasa lebih nyaman.'),
(825, 802, 'P22.23', 'Apa saja indikator kesiapan untuk menikah versi BKKBN yang perlu dipahami Gen Z?', 'a.	Persiapan Fisik\n-Alat reproduksi berfungsi dengan normal.\n-Kesehatan fisik secara umum: kesehatan jantung, paru-paru, dll.\n-Mempersiapkan nutrisi yang baik sebelum kehamilan.\nb.	Persiapan Psikologis\n-Kematangan tertentu secara psikologis untuk menghadapi tantangan-tantangan ketika berumah tangga.\n-Menjaga keseimbangan emosi/ perasaan jiwa.\nc.	Persiapan Kognitif \n-Kesiapan diri terhadap perbedaan kultur, ilmu dan emosional.\n-Memahami kelebihan dan kekurangan pasangan\n-Memahami perbedaan pola pikir pasangan.\nd.	Persiapan ekonomi/keuangan\nPernikahan tidak hanya berdasarkan cinta, namun juga harus mempertimbangkan persiapan finansial untuk memenuhi kebutuhan ekonomi keluarga.'),
(826, 802, 'P22.24', 'Apa saja resiko yang dapat terjadi jika seorang remaja hamil dibawah usia 21 tahun?', 'a.        Dampak pada Ibu\n-resiko kematian ibu, pada ibu risiko kematian atau komplikasi dalam kehamilan akan meningkat dikarenakan organ reproduksinya belum siap untuk menjalani proses persalinan\n-Tekanan darah tinggi dan keracunan dalam kehamilan\n-depresi pasca melahirkan (baby blues syndrome), remaja Perempuan lebih berisiko mengalami depresi pasca melahirkan karena merasa tidak siap, terutama jika tidak mendapat dukungan dari keluarga dan/ pasangan\n-aborsi\nb.        Dampak pada bayi\n-Bayi lahir premature\n-bayi berat badan lahir rendah/BBLR (kurang dari 2.500 gr)\n-risiko kelainan pada bayi'),
(827, 802, 'P22.25', 'Gimana kalau ada remaja yang sudah terlanjur menyalahgunakan NAPZA?', 'Bagi remaja yang sudah menyalahgunakan NAPZA perlu upaya pencegahan, terapi (perawatan) dan rehabilitasi untuk memberikan pemulihan pada kondisi fisik dan psikisnya. Dengan pemulihan secara fisik maupun psikis anak dan remaja akan dapat kembali pulih dan perilaku adiktif mereka dapat diubah sehingga mereka dapat kembali menjalankan perannya dalam keluarga maupun masyarakat. Upaya penanganan gangguan penggunaan NAPZA pada Anak dan Remaja juga dilakukan dengan pendekatan promotif, preventif, kuratif dan rehabilitatif. Sehingga memerlukan pendekatan yang khusus dan berbeda dengan orang dewasa. Proses rehabilitasi harus mempertimbangkan kondisi psikologis, sosial, dan biologis anak dan remaja yang sedang dalam fase perkembangan.'),
(828, 802, 'P22.26', 'Apakah benar NAPZA itu bisa memicu masalah kesehatan mental?', 'Ya, Selain menyebabkan kerusakan pada organ-organ tubuh, penyalahgunaan narkoba juga dapat merusak kesehatan mental penggunanya. Diantaranya:\n1.	Gangguan Kecemasan dan Depresi: walaupun narkoba bisa membuat penggunanya merasa tenang dan rileks untuk mengatasi perasaan cemas, stres, dan depresi, efek ini ternyata hanya bersifat sementara. Penggunaan narkoba dalam jangka waktu yang lama dapat memperburuk gangguan kecemasan dan depresi yang sudah dialami, bahkan dapat memicu gangguan mental lainnya.\n2.	Meningkatkan Risiko Psikosis: Beberapa jenis obat-obatan psikotropika, seperti LSD dan ekstasi, dapat menimbulkan gejala-gejala psikotik, seperti halusinasi, delusi, dan gangguan realitas lainnya yang menyebabkan penderitanya bisa melihat, mendengar, mencium, atau merasakan hal-hal yang sebenarnya tidak ada. Selain halusinasi, narkoba juga dapat meningkatkan risiko gangguan kejiwaan lainnya, seperti bipolar dan gangguan psikotik kronis, seperti skizofrenia.\n3.	Merusak Kemampuan Berpikir dan Fungsi Kognitif\nPenggunaan narkoba dalam jangka waktu lama dapat menyebabkan perubahan pada sel saraf otak Perubahan ini kemudian akan menyebabkan gangguan pada fungsi otak yang mengendalikan kemampuan berpikir dan berkomunikasi. Akibatnya, daya ingat dan konsentrasi akan menurun, sehingga penderitanya akan mengalami kesulitan dalam berpikir dan mengambil keputusan yang tepat.\nPenggunaan narkoba yang bersifat stimulan, seperti metamfetamin dan ekstasi, juga dapat merusak fungsi kognitif penggunanya, sehingga mempengaruhi kemampuan belajar dan konsentrasi dalam jangka panjang.\n4.	Ketergantungan Emosional dan Perubahan Suasana Hati\nZat-zat dari narkoba akan masuk ke otak lewat aliran darah dan berinteraksi dengan sistem limbik di otak untuk melepas emosi atau perasaan senang, tenang, dan bahagia. Hal ini dapat menyebabkan pengguna narkoba kehilangan kendali atas impulsnya. \nSetelah efeknya berakhir, pengguna narkoba cenderung akan mengkonsumsi narkoba lagi untuk mempertahankan efek emosional positif yang sempat mereka rasakan. Jika digunakan secara terus menerus, hal ini dapat menyebabkan ketergantungan emosional pada narkoba, atau kecanduan.\nPecandu narkoba bisa mengalami perubahan suasana hati yang ekstrim, terutama yang mengkonsumsi kokain atau amfetamin. Kedua jenis narkoba ini dapat menimbulkan perasaan euforia tinggi, yang kemudian berubah menjadi kelelahan, kecemasan, dan depresi, setelah efeknya hilang.\n5.	Perubahan Perilaku\nKarena kemampuan mengontrol impulsnya terganggu, pengguna narkoba cenderung tidak bisa mengendalikan perilakunya, misalnya mudah menjadi agresif atau melakukan kekerasan, baik secara tindakan maupun ucapan. Narkoba juga bisa memunculkan pikiran untuk menyakiti diri atau bunuh diri, terutama pada remaja dan anak-anak muda yang mentalnya lemah.'),
(829, 802, 'P22.27', 'Bagaimana cara remaja bisa terbebas dari bujukan atau tekanan teman untuk menggunakan NAPZA?', 'Dapat dengan mengadakan program pelatihan misalnya ketrampilan psikososial. Program latihan ini diterapkan atas dasar teori belajar, yang mengatakan bahwa gangguan penyalahgunaan Napza merupakan perilaku yang dipelajari individu dalam lingkup pergaulan sosialnya. Perilaku ini mempunyai maksud dan arti tertentu bagi yang bersangkutan.Dalam pelatihan ini terdiri dari dua golongan yaitu,pertama Psychological Inoculation dalam pelatihan ini diputar film yang memperlihatkan bagaimana remaja mendapatkan tekanan dari pergaulannya, kemudian dalam hal ini dikembangkan sikap remaja untuk menentang dorongan dan tekanan tersebut.Kedua Personal and Social Skill training kepada remaja dikembangkan suatu ketrampilan dalam menghadapi problema hidup umum termasuk merokok dan penyalahgunaan Napza. Ketrampilan ini mengajarkan kepada remaja agar mampu mengatakan tidak, serta mengembangkan keberanian dan ketrampilan untuk mengekspresikan kebenaran, sehingga remaja terbebas dari bujukan atau tekanan kelompoknya.'),
(830, 802, 'P22.28', 'Apa itu KNPI?', 'KNPI adalah singkatan dari Kissing, Necking, Petting, dan Intercouse. Kissing diartikan mencium dengan Hasrat seksual. Necking artinya mencium di bagian leher atau merangsang di bagian telinga pasangan. Petting, yang diartikan bercumbuan dengan cara menggesek-gesekkan penis ke vagina dengan masih memakai baju, memegang alat vital pasangan atau mengeluarkan sperma di vagina. Sedangkan, Intercourse atau melakukan hubungan seksual/bersetubuh selayaknya suami istri. Itu semua merupakan aktivitas/perilaku seksual remaja atau gaya berpacaran yang tidak sehat.  Oleh karena itu, hubungan seks sebelum menikah perlu untuk dihindari karena banyak akibat yang bisa merugikannya.'),
(831, 802, 'P22.29', 'Kenapa remaja tidak dianjurkan diet demi bentuk badan yang ideal atau bagus?', 'Memang biasanya di usia remaja banyak yang memiliki keinginan untuk berdiet demi mendapatkan bentuk badan yang ideal. Namun, anak muda sebenarnya tidak perlu berdiet sebab untuk menjadi sehat badan kita membutuhkan lemak dalam jumlah tertentu. Jika seseorang memiliki kelebihan berat badan/kegemukan sebaiknya dibantu oleh seorang dokter atau ahli gizi untuk mengurangi berat badannya.'),
(832, 802, 'P22.30', 'Mengapa pendidikan kesehatan reproduksi penting untuk diberikan sejak usia sekolah?', 'Pendidikan kesehatan reproduksi penting diberikan sejak usia sekolah untuk memberikan informasi akurat dan membantu remaja memahami perubahan tubuh selama pubertas, risiko seksual, dan hak-hak reproduksi mereka. Dengan edukasi dini, remaja lebih siap menghadapi masa pubertas, membangun hubungan sehat, dan mencegah penyakit menular seksual serta kehamilan tidak direncanakan.  Pendidikan kesehatan reproduksi bagi anak usia sekolah lebih menekankan kepada proses pertumbuhan dan perkembangan untuk mencapai dewasa sehat dan mengasah kemampuan/daya tangkal peserta didik untuk menghindarkan diri dari perilaku berisiko atau pengaruh luar yang akan berdampak negatif bagi kesehatan mereka khususnya kesehatan reproduksi (https://uks.kemdikbud.go.id).'),
(833, 802, 'P22.31', 'Kenapa kita Gen Z perlu tahu tentang kesehatan reproduksi sejak dini? Bukankah itu tabu?', 'Pendidikan tentang Kesehatan reproduksi sangat penting untuk dilakukan sejak dini untuk mencegah terjadinya permasalahan-permasalahan yang terkait dengan alat reproduksi pada remaja. Pendidikan tentang Kesehatan reproduksi ini bisa diberikan di sekolah-sekolah, tidak harus dengan menunjukkan alat kelaminnya secara langsung tetapi juga bisa dengan melalui animasi atau bisa dengan membuat documenter yang singkat tetapi jelas dan tidak perlu ditampakkan alat kelamin. Dengan adanya Pendidikan Kesehatan reproduksi sejak dini dapat menjaga diri para remaja dalam pergaulan bebas, lebih aware dengan perubahan pada dirinya dan juga dapat mendeteksi kelainan pada tubuhnya lebih dini.'),
(834, 802, 'P22.32', 'Apa itu TRIAD KRR?', 'TRIAD KRR (Tiga Ancaman Dasar Kesehatan Reproduksi Remaja) adalah tiga risiko yang dihadapi oleh remaja, yaitu seksualitas, HIV/AIDS dan Napza.'),
(835, 802, 'P22.33', 'Apa aja penyebab utama dari masalah Kesehatan reproduksi remaja?', 'Penyebab masalah Kesehatan reproduksi remaja atau TRIAD KRR diantaranya yaitu, minimnya pengetahuan remaja tentang Kesehatan reproduksi dan dukungan orang tua, teman sebaya, dan sekolah. Selain itu juga, tidak tersedianya informasi yang akurat dan benar mengenai Kesehatan reproduksi akan membuat remaja melakukan eksplorasi sendiri. Sehingga dengan adanya PIK R diharapkan dapat meningkatkan ketahanan remaja.'),
(836, NULL, 'P23', 'PPKS', NULL),
(837, 836, 'P23.1', 'Apa tujuan utama dari terbentuknya Satyagatra', 'Untuk mendukung keluarga menjalankan fungsi keluarga secara optimal dan mewujudkan keluarga berkualitas .\n Untuk mendukung keluarga menjalankan fungsi keluarga secara optimal dan mewujudkan keluarga berkualitas.'),
(838, 836, 'P23.2', 'Apa itu Satyagatra?', 'Kepanjangan dari Pusat Pelayanan Keluarga Sejahtera yang selanjutnya disebut Satyagatra adalah wadah kegiatan terpadu yang mudah diakses oleh masyarakat, dengan kegiatan dan/atau rangkaian kegiatan pelayanan keluarga sesuai siklus hidup yang dilaksanakan dalam bentuk komunikasi, informasi dan edukasi, konsultasi dan konseling serta pendampingan maupun rujukan.'),
(839, 836, 'P23.3', 'Kapan Satyagtra mulai dibentuk?', 'Satyagatra mulai dibentuk pada tahun 2012 oleh BKKBN untuk memperkuat ketahanan keluarga dan menurunkan kerentanan keluarga dengan akronim PPKS'),
(840, 836, 'P23.4', 'Apa akronim awal sebelum menjadi Satyagatra?', 'PPKS ( Pusat Pelayanan Keluarga Sejahtera ) .'),
(841, 836, 'P23.5', 'Tahun berapa nama Satyagatra mulai digunakan secara resmi?', 'Tahun 2023 berdasarkan Peraturan BKKBN Nomor 15 Tahun 2023.'),
(842, 836, 'P23.6', 'Apa saja jenis pelayanan di Satyagatra?', '8 Layanan Utama dan 1 layanan lainnya :\n 1. Pelayanan data dan informasi program bangga kencana \n 2. Konsultasi dan Konseling keluarga balita dan anak\n 3. Konsultasi dan Konseling keluarga remaja dan remaja \n 4. Konsultasi dan Konseling pra nikah\n 5. Konsultasi dan Konseling keluarga lansia dan lansia\n 6. Konsultasi dan Konseling KB dan Kesehatan Reproduksi \n 7. Konsultasi dan Konseling Keluarga harmonis \n 8. Konsultasi dan Konseling Usaha Ekonomi Keluarga\n Layanan lainnya merupakan pelayanan pendukung sebagai bentuk integrasi pelayanan ddengan mita kerja'),
(843, 836, 'P23.7', 'Apa definisi sistem rujukan?', 'Proses mencari bantuan ke fasilitas dengan sumber daya lebih baik saat tenaga kesehatan tidak mampu menangani suatu kondisi.'),
(844, 836, 'P23.8', 'Apa itu rujukan satyagatra secara vertikal?', 'Rujukan ke fasilitas kesehatan dengan tingkat pelayanan lebih tinggi'),
(845, 836, 'P23.9', 'Apa itu rujukan satyagatra secara horizontal?', 'Rujukan ke fasilitas dengan jenis yang sama namun kompetensi berbeda.'),
(846, 836, 'P23.10', 'Apa tujuan dari sistem rujukan Satyagatra?', 'Untuk melimpahkan tugas kepada mitra kerja yang lebih kompeten jika Satyagatra tidak mampu menangani masalah klien.'),
(847, 836, 'P23.11', 'Siapa klien dalam konteks Satyagatra?', 'Orang yang menerima layanan konsultasi dan konseling.'),
(848, 836, 'P23.12', 'Ada dimana Satyagatra?', 'Ada tiga tingkatan yaitu tingkat Provinsi, Kabupaten/Kota dan Kecamatan. Setiap pembentukan harus ada Surat Keputusan Pengelola dan Pelaksana dari perangkat daerah di wilayah tersebut.'),
(849, 836, 'P23.13', 'Apa saja prinsip pelaksanaan rujukan Satyagatra?', 'Berdasarkan permasalahan, ditujukan pada lembaga pemerintah/non-pemerintah, dan bisa antar wilayah maupun lebih tinggi.'),
(850, 836, 'P23.14', 'Siapa yang disebut pengelola Satyagatra?', 'Seseorang atau sekelompok orang yang mendapat mandat untuk mengelola Satyagatra.'),
(851, 836, 'P23.15', 'Apa dasar hukum utama penyelenggaraan Satyagatra?', 'UU No. 52 Tahun 2009, UU No. 25 Tahun 2009, PP No. 87 Tahun 2014, dan Peraturan BKKBN No. 15 Tahun 2023'),
(852, 836, 'P23.16', 'Apa tujuan rujukan pelayanan di Satyagatra?', 'Memberikan pelayanan lanjutan bagi klien yang tidak bisa ditangani langsung di Satyagatra.'),
(853, 836, 'P23.17', 'Apa itu keluarga berkualitas menurut Satyagatra?', 'Keluarga yang sejahtera, sehat, mandiri, harmonis, dan bertakwa kepada Tuhan.'),
(854, 836, 'P23.18', 'Siapa yang disebut sebagai Konselor dalam Pelaksana Pelayanan Teknis Satyagatra?', 'Konselor adalah seseorang atau sekelompok orang yang memiliki kompetensi dan informasi terkait kependudukan secara umum, serta keluarga berencana dan pembangunan keluarga secara khusus.'),
(855, 836, 'P23.19', 'Apa definisi konseling?', 'Konseling adalah suatu pertemuan langsung dengan individu yang bertujuan memberikan bantuan agar individu dapat menyesuaikan diri secara lebih efektif dengan dirinya sendiri dan lingkungannya.'),
(856, 836, 'P23.20', 'Apa perbedaan utama antara konsultasi dan konseling?', 'Konsultasi adalah proses pemberian bantuan secara tidak langsung oleh seorang ahli kepada seseorang di bidang tertentu, sedangkan konseling adalah proses bantuan langsung (tatap muka) untuk membantu individu mengatasi masalah dan mengembangkan potensinya.'),
(857, 836, 'P23.21', 'Apa tujuan utama konseling secara umum?', 'Tujuannya adalah membantu pertumbuhan dan perkembangan individu serta membantunya agar dapat berperan aktif di lingkungan sosialnya.'),
(858, 836, 'P23.22', 'Apa saja manfaat konseling?', 'Manfaat konseling antara lain: memandu, menyembuhkan, memfasilitasi, memodifikasi, merekonstruksi, mengembangkan, mengkomunikasikan, mempengaruhi, dan mengorganisasi.'),
(859, 836, 'P23.23', 'Apa saja teknik dasar dalam konseling?', 'Teknik dasar konseling meliputi: rapport, attending, empati, acceptance, restatement, reflection of feeling, klarifikasi, parafrasing, konfrontasi, bertanya (terbuka dan tertutup), eksplorasi, interpretasi, menyimpulkan sementara dan akhir, serta termination.'),
(860, 836, 'P23.24', 'Bagaimana tahapan konseling secara umum?', 'Terdiri dari 3 tahap: (1) Tahap awal (membangun hubungan dan mengidentifikasi masalah), (2) Tahap pertengahan (menjelajahi masalah dan memberikan bantuan), dan (3) Tahap akhir (evaluasi, perubahan perilaku, dan pengakhiran).'),
(861, 836, 'P23.25', 'Apa saja etika yang harus dijunjung dalam konseling?', 'Etika konseling meliputi tanggung jawab profesi, menjaga kerahasiaan, memberikan informasi yang relevan, dan menyadari pengaruh konselor dalam hubungan konseling.'),
(862, 836, 'P23.26', 'Apa jenis-jenis konseling berdasarkan tema atau sasaran?', 'Konseling pendidikan, pekerjaan, keluarga, perkawinan, agama, rehabilitasi, individual, dan kelompok.'),
(863, 836, 'P23.27', 'Apa saja pendekatan konseling yang dibahas dalam panduan?', 'Tiga pendekatan utama: (1) Psikoanalisis, (2) Behavioristik, (3) Humanistik.'),
(864, 836, 'P23.28', 'Apa saja prinsip kemitraan di Satyagatra?', 'Ada 3 prinsip yaitu Kesetaraan atau keseimbangan (equity); Transparansi, meliputi transparansi pengelolaan informasi dan keuangna serta prinsip saling menguntungkan dimana kemitraan harus membawa manfaat bagi semua pihak yang terlibat.'),
(865, 836, 'P23.29', 'Apakah ada dukungan penganggaran dalam pengelolaan satyagatra?', 'Ada 3 hal yang khusus perlu dukungan penganggaran untuk penyelenggaraan Satyagatra seperti: Honorarium untuk tenaga pelaksana dan pengelola satyagatra; Biaya operasional Satyagatra dan Biaya Sosialisasi dan Promosi'),
(866, 836, 'P23.30', 'Perlukah Satyagatra menjalin kerjasama sistem rujukan?', 'Iya, Satyagatra memerlukan menjaring kemitraan dengan fasilitas lain terkait tindak lanjut hasil konsultasi (rujukan). Misalnya hasil konseling keluarga ditengarai terjadi kekerasan dalam rumah tangga maka perlu jejaring kemitraan dengan LPPA maupun dengan psikolog keluarga. Selain itu rujukan lain terkait kasus medis dengan fasilitas pelayanan kesehatan terdekat.'),
(867, 836, 'P23.31', 'Mitra kerja apa saja yang dapat bekerjasama dengan Satyagatra?', 'Instansi pemerintah (seperti Dinas Sosial, Dinas Kesehatan, DP3AP2KB, dsb), Instansi swasta, Lembaga Pendidikan, Komunitas/Masyarakat dan Media'),
(868, 836, 'P23.32', 'Apakah ada sistem pencatatan dan pelaporan pelayanan di Satyagatra?', 'Pencatatan dan pelaporan layanan semua terlaporkan di SIGA (Sistem Informasi Keluarga)'),
(869, 836, 'P23.33', 'Apa saja hasil akhir pelayanan di Satyagatra?', 'Pengelola dan Konselor membagi hasil pelayanan dalam 3 jenis yaitu Pelayanan tuntas, pelayanan berulang dan pelayanan rujukan. Khusus untuk pelayanan rujukan perlu ada formulir-formulir yang perlu dilengkapi untuk ke fasilitas pelayanan kesehatan'),
(870, NULL, 'P24', 'Partisipasi Remaja', NULL),
(871, 870, 'P24.1', 'Bagaimana upaya pencegahan penyakit menular seksual (PMS) bisa ditingkatkan di kalangan remaja?', 'Pemerintah dan sektor kesehatan memiliki peran krusial dalam meningkatkan kesadaran dan pencegahan PMS pada remaja. Program pencegahan yang terintegrasi dalam kurikulum sekolah, penyediaan klinik kesehatan remaja yang ramah, dan kampanye pencegahan di tingkat nasional dapat membantu menciptakan lingkungan yang mendukung kesehatan seksual remaja. Subsidi untuk kondom dan layanan pengujian yang terjangkau juga dapat merangsang perilaku pencegahan.'),
(872, 870, 'P24.2', 'Apa hubungan antara kesehatan reproduksi dengan upaya pencegahan kekerasan seksual?', 'Kesehatan reproduksi memiliki hubungan yang erat dengan upaya pencegahan kekerasan seksual. Pengetahuan dan pemahaman yang baik tentang kesehatan reproduksi, termasuk hak-hak reproduksi dan batasan aktivitas seksual, dapat membantu individu mengenali dan menghindari situasi berisiko kekerasan seksual. Pendidikan kesehatan reproduksi juga penting untuk meningkatkan kesadaran tentang penyakit menular seksual dan cara mencegahnya, yang seringkali terkait dengan kekerasan seksual.'),
(873, 870, 'P24.3', 'Apa langkah yang dilakukan BKKBN untuk meningkatkan partisipasi remaja dalam program pembangunan keluarga?', 'Membentuk dan membina PIK Remaja untuk meningkatkan literasi remaja tentang kesehatan reproduksi dan perencanaan masa depan.'),
(874, NULL, 'P25', 'Pelayanan Ramah Lansia', NULL),
(875, 874, 'P25.1', 'Sasaran Bina Keluarga Lansia (BKL) adalah…', 'Keluarga lansia dan lansia'),
(876, 874, 'P25.2', 'Apa kelebihan dan kekurangan Panti Jompo Lansia', '1, Kelebihan Panti Jompo :  pelayanan medis tingkat lanjut, kemudahan bagi lansia untuk berinteraksi dengan orang lain, dan aktivitas harian yang teratur.  \n2, Kekurangan Panti Jompo : keterbatasan kebebasan, kemungkinan perasaan tidak nyaman, dan potensi pelayanan yang kurang berkualitas dibandingkan dengan di rumah sendiri'),
(877, 874, 'P25.3', 'Mengapa kehadiran keluarga penting bagi Lansia?', 'Lansia akan lebih merasa lebih bahagia bila hidup dalam lingkungan keluarga, anak,\ncucu, dan akan lebih terlayani, terawat, serta terlindungi.'),
(878, 874, 'P25.4', 'Bagaimana peran keluarga dalam mendukung program lansia?', '1. Mengembangkan potensi keluarga termasuk Lansia, anggota keluarga yang memiliki Lansia seyogyanya selalu berupaya memberikan peluang, bimbingan, dan motivasi untuk membantu Lansia mengembangkan potensinya.\n2. Mengembangkan sosial dan ekonomi keluarga, Lansia dapat diberdayakan untuk membantu mengembangkan usaha ekonomi keluarga antara lain dengan memanfaatkan kemampuan dan ketrampilan sesuai dengan minat Lansia.\n3. Penyemaian 8 fungsi keluarga; Lansia dapat diberdayakan untuk membantu upaya penerapan penanaman nilai-nilai dalam 8 fungsi keluarga kepada anak dan cucu.'),
(879, 874, 'P25.5', 'Apakah stimulasi otak penting bagi lansia?mengapa?', 'Ya penting,\n1. Untuk mengantisipasi melambatnya kerja otak, sehingga diperlukan usaha untuk terus menerus\ndalam melatih otak\n2. Mengaktifkan kerja otak dengan berbagai macam aktivitas dapat memacu tumbuhnya atau\nterbentuknya sel-sel baru, serta memperkuat jaringan sinaps pada otak'),
(880, 874, 'P25.6', 'Apa yang dilakukan BKKBN untuk mengembangkan pelayanan ramah lansia?', 'Mengembangkan program BKL dan memberikan panduan untuk mewujudkan lansia yang sehat dan produktif.'),
(881, NULL, 'P26', 'Pemberdayaan Ekonomi Keluarga', NULL),
(882, 881, 'P26.1', 'Apa itu UMKM?', 'Usaha Mikro, Kecil, dan Menengah.'),
(883, 881, 'P26.2', 'Siapa yang termasuk usaha mikro?', 'Usaha dengan omzet maksimal Rp300 juta per tahun.'),
(884, 881, 'P26.3', 'Apa ciri utama usaha kecil?', 'Memiliki omzet Rp300 juta – Rp2,5 miliar per tahun.'),
(885, 881, 'P26.4', 'UMKM diatur dalam undang-undang apa?', 'UU No. 20 Tahun 2008.'),
(886, 881, 'P26.5', 'Apakah UMKM wajib punya NIB?', 'Ya, untuk legalitas usaha.'),
(887, 881, 'P26.6', 'Apa manfaat punya NIB?', 'Legalitas, akses pembiayaan, dan kemudahan izin usaha.'),
(888, 881, 'P26.7', 'Apa itu NIB?', 'Nomor Induk Berusaha.'),
(889, 881, 'P26.8', 'Apa contoh UMKM?', 'Warung makan, usaha laundry, kerajinan tangan.'),
(890, 881, 'P26.9', 'Apa tujuan pelatihan UMKM?', 'Meningkatkan kapasitas dan daya saing usaha.'),
(891, 881, 'P26.10', 'Apakah UMKM bisa ekspor?', 'Bisa, dengan syarat dan pelatihan yang tepat.'),
(892, 881, 'P26.11', 'Apa tantangan utama UMKM?', 'Modal, pemasaran, dan digitalisasi.'),
(893, 881, 'P26.12', 'Bagaimana cara UMKM go digital?', 'Gunakan media sosial, marketplace, dan pembayaran online.'),
(894, 881, 'P26.13', 'Apa itu sertifikasi halal UMKM?', 'Sertifikat produk halal dari MUI atau BPJPH.'),
(895, 881, 'P26.14', 'Apakah UMKM bisa dapat bantuan pemerintah?', 'Bisa, seperti bantuan BPUM atau KUR'),
(896, 881, 'P26.15', 'Apa itu KUR?', 'Kredit Usaha Rakyat, pinjaman bersubsidi untuk UMKM.'),
(897, 881, 'P26.16', 'Apa manfaat bergabung dengan koperasi UMKM?', 'Akses modal, pelatihan, dan jaringan usaha.'),
(898, 881, 'P26.17', 'Bagaimana UMKM bisa naik kelas?', 'Tingkatkan kualitas produk, manajemen, dan pemasaran.'),
(899, 881, 'P26.18', 'Apa itu digital marketing untuk UMKM?', 'Promosi online lewat media sosial, iklan digital, dll.'),
(900, 881, 'P26.19', 'Apa platform jualan online untuk UMKM?', 'Tokopedia, Shopee, Bukalapak, dan lainnya.'),
(901, 881, 'P26.20', 'Kenapa UMKM penting bagi ekonomi?', 'Menyerap tenaga kerja dan mendorong pertumbuhan ekonomi lokal.'),
(902, 881, 'P26.21', 'Kenapa perlu pencatatan keuangan?', 'Agar keuangan usaha lebih tertata dan jelas.'),
(903, 881, 'P26.22', 'Apa itu laporan laba rugi?', 'Laporan untung-rugi usaha dalam periode tertentu.'),
(904, 881, 'P26.23', 'Apa itu arus kas?', 'Catatan pemasukan dan pengeluaran uang.'),
(905, 881, 'P26.24', 'Kenapa penting punya rekening usaha sendiri?', 'Memisahkan uang pribadi dan usaha.'),
(906, 881, 'P26.25', 'Apa itu Rencana Usaha (Business Plan)?', 'Dokumen rencana pengembangan usaha.'),
(907, 881, 'P26.26', 'Apa itu break-even point (BEP)?', 'Titik balik modal, tidak rugi dan belum untung.'),
(908, 881, 'P26.27', 'Apa itu margin keuntungan?', 'Selisih harga jual dan biaya produksi.'),
(909, 881, 'P26.28', 'Kenapa penting buat harga jual yang tepat?', 'Agar usaha tetap untung dan kompetitif.'),
(910, 881, 'P26.29', 'Apa itu stok barang?', 'Persediaan produk untuk dijual.'),
(911, 881, 'P26.30', 'Kenapa perlu manajemen stok?', 'Menghindari kerugian karena barang rusak atau kedaluwarsa.'),
(912, 881, 'P26.31', 'Apa itu branding?', 'Citra dan identitas usaha di mata pelanggan.'),
(913, 881, 'P26.32', 'Kenapa penting punya logo usaha?', 'Untuk pengenalan dan identitas visual.'),
(914, 881, 'P26.33', 'Apa itu target pasar?', 'Kelompok konsumen yang dituju.'),
(915, 881, 'P26.34', 'Apa manfaat promosi?', 'Menarik pelanggan baru dan menjaga loyalitas'),
(916, 881, 'P26.35', 'Apa itu strategi harga?', 'Menentukan harga agar kompetitif dan menguntungkan.'),
(917, 881, 'P26.36', 'Kenapa penting survei pasar?', 'Mengetahui kebutuhan dan perilaku konsumen'),
(918, 881, 'P26.37', 'Apa itu digital marketing?', 'Promosi usaha melalui media digital.'),
(919, 881, 'P26.38', 'Platform apa saja yang bisa digunakan UMKM?', 'Instagram, WhatsApp, Shopee, Tokopedia.'),
(920, 881, 'P26.39', 'Apa manfaat media sosial untuk UMKM?', 'Meningkatkan jangkauan promosi.'),
(921, 881, 'P26.40', 'Apa itu konten marketing?', 'Promosi lewat informasi atau hiburan yang relevan.'),
(922, 881, 'P26.41', 'Apa itu inovasi produk?', 'Pembaruan atau variasi produk yang sudah ada.'),
(923, 881, 'P26.42', 'Kenapa penting riset pasar?', 'Untuk menyesuaikan produk dengan kebutuhan konsumen.'),
(924, 881, 'P26.43', 'Apa itu diversifikasi usaha?', 'Menambah variasi produk atau jasa.'),
(925, 881, 'P26.44', 'Apa pentingnya pelayanan konsumen?', 'Meningkatkan kepuasan dan loyalitas pelanggan.'),
(926, 881, 'P26.45', 'Bagaimana meningkatkan repeat order?', 'Produk bagus, pelayanan baik, dan follow-up aktif.'),
(927, 881, 'P26.46', 'Apa manfaat testimoni pelanggan?', 'Meningkatkan kepercayaan calon pembeli.'),
(928, 881, 'P26.47', 'Apa itu kemasan produk?', 'Pembungkus produk untuk menarik perhatian dan menjaga kualitas.'),
(929, 881, 'P26.48', 'Apa pentingnya desain kemasan?', 'Menarik dan membedakan dari pesaing.'),
(930, 881, 'P26.49', 'Kenapa UMKM harus adaptif terhadap tren?', 'Agar tetap relevan dan kompetitif.'),
(931, 881, 'P26.50', 'Apa itu branding personal untuk pelaku UMKM?', 'Citra positif pemilik usaha sebagai pendukung promosi.'),
(932, 881, 'P26.51', 'Apa itu KUR?', 'Kredit Usaha Rakyat, pinjaman dengan bunga rendah.'),
(933, 881, 'P26.52', 'Siapa yang bisa mengajukan KUR?', 'UMKM yang memiliki usaha aktif dan legal.'),
(934, 881, 'P26.53', 'Apa itu inkubasi bisnis?', 'Program pembinaan untuk pelaku usaha baru.'),
(935, 881, 'P26.54', 'Apa manfaat pelatihan UMKM?', 'Menambah pengetahuan dan keterampilan bisnis'),
(936, 881, 'P26.55', 'Apa itu koperasi UMKM?', 'Wadah kerja sama antar pelaku usaha.'),
(937, 881, 'P26.56', 'Apa itu marketplace?', 'Platform jual beli online seperti Tokopedia dan Shopee.'),
(938, 881, 'P26.57', 'Apakah UMKM bisa ekspor?', 'Bisa, dengan dukungan pelatihan dan regulasi.'),
(939, 881, 'P26.58', 'Apa itu sertifikat halal?', 'Tanda bahwa produk sesuai syariat Islam.'),
(940, 881, 'P26.59', 'Apa manfaat sertifikat halal bagi UMKM?', 'Menambah kepercayaan konsumen dan memperluas pasar.'),
(941, 881, 'P26.60', 'Apa tantangan utama UMKM?', 'Modal, pemasaran, digitalisasi, dan SDM.'),
(942, 881, 'P26.61', 'Apa mekanisme seleksi peserta program pemberdayaan ekonomi? Adakah prioritas untuk kelompok rentan seperti perempuan kepala keluarga, penyandang disabilitas, atau keluarga miskin?', 'Program Usaha Peningkatan Pendapatan Keluarga Sejahtera (UPPKS) dari BKKBN menyasar keluarga pra sejahtera dan keluarga sejahtera I, termasuk perempuan kepala keluarga, penyandang disabilitas, dan keluarga miskin. Mekanisme seleksi dilakukan melalui identifikasi oleh kader dan fasilitator di lapangan, dengan mempertimbangkan kondisi sosial-ekonomi dan potensi peserta dalam menjalankan usaha ekonomi produktif.​\nYo Sakurga'),
(943, 881, 'P26.62', 'Apakah ada pelatihan manajemen usaha kecil dan literasi keuangan sebelum pemberian bantuan modal?', 'Ya, BKKBN menyediakan pelatihan manajemen usaha kecil dan literasi keuangan melalui program UPPKS. Pelatihan ini mencakup pengelolaan usaha mikro, perencanaan keuangan, dan strategi pemasaran untuk meningkatkan kapasitas peserta dalam menjalankan usaha secara mandiri dan berkelanjutan.'),
(944, 881, 'P26.63', 'Bagaimana BKKBN menangani kegagalan usaha peserta? Apakah ada bantuan ulang atau perbaikan strategi?', 'Dalam menghadapi kegagalan usaha peserta, BKKBN melalui program UPPKS memberikan pendampingan dan pembinaan lanjutan. Langkah-langkah ini meliputi evaluasi usaha, pelatihan ulang, dan fasilitasi akses ke sumber daya tambahan untuk membantu peserta memperbaiki strategi usaha mereka.'),
(945, 881, 'P26.64', 'Bagaimana keterlibatan masyarakat dalam merancang program pemberdayaan ekonomi ini? Apakah masyarakat hanya sebagai penerima manfaat atau juga ikut merancang?', 'Masyarakat tidak hanya sebagai penerima manfaat, tetapi juga terlibat aktif dalam perencanaan dan pelaksanaan program pemberdayaan ekonomi. Melalui pendekatan partisipatif, BKKBN mendorong masyarakat untuk berperan dalam identifikasi kebutuhan, perencanaan kegiatan, dan evaluasi program, sehingga program lebih sesuai dengan kondisi dan potensi lokal.'),
(946, NULL, 'P27', 'Pendampingan Keluarga Beresiko Stunting', NULL),
(947, 946, 'P27.1', 'Dalam melakukan wawancara, pengumpul data perlu melakukan upaya terbaik untuk memperoleh jawaban responden. Salah satu uayanya adalah dengan melakukan probing. Pengertian Probing adalah: ...', 'Merangsang pikiran responden sehingga memperoleh informasi lebih banyak, dalam hal ini pewawancara harus mampu komunikatif, rileks, interaktif, akrab dan kritis tapi tidak memojokkan responden dan tidak bernada interogasi.'),
(948, 946, 'P27.2', 'Agar dapat login kedalam aplikasi Elsimil Tim Pendamping Keluarga harus teregistrasi kedalam aplikasi Elsimil terlebih dahulu. Apabila TPK belum teregistrasi maka hal paling tepat yang dapat dilakukan adalah....', 'Meminta kepada admin Kecamatan untuk meregistrasikan dirinya ke dalam aplikasi Elsimil'),
(949, 946, 'P27.3', 'Nama alat yang digunakan untuk mengukur tinggi badan anak usia diatas 2 tahun', 'Stadiometer'),
(950, 946, 'P27.4', 'Apa bentuk pendampingan keluarga berisiko stunting yang dilakukan oleh BKKBN?', 'Menyediakan kader pendamping, melakukan skrining kesehatan keluarga, dan mengarahkan intervensi pencegahan stunting.'),
(951, NULL, 'P28', 'Pendataan Keluarga', NULL),
(952, 951, 'P28.1', 'Bagaimana BKKBN memanfaatkan Rumah Dataku dalam mendukung pendataan keluarga?', 'Mengelola data keluarga berbasis komunitas untuk mendukung perencanaan program pembangunan keluarga.'),
(953, NULL, 'P29', 'Perencanaan Kehidupan Berkeluarga', NULL),
(954, 953, 'P29.1', 'Bagaimana cara mengetahui bahwa diri kita benar-benar siap membangun keluarga yang sehat dan harmonis melalui pernikahan?', 'Terdapat 10 dimensi kesiapan berkeluarga:\n1. Kesiapan usia\nUntuk wanita, usia ideal menikah itu 21 tahun, sedangkan laki-laki adalah 25 tahun. Usia ideal biasanya berhubungan dengan siap atau tidaknya catin dari segi fisik, mental, hingga finansial, untuk menikah. Apalagi kalau dikaitkan dengan kematangan alat reproduksi, yang nantinya akan sangat berpengaruh di proses kehamilan. Kematangan ini tidak hanya dibutuhkan pada catin wanita, tetapi juga laki-laki. Jadi, jangan sampai terlalu muda.\n2. Kesiapan fisik\nSemua catin pasti ingin tampil cantik dan ganteng di hari pernikahan. Ternyata, ada yang tidak kalah penting, yaitu kondisi kesehatan yang prima, agar catin bisa melakukan tugas sehari-sehari sebagai suami atau istri dengan baik.\n3. Kesiapan finansial\nSaat catin sudah menikah, tentunya kebutuhan menjadi bertambah. Selain catin akan hidup bersama pasangan, tanggung jawab catin biasanya juga akan jauh berkembang ketika punya anak. Jadi, penting buat catin untuk betul-betul mempersiapkan kondisi keuangannya. Pastikan catin dan pasangan punya sumber keuangan yang cukup untuk memenuhi kebutuhan dasar keluarga. Diskusi dengan pasangan juga perlu tentunya untuk mempersiapkan rencana masa depan yang butuh perencanaan keuangan.\n4. Kesiapan mental\nSelain fisik, kesiapan mental juga sangat diperlukan dalam membina keluarga. Masih berkaitan dengan usia ideal menikah, karena ternyata, usia yang matang juga biasanya memiliki kondisi mental yang matang juga. Tentunya dalam berkeluarga pasti akan ada tantangan dan permasalahan yang harus dihadapi catin dan pasangannya. Di sinilah kesiapan mental akan diuji. Catin dituntut untuk tangguh, tidak mudah putus asa, dan dapat saling menguatkan dan memberi semangat pada pasangan untuk bersama-sama menghadapi permasalahan. Semua kualitas diri catin ini dapat dimiliki apabila memiliki mental yang kuat.\n5. Kesiapan emosi\nKalau sudah punya pasangan dan hidup berkeluarga, tentunya catin harus belajar menjadi seseorang yang pengertian dan memahami pasangan. Kebayang ngga sih gak enaknya kalau setiap ada permasalahan, baik catin ataupun pasangan gampang marah dan tidak mau mengalah? Oleh karena itu, penting bagi catin untuk belajar mengelola emosi dan memiliki emosi yang matang.\n6. Kesiapan sosial\nKatanya kalau pengantin baru rasanya dunia milik berdua. Boleh aja menikmati masa-masa indah berdua. Tapi, perlu diingat kalau catin akan hidup bertetangga. Sebagai keluarga baru, catin juga harus mengasah kepedulian dan kepekaan akan kondisi di sekitarnya. Pasti rasanya lebih tenang apabila lingkungan sekeliling catin bisa peduli dan saling membantu ketika dibutuhkan. Jadi, prinsip kekeluargaan dan gotong royong harus selalu dijaga.\n7. Kesiapan moral\nSaat catin akan membangun keluarga, catin harus punya pondasi yang kuat akan nilai-nilai moral yang baik, seperti kejujuran, integritas, etika, juga dalam agama. Apalagi, nantinya catin akan menjadi calon orang tua yang dituntut untuk mendidik anak. Anak yang tumbuh dalam keluarga dengan pondasi moral yang kuat, akan mudah beradaptasi menjadi pribadi dengan moral yang kuat juga.\n8. Kesiapan interpersonal\nApa sih yang dimaksud dengan kesiapan interpersonal? Karena nantinya catin akan hidup bersama pasangan setelah menikah, pastinya akan sering menghabiskan waktu bersama. Jadi catin harus punya kemampuan untuk berinteraksi dan berkomunikasi dengan baik.\n9. Keterampilan hidup\nKeterampilan dasar dalam berumah tangga meliputi pekerjaan rumah, membersihkan dan merapikan rumah, memasak, apalagi apabila nanti sudah ada anak. Kemampuan ini harus dimiliki kedua pasangan, baik wanita maupun pria.\n10. Kesiapan intelektual\nBagi catin, kesiapan intelektual bisa diwujudkan dari kemampuan mencari informasi seputar pernikahan dan keluarga, tentunya yang benar dan jauh dari hoaks ya. Apalagi di era digital ini, banyak kan informasi tentang kesehatan, pengasuhan anak, hingga tips-tips seputar keluarga yang beredar. Catin harus bisa memilah mana sumber informasi yang valid dan tidak menjerumuskan.\n\nUntuk mengukur kesiapan, bisa mengikuti tes di questionnaire.siapnikah.org.'),
(955, 953, 'P29.2', 'Bagaimana jika berencana menikah dengan pasangan namun tidak mendapat restu orang tua?', 'Pernikahan yang harmonis sebaiknya didukung oleh restu orang tua. Jika belum mendapat restu, cari tahu penyebabnya. Bisa jadi orang tua belum mengenal pasangan dengan baik atau memiliki kekhawatiran tertentu. Komunikasikan dengan sabar dan coba cari jalan tengah. Jika memungkinkan, libatkan pihak ketiga yang netral untuk membantu menjembatani perbedaan.'),
(956, NULL, 'P30', 'Rumah DataKu', NULL),
(957, 956, 'P30.1', 'Apa itu Rumah Dataku?', 'Rumah Dataku adalah tempat atau wadah setara kelompok kegiatan di tingkat desa/kelurahan yang melaksanakan kegiatan pengumpulan, verifikasi dan analisis, penyajian serta pemanfaatan data kependudukan dan keluarga serta pembangunan'),
(958, 956, 'P30.2', 'Apa tujuan adanya Rumah DataKu?', 'Membangun kepedulian dan kesadaran akan data, permasalahan kependudukan, dan pendidikan wawasan kependudukan dan keluarga bagi masyarakat, Menyediakan data dan analisis kependudukan serta informasi keluarga bagi pemerintah dan lintas sektoral dalam upaya memberikan intervensi peningkatan kesejahteraan masyarakat yang tepat sasaran dan tepat guna, serta membangun kelompok kegiatan dalam bidang data pada tingkat mikro yang mampu menjadi rekan strategis pemerintah lokal dalam mengambil keputusan dan kebijakan yang berkaitan dengan peningkatan kesejahteraan masyarakat.'),
(959, 956, 'P30.3', 'Apa fungsi Rumah DataKu?', 'Pusat data kependudukan dan informasi keluarga di level desa/kelurahan, penyedia data basis bagi intervensi pembangunan kependudukan, dan Instrumen pendidikan kependudukan dan keluarga bagi masyarakat'),
(960, 956, 'P30.4', 'Bagaimana struktur Rumah DataKu terbentuk?', 'Struktur Rumah DataKu terdiri dari ketua dan minimal 2 Kader atau disesuaikan dengan kompleksitas pada Rumah DataKu'),
(961, 956, 'P30.5', 'Apa saja kegiatan pokok dalam Rumah DataKu?', 'Kegiatan pokok Rumah DataKu meliputi 5 hal yaitu pengumpulan dan updating data, pengolahan data, analisis data, dan penyajian data serta memberikan masukan atas temuan yang dianggap penting dan perllu ditindaklanjuti'),
(962, 956, 'P30.6', 'Berapa jenis klasifikasi yang ada dalam pengelompokan Rumah DataKu?', 'Ada 3 klasifikasi. Sederhana, Lengkap, Paripurna'),
(963, 956, 'P30.7', 'Apa saja syarat wajib dalam pembentukan Rumah DataKu?', 'Memiliki SK lengkap dengan struktur keanggotaan, orientasi dasar pengurus Rumah DataKu, 1 jenis sarana prasarana, 1 jenis data, dan 1 bentuk penyajian data'),
(964, 956, 'P30.8', 'Apa saja sarana prasarana yang terdapat di Rumah DataKu?', 'Papan Nama, Buku Data, Papan Data, Pojok Kependudukan, Sarana Pengolahan Data (komputer, laptop, dll), sarana prasarana lainnya'),
(965, 956, 'P30.9', 'Jenis data apa saja yang bisa dimasukkan dalam Rumah DataKu?', 'Kuantitas Penduduk, Kualitas Penduduk, Mobilitas Penduduk, Pembangunan Keluarga, Administrasi Kependudukan, Perlindungan Sosial, Potensi Desa, dan data lain yang dapat menunjang kegiatan pembangunan desa/kelurahan'),
(966, 956, 'P30.10', 'Apa saja bentuk penyajian data yang dapat disajikan di Rumah DataKu?', 'Pencatatan dalam buku data baik secara manual di buku maupun dalam media penyimpanan elektronik serta taebl data / infografis yang bisa ditampilkan dalam berbagai bentuk dan cara'),
(967, 956, 'P30.11', 'Ada berapa dan apa saja bentuk pemanfaatan Rumah DataKu?', 'Ada 3 pemanfaatan, Perencanaan, Intervensi, serta Penelitian'),
(968, NULL, 'P31', 'SIRIKA', NULL),
(969, 968, 'P31.1', 'Apa alamat website/aplikasi Sistem Informasi Rantai Pasok Alokon (SIRIKA) saat ini?', 'https://siga-sirika.bkkbn.go.id'),
(970, 968, 'P31.2', 'Bagaimana cara mendapatkan username SIRIKA bagi fasyankes?', 'Fasyankes baru/lama dapat melaporkan kepada OPD KB Kabupaten/Kota untuk selanjutnya dapat diteruskan kepada Tim SIRIKA Provinsi. Saat ini pembuatan username fasyankes baru sudah dapat dilakukan oleh admin provinsi masing-masing melalui user admin provinsi melalui menu Pengaturan > Profil > User > Tambah User.'),
(971, 968, 'P31.3', 'Apakah semua fasyankes dan jejaring yang memiliki K/O/KB di SIGA secara otomatis memiliki akses pada Aplikasi SIRIKA?', 'Jejaring tidak memiliki akses (username) dalam SIRIKA. Hanya fasyankes saja yang memiliki akses (username) dalam SIRIKA.'),
(972, 968, 'P31.4', 'Bagaimana stock alokon APBN jejaring dapat diinputkan dalam SIRIKA?', 'Diinputkan oleh fasyankes induknya, atau bisa berdiri sebagai fasyankes sendiri agar dapat memiliki username SIRIKA.'),
(973, 968, 'P31.5', 'Bagaimana jika ada fasyankes yang sama sekali tidak menerima alokon APBN?', 'Admin Provinsi dapat menonaktifkan user fasyankes tersebut.'),
(974, 968, 'P31.6', 'Apakah seluruh alokon yang ada di fasyankes diinputkan dalam SIRIKA?', 'Tidak, hanya alokon yang bersumber dari APBN (BKKBN) saja yang diinputkan dalam SIRIKA.'),
(975, 968, 'P31.7', 'Apakah alokon dari OPD KB Kabupaten/Kota juga merupakan alokon APBN atau APBD?', 'Alokon yang berada di OPD KB Kabupaten/Kota selama berasal dari Perwakilan BKKBN, maka merupakan alokon APBN.'),
(976, 968, 'P31.8', 'Bagaimana cara menginputkan alokon yang bersumber dari pembelian mandiri?', 'Alokon yang dibeli secara mandiri oleh fasyankes TETAP diinputkan oleh petugas pencatatan pelaporan ke dalam Mutasi Alokon SIGA.'),
(977, 968, 'P31.9', 'OPD KB Kabupaten/Kota ingin mendistribusikan alokon ke fasyankes tertentu namun terdapat notifikasi “Gudang ini belum membuat tahun bulan lapor”. Apa solusi dari permasalahan tersebut?', 'Fasyankes tersebut harus membuat bulan lapor di SIGA.'),
(978, 968, 'P31.10', 'Apakah saat ini terdapat menu pembatalan SPMB pada SIRIKA?', 'Ya, saat ini sudah terdapat menu pembatalan SPMB, jadi jika jumlah dan item alokon yang akan didistribusikan terdapat kesalahan maka dapat dilakukan pembatalan SPMB. Namun saat ini belum terdapat menu EDIT SPMB.'),
(979, 968, 'P31.11', 'Bagaimana jika terdapat kabupaten/kota yang tidak bisa melakukan Stock Opname karena masih terdapat SPMB yang menggantung?', 'Kabupaten/Kota harus menyelesaikan dulu SPMB tersebut, apakah dilanjutkan atau dibatalkan.'),
(980, 968, 'P31.12', 'Apakah informasi harga satuan alokon dalam SBBK saat ini dihapuskan?', 'Iya, saat ini untuk angka harga satuan alokon tidak ada dalam SBBK. Terdapat perbedaan metode untuk pencatatan nilai rupiah di SAKTI dan SIRIKA. Pada SAKTI menggunakan Metode FIFO sedangkan di SIRIKA menggunakan FEEA, sehingga menimbulkan ketidaksinkronan dalam pencatatan nilai. Hal ini seringkali menjadi temuan BPK ketika dilakukan pemeriksaan.'),
(981, 968, 'P31.13', 'Mengapa angka saldo akhir di SIGA berwarna merah? Apakah tampilan baru atau maknanya apa?', 'Sebagai notifikasi WARNING, yang artinya saldo di R2 SIGA (Mutasi Alokon) TIDAK SAMA dengan saldo yang ada di SIRIKA.'),
(982, 968, 'P31.14', 'Bagaimana cara membatalkan SPMB dalam SIRIKA?', 'Jika ingin membatalkan SPMB dalam SIRIKA, maka klik tanda silang. Nanti notifikasi “barang masih dalam proses SPMB” tidak akan muncul dan Stock Opname bisa dilanjutkan.'),
(983, 968, 'P31.15', 'Bagaimana cara memasukkan kategori distribusi pada SIRIKA?', 'Login menggunakan akun operator KBKR, klik Kategori Distribusi > Klik Cari/Edit menggunakan simbol pensil/pilih kategori distribusi yang diinginkan.'),
(984, 968, 'P31.16', 'Bagaimana cara mengatur minimum per kemas, ambang kadaluarsa untuk masing-masing jenis alokon?', 'Melalui menu daftar fasilitas → klik cari/edit simbol loop pada kolom aksi → klik pensil pada kolom aksi untuk masing-masing jenis alokon yang akan diedit.'),
(985, 968, 'P31.17', 'Bagaimana jika ada fasyankes yang sampai dengan saat ini belum melaksanakan Input Stock Awal Alokon APBN pada Aplikasi SIRIKA?', 'Segera melakukan input stock alokon melalui menu Penerimaan Manual dengan tanggal Stock Opname pada akhir bulan.'),
(986, 968, 'P31.18', 'Apakah saat ini sudah dilakukan integrasi antara SIRIKA dengan SIGA?', 'Integrasi SIRIKA dengan SIGA akan mulai dilaksanakan pada bulan Oktober (info VM Kegiatan Rapat Evaluasi SIRIKA pada Jumat, 29 Agustus 2025).'),
(987, 968, 'P31.19', 'Apa manfaat Stock Opname penyesuaian pelayanan?', 'Menu ini digunakan untuk menyamakan stok alokon antara SIRIKA dengan SIGA. Stock Opname dilakukan di akhir bulan saat pada pelayanan KB di bulan tersebut dipastikan sudah selesai (tidak ada lagi pelayanan KB yang akan dilakukan pada bulan tersebut). Hal ini dapat memperbaiki jumlah pelayanan dalam bulan tersebut untuk kemudian dapat dijadikan dasar untuk penyesuaian jumlah stok alokon pada Aplikasi SIRIKA. Melalui menu Stock Opname Penyesuaian Pelayanan ini hal tersebut dapat dilaksanakan.'),
(988, 968, 'P31.20', 'Apakah Stock Opname penyesuaian pelayanan ini harus dilaksanakan setiap bulan?', 'Secara umum, Stock Opname harus dilakukan setiap akhir bulan (tidak hanya ketika ada penyesuaian untuk pelayanan), namun jika terdapat perbedaan stok dapat terjadi jika alokon kadaluarsa/ED.'),
(989, 968, 'P31.21', 'Bagaimana cara mengatur alamat dan mengubah logo gudang?', 'Login menggunakan akun operator Gudang, klik Informasi Gudang > Klik Cari/Edit menggunakan simbol pensil.'),
(990, 968, 'P31.22', 'Apa satuan untuk BMHP Implan Kasa Steril? Apakah box atau buah?', 'Saat ini satuan untuk BMHP Implan Kasa Steril adalah buah.'),
(991, 968, 'P31.23', 'Apakah item BMHP Implan pada SIRIKA sekarang dibatasi hanya 8 item saja?', 'Saat ini SIRIKA sudah mengakomodir item BMHP Implan di luar 8 item.'),
(992, 968, 'P31.24', 'Jika akan melakukan Stock Opname, akun apa yang digunakan? Apakah akun KBKR atau akun gudang?', 'Dapat menggunakan akun Gudang dengan username awalan OPG.'),
(993, 968, 'P31.25', 'Yang diinput apakah hanya alokon saja?', 'BMHP alokon juga diinput.'),
(994, 968, 'P31.26', 'Apa perbedaan menu Stock Opname pada level provinsi dan kab/kota dengan Stock Opname pada level fasyankes?', 'Stock Opname pada level provinsi dan kab/kota hanya terdapat penyesuaian lebih dan penyesuaian kurang. Sedangkan pada level fasyankes terdapat penyesuaian untuk pelayanan.'),
(995, 968, 'P31.27', 'Apakah Alkon yang sudah Expired maupun BMHP tidak perlu diinput?', 'Tidak perlu diinput, yang diinput adalah alkon dan BMHP yang belum expired (stok yang bisa digunakan).'),
(996, 968, 'P31.28', 'Jika memiliki alkon dari pembelian APBD, namun disampaikan untuk APBD belum bisa diakomodir oleh SIRIKA yang baru, untuk alkon APBD tidak perlu dimasukkan ke stok awal ya?', 'Untuk alkon APBD tidak perlu dimasukkan ke SIRIKA.'),
(997, 968, 'P31.29', 'Jika mau dropping alkon APBD bersamaan dengan APBN dalam 1 SBBK/permintaan lalu mekanismenya sebaiknya seperti bagaimana?', 'Jika ingin jadi 1 maka menggunakan SBBK manual, di provinsi BAST jadi 1, dan SBBK yang dipisahkan.'),
(998, 968, 'P31.30', 'Jika saat input stok awal ada kesalahan input jumlah tetapi sudah di-submit, cara edit atau hapus bagaimana?', 'Untuk inputan yang sudah di-Submit tidak bisa diedit ataupun dihapus, namun bisa melakukan penyesuaian melalui Stock Opname. Dan jika ada kesalahan jumlah yang masih bisa disesuaikan saat Stock Opname, tetapi jika kesalahan batch ID maka dihapuskan dulu datanya di Stock Opname kemudian diinput ulang.'),
(999, 968, 'P31.31', 'Bagaimana cara melakukan Stock Opname pada aplikasi SIRIKA?', 'Masuk ke dalam aplikasi SIRIKA, klik menu Stock Opname. Klik Mulai/Sedang melakukan Stock Opname.'),
(1000, 968, 'P31.32', 'Bagaimana cara menyelesaikan Stock Opname pada aplikasi SIRIKA?', 'Klik menu Selesai/Tidak Sedang Stock Opname.'),
(1001, 968, 'P31.33', 'Bagaimana cara input stok awal di aplikasi SIRIKA?', 'Masuk ke menu Penerimaan, klik manual kemudian klik menu tambah penerimaan barang, untuk tipe penerimaan dapat dipilih ke stok awal.'),
(1002, 968, 'P31.34', 'Bagaimana cara membuat SBBK?', 'Klik menu Distribusi, pilih Rutin atau Non Rutin. Pada menu aksi klik Cetak SBBK, bisa dipilih Excel atau PDF.'),
(1003, 968, 'P31.35', 'Bagaimana cara menerima alkon secara sistematis?', 'Klik menu Penerimaan, pilih Sistematis lalu klik aksi untuk penerimaan yang akan dipilih.'),
(1004, 968, 'P31.36', 'Bagaimana cara melihat stok alkon yang ada di SIRIKA?', 'Pilih menu Dashboard, kemudian klik Laporan Stok, pilih tipe barang, kemudian klik Cari.'),
(1005, 968, 'P31.37', 'Apakah fasyankes yang tidak mendapatkan droping alokon APBN tetap dimasukkan dalam SIRIKA?', 'Fasyankes yang tidak menerima alokon APBN dapat dinon-aktifkan di SIRIKA. Input alokon non-APBN (APBD dan atau Mandiri) dapat dilakukan pada R/II/KB SIGA'),
(1006, 968, 'P31.38', 'Apakah saat ini SIRIKA-SIGA sudah terintegrasi dalam hal pengurangan stock alokon untuk pelayanan KB?', 'Sampai dengan saat ini (9 Oktober 2025) integrasi antara pelayanan KB pada SIGA (R/I/KB SIGA) dengan stock alokon pada SIRIKA belum optimal. Sehingga fasyankes dapat melakukan pemadanan stock alokon yang digunakan untuk pelayanan KB melalui SO Bulanan yang dilakukan pada akhir bulan sampai dengan tanggal 10 bulan berikutnya. Khusus untuk SO pada akun fasyankes, terdapat kolom/ bagian yang digunakan untuk penyesuaian pelayanan KB.'),
(1007, 968, 'P31.39', 'Apakah fasyankes yang sampai dengan saat ini (9 Oktober 2025) belum melakukan input stock awal (penerimaan manual) pada SIRIKA masih dapat melakukan input stock awal alokon pada menu penerimaan manual?', 'Bisa, fasyankes yang belum melakukan input stock awal diharapkan segera melakukan input stock awal melalui penerimaan manual dengan stock alokon pada 30 September 2025.'),
(1008, 968, 'P31.40', 'Apa yang harus dilakukan jika terdapat penerimaan menggantung namun sudah terlanjur SO Bulanan?', 'Idealnya SO Bulanan hanya dapat dilakukan ketika sudah tidak terdapat transaksi menggantung. Namun, jika kondisi ini terjadi, lakukan penyesuaian stock melalui SO bulan berikutnya untuk menyesuaikan dengan stock alokon real di fasyankes.');
INSERT INTO `faq` (`id`, `parent_id`, `key_name`, `question_text`, `answer_text`) VALUES
(1009, 968, 'P31.41', 'Bagaimana cara melihat daftar fasyankes yang sudah dan belum melakukan SO?', 'Dapat dilihat melalui link https://siga-sirika.bkkbn.go.id/sirikaLandingPage'),
(1010, NULL, 'P32', 'SSK', NULL),
(1011, 1010, 'P32.1', 'Apa yang dimaksud dengan Sekolah Siaga Kependudukan (SSK)?', 'SSK adalah sekolah yang mengintegrasikan pendidikan kependudukan, keluarga berencana, dan pembangunan keluarga ke dalam mata pelajaran, muatan lokal, kegiatan kesiswaan, dan bimbingan konseling.'),
(1012, 1010, 'P32.2', 'Apa tujuan utama dari SSK?', 'Untuk membentuk karakter generasi berencana melalui penguatan pengetahuan, sikap, dan keterampilan peserta didik mengenai isu-isu kependudukan.'),
(1013, 1010, 'P32.3', 'Apa manfaat penerapan SSK di sekolah?', '1. Peserta didik memiliki sikap, pengetahuan, dan keterampilan tentang peduli kependudukan. \n2.  Peserta didik berperilaku yang mencerminkan keluarga berkualitas. \n3.  Peserta didik memiliki pengetahuan yang utuh  tentang  masalah  dan manfaat kependudukan setempat (local genius). \n4.  Peserta didik mampu menyajikan data mikro kependudukan dalam bentuk \npeta, grafik atau digital untuk dianalisa sederhana. \n5.  Mengurangi drop out (putus sekolah) dan kasus lainnya yang banyak terjadi di sekolah. \n6.  Meningkatkan pengetahuan tenaga pendidik dan peserta didik akan manfaat dan dampak dari kependudukan.'),
(1014, 1010, 'P32.4', 'Apa yang dimaksud dengan Pojok Kependudukan?', 'Sebuah sumber belajar di sekolah yang menyediakan informasi dan bacaan terkait kependudukan.'),
(1015, 1010, 'P32.5', 'Apa saja tahapan pembentukan SSK?', 'Dimulai dari rapat koordinasi, perjanjian kerjasama, sosialisasi, penyusunan materi, orientasi guru, rapat penguatan, pembuatan pojok kependudukan, hingga pencanangan SSK.'),
(1016, 1010, 'P32.6', 'Bagaimana integrasi SSK dengan program Bangga Kencana?', 'SSK menjadi wadah sosialisasi program Bangga Kencana seperti GENRE, PIK KRR, dan Kespro Remaja.'),
(1017, 1010, 'P32.7', 'Bagaimana integrasi SSK dengan lintas sektor?', 'Integrasi SSK dengan lintas sektor dapat dilakukan dengan melibatkan Kementerian Pendidikan, BNN, Kementerian LH, dan Kementerian Dalam Negeri dalam berbagai program terkait.'),
(1018, 1010, 'P32.8', 'Apa manfaat Pojok Kependudukan bagi peserta didik?', 'Pojok Kependudukan menjadi tempat belajar mandiri, diskusi, dan konsultasi tentang isu-isu kependudukan. Di tempat ini, peserta didik bisa mengakses informasi yang relevan, berdiskusi dengan guru, serta memanfaatkan media dan bacaan untuk memperluas wawasan mereka.'),
(1019, 1010, 'P32.9', 'Apa kontribusi Dinas Pendidikan dalam mendukung pelaksanaan SSK?', 'Dinas Pendidikan berperan dalam mendukung kebijakan integrasi pendidikan kependudukan ke sekolah melalui penerbitan SK penunjukan, pelatihan guru, dan penguatan forum koordinasi seperti MKKS, MGMP, serta memfasilitasi sarana penunjang seperti modul pembelajaran dan Pojok Kependudukan.'),
(1020, 1010, 'P32.10', 'Bagaimana indikator keberhasilan penerapan SSK diukur?', 'Indikator keberhasilan diukur dari tiga aspek: input (ketersediaan sarana, RPP, dan sekolah percontohan), proses (pelaksanaan pembelajaran, kunjungan lapangan, dan pengolahan data), serta output (peningkatan pemahaman dan perubahan sikap siswa terhadap isu kependudukan).'),
(1021, 1010, 'P32.11', 'Bagaimana pendidikan kependudukan bisa diintegrasikan dalam pelajaran biologi?', 'Dalam pelajaran biologi, pendidikan kependudukan bisa diintegrasikan melalui topik kesehatan reproduksi, pertumbuhan populasi, dan dampaknya terhadap lingkungan. Bahkan bisa melibatkan ahli seperti bidan untuk menjelaskan langsung tentang kesehatan reproduksi remaja.'),
(1022, 1010, 'P32.12', 'Apa saja kegiatan kesiswaan yang dapat menunjang pelaksanaan SSK?', 'Kegiatan seperti Lomba Karya Tulis Ilmiah Kependudukan, Pramuka, Debat tema kependudukan, diskusi kelompok, kampanye Genre, dan simulasi wawancara lapangan menjadi kegiatan yang mampu meningkatkan pemahaman sekaligus keterampilan sosial siswa.'),
(1023, 1010, 'P32.13', 'Apa saja klasifikasi SSK?', 'Klasifikasi SSK terdiri dari terdaftar, dasar, dan paripurna.'),
(1024, 1010, 'P32.14', 'Apa syarat atau indikator yang harus dipenuhi untuk menjadi SSK Dasar?', '-        Memiliki SK Penunjukan sebagai SSK\n-        Berpartisipasi dalam kegiatan sosialisasi Program SSK\n-        Minimal 1–2 guru telah mengikuti orientasi/pelatihan penyusunan RPP/Modul Ajar terintegrasi materi Bangga Kencana\n-        Menyusun 1–2 RPP/Modul Ajar yang terintegrasi materi Bangga Kencana\n-        Melakukan 1 kali pertemuan koordinasi dan penguatan SSK\n-        Tersedia materi Bangga Kencana di perpustakaan sekolah (pojok kependudukan)\n-        Memiliki 1 kegiatan kesiswaan atau ekstrakurikuler yang mengandung konten Bangga Kencana\nDengan catatan, apabila ada indikator yang tidak terpenuhi, maka SSK tersebut masuk kedalam klasifikasi di bawah Dasar, yakni SSK Terdaftar.'),
(1025, 1010, 'P32.15', 'Apa syarat atau indikator yang harus dipenuhi untuk menjadi SSK Paripurna?', '-	Memiliki SK Penunjukan sebagai SSK\n-	Pernah mengikuti kegiatan sosialisasi Program SSK\n-	Minimal 3 guru telah mengikuti orientasi/pelatihan penyusunan RPP/Modul Ajar terintegrasi materi Bangga Kencana\n-	Menyusun lebih dari 2 RPP/Modul Ajar yang terintegrasi materi Bangga Kencana\n-	Melakukan koordinasi dan penguatan SSK lebih dari 1 kali\n-	Memiliki pojok kependudukan yang fungsional dan lengkap\n-	Memiliki lebih dari 1 kegiatan kesiswaan atau ekstrakurikuler yang mengandung konten Bangga Kencana'),
(1026, NULL, 'P33', 'SiPerindu', NULL),
(1027, 1026, 'P33.1', 'Apa yang dimaksud Peringatan Dini Pengendalian Penduduk?', 'Peringatan Dini Pengendalian Penduduk adalah suatu usaha untuk memperingatkan potensi atau masalah kependudukan yang akan timbul baik bersifat segera ataupun yang akan datang akibat situasi kependudukan serta kebijakan pengendalian penduduk yang sedang dilaksanakan kepada masyarakat dan pemangku kepentingan di bidang pembangunan kependudukan.'),
(1028, 1026, 'P33.2', 'Siapa pelaksana Peringatan Dini Pengendalian Penduduk Tingkat Nasional?', 'Pelaksana Peringatan Dini Pengendalian Penduduk Tingkat Nasional adalah Badan Kependudukan dan Keluarga Berencana Nasional.'),
(1029, 1026, 'P33.3', 'Siapa pelaksana Peringatan Dini Pengendalian Penduduk Tingkat Provinsi?', 'Pelaksana Peringatan Dini Pengendalian Penduduk Tingkat Provinsi adalah perangkat daerah yang membawahi urusan pengendalian penduduk dan keluarga berencana provinsi.'),
(1030, 1026, 'P33.4', 'Siapa pelaksana Peringatan Dini Pengendalian Penduduk Tingkat Kabupaten/Kota?', 'Pelaksana Peringatan Dini Pengendalian Penduduk Tingkat Kabupaten/Kota adalah perangkat daerah yang membawahi urusan pengendalian penduduk dan keluarga berencana kabupaten/kota.'),
(1031, 1026, 'P33.5', 'Apa saja tahapan Pengelolaan Peringatan Dini Pengendalian Penduduk?', 'a. penyediaan informasi Peringatan Dini Pengendalian Penduduk; b. penyediaan sumber daya Peringatan Dini Pengendalian Penduduk; c. pelaksanaan Peringatan Dini Pengendalian Penduduk; dan d. pelaporan, monitoring dan evaluasi pelaksanaan Peringatan Dini Pengendalian Penduduk.'),
(1032, 1026, 'P33.6', 'Apa saja yang termasuk penyediaan informasi Peringatan Dini Pengendalian Penduduk', 'a. informasi komponen kependudukan; b. informasi kualitas penduduk; dan c. informasi dampak kependudukan.'),
(1033, 1026, 'P33.7', 'Apa saja yang termasuk Informasi komponen kependudukan?', 'a. fertilitas;\nb. mortalitas;\nc. mobilitas dan migrasi penduduk;\nd. jenis kelamin;\ne. kelompok umur; dan\nf. persebaran penduduk.'),
(1034, 1026, 'P33.8', 'Apa saja yang termasuk Informasi kualitas penduduk?', 'a. pendidikan;\nb. kesehatan; dan\nc. keterpenuhan standar hidup layak.'),
(1035, 1026, 'P33.9', 'Apa saja yang termasuk Informasi dampak kependudukan?', 'a. sosial;\nb. ekonomi;\nc. politik;\nd. pertahanan dan keamanan; dan\ne. daya dukung alam dan daya tampung lingkungan'),
(1036, 1026, 'P33.10', 'Melalui apa saja penyediaan informasi Peringatan Dini Pengendalian Penduduk?', 'Penyediaan informasi Peringatan Dini Pengendalian Penduduk dilaksanakan melalui Sistem Aplikasi dan Kajian Ilmiah.'),
(1037, 1026, 'P33.11', 'Melalui apa saja penyediaan sumber daya Peringatan Dini Pengendalian Penduduk?', 'Penyediaan sumber daya Peringatan Dini Pengendalian Penduduk dilakukan melalui peningkatan sumber daya manusia yang terampil dalam pelaksanaan Peringatan Dini Pengendalian Penduduk dan pendanaan pelaksanaan Peringatan Dini Pengendalian Penduduk.'),
(1038, 1026, 'P33.12', 'Dari mana sumber pendanaan pelaksanaan Peringatan Dini Pengendalian Penduduk?', 'Pendanaan pelaksanaan Peringatan Dini Pengendalian Penduduk bersumber dari: a. anggaran pendapatan dan belanja negara; b. anggaran pendapatan dan belanja daerah; dan c. sumber pendanaan lainnya yang sah sesuai dengan ketentuan peraturan perundang undangan.'),
(1039, 1026, 'P33.13', 'Apa tujuan pelaporan, monitoring dan evaluasi pelaksanaan Peringatan Dini Pengendalian Penduduk?', 'Pelaporan, monitoring dan evaluasi pelaksanaan Peringatan Dini Pengendalian Penduduk bertujuan untuk:\na. mengetahui kemajuan dan keberhasilan pelaksanaan Peringatan Dini Pengendalian Penduduk;\nb. mengetahui hambatan dan kendala pelaksanaan Peringatan Dini Pengendalian Penduduk;\nc. memberikan umpan balik bagi kemajuan pelaksanaan Peringatan Dini Pengendalian Penduduk; dan\nd. memberikan penilaian kesesuaian terhadap kegiatan, keluaran, dan target strategi pelaksanaan Peringatan Dini Pengendalian Penduduk.'),
(1040, 1026, 'P33.14', 'Siapa yang membuat laporan pelaksanaan Peringatan Dini Pengendalian Penduduk?', 'Pelaporan pelaksanaan Peringatan Dini Pengendalian Penduduk dilaksanakan oleh pelaksana Peringatan Dini Pengendalian Penduduk tingkat Nasional, tingkat Provinsi, dan tingkat Kabupaten/Kota.'),
(1041, 1026, 'P33.15', 'Melalui apa pelaporan pelaksanaan Peringatan Dini Pengendalian Penduduk?', 'Pelaporan pelaksanaan Peringatan Dini Pengendalian Penduduk dilaksanakan melalui Sistem Aplikasi Peringatan Dini Pengendalian Penduduk.'),
(1042, 1026, 'P33.16', 'Bagaimana mekanisme pelaporan pelaksanaan Peringatan Dini Pengendalian Penduduk?', 'Pelaporan pelaksanaan Peringatan Dini Pengendalian Penduduk disampaikan kepada Kepala BKKBN paling sedikit 1 (satu) kali dalam 1 (satu) tahun atau sewaktu-waktu apabila diperlukan.'),
(1043, 1026, 'P33.17', 'Siapa yang melaksanakan monitoring dan evaluasi pelaksanaan Peringatan Dini Pengendalian Penduduk?', 'Monitoring dan evaluasi pelaksanaan Peringatan Dini Pengendalian Penduduk dilakukan oleh kementerian/lembaga, pemerintah daerah provinsi, dan pemerintah daerah kabupaten/kota sesuai dengan kewenangannya.'),
(1044, 1026, 'P33.18', 'Apa peran BKKBN dalam monitoring dan evaluasi pelaksanaan Peringatan Dini Pengendalian Penduduk?', 'BKKBN mengoordinasikan monitoring dan evaluasi pelaksanaan Peringatan Dini Pengendalian Penduduk.'),
(1045, 1026, 'P33.19', 'Apa yang dimaksud dengan Sistem aplikasi Peringatan Dini Pengendalian Penduduk?', 'Sistem aplikasi peringatan dini pengendalian penduduk merupakan alat bantu bagi pemerintah dan masyarakat dalam mendapatkan informasi peringatan dini situasi kependudukan serta rekomendasi kebijakan, untuk kesiapsiagaan dan respon terhadap program pengendalian penduduk.'),
(1046, 1026, 'P33.20', 'Apa yang dilakukan Kementerian Dalam Negeri terkait implementasi kebijakan pengendalian penduduk dalam perencanaan pembangunan?', 'Kementerian Dalam Negeri melalui Peraturan Menteri Dalam Negeri Nomor 22 Tahun 2018 tentang Penyusunan Rencana Kerja Pemerintah Daerah Tahun 2019 sejatinya telah mengamanatkan penyediaan peringatan dini dampak kependudukan (yang kemudian maknanya diperluas menjadi peringatan dini pengendalian penduduk) sebagai langkah dari implementasi kebijakan pengendalian penduduk dalam perencanaan pembangunan'),
(1047, 1026, 'P33.21', 'Adakah peraturan tentang peringatan dini pengendalian penduduk provinsi dan kabupaten/kota dalam perencanaan pembangunan daerah?', 'Peraturan Menteri Dalam Negeri Nomor 90 Tahun 2019 tentang Klasifikasi, Kodefikasi, dan Nomenklatur Perencanaan Pembangunan dan Keuangan Daerah dimana sub-kegiatan terkait dengan peringatan dini pengendalian penduduk tercantum dalam nomenklatur urusan provinsi dan kabupaten/kota.'),
(1048, 1026, 'P33.22', 'Apa saja isu strategis yang dapat digunakan dalam kajian atau analisis peringatan dini pengendalian penduduk?', 'Beberapa isu strategis yang berkembang yang dapat digunakan dalam kajian atau analisis peringatan dini pengendalian penduduk adalah sebagai berikut:\n1. Isu meningkatnya fertilitas;\n2. Isu meningkatnya penyediaan layanan pendidikan;\n3. Isu kelompok muda;\n4. Isu usia reproduksi dan pemberdayaan perempuan;\n5. Isu meningkatnya kelompok lansia;\n6. Isu meningkatnya kebutuhan perumahan;\n7. Isu menghadapi pola migrasi;\n8. Isu dampak lingkungan;\n9. Isu kemitraan dalam menghadapi permasalahan kependudukan;\n10. Isu bonus demografi;\n11. Isu pembangunan keluarga;\n12. Isu stunting; dan\n13. Isu lainnya sesuai dengan kebutuhan.'),
(1049, 1026, 'P33.23', 'Bagaimana Sistem Peringatan Dini Pengendalian Penduduk disusun?', 'Sistem Peringatan Dini Pengendalian Penduduk disusun berdasarkan Undang-Undang Nomor 23 Tahun 2014 tentang Pemerintah Daerah yang menjadi acuan bagi pelaksanaan urusan pengendalian penduduk dan KB, dimana dapat disimpulkan bahwa urusan pemerintahan ini berbentuk konkuren yang bersifat wajib non pelayanan dasar sehingga pemerintah daerah, baik provinsi maupun kabupaten/kota wajib melaksanakan kewenangannya.'),
(1050, 1026, 'P33.24', 'Apa tujuan Sistem Peringatan Dini Pengendalian Penduduk?', 'Sistem Peringatan Dini Pengendalian Penduduk merupakan sebuah upaya dengan tujuan:\na. tersedianya acuan pelaksanaan peringatan dini pengendalian penduduk;\nb. terwujudnya kesamaan pengertian, penafsiran dan persepsi dalam memberikan informasi peringatan dini pengendalian penduduk di tingkat pusat, provinsi, kabupaten dan kota;\nc. terwujudnya pemaduan dan sinkronisasi kebijakan pembangunan pengendalian penduduk di tingkat pusat, provinsi, kabupaten dan kota;\nd. terwujudnya kebijakan, program dan kegiatan pembangunan yang sesuai dengan masalah dan kebutuhan penduduk.'),
(1051, 1026, 'P33.25', 'Apa saja status atau level peringatan dini pengendalian penduduk?', 'Status atau level peringatan dini pengendalian penduduk, yaitu normal, waspada, siaga, dan awas.'),
(1052, 1026, 'P33.26', 'Bagaimana penentuan status atau level peringatan dini pengendalian penduduk?', 'Penentuan status atau level peringatan dini pengendalian penduduk berdasarkan perhitungan ambang batas level atau benchmark tiap indikator yang dilakukan oleh pakar kependudukan.'),
(1053, 1026, 'P33.27', 'Apa saja sumber data penyediaan informasi peringatan dini pengendalian penduduk?', 'Sumber data yang dapat digunakan dalam proses penyediaan informasi peringatan dini pengendalian penduduk adalah sebagai berikut:\n1. Sumber data sekunder yang resmi dikeluarkan oleh pemerintah meliputi data Sensus Penduduk, Susenas, Supas, Riskesdas, SDKI, data Potensi Desa, data Statistik Rutin, data Pendataan Keluarga (PK), data administrasi kependudukan (Adminduk).\n2. Sumber data yang kedua adalah data primer yang diambil langsung kepada masyarakat sesuai dengan kepentingan analisis.'),
(1054, 1026, 'P33.28', 'Apa saja isi laporan pelaksanaan kegiatan dalam rangka peringatan dini pengendalian penduduk?', 'Isi laporan pelaksanaan kegiatan dalam rangka peringatan dini pengendalian penduduk meliputi:\na. Laporan fasilitasi pembinaan sistem peringatan dini pengendalian penduduk yang memuat jumlah peserta yang sudah mendapatkan orientasi dan mengisi formulir pada sistem aplikasi peringatan dini pengendalian penduduk.\nb. Laporan pelaksanaan peringatan dini pengendalian penduduk yang memuat jumlah rencana aksi yang sudah disusun dan dilaporkan melalui sistem aplikasi peringatan dini pengendalian penduduk.\nc. Laporan dampak pelaksanaan peringatan dini pengendalian penduduk yang memuat jumlah perubahan status peringatan dini pengendalian penduduk.\nd. Keluaran kegiatan peringatan dini pengendalian penduduk di masing-masing tingkatan berupa hasil kajian atau analisis isu strategis di masing-masing wilayah dan pengembangan model solusi strategis pengendalian penduduk.\ne. Terlaksananya kegiatan sosialisasi, diseminasi dan advokasi informasi peringatan dini pengendalian penduduk berupa hasil kajian/analisis dan pengembangan model solusi strategis kepada pemangku kepentingan, kelompok kerja Bangga Kencana, dan masyarakat.'),
(1055, NULL, 'P34', 'Stunting', NULL),
(1056, 1055, 'P34.1', 'Apa yang dimaksud 1000HPK?', '1000HPK kepanjangan dari 1000 Hari Pertama Kehidupan yang dimulai sejak anak dalam kandungan sampai dengan usia 2 tahun pertama.'),
(1057, 1055, 'P34.2', 'Persoalan stunting adalah hal yang perlu diperhatikan, tetapi di saat yang bersamaan tidak semua keluarga memiliki akses yang mudah terhadap ekonomi guna mendapatkan sumber pangan yang sehat dan bergizi. Lalu bagaimana solusinya?', 'Makan sehat tak perlu mahal\nSeharusnya sebagai negara adipangan yang melimpah, masyarakat dapat lebih memanfaatkan potensi pangan lokal yang ada di sekitar. Pengetahuan tersebut akan meningkatkan gizi anak bangsa dan mematahkan anggapan pemberian makanan anak dari bahan-bahan yang monoton serta menepis anggapan makanan sehat harus mahal. Bisa berupa tempe, tahu, ikan lele, ikan kembung, telur, hati ayam, kacang-kacangan.'),
(1058, 1055, 'P34.3', 'Penyebutan stunting terkadang terdengar lebih sadis dalam masyarakat, seperti \"kecenthet/kerdil/kurcaci\" sehingga membuat orang tua merasa malu dan ragu dalam merawat anak. Lantas bagaimana cara yang tepat untuk membantu mereka?', 'Perlu dipahami bahwa stunting adalah terhambatnya pertumbuhan akibat masalah gizi yang kronis. Jangan mengatakan, \"Wah, anak ibu stunting\" atau \"Wah, anaknya kerdil\" karena bisa membuat orang yang menerima tersinggung berat. Ketika sudah tersinggung tentu akan menjadi sulit untuk mengajak ibu memperbaiki gizi anak. Lebih baik menggunakan pesan yang positif. Misalnya \"Ayo, kita perhatikan gizi anak supaya otaknya pintar\"'),
(1059, 1055, 'P34.4', 'Apa yang dimaksud dengan stunting?', 'Stunting adalah gangguan pertumbuhan dan perkembangan anak akibat kekurangan gizi kronis dan infeksi berulang, yang ditandai dengan panjang atau tinggi badan berada di bawah standar yang ditetapkan oleh menteri yang menyelenggarakan urusan pemerintahan di bidang kesehatan'),
(1060, 1055, 'P34.5', 'Apa itu Percepatan Penurunan Stunting?', 'Percepatan penurunan stunting adalah setiap upaya yang mencakup intervensi spesifik dan intervensi sensitif yang dilaksanakan secara konvergen, holistik, integratif, dan berkualitas melalui kerja sama multisektoral'),
(1061, 1055, 'P34.6', 'Siapa saja yang menjadi kelompok sasaran percepatan penurunan stunting?', 'Kelompok sasaran pelaksanaan percepatan penurunan stunting meliputi:\n1.        Remaja\n2.        Calon pengantin\n3.        Ibu hamil\n4.        Ibu menyusui\n5.        Anak usia 0 – 59 bulan'),
(1062, 1055, 'P34.7', 'Masalah non kesehatan apa saja yang menjadi akar masalah stunting?', 'Masalah non kesehatan yang menjadi akar permasalahan stunting adalah Pola Makan, Pola Asih dan Sanitasi dan Akses Air Bersih'),
(1063, 1055, 'P34.8', 'Pelaksanaan percepatan penurunan stunting di desa/kelurahan menjadi tanggung jawab...', 'Kepala Desa/Lurah'),
(1064, 1055, 'P34.9', 'Apakah yang dimaksud program ABCDE pada Cegah Stunting', 'A adalah Aktif minum TTD (Tablet Tambah Darah)\nB adalah Bumil teratur periksa kehamilan minimal 6 kali\nC adalah Cukupi konsumsi protein hewani\nD adalah Datang ke Posyandu setiap bulan\nE adalah Eksklusif ASI selama 6 bulan'),
(1065, 1055, 'P34.10', 'Apa penyebab stunting', 'Stunting terkait dengan banyak penyebab, antara lain faktor asupan gizi ibu dan anak, status kesehatan balita, ketahanan pangan, lingkungan sosial dan kesehatan, lingkungan pemukiman, dan kemiskinan'),
(1066, 1055, 'P34.11', 'Apakah perbedaan dari Stunting, Wasting, dan Underweight?', 'Stunting, wasting, dan underweight adalah tiga kondisi malnutrisi yang berbeda, semuanya penting untuk dipahami dalam konteks kesehatan anak. Stunting, atau pendek, terjadi ketika tinggi badan anak rendah untuk usianya. Wasting, atau kurus, terjadi ketika berat badan anak rendah untuk tinggi badannya. Underweight, atau berat badan kurang, terjadi ketika berat badan anak rendah untuk usianya. Kementerian Kesehatan (Kemenkes) menggunakan survei seperti Survei Kesehatan Indonesia (SKI) untuk memantau dan mengevaluasi prevalensi ketiga kondisi ini, serta untuk melacak intervensi yang dilakukan.'),
(1067, 1055, 'P34.12', 'Apa sih stunting itu sebenarnya? Beda dengan kurang gizi biasa?', 'Stunting adalah kondisi di mana tinggi badan anak lebih rendah dari rata-rata untuk usianya akibat kekurangan nutrisi yang berlangsung dalam jangka waktu lama, terutama selama 1.000 hari pertama kehidupan (sejak dalam kandungan hingga usia dua tahun). Stunting berbeda dengan kurang gizi biasa (gizi buruk) karena stunting merupakan akibat dari kekurangan gizi kronis (jangka panjang), sedangkan gizi buruk biasanya terjadi akibat kekurangan asupan gizi dalam waktu yang lebih singkat dan umumnya ditandai dengan berat badan yang turun drastis atau anak tampak sangat kurus.'),
(1068, 1055, 'P34.13', 'Kok bisa sih ada stunting di negara yang kaya akan sumber daya seperti Indonesia?', 'Stunting masih terjadi di Indonesia meskipun negara ini kaya akan sumber daya alam karena penyebabnya bukan hanya kekurangan pangan, tetapi juga faktor sosial-ekonomi, pendidikan, perilaku, dan akses layanan kesehatan. Banyak keluarga, meski tinggal di daerah yang kaya sumber makanan seperti pesisir laut, tetap mengalami stunting akibat rendahnya pengetahuan tentang gizi, mitos-mitos yang salah soal makanan, tingkat pendidikan yang rendah, pendapatan keluarga yang terbatas, serta akses yang kurang terhadap sanitasi dan layanan kesehatan. Jadi, kekayaan sumber daya alam tidak otomatis menjamin kecukupan gizi jika distribusi, pengetahuan, dan akses terhadap sumber daya tersebut tidak merata atau tidak dimanfaatkan secara optimal'),
(1069, 1055, 'P34.14', 'Kapan sih periode kritis untuk mencegah stunting?', 'Periode kritis untuk mencegah stunting adalah selama 1000 Hari Pertama Kehidupan (HPK), yang dimulai sejak masa kehamilan hingga anak berusia 23 bulan (sekitar 2 tahun). Pada periode ini, intervensi gizi dan pemenuhan kebutuhan nutrisi sangat penting untuk mencegah stunting, karena ini adalah masa emas pertumbuhan dan perkembangan anak. Pencegahan stunting meliputi pemenuhan gizi ibu hamil, pemberian ASI eksklusif selama 6 bulan pertama, serta pemberian makanan pendamping ASI yang bergizi setelah 6 bulan hingga usia 23 bulan. Dengan kata lain, pencegahan stunting harus dimulai sejak kehamilan dan berlanjut hingga anak berusia dua tahun, karena pada masa ini kekurangan gizi dapat menyebabkan dampak yang bersifat irreversible pada pertumbuhan dan perkembangan anak'),
(1070, 1055, 'P34.15', 'Apakah stunting bisa \"disembuhkan\" atau diperbaiki setelah anak berusia di atas 2 tahun?', 'Stunting pada anak di atas usia 2 tahun tidak bisa disembuhkan sepenuhnya karena gangguan pertumbuhan dan perkembangan otak yang sudah terjadi bersifat permanen dan sulit diperbaiki. Namun, stunting masih bisa diperbaiki atau diperbaiki kondisi tumbuh kembangnya dengan intervensi gizi dan medis yang tepat untuk meningkatkan perkembangan otak dan fisik anak. Intervensi tersebut tetap penting untuk diberikan agar perkembangan otak anak yang stunting dapat terus berlanjut meskipun tidak mencapai potensi optimal seperti anak tanpa stunting. Direktur Gizi dan Kesehatan Ibu-Anak Kemenkes RI, Lovely Daisy, menyatakan bahwa pertumbuhan optimal otak anak biasanya mencapai 85 persen pada usia 2 tahun, dan anak stunting umumnya berada di bawah angka tersebut. Oleh karena itu, meski tidak bisa kembali ke potensi optimal, intervensi gizi dan pengobatan tetap diberikan untuk memperbaiki kondisi anak setelah usia 2 tahun. Singkatnya, stunting setelah usia 2 tahun tidak bisa disembuhkan sepenuhnya, tapi perbaikan tumbuh kembang masih mungkin dengan intervensi yang tepat'),
(1071, 1055, 'P34.16', 'Apakah stunting hanya masalah tinggi badan, atau ada dampak lain yang lebih serius?', 'Stunting bukan hanya masalah tinggi badan yang pendek, tetapi juga memiliki dampak serius lainnya. Selain tubuh yang lebih pendek dan berat badan rendah, anak yang mengalami stunting cenderung memiliki tingkat kecerdasan di bawah rata-rata, sehingga kemampuan belajar dan prestasinya di sekolah menurun. Kondisi ini juga membuat anak lebih mudah sakit karena sistem kekebalan tubuhnya kurang optimal. Selain itu, stunting meningkatkan risiko penyakit kronis di masa dewasa seperti penyakit jantung, stroke, diabetes, dan hipertensi. Dampak jangka panjang lainnya termasuk gangguan perkembangan mental, risiko depresi, serta penurunan produktivitas saat dewasa.'),
(1072, 1055, 'P34.17', 'Apakah stunting mempengaruhi mental health juga?', 'Pada kasus stunting, risiko disfungsi psikososial lebih tinggi dibandingkan kondisi normal. Anak stunting terdeteksi memiliki kepercayaan diri yang rendah dan berisiko pula memunculkan masalah keluarga terutama ketika menginjak usia remaja . Anak stunting juga mudah cemas dan rentan mengalami depresi . Setalah beranjak remaja, anak dapat berisiko memiliki kemampuan kognitif yang rendah, yaitu kurang berkembang dibandingkan dengan remaja tidak stunting. Anak stunting diawal dua tahun kehidupannya cenderung berisiko mengalami permasalahan pada kondisi psikologis ketika remaja bila dibandingkan dengan anak normal. Diantaranya adalah kecenderungan cemas dan rentan depresi, kepercayaan diri yang rendah, dan menampakkan perilaku-perilaku hiperaktif yang mengarah pada perilaku yang bertentangan dengan kondisi normal. Meskipun demikian, dengan stimulasi perkembangan anak yang baik, pengaruh negatif dari kejadian stunting terhadap perkembangan anak dapat diminimalisir dampaknya. Anak dengan stunting dan dampaknya terhadap pertumbuhan dan perkembangan selanjutnya, dapat mempengaruhi kualitas sumber daya manusia Indonesia untuk berdaya saing dengan negara-negara lainnya. Orang tua adalah kunci dari penanggulangan stunting di Indonesia. Untuk itu, perlu edukasi terhadap orang tua dalam pembenahan pada pola asuh, pola pemberian asupan gizi, dan juga sanitasi serta akses air bersih.'),
(1073, 1055, 'P34.18', 'Apakah fast food culture berkontribusi terhadap stunting?', 'Fast food culture berkontribusi terhadap stunting karena makanan cepat saji atau junk food mengandung banyak lemak jenuh, garam, gula, dan kalori tinggi namun rendah nutrisi penting seperti vitamin, mineral, protein, kalsium, dan zat besi yang dibutuhkan untuk pertumbuhan anak. Anak yang mendapat kalori dari makanan tinggi gula, tinggi garam, dan tinggi lemak memiliki tubuh yang lebih pendek atau mengalami indikasi stunting dibandingkan dengan anak seusia mereka yang makan junk food lebih sedikit. Konsumsi junk food berlebihan dapat menyebabkan kekurangan gizi pada anak, yang dapat menghambat pertumbuhan fisik sehingga menyebabkan stunting.'),
(1074, 1055, 'P34.19', 'Apakah ada hubungan antara stunting dan perubahan iklim?', 'Perubahan iklim yang semakin ekstrem dapat memengaruhi kondisi kesehatan anak, termasuk peningkatan prevalensi stunting, melalui ketidakmampuan memenuhi kebutuhan dasar seperti gizi, air bersih, dan lingkungan sehat. Perubahan iklim menyebabkan penurunan produksi pangan hingga 44%, yang mengancam ketahanan pangan dan meningkatkan risiko malnutrisi pada anak-anak, sehingga berkontribusi pada kasus stunting. Selain itu, perubahan iklim juga memengaruhi kualitas dan kuantitas pangan yang tersedia, seperti penurunan kandungan gizi pada tanaman pangan akibat tingginya konsentrasi karbon dioksida. Oleh karena itu, penanganan perubahan iklim harus terintegrasi dengan upaya penurunan stunting untuk melindungi kesehatan anak dan memastikan generasi masa depan yang sehat dan tangguh'),
(1075, 1055, 'P34.20', 'Apa saja \"superfoods\" lokal Indonesia yang bisa mencegah stunting?', 'Beberapa \"superfoods\" lokal Indonesia yang dapat mencegah stunting antara lain:\n - Ikan patin: Ikan ini kaya protein, omega-3, vitamin, dan mineral yang penting untuk pertumbuhan dan perkembangan anak serta pencegahan stunting. Konsumsi ikan patin dapat meningkatkan perkembangan otak, kesehatan jantung, dan daya tahan tubuh anak.\n - Daun kelor (Moringa oleifera): Daun kelor mengandung protein, vitamin A, vitamin C, kalsium, zat besi, dan nutrisi lain yang sangat penting untuk mencegah stunting. Kandungan nutrisinya jauh lebih tinggi dibandingkan beberapa sumber pangan lain, seperti beta-karoten 4 kali wortel dan zat besi 25 kali bayam. Daun kelor juga dapat meningkatkan sistem kekebalan tubuh dan membantu memperbaiki status gizi anak-anak di daerah dengan prevalensi stunting tinggi.\n - Singkong: Singkong merupakan sumber pangan lokal yang berpotensi dikembangkan menjadi makanan bergizi tinggi seperti tepung mocaf (modified cassava flour). Meskipun secara alami rendah protein, singkong bisa dimodifikasi untuk memenuhi kebutuhan nutrisi penting seperti vitamin, zat besi, zinc, dan protein yang dibutuhkan untuk mencegah stunting.\n  Ketiga superfood ini merupakan contoh pangan lokal Indonesia yang kaya nutrisi dan efektif mendukung pencegahan stunting melalui peningkatan asupan gizi anak-anak.'),
(1076, 1055, 'P34.21', 'Apa inovasi teknologi terkini yang bisa membantu mendeteksi dan mencegah stunting?', 'Inovasi teknologi terkini yang dapat membantu mendeteksi dan mencegah stunting adalah alat Electronic Stunting Detection System (ESDS) berbasis kecerdasan buatan (Artificial Intelligence/AI) yang dikembangkan oleh mahasiswa Universitas Gadjah Mada (UGM). Alat ini mampu mengukur massa dan panjang tubuh bayi secara cepat dalam lima detik dan langsung menghitung status gizi bayi menggunakan rumus yang telah ditetapkan. ESDS juga terintegrasi dengan sistem informasi dan aplikasi smartphone untuk menyimpan data pengukuran secara otomatis, sehingga pertumbuhan dan perkembangan bayi dapat dipantau secara berkala. Dengan bantuan machine learning, alat ini memberikan deteksi dini stunting pada anak di bawah dua tahun, memudahkan orang tua dan tenaga kesehatan dalam pemantauan mandiri serta diharapkan dapat membantu percepatan penurunan angka prevalensi stunting di Indonesia'),
(1077, 1055, 'P34.22', 'Kenapa ASI eksklusif penting untuk mencegah stunting?', 'ASI eksklusif penting untuk mencegah stunting karena ASI mengandung nutrisi lengkap yang sangat dibutuhkan bayi selama 0-6 bulan pertama kehidupan, sehingga dapat memenuhi kebutuhan gizi bayi secara optimal dan mencegah kekurangan gizi kronis yang menyebabkan stunting. Pemberian ASI eksklusif terbukti membantu menurunkan risiko stunting dengan memastikan bayi mendapatkan asupan nutrisi yang cukup untuk pertumbuhan fisik dan perkembangan otak yang optimal. Selain itu, ASI juga mengandung komponen seperti Human Milk Oligosaccharide (HMO) yang berfungsi sebagai prebiotik untuk mendukung kesehatan usus dan mencegah infeksi, yang dapat memperkuat daya tahan tubuh bayi sehingga tumbuh kembangnya tidak terganggu. Pemberian ASI eksklusif selama 6 bulan pertama dapat menurunkan risiko kematian akibat penyakit infeksi seperti pneumonia dan diare yang juga berkontribusi pada pencegahan stunting.'),
(1078, 1055, 'P34.23', 'Apakah program pemerintah untuk mengatasi stunting sudah cukup kekinian untuk Gen Z?', 'Program pemerintah untuk mengatasi stunting saat ini menunjukkan upaya yang cukup kekinian dan melibatkan berbagai inovasi serta kolaborasi dengan masyarakat, yang relevan untuk generasi Z. Misalnya, program \"Gerakan Orang Tua Asuh Cegah Stunting\" yang melibatkan sekitar 7.000 orang tua asuh secara langsung tanpa perantara, menggunakan pendekatan gotong royong dan teknologi monitoring serta evaluasi yang sedang disusun SOP-nya untuk memperlancar pelaksanaan program ke depan. Selain itu, inovasi digital seperti Digital Analisis Z-Score (Digiztunt) di tingkat kecamatan juga diterapkan sebagai bagian dari intervensi stunting yang modern dan terintegrasi. Program ini tidak hanya fokus pada pemberian makanan bergizi gratis bagi ibu hamil dan balita, tetapi juga memperkuat sinergi lintas sektor dan kolaborasi dengan dunia usaha serta masyarakat, yang menunjukkan pendekatan yang adaptif dan kontekstual terhadap kebutuhan generasi muda saat ini.'),
(1079, 1055, 'P34.24', 'Apakah suplemen vitamin selama kehamilan benar-benar efektif mencegah stunting?', 'Suplemen vitamin selama kehamilan terbukti efektif dalam mencegah stunting pada anak. Penelitian menunjukkan bahwa suplementasi mikronutrien seperti zink, zat besi, asam folat, dan vitamin-vitamin penting lainnya pada ibu hamil dapat meningkatkan status gizi ibu, yang berpengaruh signifikan terhadap pertumbuhan janin dan mencegah risiko stunting setelah lahir. Misalnya, suplementasi zink pada ibu hamil meningkatkan kadar zink serum ibu, osteocalcin darah tali pusat, dan panjang badan bayi, yang berkorelasi dengan pencegahan stunting. Selain itu, asupan vitamin D dan vitamin B9 (asam folat) selama kehamilan juga penting untuk mencegah stunting dengan mendukung perkembangan janin secara optimal. Secara keseluruhan, pemenuhan nutrisi yang cukup melalui suplemen vitamin dan mineral selama kehamilan sangat berperan dalam menurunkan risiko stunting pada anak.'),
(1080, 1055, 'P34.25', 'Bagaimana cara kampanye anti-stunting yang efektif untuk Gen Z?', 'Cara kampanye anti-stunting yang efektif untuk Gen Z adalah dengan memanfaatkan media sosial dan platform digital yang mereka gunakan sehari-hari, seperti Instagram, TikTok, dan YouTube. Konten kampanye sebaiknya dikemas secara menarik, sederhana, dan relevan dengan gaya hidup Gen Z, misalnya melalui video pendek, infografis, atau challenge yang mengajak partisipasi aktif. Selain itu, pesan kunci tentang pentingnya gizi seimbang, pola hidup sehat, serta edukasi mengenai bahaya dan pencegahan stunting perlu disampaikan secara konsisten. Pemerintah melalui program seperti Genbest telah mengamplifikasi pesan ini dengan melibatkan komunitas dan menyediakan informasi kredibel di berbagai kanal digital, sehingga Gen Z dapat menjadi agen perubahan dalam pencegahan stunting di lingkungan mereka.'),
(1081, 1055, 'P34.26', 'Apakah ada korelasi antara stunting dan kemiskinan multi-dimensi?', 'Terdapat korelasi antara stunting dan kemiskinan multi-dimensi. Determinan stunting sangat kompleks dan multidimensi, tidak hanya terkait aspek kesehatan tetapi juga masalah ekonomi dan sosial budaya. Data menunjukkan bahwa lebih dari 48 persen keluarga di desil 1 (keluarga sangat miskin) berisiko mengalami stunting, yang berarti penanganan kemiskinan ekstrem dan stunting saling beririsan. Oleh karena itu, upaya menuntaskan stunting harus dibarengi dengan penyelesaian masalah kemiskinan ekstrem secara multidimensi. Selain itu, kemiskinan multidimensi mencakup berbagai aspek seperti kesehatan, pendidikan, dan standar hidup yang layak, yang semuanya berkontribusi pada risiko stunting. Dengan demikian, stunting dan kemiskinan multidimensi saling terkait secara struktural dan memerlukan pendekatan lintas sektor dan multidimensi untuk penanganannya.'),
(1082, 1055, 'P34.27', 'Apakah mitos dan budaya Indonesia dapat mempengaruhi stunting?', 'Mitos dan budaya di Indonesia dapat mempengaruhi kejadian stunting, terutama melalui pengaruhnya terhadap pola asuh dan pemberian makanan pada ibu hamil dan anak. Beberapa mitos yang dipercaya secara turun-temurun menyebabkan ibu hamil menghindari makanan tertentu yang sebenarnya penting untuk pemenuhan gizi, sehingga pertumbuhan anak menjadi terhambat karena gizinya tidak terpenuhi dengan baik. Contohnya, di beberapa daerah seperti Pekalongan, terdapat larangan bagi ibu hamil untuk mengonsumsi cumi-cumi, udang, telur, dan makanan lain dengan alasan yang bersifat klenik, yang berdampak pada kurangnya asupan gizi selama kehamilan. Selain itu, budaya ideasional berupa kepercayaan yang salah tentang stunting, seperti anggapan bahwa stunting adalah keturunan atau akibat kesalahan pola asuh yang diwariskan, juga berkontribusi pada kasus stunting. Budaya ini membentuk pola pikir dan perilaku yang salah dalam pemberian makanan dan pengasuhan anak, termasuk pemberian ASI yang tidak optimal dan pernikahan dini yang mempengaruhi kesehatan ibu dan anak.'),
(1083, 1055, 'P34.28', 'Apakah masalah stunting hanya relevan bagi yang berencana punya anak, atau semua Gen Z perlu tahu?', 'Masalah stunting tidak hanya relevan bagi mereka yang berencana punya anak, tetapi semua Gen Z perlu tahu dan peduli. Gen Z adalah generasi penerus yang akan memulai rumah tangga di masa depan, sehingga pemahaman tentang pencegahan stunting sejak dini sangat penting. Edukasi mengenai stunting perlu diberikan kepada Gen Z agar mereka dapat menjalankan perilaku hidup sehat dan mencegah stunting sejak dini. Dengan pengetahuan yang baik, Gen Z dapat berperan aktif dalam menurunkan angka stunting di masa mendatang, baik untuk diri sendiri, keluarga, maupun lingkungan sekitar'),
(1084, 1055, 'P34.29', 'Apakah urbanisasi mempengaruhi stunting di Indonesia?', 'Urbanisasi mempengaruhi kejadian stunting di Indonesia, terutama karena arus urbanisasi yang tinggi membawa penduduk dari desa ke kota yang berpotensi meningkatkan prevalensi stunting di wilayah perkotaan. Contohnya, di Provinsi Riau, urbanisasi tinggi memicu peningkatan masalah stunting di beberapa kabupaten dan kota karena pendatang yang membawa anak dalam kondisi stunting. Selain itu, faktor-faktor yang berhubungan dengan urbanisasi seperti kemiskinan, status gizi ibu selama kehamilan, kunjungan antenatal, dan kondisi sosial ekonomi di perkotaan juga berkontribusi terhadap stunting.'),
(1085, 1055, 'P34.30', 'Apakah trend diet plant-based di kalangan Gen Z berdampak pada pencegahan stunting?', 'Trend diet plant-based di kalangan Gen Z memang semakin populer dan didorong oleh kesadaran akan kesehatan, keberlanjutan, dan etika. Namun, belum ada bukti langsung bahwa tren ini berdampak signifikan pada pencegahan stunting. Gen Z cenderung memilih pola makan sehat dan beragam, termasuk makanan berbasis nabati yang kaya akan buah, sayur, kacang-kacangan, dan biji-bijian, yang jika diterapkan dengan benar bisa mendukung asupan gizi seimbang dan berpotensi membantu mencegah stunting. Namun, kunci pencegahan stunting tetap pada kecukupan gizi makro dan mikro, terutama pada masa pertumbuhan anak, sehingga pola makan plant-based harus dirancang agar tidak kekurangan protein, zat besi, zinc, vitamin B12, dan nutrisi penting lainnya yang umumnya banyak terdapat pada produk hewani'),
(1086, 1055, 'P34.31', 'Apakah stunting bisa diatasi dengan food technology dan cultured meat di masa depan?', 'Stunting dapat diatasi di masa depan dengan dukungan teknologi pangan, termasuk teknologi makanan dan cultured meat, sebagai bagian dari upaya meningkatkan kualitas gizi anak-anak. Meskipun tidak secara eksplisit disebutkan cultured meat, pemanfaatan teknologi pangan yang inovatif dapat membantu menyediakan makanan bergizi yang lebih mudah diakses dan tepat sasaran, yang sangat penting dalam intervensi pencegahan stunting. Teknologi ini memungkinkan pengembangan makanan pendamping ASI yang kaya nutrisi serta fortifikasi makanan yang dapat meningkatkan asupan gizi anak-anak. Selain itu, digitalisasi dan teknologi juga berperan penting dalam edukasi gizi, pemantauan tumbuh kembang anak, dan distribusi makanan bergizi secara lebih efektif dan efisien. Dengan aplikasi mobile dan telemedicine, edukasi gizi dan intervensi dapat menjangkau masyarakat luas, termasuk daerah terpencil, sehingga membantu mencegah stunting secara lebih tepat sasaran.'),
(1087, 1055, 'P34.32', 'Bagaimana Gen Z bisa menggunakan creative content untuk kampanye anti-stunting?', 'Gen Z dapat menggunakan creative content, seperti video pendek di TikTok, untuk kampanye anti-stunting dengan cara membuat konten yang relevan, menarik, dan mudah dipahami oleh sesama anak muda. Misalnya, kampanye #SadarStunting 2022 memanfaatkan format video vertikal, melibatkan talent muda, menggunakan unsur humor, musik, dan tema kekinian yang dekat dengan kehidupan Gen Z. Konten tersebut tidak hanya mengedukasi tentang pencegahan stunting, tetapi juga membangun kesadaran akan pentingnya persiapan pernikahan, kehamilan, dan pola hidup sehat sejak remaja, sehingga pesan kampanye lebih efektif dan mudah diterima oleh target audiens muda.'),
(1088, 1055, 'P34.33', 'Apa tanggung jawab kita sebagai Gen Z dalam mengatasi masalah stunting di Indonesia?', 'Tanggung jawab Gen Z dalam mengatasi masalah stunting di Indonesia meliputi beberapa hal penting, antara lain:\n  - Meningkatkan pengetahuan tentang nutrisi dengan mengedukasi diri sendiri mengenai pentingnya gizi seimbang melalui berbagai sumber terpercaya seperti seminar, buku, dan informasi digital.\n - Mempraktikkan pola makan sehat sejak dini sebagai langkah pencegahan yang juga akan menjadi contoh baik ketika membangun keluarga di masa depan.\n - Mendukung dan berpartisipasi aktif dalam program pemerintah yang bertujuan menurunkan angka stunting, seperti penyuluhan kesehatan dan kampanye nutrisi.\n - Mengadvokasi pentingnya gizi di lingkungan sekitar melalui media sosial, kegiatan komunitas, atau organisasi di sekolah dan kampus untuk meningkatkan kesadaran masyarakat luas.\n - Memahami dan menyebarkan informasi tentang stunting, penyebab, dampak, dan cara pencegahannya agar dapat menjadi agen perubahan yang peduli terhadap kesehatan anak-anak di masa depan.\n  Dengan peran tersebut, Gen Z dapat membantu mengurangi prevalensi stunting di Indonesia dan memastikan generasi mendatang tumbuh sehat dan kuat. Edukasi sebelum pernikahan mengenai pentingnya asupan gizi juga sangat penting untuk memutus siklus stunting.'),
(1089, 1055, 'P34.34', 'Bagaimana cara meyakinkan teman yang masih kuliah bahwa stunting adalah masalah yang relevan untuk mereka saat ini?', 'Untuk meyakinkan teman yang masih kuliah bahwa stunting adalah masalah yang relevan untuk mereka saat ini, bisa dengan menjelaskan bahwa pemerintah melalui BKKBN telah meluncurkan program \"Mahasiswa Peduli Stunting\" (Mahasiswa Penting). Program ini secara khusus melibatkan mahasiswa dari berbagai perguruan tinggi untuk berperan aktif dalam upaya pencegahan dan penurunan stunting di masyarakat melalui kegiatan seperti KKN Tematik, Merdeka Belajar Kampus Merdeka (MBKM), dan pengabdian masyarakat lainnya. Dengan terlibat dalam program ini, mahasiswa tidak hanya berkontribusi pada penyelesaian masalah nasional, tetapi juga mengimplementasikan ilmu yang mereka pelajari dan memperkuat peran mereka sebagai agen perubahan di masyarakat. Jadi, isu stunting bukan hanya urusan pemerintah atau tenaga kesehatan, tetapi juga sangat relevan dan membutuhkan partisipasi aktif mahasiswa pada masa sekarang.'),
(1090, 1055, 'P34.35', 'Apa perkembangan riset terbaru tentang stunting yang perlu diketahui oleh Gen Z?', 'Perkembangan riset terbaru tentang stunting yang perlu diketahui oleh Gen Z adalah bahwa penurunan prevalensi stunting di Indonesia terus diupayakan melalui berbagai program dan target nasional. Data terbaru menunjukkan bahwa prevalensi stunting di Indonesia menurun dari 24,4% pada tahun 2021 menjadi 21,6% pada tahun 2022, namun angka ini masih di atas standar WHO yaitu kurang dari 20%. Pemerintah menargetkan penurunan prevalensi stunting menjadi 14% pada tahun 2024 dan 18% pada tahun 2025 dengan program-program seperti Makan Bergizi Gratis yang menyasar ibu hamil dan anak balita. Penanganan stunting dilakukan secara multisektoral, melibatkan perbaikan gizi, sanitasi, dan lingkungan hidup yang sehat, serta edukasi kepada ibu hamil dan keluarga. Selain itu, riset juga menyoroti dampak jangka panjang stunting terhadap kemampuan kognitif dan kesehatan anak, sehingga penanganan stunting tidak hanya soal tinggi badan tetapi juga perkembangan otak dan kemampuan belajar anak. Pendekatan intervensi gizi prenatal dan pasca kelahiran serta penguatan sistem kekebalan tubuh anak juga menjadi fokus penting dalam riset terbaru untuk mencegah dan mengurangi stunting.'),
(1091, 1055, 'P34.36', 'Apakah sosial media mempengaruhi persepsi Gen Z tentang stunting?', 'Ya, sosial media sangat mempengaruhi persepsi Gen Z tentang stunting. Paparan informasi di media sosial, seperti kampanye edukasi dan konten dari influencer, dapat meningkatkan pengetahuan dan sikap positif terhadap pencegahan stunting. Namun, penyajian informasi yang tidak tepat atau berlebihan juga bisa memicu persepsi yang salah atau bahkan negatif.'),
(1092, 1055, 'P34.37', 'Bagaimana mengukur status gizi yang buruk pada calon pengantin?', 'Status Gizi Buruk dapat diketahui melalui Pengukuran Lingkar Lengan Atas (LILA) dan Indeks Massa Tubuh (IMT)'),
(1093, NULL, 'P35', 'Tim Pendamping Keluarga (TPK)', NULL),
(1094, 1093, 'P35.1', 'Apa itu Tim Pendamping Keluarga (TPK)?', 'Sekelompok tenaga yang dibentuk dan terdiri dari Bidan, Kader TP PKK dan Kader KB untuk melaksanakan pendampingan meliputi penyuluhan, fasilitasi pelayanan rujukan dan fasilitasi penerimaan program bantuan sosial kepada calon pengantin/calon pasangan usia subur, ibu hamil, ibu pasca persalinan, anak usia 0-59 bulan serta melakukan surveilans keluarga berisiko stunting untuk mendeteksi dini faktor-faktor risiko stunting. Dalam berbagai kondisi, komposisi tim pendamping keluarga dapat disesuaikan melalui bekerjasama dengan Bidan dari Desa/Kelurahan lainnya atau melibatkan perawat atau tenaga kesehatan lainnya'),
(1095, 1093, 'P35.2', 'Apa saja tugas dan tanggung jawab TPK di masyarakat?', 'Melaksanakan pendampingan kepada keluarga yang memiliki calon pengantin (catin)/Calon Pasangan Usia Subur (ca PUS), ibu hamil, ibu pascapersalinan, dan balita dengan fokus pada baduta yang meliputi: \n 1. Penyuluhan 2. Fasilitasi pelayanan rujukan 3. Fasilitasi penerimaan program bantuan sosial 4. Surveilans/pengamatan berkelanjutan untuk mendeteksi dini faktor risiko stunting.'),
(1096, 1093, 'P35.3', 'Siapa saja yang biasanya tergabung dalam TPK?', 'Bidan/, Kader PKK, Kader KB'),
(1097, 1093, 'P35.4', 'Apa pengertian Pendampingan Keluarga ?', 'Serangkaian kegiatan yang meliputi penyuluhan, fasilitasi pelayanan rujukan dan fasilitasi pemberian bantuan sosial yang bertujuan untuk meningkatkan akses informasi dan pelayanan kepada keluarga dan/atau keluarga berisiko stunting seperti ibu hamil, ibu pasca persalinan, anak usia 0 – 59 bulan, serta semua calon pengantin/calon pasangan usia subur melalui pendampingan 3 (tiga) bulan pranikah sebagai bagian dari pelayanan nikah untuk deteksi dini faktor risiko stunting dan melakukan upaya meminimalisir atau pencegahan pengaruh dari faktor risiko stunting.'),
(1098, 1093, 'P35.5', 'Apa tujuan utama dari pembentukan TPK?', 'Sebagai upaya percepatan penurunan stunting'),
(1099, 1093, 'P35.6', 'Bagaimana TPK membantu dalam penurunan angka stunting?', 'Melakukan penyuluhan, fasilitasi pelayanan rujukan, dan fasilitasi penerimaan program bantuan sosial kepada sasaran prioritas percepatan penurunan stunting sesuai dengan kebutuhan mereka dalam kerangka percepatan penurunan stunting.'),
(1100, 1093, 'P35.7', 'Bagaimana Tim Pendamping Keluarga (TPK) mendukung program 1000 Hari Pertama Kehidupan (HPK)?', 'Mendampingi keluarga dalam merencanakan dan memastikan kecukupan gizi serta perawatan yang baik bagi ibu hamil dan anak-anak selama 1000 Hari Pertama Kehidupan.'),
(1101, 1093, 'P35.8', 'Apa yang dimaksut Intervensi gizi sensitif ?', 'Intervensi yang secara tidak langsung mempengaruhi kejadian stunting. Intervensi ini mencakup utamanya faktor keamanan pangan, pelayanan kesehatan, penyediaan sanitasi dan air bersih yang layak dan aman.'),
(1102, 1093, 'P35.9', 'Apa bentuk pelatihan yang diterima oleh anggota TPK?', 'Orientasi Tim Pendamping Keluarga (TPK)'),
(1103, 1093, 'P35.10', 'Tujuan strategi nasional percepatan penurunan stunting sesuai dengan Peraturan Presiden RI Nomor 72 tahun 2021 tentang Percepatan Penurunan Stunting, yaitu :', 'a. Menurunkan prevalensi stunting; b. Meningkatkan kualitas penyiapan kehidupan berkeluarga;c. Menjamin pemenuhan asupan gizi; d. Memperbaiki pola asuh; e. Meningkatkan akses dan mutu pelayanan kesehatan; dan f. Meningkatkan akses air minum dan sanitasi.'),
(1104, 1093, 'P35.11', 'Apa yang dimaksut Intervensi gizi spesifik?', 'Intervensi yang secara langsung mempengaruhi pemenuhan gizi dan perkembangan janin dan anak terutama sampai berusia kurang dari 23 bulan. Intervensi ini bertujuan untuk memastikan kecukupan gizi ibu hamil dan anak serta penurunan faktor risiko infeksi.'),
(1105, 1093, 'P35.12', 'Definisi Pendampingan Keluarga adalah?', 'Serangkaian kegiatan yang meliputi penyuluhan, fasilitasi pelayanan rujukan dan fasilitasi pemberian bantuan sosial yang bertujuan untuk meningkatkan akses informasi dan pelayanan keluarga dan/atau keluarga beresiko stunting dengan sasaran prioritas yaitu ibu hamil, ibu pasca persalinan, anak usia 0 – 59 bulan, dan semua calon pengantin/calon pasangan usia subur melalui pendampingan 3 (tiga) bulan pranikah sebagai bagian dari pelayanan nikah untuk deteksi dini faktor risiko stunting dan melakukan upaya meminimalisir atau pencegahan pengaruh dari faktor risiko stunting.'),
(1106, 1093, 'P35.13', 'Apabila ditemukan baduta dengan perlambatan pertambahan berat badan (weight faltering) atau grafik KMS Berat Badan Tidak Naik (T), apa yang harus dilakukan TPK?', 'a. Tanyakan dan catat keadaan Kesehatan anak apabila ada keluhan (batuk, diare, panas, rewel, dll) serta kebiasaan makan anak \n b. Berikan penjelasan tentang kemungkinan anak mengalami perlambatan pertambahan berat badan (weight faltering) \n c. Rujuk ke tenaga Kesehatan Puskesmas/Pustu/Poskesdes dan berikan penjelasan tujuan rujukan untuk melakukan konfirmasi risiko gangguan pertumbuhan agar dapat ditindaklanjuti secara cepat dan tepat.');
INSERT INTO `faq` (`id`, `parent_id`, `key_name`, `question_text`, `answer_text`) VALUES
(1107, 1093, 'P35.14', 'Apa manfaat pemeriksaan kehamilan bagi Ibu Hamil?', 'Melakukan pemeriksaan kehamilan atau Antenatal Care (ANC) bertujuan untuk meningkatkan kesehatan fisik dan mental pada ibu hamil secara optimal, hingga mampu menghadapi masa persalinan, nifas, menghadapi persiapan pemberian ASI secara eksklusif, serta kembalinya kesehatan alat reproduksi dengan wajar.'),
(1108, 1093, 'P35.15', 'Dalam mendukung tujuan strategi nasional, maka selanjutnya disusun Rencana Aksi Nasional Percepatan Penurunan Stunting (RAN PASTI) untuk mendorong dan menguatkan konvergensi antar program melalui pendekatan keluarga berisiko stunting yang terdiri atas kegiatan prioritas yang paling sedikit mencakup apa saja?', 'a. Penyediaaan data keluarga berisiko stunting;\n b. Pendampingan keluarga berisiko stunting;\n c. Pendampingan semua calon pengantin/ calon PUS;\n d. Surveilans keluarga berisiko stunting; dan\n e. Audit kasus stunting.'),
(1109, 1093, 'P35.16', 'Bagaimana TPK melibatkan masyarakat dalam program pendampingan?', 'Dengan cara mengedukasi, mengajak diskusi, serta memfasilitasi masyarakat untuk aktif dalam program-program yang mendukung kesejahteraan keluarga.'),
(1110, 1093, 'P35.17', 'Apakah TPK mendapat dukungan dari pemerintah daerah atau pusat?', 'TPK mendapat dukungan dari pemerintah daerah dan pemerintah'),
(1111, 1093, 'P35.18', 'Apakah Peran Bidan dalam Tim Pendamping Keluarga (TPK)?', 'Sebagai koordinator pendampingan keluarga dan pemberi pelayanan kesehatan.'),
(1112, 1093, 'P35.19', 'Apakah Peran Kader PKK dalam Tim Pendamping Keluarga (TPK)?', 'Sebagai penggerak dan fasilitator (mediator) pelayanan-pelayanan bagi keluarga.'),
(1113, 1093, 'P35.20', 'Apakah Peran Kader KB dalam Tim Pendamping Keluarga (TPK)?', 'Sebagai pencatat dan pelapor data/perkembangan pelaksanaan pendampingan keluarga dan/atau kelompok sasaran.'),
(1114, 1093, 'P35.21', 'Nama aplikasi untuk pencatatan yang digunakan TPK dalam melakukan pendampingan sasaran adalah?', 'Elsimil'),
(1115, 1093, 'P35.22', 'Apa pesan kunci Tim Pendamping Keluarga (TPK)?', 'Ikhlas Tuntas'),
(1116, 1093, 'P35.23', 'Teknik penyuluhan akronim “SAJI” kepanjangannya apa?', 'Salam, Ajak Bicara, Jelaskan, Ingatkan'),
(1117, 1093, 'P35.24', 'Risiko terjadinya stunting itu salah satu faktor 4T, apa pengertiannya?', 'Terlalu Muda, Terlalu Tua, Terlalu Dekat, Terlalu Banyak'),
(1118, 1093, 'P35.25', 'Peraturan Presiden Nomor 72 Tahun 2021 tentang apa?', 'Percepatan Penurunan Stunting'),
(1119, 1093, 'P35.26', 'Apakah pengertian stunting itu?', 'Gangguan pertumbuhan dan perkembangan anak akibat kekurangan gizi kronis dan infeksi berulang, yang ditandai dengan panjang atau tinggi badannya berada dibawah standar yang ditetapkan oleh Menteri yang menyelenggarakan urusan pemerintahan di bidang kesehatan.'),
(1120, 1093, 'P35.27', 'Sebutkan 3 (tiga) langkah kerja TPK !', '1. Koordinasi 2. Pelaksanaan penyuluhan, fasilitasi pelayanan rujukan \n dan fasilitasi penerimaan program bantuan sosial 3. Pencatatan dan Pelaporan'),
(1121, 1093, 'P35.28', 'Kedudukan TPK berada di mana?', 'Desa/ Kelurahan'),
(1122, 1093, 'P35.29', 'Aktivitas pendampingan TPK yang dicatat meliputi apa saja?', 'a) Data identitas dan karakteristik keluarga (keluarga berisiko b) Data sasaran yang didampingi c) Data Penapisan d) Data Kegiatan Pendampingan'),
(1123, 1093, 'P35.30', 'Sebutkan 5 (lima) kelompok sasaran percepatan penurunan stunting !', 'a. Remaja; b. Calon pengantin; c. Ibu hamil & Ibu Pasca Persalinan; d. Ibu menyusui; dan e. Anak berusia O (nol) – 59 (lima puluh sembilan) bulan.'),
(1124, 1093, 'P35.31', 'ASI Eksklusif diberikan pada usia berapa?', '6 bulan pertama sejak bayi baru lahir'),
(1125, 1093, 'P35.32', 'Berapa kenaikan berat badan ideal ibu selama kehamilan?', 'Kenaikan berat badan normal pada saat ibu hamil di rentang 11 – 16 kg.'),
(1126, 1093, 'P35.33', 'Apa pengertian 1000 HPK?', 'Masa sejak konsepsi sampai anak berusia 2 tahun. Periode ini disebut juga “Periode Emas” karena pada masa ini pertumbuhan dan perkembangan otak sangat pesat, untuk itu semua kebutuhan dasar berupa asupan gizi, kasih sayang, stimulasi, imunisasi dan kebersihan harus terpenuhi. Kebutuhan yang tidak terpenuhi pada 1000 HPK akan menimbulkan dampak bersifat permanen yaitu terhambatnya pertumbuhan fisik, perkembangan mental, kecerdasan dan perilaku.'),
(1127, 1093, 'P35.34', 'Apa saja yang harus dihindari ibu selama hamil?', 'a. Kerja terlalu berat \n b. Merokok atau terpapar asap rokok \n c. Minum-minuman bersoda, atau minuman beralkohol \n d. Minum obat-obatan tanpa resep dokter \n e. Stress berlebihan'),
(1128, 1093, 'P35.35', 'Apa saja dampak anemia pada ibu hamil?', 'Dapat meningkatkan risiko terjadinya masalah kesehatan antara lain perdarahan pascapersalinan, kelahiran prematur, kelahiran bayi dengan berat badan lahir rendah, keguguran, serta kematian janin dan/atau ibu'),
(1129, 1093, 'P35.36', 'Siapa yang membentuk dan mengoordinasikan Tim Pendamping Keluarga (TPK)?', 'BKKBN bersama dinas terkait membentuk dan membina Tim Pendamping Keluarga (TPK).'),
(1130, 1093, 'P35.37', 'Apa yang BKKBN lakukan apabila terdapat kasus remaja yang mendapatkan kekerasan dalam rumah oleh orang tuanya?', 'Melakukan konsultasi dan konseling keluarga remaja dan remaja melalui Satyagatra'),
(1131, NULL, 'P36', 'UPPKA', NULL),
(1132, 1131, 'P36.1', 'Apakah BKKBN memfasilitasi pengembangan ekonomi dengan pemberian bantuan modal?', 'Ya! BKKBN memiliki program Upaya Pengembangan Pemberdayaan Ekonomi Keluarga (UPPEK). Program ini bertujuan untuk menjalin kerjasama dengan keluarga penerima untuk meningkatkan kemandirian ekonomi keluarga.'),
(1133, 1131, 'P36.2', 'Kelompok UPPKA kami sudah berdiri, tapi kenapa banyak anggota yang tidak aktif? Apa yang harus dilakukan?', 'Sesuai modul, anggota perlu dilibatkan aktif dalam perencanaan, pelaksanaan, dan evaluasi kegiatan. Bangun rasa memiliki dengan memberikan peran dan tanggung jawab yang jelas kepada setiap anggota.'),
(1134, 1131, 'P36.3', 'Apa tanda-tanda kalau kelompok UPPKA sudah dianggap mandiri?', 'Tandanya antara lain: usaha dikelola secara swadaya, tidak bergantung pada bantuan luar, anggota memiliki keterampilan memadai, dan pemasaran berjalan lancar.'),
(1135, 1131, 'P36.4', 'Apa saja keterampilan yang penting diberikan kepada anggota UPPKA?', 'Keterampilan yang perlu diberikan antara lain: keterampilan produksi, manajemen usaha kecil, pemasaran produk, serta literasi keuangan dasar.'),
(1136, 1131, 'P36.5', 'Bagaimana mengukur keberhasilan kelompok UPPKA setelah berjalan setahun?', 'Indikator keberhasilan meliputi: adanya peningkatan pendapatan keluarga, kelompok usaha aktif dan mandiri, keterampilan anggota meningkat, serta usaha berkelanjutan.'),
(1137, 1131, 'P36.6', 'Apakah kelompok UPPKA boleh bergabung dengan program lain di desa?', 'Boleh, bahkan dianjurkan! Di modul ini disebutkan bahwa sinergi dengan program desa (seperti BUMDes, PKK, atau koperasi) dapat memperkuat kapasitas usaha kelompok.'),
(1138, 1131, 'P36.7', 'Jika kelompok sudah punya produk, bagaimana cara menentukan harga jual yang sesuai?', 'Penentuan harga dapat dilakukan berdasarkan biaya produksi, biaya operasional, dan margin keuntungan yang wajar agar usaha tetap berkelanjutan.'),
(1139, 1131, 'P36.8', 'Apakah semua anggota harus punya usaha sendiri, atau cukup ikut kelompok saja?', 'Keduanya dapat dilakukan! Anggota dapat fokus pada usaha kelompok, atau mengelolanya sembari membesarkan usaha milik pribadi. Tentu dengan syarat tetap berkomitmen dalam menjadi anggota UPPKA.'),
(1140, 1131, 'P36.9', 'Apa bentuk dukungan pemerintah terhadap kelompok UPPKA yang aktif?', 'Pemerintah dapat memberikan pelatihan tambahan, bantuan peralatan, akses permodalan, hingga kesempatan mengikuti pameran usaha.'),
(1141, 1131, 'P36.10', 'Apakah keluarga anggota UPPKA boleh dilibatkan dalam usaha?', 'Sangat boleh, bahkan dianjurkan untuk memberdayakan seluruh keluarga, memperkuat ekonomi rumah tangga, dan mempererat rasa memiliki usaha.'),
(1142, 1131, 'P36.11', 'Bagaimana peran UPPKA dalam mendukung program Keluarga Berencana (KB)?', 'Dengan meningkatkan kesejahteraan ekonomi keluarga, UPPKA membantu mewujudkan keluarga kecil bahagia dan sejahtera, sejalan dengan tujuan program KB.'),
(1143, 1131, 'P36.12', 'Bagaimana peran BKKBN dalam meningkatkan pemberdayaan ekonomi keluarga melalui UPPKA?', 'Melalui program UPPKA, BKKBN membantu pengembangan usaha ekonomi keluarga berbasis kelompok.');
INSERT INTO `users` (`id`, `username`, `password`) VALUES
(2, 'BKKBNDIYBANGGA', '$2y$10$mrYXcJjlvnjGPRX1izUba.Hz7nBtPi/gYOsJqXPw4wkHMZmntvb.C');
